#include <wiringPi.h>
#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <ctype.h>
#include <string.h>
#include <pthread.h>
#include <errno.h>

// Define GPIO pins for segments and digits
// Ensure these match your wiring
#define SEG_A 6
#define SEG_B 5
#define SEG_C 4
#define SEG_D 3
#define SEG_E 2
#define SEG_F 1
#define SEG_G 0

#define DIGIT_1 7
#define DIGIT_2 11
#define DIGIT_3 10
#define DIGIT_4 13
#define DIGIT_5 12
#define DIGIT_6 14

// Array to hold the GPIO pins for segments and digits
static const int segmentPins[] = {SEG_A, SEG_B, SEG_C, SEG_D, SEG_E, SEG_F, SEG_G};
static const int digitPins[] = {DIGIT_1, DIGIT_2, DIGIT_3, DIGIT_4, DIGIT_5, DIGIT_6};

// Lookup table for 7-segment display patterns
// Each row represents a digit (0-9) or special character
static const int segmentPatterns[] = {
    0b00111111, // 0
    0b00000110, // 1
    0b01011011, // 2
    0b01001111, // 3
    0b01100110, // 4
    0b01101101, // 5
    0b01111101, // 6
    0b00000111, // 7
    0b01111111, // 8
    0b01101111  // 9
};

// Global variable to hold the display string
// Access to this variable should be thread-safe
static char displayString[7] = "      "; // Initialize with spaces
pthread_mutex_t displayMutex = PTHREAD_MUTEX_INITIALIZER;

// Function to set the segment pins based on a pattern
void setSegments(int pattern) {
    for (int i = 0; i < 7; i++) {
        digitalWrite(segmentPins[i], (pattern >> i) & 1);
    }
}

// Function to display a digit on a specific digit display
void displayDigit(int digit, char character) {
    int index;

    if (isdigit(character)) {
        index = character - '0';
    } else {
        index = -1; // Invalid character
    }

    // Turn on the segments for the digit
    if (index >= 0 && index < 10) {
        setSegments(segmentPatterns[index]);
    } else {
        setSegments(0); // Turn off all segments for invalid characters
    }

    // Activate the digit
    digitalWrite(digitPins[digit], HIGH);
    delay(2); // Short delay to allow the digit to be visible
    digitalWrite(digitPins[digit], LOW);
}

// Thread function to continuously update the 7-segment display
void *displayUpdateThread(void *arg) {
    while (1) {
        pthread_mutex_lock(&displayMutex);
        for (int i = 0; i < 6; i++) {
            displayDigit(i, displayString[i]);
        }
        pthread_mutex_unlock(&displayMutex);
        delay(1); // Adjust delay for desired refresh rate
    }
    return NULL;
}

// Function to initialize the GPIO pins
int initializeGPIO() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return -1;
    }

    // Set segment pins as output
    for (int i = 0; i < 7; i++) {
        pinMode(segmentPins[i], OUTPUT);
        digitalWrite(segmentPins[i], LOW); // Initialize to LOW
    }

    // Set digit pins as output
    for (int i = 0; i < 6; i++) {
        pinMode(digitPins[i], OUTPUT);
        digitalWrite(digitPins[i], LOW); // Initialize to LOW
    }

    return 0;
}

int main() {
    pthread_t displayThread;
    int errorCode;

    // Initialize GPIO
    if (initializeGPIO() == -1) {
        return 1;
    }

    // Create the display update thread
    errorCode = pthread_create(&displayThread, NULL, displayUpdateThread, NULL);
    if (errorCode) {
        fprintf(stderr, "Error creating display thread: %s\n", strerror(errorCode));
        return 1;
    }

    // Main loop to update the display with the current time
    while (1) {
        time_t timer;
        struct tm *currentTime;

        timer = time(NULL);
        currentTime = localtime(&timer);

        if (currentTime == NULL) {
            fprintf(stderr, "Error getting current time!\n");
            delay(1000); // Wait and try again
            continue;
        }

        // Format the time string
        char timeString[7];
        snprintf(timeString, sizeof(timeString), "%02d%02d%02d", currentTime->tm_hour, currentTime->tm_min, currentTime->tm_sec);

        // Update the display string safely
        errorCode = pthread_mutex_lock(&displayMutex);
        if (errorCode) {
            fprintf(stderr, "Error locking mutex: %s\n", strerror(errorCode));
        }
        strncpy(displayString, timeString, 6);
        errorCode = pthread_mutex_unlock(&displayMutex);
        if (errorCode) {
            fprintf(stderr, "Error unlocking mutex: %s\n", strerror(errorCode));
        }

        delay(200); // Update every 200ms
    }

    // Join the display thread (this will never be reached in this example)
    pthread_join(displayThread, NULL);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>

// Define the number of LEDs and the base GPIO pin
#define NUM_LEDS 8
#define BASE_GPIO_PIN 0 // WiringPi pin 0 corresponds to GPIO17

// Define the delay between LED changes in milliseconds
#define DELAY_MS 100

// Function to initialize the GPIO pins for the LEDs
int initializeLEDs() {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return -1; // Indicate failure
    }

    // Set the GPIO pins for the LEDs as output
    for (int i = 0; i < NUM_LEDS; i++) {
        pinMode(BASE_GPIO_PIN + i, OUTPUT);
        digitalWrite(BASE_GPIO_PIN + i, LOW); // Ensure LEDs are initially off
    }
    return 0; // Indicate success
}

// Function to run the LED sequence
void runLEDSequence() {
    while (1) {
        // Turn on LEDs sequentially
        for (int led = 0; led < NUM_LEDS; led++) {
            digitalWrite(BASE_GPIO_PIN + led, HIGH);
            delay(DELAY_MS);
        }

        // Turn off LEDs sequentially
        for (int led = 0; led < NUM_LEDS; led++) {
            digitalWrite(BASE_GPIO_PIN + led, LOW);
            delay(DELAY_MS);
        }
    }
}

int main(void) {
    printf("Raspberry Pi - 8-LED Sequencer\n");
    printf("==============================\n");
    printf("Connect LEDs to WiringPi pins %d-%d and watch...\n", BASE_GPIO_PIN, BASE_GPIO_PIN + NUM_LEDS - 1);

    // Initialize the LEDs
    if (initializeLEDs() != 0) {
        fprintf(stderr, "LED initialization failed. Exiting.\n");
        return 1; // Exit with an error code
    }

    // Run the LED sequence
    runLEDSequence();

    return 0; // Program should not reach here in normal execution
}

#include <stdio.h>
#include <stdint.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdbool.h>
#include <time.h>
#include <math.h>

// Constants
#define D6T_ADDR 0x0A  // I2C 7-bit address
#define D6T_CMD 0x4D   // Command for compensated output
#define D6T_SET_ADD 0x01 // Register address for initial settings

#define NUM_PIXELS 1024  // 32x32
#define NUM_READ_BYTES ((NUM_PIXELS + 1) * 2 + 1)
#define I2C_DEVICE "/dev/i2c-1" // I2C device file

// Configuration parameters
#define D6T_IIR_FILTER 0x00  // IIR filter setting
#define D6T_AVERAGE_COUNT 0x04 // Moving average count

// Global variables
uint8_t read_buffer[NUM_READ_BYTES];
double ptat_temp;
double pixel_temperatures[NUM_PIXELS];

// Function Prototypes
static int i2c_read_data(uint8_t dev_addr, uint8_t reg_addr, uint8_t *data, int length);
static int i2c_write_data(uint8_t dev_addr, uint8_t *data, int length);
static uint8_t calculate_crc(uint8_t data);
static bool check_pec(uint8_t buf[], int data_length);
static int16_t convert_bytes_to_int16(uint8_t *buf, int index);
static void delay_ms(int milliseconds);
static int initialize_sensor(void);
static int read_sensor_data(void);
static void print_sensor_data(void);


/**
 * @brief Reads data from the I2C device.
 *
 * @param dev_addr  I2C device address.
 * @param reg_addr  Register address to read from.
 * @param data      Pointer to the buffer to store the read data.
 * @param length    Number of bytes to read.
 * @return 0 on success, -1 on failure.
 */
static int i2c_read_data(uint8_t dev_addr, uint8_t reg_addr, uint8_t *data, int length) {
    int file_descriptor = open(I2C_DEVICE, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error opening I2C device: %s\n", strerror(errno));
        return -1;
    }

    struct i2c_msg messages[2];
    messages[0].addr = dev_addr;
    messages[0].flags = 0; // Write
    messages[0].len = 1;
    messages[0].buf = &reg_addr;

    messages[1].addr = dev_addr;
    messages[1].flags = I2C_M_RD; // Read
    messages[1].len = length;
    messages[1].buf = data;

    struct i2c_rdwr_ioctl_data ioctl_data;
    ioctl_data.msgs = messages;
    ioctl_data.nmsgs = 2;

    if (ioctl(file_descriptor, I2C_RDWR, &ioctl_data) != 2) {
        fprintf(stderr, "Error during I2C read: %s\n", strerror(errno));
        close(file_descriptor);
        return -1;
    }

    close(file_descriptor);
    return 0;
}

/**
 * @brief Writes data to the I2C device.
 *
 * @param dev_addr  I2C device address.
 * @param data      Pointer to the buffer containing the data to write.
 * @param length    Number of bytes to write.
 * @return 0 on success, -1 on failure.
 */
static int i2c_write_data(uint8_t dev_addr, uint8_t *data, int length) {
    int file_descriptor = open(I2C_DEVICE, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error opening I2C device: %s\n", strerror(errno));
        return -1;
    }

    if (ioctl(file_descriptor, I2C_SLAVE, dev_addr) < 0) {
        fprintf(stderr, "Error acquiring I2C bus: %s\n", strerror(errno));
        close(file_descriptor);
        return -1;
    }

    if (write(file_descriptor, data, length) != length) {
        fprintf(stderr, "Error writing to I2C device: %s\n", strerror(errno));
        close(file_descriptor);
        return -1;
    }

    close(file_descriptor);
    return 0;
}

/**
 * @brief Calculates the CRC8 checksum.
 *
 * @param data  Data byte to calculate the CRC for.
 * @return The calculated CRC value.
 */
static uint8_t calculate_crc(uint8_t data) {
    uint8_t crc = data;
    for (int i = 0; i < 8; i++) {
        uint8_t temp = crc;
        crc <<= 1;
        if (temp & 0x80) {
            crc ^= 0x07;
        }
    }
    return crc;
}

/**
 * @brief Checks the PEC (Packet Error Check) byte.
 *
 * @param buf          Data buffer.
 * @param data_length  Length of the data buffer (excluding the PEC byte).
 * @return true if the PEC is valid, false otherwise.
 */
static bool check_pec(uint8_t buf[], int data_length) {
    uint8_t crc = calculate_crc((D6T_ADDR << 1) | 1); // I2C Read address (8bit)
    for (int i = 0; i < data_length; i++) {
        crc = calculate_crc(buf[i] ^ crc);
    }
    bool ret = (crc != buf[data_length]);
    if (ret) {
        fprintf(stderr, "PEC check failed: Calculated CRC = 0x%02X, Received PEC = 0x%02X\n", crc, buf[data_length]);
    }
    return !ret; // Return true if PEC is valid
}

/**
 * @brief Converts two bytes from the buffer to a signed 16-bit integer (little-endian).
 *
 * @param buf    Data buffer.
 * @param index  Starting index of the two bytes in the buffer.
 * @return The converted 16-bit integer.
 */
static int16_t convert_bytes_to_int16(uint8_t *buf, int index) {
    uint16_t ret = (uint16_t)buf[index];
    ret |= ((uint16_t)buf[index + 1]) << 8;
    return (int16_t)ret;
}

/**
 * @brief Delays execution for a specified number of milliseconds.
 *
 * @param milliseconds  Delay time in milliseconds.
 */
static void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}

/**
 * @brief Initializes the D6T-32L sensor with predefined settings.
 *
 * @return 0 on success, -1 on failure.
 */
static int initialize_sensor(void) {
    uint8_t init_data[] = {D6T_SET_ADD, ((D6T_IIR_FILTER << 4) & 0xF0) | (0x0F & D6T_AVERAGE_COUNT)};
    if (i2c_write_data(D6T_ADDR, init_data, sizeof(init_data)) != 0) {
        fprintf(stderr, "Sensor initialization failed.\n");
        return -1;
    }
    return 0;
}

/**
 * @brief Reads temperature data from the sensor.
 *
 * @return 0 on success, -1 on failure.
 */
static int read_sensor_data(void) {
    memset(read_buffer, 0, NUM_READ_BYTES);

    // Retry reading the data up to 5 times
    for (int i = 0; i < 5; i++) {
        if (i2c_read_data(D6T_ADDR, D6T_CMD, read_buffer, NUM_READ_BYTES) == 0) {
            if (check_pec(read_buffer, NUM_READ_BYTES - 1)) {
                // Convert PTAT temperature
                ptat_temp = (double)convert_bytes_to_int16(read_buffer, 0) / 10.0;

                // Convert pixel temperatures
                for (int j = 0; j < NUM_PIXELS; j++) {
                    pixel_temperatures[j] = (double)convert_bytes_to_int16(read_buffer, 2 + 2 * j) / 10.0;
                }
                return 0; // Success
            } else {
                fprintf(stderr, "PEC check failed, retrying...\n");
            }
        } else {
            fprintf(stderr, "I2C read failed, retrying...\n");
        }
        delay_ms(50); // Wait before retrying
    }

    fprintf(stderr, "Failed to read sensor data after multiple retries.\n");
    return -1; // Failure
}

/**
 * @brief Prints the temperature data to the console.
 */
static void print_sensor_data(void) {
    printf("PTAT temperature: %.1f °C\n", ptat_temp);
    printf("Pixel temperatures: ");
    for (int i = 0; i < NUM_PIXELS; i++) {
        printf("%.1f ", pixel_temperatures[i]);
        if ((i + 1) % 32 == 0) {
            printf("\n"); // Newline after each row
        }
    }
    printf("°C\n");
}

int main() {
    // Initialize the sensor
    if (initialize_sensor() != 0) {
        fprintf(stderr, "Sensor initialization failed. Exiting.\n");
        return 1;
    }
    delay_ms(500); //Initial delay

    while (1) {
        // Read sensor data
        if (read_sensor_data() == 0) {
            // Print the data
            print_sensor_data();
        } else {
            fprintf(stderr, "Failed to read and print sensor data.\n");
        }

        delay_ms(200); // Delay between readings
    }

    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
