#include <stdbool.h>
#include <time.h>
#include <math.h>

// Constants
#define D6T_I2C_ADDR 0x0A  // I2C 7-bit address of the D6T sensor
#define D6T_COMMAND 0x4C   // Command to request temperature data

#define NUM_ROWS 4
#define NUM_PIXELS (NUM_ROWS * 4) // Assuming a 4x4 sensor
#define READ_BUF_SIZE ((NUM_PIXELS + 1) * 2 + 1) // (Pixels + PTAT) * 2 bytes + PEC byte
#define I2C_DEVICE_PATH "/dev/i2c-1" // I2C device file on Raspberry Pi

// Global Variables
uint8_t read_buffer[READ_BUF_SIZE];
double ambient_temperature; // PTAT (Package Temperature)
double pixel_temperatures[NUM_PIXELS];

// Function Prototypes
void delay_ms(int milliseconds);
int i2c_read_bytes(int i2c_fd, uint8_t dev_addr, uint8_t command, uint8_t *data, int length);
bool check_pec(uint8_t data[], int data_len);
int16_t convert_bytes_to_int16(uint8_t *buf, int index);


// Function to introduce delay in milliseconds
void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}

// Function to read bytes from I2C device
int i2c_read_bytes(int i2c_fd, uint8_t dev_addr, uint8_t command, uint8_t *data, int length) {
    struct i2c_msg messages[2];
    struct i2c_ioctl_rdwr_data transfer;

    // Message 1: Write the command to the device
    messages[0].addr = dev_addr;
    messages[0].flags = 0; // Write
    messages[0].len = 1;
    messages[0].buf = &command;

    // Message 2: Read the data from the device
    messages[1].addr = dev_addr;
    messages[1].flags = I2C_M_RD; // Read
    messages[1].len = length;
    messages[1].buf = data;

    transfer.msgs = messages;
    transfer.nmsgs = 2;

    if (ioctl(i2c_fd, I2C_RDWR, &transfer) < 0) {
        fprintf(stderr, "I2C read failed: %s\n", strerror(errno));
        return -1;
    }

    return 0;
}

// Function to calculate CRC8 checksum (PEC) - Maxim Application Note 3724
uint8_t calculate_crc8(const uint8_t *data, size_t length) {
    uint8_t crc = 0x00;
    size_t i, j;

    for (i = 0; i < length; i++) {
        crc ^= data[i];
        for (j = 0; j < 8; j++) {
            if ((crc & 0x80) != 0) {
                crc = (uint8_t)((crc << 1) ^ 0x07);
            } else {
                crc <<= 1;
            }
        }
    }
    return crc;
}

// Function to check PEC (Packet Error Check)
bool check_pec(uint8_t data[], int data_len) {
    uint8_t calculated_pec = calculate_crc8(data, data_len - 1);
    if (calculated_pec != data[data_len - 1]) {
        fprintf(stderr, "PEC check failed: Calculated PEC = 0x%02X, Received PEC = 0x%02X\n", calculated_pec, data[data_len - 1]);
        return false;
    }
    return true;
}

// Function to convert two bytes (little-endian) to a signed 16-bit integer
int16_t convert_bytes_to_int16(uint8_t *buf, int index) {
    return (int16_t)((buf[index]) | (buf[index + 1] << 8));
}

int main() {
    int i2c_file_descriptor;

    // Open I2C device
    i2c_file_descriptor = open(I2C_DEVICE_PATH, O_RDWR);
    if (i2c_file_descriptor < 0) {
        fprintf(stderr, "Failed to open I2C device: %s\n", strerror(errno));
        return 1;
    }

    // Main loop
    while (1) {
        // Read data from the sensor
        if (i2c_read_bytes(i2c_file_descriptor, D6T_I2C_ADDR, D6T_COMMAND, read_buffer, READ_BUF_SIZE) != 0) {
            fprintf(stderr, "Failed to read data from sensor.\n");
            close(i2c_file_descriptor);
            return 1;
        }

        // Verify PEC
        if (!check_pec(read_buffer, READ_BUF_SIZE)) {
            fprintf(stderr, "PEC check failed. Data may be corrupted.\n");
        } else {
            // Convert and store temperature data
            ambient_temperature = (double)convert_bytes_to_int16(read_buffer, 0) / 10.0;
            for (int i = 0; i < NUM_PIXELS; i++) {
                pixel_temperatures[i] = (double)convert_bytes_to_int16(read_buffer, 2 + (2 * i)) / 10.0;
            }

            // Print the temperature data
            printf("Ambient Temperature: %.1f °C\n", ambient_temperature);
            printf("Pixel Temperatures: ");
            for (int i = 0; i < NUM_PIXELS; i++) {
                printf("%.1f °C ", pixel_temperatures[i]);
            }
            printf("\n\n");
        }

        delay_ms(300); // Delay before next read
    }

    // Close I2C device (never reached in this example due to the infinite loop)
    close(i2c_file_descriptor);
    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <stdbool.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
