#include <time.h>
#include <math.h>

// Constants
#define D6T_I2C_ADDR 0x0A         // I2C 7-bit address of the D6T sensor
#define D6T_CMD_READ 0x4C         // Command to read temperature data
#define NUM_PIXELS 8              // Number of pixels in the sensor array
#define DATA_FRAME_SIZE (NUM_PIXELS + 1) * 2 + 1 // Size of the data frame (temperature values + PTAT + PEC)
#define I2C_DEVICE "/dev/i2c-1" // I2C device file for Raspberry Pi

// Global variables
double ambient_temperature;  // PTAT (Package Temperature)
double pixel_temperatures[NUM_PIXELS]; // Temperature of each pixel
uint8_t read_buffer[DATA_FRAME_SIZE]; // Buffer to store raw data read from the sensor

// Function prototypes
int i2c_read_data(int file_descriptor, uint8_t address, uint8_t *data, int length);
bool check_pec(uint8_t data[], int data_length);
int16_t convert_bytes_to_int16(uint8_t *buffer, int index);
void delay_ms(int milliseconds);
int initialize_sensor(int file_descriptor);

/**
 * @brief Reads data from the I2C device.
 *
 * @param file_descriptor File descriptor of the I2C device.
 * @param address I2C address of the slave device.
 * @param data Pointer to the buffer to store the read data.
 * @param length Number of bytes to read.
 * @return 0 on success, -1 on failure.
 */
int i2c_read_data(int file_descriptor, uint8_t address, uint8_t *data, int length) {
  if (ioctl(file_descriptor, I2C_SLAVE, address) < 0) {
    fprintf(stderr, "Error: Failed to acquire bus access or talk to slave. Error code: %s\n", strerror(errno));
    return -1;
  }

  if (write(file_descriptor, &D6T_CMD_READ, 1) != 1) {
        fprintf(stderr, "Error: Failed to write register address. Error code: %s\n", strerror(errno));
        return -1;
    }

  ssize_t bytes_read = read(file_descriptor, data, length);
  if (bytes_read != length) {
    fprintf(stderr, "Error: Failed to read complete data. Expected %d bytes, got %zd. Error code: %s\n", length, bytes_read, strerror(errno));
    return -1;
  }

  return 0;
}

/**
 * @brief Calculates and checks the Packet Error Check (PEC) byte.
 *
 * @param data Array containing the data to be checked.
 * @param data_length Length of the data array (excluding the PEC byte).
 * @return true if the PEC is valid, false otherwise.
 */
bool check_pec(uint8_t data[], int data_length) {
    uint8_t crc = 0x00; // Initialize CRC
    uint8_t i;

    // Calculate CRC for the I2C read address
    crc = crc ^ (D6T_I2C_ADDR << 1 | 0x01); // I2C read address (8-bit)

    // Calculate CRC for the data bytes
    for (i = 0; i < data_length; i++) {
        uint8_t current_byte = data[i];
        for (int bit = 0; bit < 8; bit++) {
            uint8_t topbit = crc & 0x80;
            crc <<= 1;
            if (topbit) {
                crc ^= 0x07;
            }
            if (current_byte & 0x80) {
                crc ^= 0x07;
            }
            current_byte <<= 1;
        }
    }

    // Compare calculated CRC with received PEC
    if (crc != data[data_length]) {
        fprintf(stderr, "PEC check failed: Calculated PEC = 0x%02X, Received PEC = 0x%02X\n", crc, data[data_length]);
        return false;
    }

    return true;
}

/**
 * @brief Converts two bytes from the buffer to a signed 16-bit integer (little-endian).
 *
 * @param buffer Pointer to the data buffer.
 * @param index Starting index of the two bytes to convert.
 * @return The converted signed 16-bit integer.
 */
int16_t convert_bytes_to_int16(uint8_t *buffer, int index) {
  return (int16_t)((buffer[index]) | (buffer[index + 1] << 8));
}

/**
 * @brief Delays execution for a specified number of milliseconds.
 *
 * @param milliseconds Delay time in milliseconds.
 */
void delay_ms(int milliseconds) {
  struct timespec ts;
  ts.tv_sec = milliseconds / 1000;
  ts.tv_nsec = (milliseconds % 1000) * 1000000;
  nanosleep(&ts, NULL);
}

/**
 * @brief Performs initial settings for the D6T sensor.
 *
 * @param file_descriptor File descriptor of the I2C device.
 * @return 0 on success, -1 on failure.
 */
int initialize_sensor(int file_descriptor) {
    // Example initialization sequence (replace with your sensor's specific requirements)
    uint8_t init_data1[] = {0x02, 0x00, 0x01, 0xee};
    uint8_t init_data2[] = {0x05, 0x90, 0x3a, 0xb8};
    uint8_t init_data3[] = {0x03, 0x00, 0x03, 0x8b};
    uint8_t init_data4[] = {0x03, 0x00, 0x07, 0x97};
    uint8_t init_data5[] = {0x02, 0x00, 0x00, 0xe9};

    uint8_t* init_sequences[] = {init_data1, init_data2, init_data3, init_data4, init_data5};
    size_t init_sizes[] = {sizeof(init_data1), sizeof(init_data2), sizeof(init_data3), sizeof(init_data4), sizeof(init_data5)};

    for (size_t i = 0; i < sizeof(init_sequences) / sizeof(init_sequences[0]); ++i) {
        if (ioctl(file_descriptor, I2C_SLAVE, D6T_I2C_ADDR) < 0) {
            fprintf(stderr, "Error: Failed to acquire bus access for initialization sequence %zu. Error code: %s\n", i, strerror(errno));
            return -1;
        }
        if (write(file_descriptor, init_sequences[i], init_sizes[i]) != (ssize_t)init_sizes[i]) {
            fprintf(stderr, "Error: Failed to write initialization data %zu. Error code: %s\n", i, strerror(errno));
            return -1;
        }
        delay_ms(10); // Small delay between initialization steps
    }

    return 0;
}

/**
 * @brief Main function to read and display temperature data from the D6T sensor.
