void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}

// Function to read data from the I2C device
int i2c_read_data(int file_descriptor, uint8_t device_address, uint8_t command, uint8_t *data, int length) {
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        perror("Failed to acquire bus access and/or talk to slave.\n");
        return -1;
    }

    if (write(file_descriptor, &command, 1) != 1) {
        perror("Failed to write to the i2c bus.\n");
        return -1;
    }

    int bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Failed to read complete data from I2C. Expected %d, got %d\n", length, bytes_read);
        return -1;
    }

    return 0;
}

// Function to calculate CRC8 checksum (PEC)
uint8_t calculate_crc(uint8_t data) {
    uint8_t crc = data;
    for (int i = 0; i < 8; i++) {
        if (crc & 0x80) {
            crc = (crc << 1) ^ 0x07;
        } else {
            crc <<= 1;
        }
    }
    return crc;
}

// Function to check PEC (Packet Error Check)
bool check_pec(uint8_t *data, int length) {
    uint8_t crc = calculate_crc((D6T_I2C_ADDR << 1) | 1); // I2C read address
    for (int i = 0; i < length; i++) {
        crc = calculate_crc(data[i] ^ crc);
    }

    return (crc == data[length]);
}

// Function to convert two bytes to a signed 16-bit integer (little-endian)
int16_t convert_bytes_to_int16(uint8_t *buffer, int index) {
    return (int16_t)((buffer[index]) | (buffer[index + 1] << 8));
}

