// Function to read IR data
int read_ir_data(unsigned char data[4]) {
    unsigned int count = 0;
    unsigned char i, idx, bit_index;

    // Wait for the start signal (low pulse)
    while (digitalRead(IR_RECEIVE_PIN) == HIGH) {
        usleep(100); // Wait a short time
        count++;
        if (count > 1000) return -1; // Timeout if no signal detected
    }

    count = 0;
    while (digitalRead(IR_RECEIVE_PIN) == LOW) {
        usleep(60); //delayMicroseconds(60);
        count++;
        if (count > 200) return -1; // Timeout
    }

    count = 0;
    while (digitalRead(IR_RECEIVE_PIN) == HIGH) {
        usleep(60); //delayMicroseconds(60);
        count++;
        if (count > 80) return -1; // Timeout
    }

    // Read the 32 bits of data
    idx = 0;
    bit_index = 0;
    data[0] = 0;
    data[1] = 0;
    data[2] = 0;
    data[3] = 0;

    for (i = 0; i < 32; i++) {
        count = 0;
        while (digitalRead(IR_RECEIVE_PIN) == LOW) {
            usleep(60); //delayMicroseconds(60);
            count++;
            if (count > 15) return -1; // Timeout
        }

        count = 0;
        while (digitalRead(IR_RECEIVE_PIN) == HIGH) {
            usleep(60); //delayMicroseconds(60);
            count++;
            if (count > 40) return -1; // Timeout
        }

        // Determine if the bit is a 0 or a 1 based on the pulse length
        if (count > 25) {
            data[idx] |= (1 << bit_index);
        }

        // Increment bit and byte indices
        bit_index++;
        if (bit_index == 8) {
            bit_index = 0;
            idx++;
        }
    }

    return 0; // Success
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
