// Define GPIO pins using BCM numbering
#define IR_PIN      5   // BCM GPIO 24

#define MOTOR_INA1  0   // BCM GPIO 17
#define MOTOR_INA2  2   // BCM GPIO 20
#define MOTOR_ENA   3   // BCM GPIO 22

#define RGB_RED_PIN   29  // BCM GPIO 21
#define RGB_GREEN_PIN 28  // BCM GPIO 20
#define RGB_BLUE_PIN  27  // BCM GPIO 16

#define RELAY_PIN   26  // BCM GPIO 12

#define SERVO_PIN   25  // BCM GPIO 26

// Constants
#define SERVO_MIN_PULSE_WIDTH 500
#define SERVO_MAX_PULSE_WIDTH 2500
#define SERVO_CENTER_PULSE_WIDTH 1500
#define SERVO_ADJUSTMENT_STEP 150

// IR timing constants (in microseconds)
#define IR_START_PULSE_MIN  8000 // 9000
#define IR_START_SPACE_MIN  4000 // 4500
#define IR_BIT_PULSE_MIN    500  // 560
#define IR_ZERO_SPACE_MAX   1000 // 560
#define IR_ONE_SPACE_MIN    1500 // 1690
#define IR_ONE_SPACE_MAX    2000

// Global variables
static int motor_speed = 50; // Motor speed (0-100)
static int servo_pulse_width = SERVO_CENTER_PULSE_WIDTH; // Servo pulse width in microseconds

// Function prototypes
void motor_forward(void);
void motor_reverse(void);
void motor_stop(void);
void motor_speed_increase(void);
void motor_speed_decrease(void);
void set_rgb_color(int red, int green, int blue);
void set_servo_angle(int pulse_width);
int decode_ir_data(unsigned char data[]);

// Motor control functions
void motor_forward(void) {
    digitalWrite(MOTOR_INA1, LOW);
    digitalWrite(MOTOR_INA2, HIGH);
    softPwmWrite(MOTOR_ENA, motor_speed);
    printf("Motor forward, speed: %d\n", motor_speed);
}

void motor_reverse(void) {
    digitalWrite(MOTOR_INA1, HIGH);
    digitalWrite(MOTOR_INA2, LOW);
    softPwmWrite(MOTOR_ENA, motor_speed);
    printf("Motor reverse, speed: %d\n", motor_speed);
}

void motor_stop(void) {
    digitalWrite(MOTOR_INA1, LOW);
    digitalWrite(MOTOR_INA2, LOW);
    softPwmWrite(MOTOR_ENA, 0);
    printf("Motor stopped\n");
}

void motor_speed_increase(void) {
    motor_speed += 10;
    if (motor_speed > 100) {
        motor_speed = 100;
    }
    softPwmWrite(MOTOR_ENA, motor_speed);
    printf("Motor speed increased to: %d\n", motor_speed);
}

void motor_speed_decrease(void) {
    motor_speed -= 10;
    if (motor_speed < 0) {
        motor_speed = 0;
    }
    softPwmWrite(MOTOR_ENA, motor_speed);
    printf("Motor speed decreased to: %d\n", motor_speed);
}

// RGB LED control function
void set_rgb_color(int red, int green, int blue) {
    softPwmWrite(RGB_RED_PIN, red);
    softPwmWrite(RGB_GREEN_PIN, green);
    softPwmWrite(RGB_BLUE_PIN, blue);
    printf("RGB color set to: R=%d, G=%d, B=%d\n", red, green, blue);
}

// Servo control function
void set_servo_angle(int pulse_width) {
    if (pulse_width < SERVO_MIN_PULSE_WIDTH) {
        pulse_width = SERVO_MIN_PULSE_WIDTH;
    } else if (pulse_width > SERVO_MAX_PULSE_WIDTH) {
        pulse_width = SERVO_MAX_PULSE_WIDTH;
    }

    for (int i = 0; i < 50; i++) {
        digitalWrite(SERVO_PIN, HIGH);
        delayMicroseconds(pulse_width);
        digitalWrite(SERVO_PIN, LOW);
        delay(20 - (pulse_width / 1000)); // 20ms period
    }
    printf("Servo set to pulse width: %d\n", pulse_width);
}

// IR decoding function
int decode_ir_data(unsigned char data[]) {
    unsigned char i, idx, cnt;
    unsigned char count;

    // Check for start pulse (9ms low, 4.5ms high)
    count = 0;
    while (digitalRead(IR_PIN) == LOW && count++ < 150) {
        delayMicroseconds(60);
    }
    if (count >= 150) return -1; // Start pulse timeout

    count = 0;
    while (digitalRead(IR_PIN) == HIGH && count++ < 80) {
        delayMicroseconds(60);
    }
    if (count >= 80) return -1; // Start space timeout

    idx = 0;
    cnt = 0;
    data[0] = 0;
    data[1] = 0;
    data[2] = 0;
    data[3] = 0;

    for (i = 0; i < 32; i++) {
        count = 0;
        while (digitalRead(IR_PIN) == LOW && count++ < 15) {
            delayMicroseconds(60);
        }
        if (count >= 15) return -1; // Bit pulse timeout

        count = 0;
        while (digitalRead(IR_PIN) == HIGH && count++ < 40) {
            delayMicroseconds(60);
        }

        if (count > 25) {
            data[idx] |= (1 << cnt);
        }

        if (cnt == 7) {
            cnt = 0;
            idx++;
        } else {
            cnt++;
        }
    }

    // Verify checksum
    if (data[0] + data[1] != 0xFF || data[2] + data[3] != 0xFF) {
        printf("Checksum error: 0x%02x + 0x%02x != 0xFF or 0x%02x + 0x%02x != 0xFF\n", data[0], data[1], data[2], data[3]);
        return -1;
    }

    return 0; // Success
}

int main(void) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Pin setup
    pinMode(IR_PIN, INPUT);
    pullUpDnControl(IR_PIN, PUD_UP);

    pinMode(MOTOR_INA1, OUTPUT);
    pinMode(MOTOR_INA2, OUTPUT);
    softPwmCreate(MOTOR_ENA, 0, 100);

    softPwmCreate(RGB_RED_PIN, 0, 100);
    softPwmCreate(RGB_GREEN_PIN, 0, 100);
    softPwmCreate(RGB_BLUE_PIN, 0, 100);

    pinMode(RELAY_PIN, OUTPUT);

    pinMode(SERVO_PIN, OUTPUT);
    set_servo_angle(SERVO_CENTER_PULSE_WIDTH);
    delay(300);

    printf("IR Remote Control Program\n");

    unsigned char ir_data[4];

    while (1) {
        if (digitalRead(IR_PIN) == LOW) {
            if (decode_ir_data(ir_data) == 0) {
                printf("Received IR code: 0x%02x\n", ir_data[2]);

                switch (ir_data[2]) {
                    case 0x44: motor_forward(); break;
                    case 0x43: motor_reverse(); break;
                    case 0x40: motor_stop(); break;
                    case 0x46: motor_speed_increase(); break;
                    case 0x15: motor_speed_decrease(); break;

                    case 0x16: set_rgb_color(100, 0, 0); break;   // Red
                    case 0x19: set_rgb_color(0, 100, 0); break;   // Green
                    case 0x0d: set_rgb_color(0, 0, 100); break;   // Blue
                    case 0x0c: set_rgb_color(100, 100, 0); break; // Yellow
                    case 0x18: set_rgb_color(0, 100, 100); break; // Cyan
                    case 0x5e: set_rgb_color(100, 100, 100); break; // White
                    case 0x1c: set_rgb_color(0, 0, 0); break;     // Off

                    case 0x08: digitalWrite(RELAY_PIN, HIGH); printf("Relay ON\n"); break;
                    case 0x5a: digitalWrite(RELAY_PIN, LOW); printf("Relay OFF\n"); break;

                    case 0x42: servo_pulse_width += SERVO_ADJUSTMENT_STEP; set_servo_angle(servo_pulse_width); break;
                    case 0x4a: servo_pulse_width -= SERVO_ADJUSTMENT_STEP; set_servo_angle(servo_pulse_width); break;

                    default: printf("Unknown IR code\n"); break;
                }
            } else {
                printf("IR decode failed\n");
            }
        }
    }

    return 0;
}

#include <stdio.h>
