// Define L293D control pins using WiringPi numbering
#define IN1_PIN  0  // WiringPi pin 0 (BCM GPIO 17)
#define IN2_PIN  2  // WiringPi pin 2 (BCM GPIO 27)
#define ENABLE_PIN 3 // WiringPi pin 3 (BCM GPIO 22) - PWM

// Define PWM range
#define PWM_RANGE 100

// Function to move the motor forward
void motorForward(int speed)
{
    digitalWrite(IN1_PIN, HIGH);
    digitalWrite(IN2_PIN, LOW);
    softPwmWrite(ENABLE_PIN, speed); // Set PWM duty cycle for speed control
    printf("Motor Forward, Speed: %d\n", speed);
}

// Function to move the motor in reverse
void motorReverse(int speed)
{
    digitalWrite(IN1_PIN, LOW);
    digitalWrite(IN2_PIN, HIGH);
    softPwmWrite(ENABLE_PIN, speed); // Set PWM duty cycle for speed control
    printf("Motor Reverse, Speed: %d\n", speed);
}

// Function to stop the motor
void motorStop()
{
    digitalWrite(IN1_PIN, LOW);
    digitalWrite(IN2_PIN, LOW);
    softPwmWrite(ENABLE_PIN, 0); // Set PWM to 0 to stop the motor
    printf("Motor Stop\n");
}

int main(void)
{
    // Initialize WiringPi
    if (wiringPiSetup() == -1)
    {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1; // Exit if initialization fails
    }

    // Set pin modes
    pinMode(IN1_PIN, OUTPUT);
    pinMode(IN2_PIN, OUTPUT);

    // Create soft PWM control on enable pin
    if (softPwmCreate(ENABLE_PIN, 0, PWM_RANGE) != 0)
    {
        fprintf(stderr, "Soft PWM creation failed!\n");
        return 1; // Exit if soft PWM creation fails
    }

    printf("Motor control program started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1)
    {
        // Move forward at 80% speed
        motorForward(80);
        delay(3000);

        // Stop the motor
        motorStop();
        delay(2000);

        // Move in reverse at 50% speed
        motorReverse(50);
