#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <wiringPi.h>
#include <pcf8591.h>
#include <lcd.h>
#include <errno.h>

// Constants
#define PCF8591_ADDRESS 0x48
#define PCF8591_BASE 100  // Arbitrary base for PCF8591
#define LM35_CHANNEL PCF8591_BASE + 0 // A0 channel of PCF8591

// LCD configuration
#define LCD_ROWS 2
#define LCD_COLS 16
#define LCD_RS 24
#define LCD_E 23
#define LCD_D4 3
#define LCD_D5 2
#define LCD_D6 0
#define LCD_D7 7

// Function to convert temperature to string
void formatTemperature(float temperature, char *buffer, size_t bufferSize) {
  snprintf(buffer, bufferSize, "%.2f C", temperature);
}

int main(void) {
  int lcdHandle;
  float temperature;
  char temperatureString[20];

  // Initialize WiringPi
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
    return 1;
  }

  // Initialize PCF8591
  pcf8591Setup(PCF8591_BASE, PCF8591_ADDRESS);

  // Initialize LCD
  lcdHandle = lcdInit(LCD_ROWS, LCD_COLS, 4, LCD_RS, LCD_E, LCD_D4, LCD_D5, LCD_D6, LCD_D7, 0, 0, 0, 0);
  if (lcdHandle == -1) {
    fprintf(stderr, "LCD initialization failed\n");
    return 1;
  }

  // Main loop
  while (1) {
    // Read analog value from LM35 via PCF8591
    int analogValue = analogRead(LM35_CHANNEL);

    // Convert analog value to temperature (LM35 outputs 10mV per degree Celsius)
    // Assuming Vref = 5V, Resolution = 8 bits (256 steps)
    temperature = ((float)analogValue / 255.0) * 5.0 * 100.0;

    // Format temperature as string
    formatTemperature(temperature, temperatureString, sizeof(temperatureString));

    // Print temperature to console
    printf("Temperature: %s\n", temperatureString);

    // Display temperature on LCD
    lcdPosition(lcdHandle, 0, 0);
    lcdPuts(lcdHandle, "Temperature:");
    lcdPosition(lcdHandle, 0, 1);
    lcdPuts(lcdHandle, temperatureString);

    // Delay for 1 second
    delay(1000);

    // Clear LCD for next reading
    lcdClear(lcdHandle);
  }

  return 0;
}

