// Define the GPIO pin connected to the buzzer (BCM GPIO 18, WiringPi pin 1)
#define BUZZER_PIN 1

// Function prototypes
int initialize_buzzer();
int beep(int frequency_hz, int duration_ms);
void play_tone(int frequency_hz, int duration_ms, const char* note_name);
void stop_buzzer();

int main()
{
    // Initialize WiringPi and the buzzer
    if (initialize_buzzer() != 0) {
        fprintf(stderr, "Buzzer initialization failed. Exiting.\n");
        return EXIT_FAILURE;
    }

    // Main loop to play the melody
    while (1) {
        play_tone(262, 300, "do"); // C4
        play_tone(294, 300, "re"); // D4
        play_tone(330, 300, "mi"); // E4
        play_tone(349, 300, "fa"); // F4
        play_tone(392, 300, "so"); // G4
        play_tone(440, 300, "la"); // A4
        play_tone(494, 300, "si"); // B4
        play_tone(523, 300, "Do"); // C5

        stop_buzzer(); // Ensure the buzzer is off after the melody
        delay(2000);    // Wait for 2 seconds before repeating
    }

    return EXIT_SUCCESS;
}

// Initializes the WiringPi library and configures the buzzer pin.
int initialize_buzzer() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return -1;
    }

    pinMode(BUZZER_PIN, PWM_OUTPUT); // Set the buzzer pin to PWM output mode
    pwmSetMode(PWM_MODE_MS);          // Set PWM signal mode to mark:space mode
    pwmSetClock(32);                 // Set the PWM clock base frequency to 19.2MHz / 32 = 600kHz

    return 0; // Return 0 on success
}

// Generates a beep sound with the specified frequency and duration.
int beep(int frequency_hz, int duration_ms) {
    if (frequency_hz < 100 || frequency_hz > 1000) {
        fprintf(stderr, "Invalid frequency: %d Hz. Frequency must be between 100 and 1000 Hz.\n", frequency_hz);
        return -1; // Indicate an error
    }

    // Calculate the PWM range based on the desired frequency.
    // The range determines the PWM cycle length.
    int pwm_range = 600000 / frequency_hz;
    pwmSetRange(pwm_range);

    // Set the PWM duty cycle to 50% to generate a square wave.
    pwmWrite(BUZZER_PIN, pwm_range / 2);

    // Delay for the specified duration.
    if (duration_ms > 0) {
        delay(duration_ms);
    }

    return 0; // Return 0 on success
}

// Plays a tone with a given frequency and duration, and prints the note name.
void play_tone(int frequency_hz, int duration_ms, const char* note_name) {
    if (beep(frequency_hz, duration_ms) == 0) {
        printf("%s\n", note_name);
    } else {
        fprintf(stderr, "Failed to play note %s.\n", note_name);
    }
}

// Stops the buzzer by setting the PWM output to 0.
void stop_buzzer() {
    pwmWrite(BUZZER_PIN, 0); // Turn off the buzzer by setting duty cycle to 0
}

