// Define GPIO pins for RGB LED (using WiringPi numbering)
#define RED_PIN   5   // BCM GPIO 24
#define GREEN_PIN 4   // BCM GPIO 23
#define BLUE_PIN  1   // BCM GPIO 18

// PWM range
#define PWM_RANGE 100

// Function to initialize the RGB LED pins
int initRgbLed(void) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return -1;
    }

    if (softPwmCreate(RED_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "Failed to create soft PWM for RED_PIN: %s\n", strerror(errno));
        return -1;
    }
    if (softPwmCreate(GREEN_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "Failed to create soft PWM for GREEN_PIN: %s\n", strerror(errno));
        return -1;
    }
    if (softPwmCreate(BLUE_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "Failed to create soft PWM for BLUE_PIN: %s\n", strerror(errno));
        return -1;
    }

    return 0;
}

// Function to set the RGB LED color
void setRgbColor(int red, int green, int blue) {
    softPwmWrite(RED_PIN, red);
    softPwmWrite(GREEN_PIN, green);
    softPwmWrite(BLUE_PIN, blue);
}

int main(void) {
    int red_value, green_value, blue_value;

    // Initialize the RGB LED
    if (initRgbLed() != 0) {
        fprintf(stderr, "RGB LED initialization failed. Exiting.\n");
        return 1;
    }

    // Seed the random number generator
    srand(time(NULL));

    // Main loop
    while (1) {
        // Generate random color values
        red_value   = rand() % (PWM_RANGE + 1); // Ensure values are within the PWM range
        green_value = rand() % (PWM_RANGE + 1);
        blue_value  = rand() % (PWM_RANGE + 1);

        // Set the RGB LED color
        setRgbColor(red_value, green_value, blue_value);

        // Delay for a short period
        delay(100); // 100ms delay
    }

    return 0;
}

