// Function prototypes
void clear_leds();
void red_button_handler();
void yellow_button_handler();
void blue_button_handler();

// Helper function to safely read a digital input
int safe_digital_read(int pin)
{
    int value = digitalRead(pin);
    if (value != LOW && value != HIGH)
    {
        fprintf(stderr, "Error: Invalid digital read value for pin %d\n", pin);
        return -1; // Indicate an error
    }
    return value;
}

// Function to turn off all LEDs
void clear_leds()
{
    digitalWrite(RED_LED_PIN, LOW);
    digitalWrite(YELLOW_LED_PIN, LOW);
    digitalWrite(BLUE_LED_PIN, LOW);
}

// Function to handle the red button press
void red_button_handler()
{
    while (safe_digital_read(RESET_BUTTON_PIN) == HIGH)
    {
        digitalWrite(RED_LED_PIN, HIGH);
        digitalWrite(YELLOW_LED_PIN, LOW);
        digitalWrite(BLUE_LED_PIN, LOW);
        delay(50); // Small delay to prevent busy-waiting
    }
    clear_leds();
}

// Function to handle the yellow button press
void yellow_button_handler()
{
    while (safe_digital_read(RESET_BUTTON_PIN) == HIGH)
    {
        digitalWrite(RED_LED_PIN, LOW);
        digitalWrite(YELLOW_LED_PIN, HIGH);
        digitalWrite(BLUE_LED_PIN, LOW);
        delay(50); // Small delay to prevent busy-waiting
    }
    clear_leds();
}

// Function to handle the blue button press
void blue_button_handler()
{
    while (safe_digital_read(RESET_BUTTON_PIN) == HIGH)
    {
        digitalWrite(RED_LED_PIN, LOW);
        digitalWrite(YELLOW_LED_PIN, LOW);
        digitalWrite(BLUE_LED_PIN, HIGH);
        delay(50); // Small delay to prevent busy-waiting
    }
    clear_leds();
}

