    pullUpDnControl(YELLOW_BUTTON_PIN, PUD_UP);
    pullUpDnControl(BLUE_BUTTON_PIN, PUD_UP);  // Enable pull-up resistor
    pullUpDnControl(RESET_BUTTON_PIN, PUD_UP); // Enable pull-up resistor

    // Main loop
    while (1)
    {
        // Read button states
        int red_button_state = safe_digital_read(RED_BUTTON_PIN);
        int yellow_button_state = safe_digital_read(YELLOW_BUTTON_PIN);
        int blue_button_state = safe_digital_read(BLUE_BUTTON_PIN);

