        if (red_button_state == -1 || yellow_button_state == -1 || blue_button_state == -1)
        {
            fprintf(stderr, "Error reading button state. Exiting.\n");
            return 1; // Exit with an error code
        }

        // Button press detection (LOW when pressed because of pull-up resistors)
        if (red_button_state == LOW)
        {
            red_button_handler();
        }
        else if (yellow_button_state == LOW)
        {
            yellow_button_handler();
        }
        else if (blue_button_state == LOW)
        {
            blue_button_handler();
        }

        delay(10); // Small delay to prevent busy-waiting
    }

    return 0; // Exit normally
}

