#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <errno.h>

// Define GPIO pins connected to ULN2003 driver (BCM numbering)
#define IN1_PIN 22
#define IN2_PIN 27
#define IN3_PIN 17
#define IN4_PIN 4

// Define motor control constants
#define STEPS_PER_REVOLUTION 512  // Number of steps for one full rotation
#define DELAY_MS 3                // Delay between steps (adjust for speed)
#define ROTATION_DELAY_MS 3000      // Delay between rotations

// Function to set the motor step sequence
void set_step(int step) {
    switch (step) {
        case 0:
            digitalWrite(IN1_PIN, LOW);
            digitalWrite(IN2_PIN, LOW);
            digitalWrite(IN3_PIN, LOW);
            digitalWrite(IN4_PIN, HIGH);
            break;
        case 1:
            digitalWrite(IN1_PIN, LOW);
            digitalWrite(IN2_PIN, LOW);
            digitalWrite(IN3_PIN, HIGH);
            digitalWrite(IN4_PIN, LOW);
            break;
        case 2:
            digitalWrite(IN1_PIN, LOW);
            digitalWrite(IN2_PIN, HIGH);
            digitalWrite(IN3_PIN, LOW);
            digitalWrite(IN4_PIN, LOW);
            break;
        case 3:
            digitalWrite(IN1_PIN, HIGH);
            digitalWrite(IN2_PIN, LOW);
            digitalWrite(IN3_PIN, LOW);
            digitalWrite(IN4_PIN, LOW);
            break;
        default:
            fprintf(stderr, "Error: Invalid step value: %d\n", step);
            break;
    }
}

// Function to rotate the motor clockwise
void rotate_clockwise(int steps) {
    for (int i = 0; i < steps; i++) {
        set_step(i % 4);
        delay(DELAY_MS);
    }
}

// Function to rotate the motor counter-clockwise
void rotate_counter_clockwise(int steps) {
    for (int i = 0; i < steps; i++) {
        set_step(3 - (i % 4));
        delay(DELAY_MS);
    }
}

