}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <sys/time.h>
#include <errno.h>

// Define GPIO pins for Trigger and Echo.  Using WiringPi numbering.
#define TRIGGER_PIN  4
#define ECHO_PIN     5

// Constants for calculations
#define SOUND_SPEED_CM_PER_S 34000.0f  // Speed of sound in cm/s
#define MICROSECONDS_TO_SECONDS 1000000.0f

// Function prototypes
void initialize_ultrasonic_sensor(void);
float measure_distance_cm(void);

/**
 * @brief Initializes the GPIO pins for the ultrasonic sensor.
 */
void initialize_ultrasonic_sensor(void) {
    // Set GPIO pins to their respective modes
    pinMode(ECHO_PIN, INPUT);   // Echo pin is an input
    pinMode(TRIGGER_PIN, OUTPUT); // Trigger pin is an output

    // Ensure trigger pin is initially low
    digitalWrite(TRIGGER_PIN, LOW);
    delay(100); // Short delay to settle
}

/**
 * @brief Measures the distance in centimeters using the ultrasonic sensor.
 * @return The measured distance in centimeters, or -1.0 on error.
 */
float measure_distance_cm(void) {
    struct timeval start_time, end_time;
    long start_us, end_us, duration_us;
    float distance_cm;

    // Trigger the ultrasonic pulse
    digitalWrite(TRIGGER_PIN, LOW);
    delayMicroseconds(2);
    digitalWrite(TRIGGER_PIN, HIGH);
    delayMicroseconds(10);
    digitalWrite(TRIGGER_PIN, LOW);

    // Measure the echo pulse duration
    while (digitalRead(ECHO_PIN) == LOW) {
        if (gettimeofday(&start_time, NULL) == -1) {
            perror("gettimeofday start");
            return -1.0f; // Indicate error
        }
    }

    while (digitalRead(ECHO_PIN) == HIGH) {
        if (gettimeofday(&end_time, NULL) == -1) {
            perror("gettimeofday end");
            return -1.0f; // Indicate error
        }
    }

    // Calculate the duration of the echo pulse
    start_us = (start_time.tv_sec * 1000000) + start_time.tv_usec;
    end_us = (end_time.tv_sec * 1000000) + end_time.tv_usec;
    duration_us = end_us - start_us;

    // Calculate the distance in centimeters
    distance_cm = (float)duration_us / MICROSECONDS_TO_SECONDS * SOUND_SPEED_CM_PER_S / 2.0f;

    return distance_cm;
}

int main(void) {
    float distance;

    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return 1; // Exit if initialization fails
    }

    // Initialize the ultrasonic sensor
    initialize_ultrasonic_sensor();

    // Main loop
    while (1) {
        distance = measure_distance_cm();

        if (distance >= 0.0f) {
            // Print the measured distance
            printf("Distance: %.2f cm\n", distance);
        } else {
            fprintf(stderr, "Error measuring distance.\n");
        }

        delay(100); // Delay between measurements
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>

// Configuration
#define IR_RECEIVE_PIN 5       // BCM GPIO 24, WiringPi pin 5
#define PULSE_TIMEOUT_US 12000 // Maximum pulse length to consider (microseconds)

// Timing Constants (microseconds)
#define HEADER_HIGH_MIN_US 8000
#define HEADER_LOW_MIN_US 4000
#define BIT_ZERO_HIGH_MIN_US 400
#define BIT_ONE_HIGH_MIN_US 1500
#define BIT_SAMPLE_PERIOD_US 560 // Typical pulse width for a bit

// Data buffer
#define DATA_BITS 32
unsigned char received_data[4];

// Function prototypes
int read_pulse(int timeout_us);
int decode_irm_data();
void print_received_data();

int main() {
    if (wiringPiSetup() < 0) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1;
    }

    pinMode(IR_RECEIVE_PIN, INPUT);
    pullUpDnControl(IR_RECEIVE_PIN, PUD_UP); // Enable pull-up resistor

    printf("IRM Decoder Program running...\n");

    while (1) {
        if (decode_irm_data() == 0) {
            print_received_data();
        }
        usleep(10000); // Sleep for 10ms to reduce CPU usage
    }

    return 0;
}

// Function to read a pulse duration from the IR receiver
int read_pulse(int timeout_us) {
    long startTime = micros();
    while (digitalRead(IR_RECEIVE_PIN) == 0 && micros() - startTime < timeout_us); // Wait for signal change or timeout
    long pulseStart = micros();
    while (digitalRead(IR_RECEIVE_PIN) == 1 && micros() - pulseStart < timeout_us); // Measure pulse width or timeout
    long pulseEnd = micros();

    if (pulseEnd - startTime >= timeout_us) {
        return -1; // Timeout occurred
    }
    return (int)(pulseEnd - startTime);
}

// Function to decode IRM data
int decode_irm_data() {
    int pulse_width;

    // Read Header
    pulse_width = read_pulse(PULSE_TIMEOUT_US);
    if (pulse_width < 0) return -1; // Timeout, no signal
    if (pulse_width < HEADER_HIGH_MIN_US) return -1; // Invalid Header High

    pulse_width = read_pulse(PULSE_TIMEOUT_US);
    if (pulse_width < 0) return -1; // Timeout
    if (pulse_width < HEADER_LOW_MIN_US) return -1; // Invalid Header Low

    // Read Data Bits
    for (int i = 0; i < 4; i++) {
        received_data[i] = 0;
        for (int j = 0; j < 8; j++) {
            pulse_width = read_pulse(PULSE_TIMEOUT_US);
            if (pulse_width < 0) return -1; // Timeout

            if (pulse_width > BIT_ONE_HIGH_MIN_US) {
                received_data[i] |= (1 << j);
            } else if (pulse_width < BIT_ZERO_HIGH_MIN_US) {
				return -1; //Invalid Bit

			}
        }
    }

    // Checksum Validation
    if ((received_data[0] + received_data[1] == 0xFF) && (received_data[2] + received_data[3] == 0xFF)) {
        return 0; // Success
    } else {
        fprintf(stderr, "Checksum Validation Failed!\n");
        return -1; // Failure
    }
}

// Function to print received data
void print_received_data() {
    printf("Received Key: 0x%02x\n", received_data[2]);
}

