#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <errno.h>

// Define GPIO pins using WiringPi numbering
#define BUTTON_PIN 1  // WiringPi GPIO 1 (BCM GPIO 18)
#define LED_PIN 2     // WiringPi GPIO 2 (BCM GPIO 27)

// Debounce delay in milliseconds
#define DEBOUNCE_DELAY 50

// Function prototypes
int initialize_gpio(void);
int read_button(void);
void update_led(int button_press_count);

int main(void) {
  int button_press_count = 0; // Counter for button presses
  int button_state = 0;         // Current state of the button

  // Initialize WiringPi and GPIO pins
  if (initialize_gpio() != 0) {
    fprintf(stderr, "GPIO initialization failed. Exiting.\n");
    return EXIT_FAILURE;
  }

  printf("Button controlled LED application started.\n");

  // Main loop
  while (1) {
    // Read button state
    button_state = read_button();

    // If button is pressed (and debounced)
    if (button_state == 1) {
      button_press_count++;
      printf("Button pressed. Count: %d\n", button_press_count);
      // Debounce delay
      delay(DEBOUNCE_DELAY);
    }

    // Update LED based on button press count
    update_led(button_press_count);

    // Small delay to prevent busy-waiting
    delay(10); // Reduced delay for responsiveness
  }

  return EXIT_SUCCESS; // This line will never be reached in this example.
}

// Initializes WiringPi and sets up GPIO pins
int initialize_gpio(void) {
  // Initialize WiringPi using WiringPi numbering
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
    return -1;
  }

  // Set button pin as input with pull-up resistor
  pinMode(BUTTON_PIN, INPUT);
  pullUpDnControl(BUTTON_PIN, PUD_UP); // Enable pull-up resistor

  // Set LED pin as output
  pinMode(LED_PIN, OUTPUT);
  digitalWrite(LED_PIN, LOW); // Initially turn the LED off

  return 0;
}

// Reads the button state with debouncing
int read_button(void) {
  static int last_button_state = HIGH; // Assume button is not pressed initially
  int current_button_state = digitalRead(BUTTON_PIN);

  // Check for falling edge (button press)
  if (last_button_state == HIGH && current_button_state == LOW) {
    delay(DEBOUNCE_DELAY); // Debounce
    current_button_state = digitalRead(BUTTON_PIN);
    if (current_button_state == LOW) {
      last_button_state = current_button_state;
      return 1; // Button is pressed
    }
  }
  // Check for rising edge (button release)
  if (last_button_state == LOW && current_button_state == HIGH) {
    delay(DEBOUNCE_DELAY); // Debounce
    current_button_state = digitalRead(BUTTON_PIN);
    if (current_button_state == HIGH) {
      last_button_state = current_button_state;
    }
  }
  last_button_state = current_button_state;
  return 0; // Button is not pressed
}

// Updates the LED state based on the button press count
void update_led(int button_press_count) {
  // Turn LED on if the button press count is odd, off if even
  if (button_press_count % 2 == 1) {
    digitalWrite(LED_PIN, HIGH); // Turn LED on
  } else {
    digitalWrite(LED_PIN, LOW);  // Turn LED off
  }
}

#include <wiringPi.h>
#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>

#define MAX_TIMINGS 85
#define DHT11_PIN 1  // WiringPi pin number (e.g., 1 for GPIO 18)
#define MAX_ATTEMPTS 5

// Global array to store DHT11 sensor values: humidity_integer, humidity_decimal, temperature_integer, temperature_decimal, checksum
int dht11_data[5] = {0, 0, 0, 0, 0};

// Function to read data from the DHT11 sensor
int read_dht11_data() {
    uint8_t last_state = HIGH;
    uint8_t counter = 0;
    uint8_t j = 0, i;

    // Initialize data array to zero before each read
    for (i = 0; i < 5; i++) {
        dht11_data[i] = 0;
    }

    // Send start signal to the DHT11 sensor
    pinMode(DHT11_PIN, OUTPUT);
    digitalWrite(DHT11_PIN, LOW);
    delay(18); // Minimum 18ms low signal
    digitalWrite(DHT11_PIN, HIGH);
    delayMicroseconds(40); // 20-40us high signal

    // Prepare to receive data from the DHT11
    pinMode(DHT11_PIN, INPUT);

    // Read DHT11 response
    for (i = 0; i < MAX_TIMINGS; i++) {
        counter = 0;
        while (digitalRead(DHT11_PIN) == last_state) {
            counter++;
            delayMicroseconds(1); // Check every microsecond
            if (counter == 255) {
                break; // Timeout condition
            }
        }

        last_state = digitalRead(DHT11_PIN);
        if (counter == 255) {
            break; // Timeout condition
        }

        // Ignore first 3 transitions (initial handshake)
        if ((i >= 4) && (i % 2 == 0)) {
            dht11_data[j / 8] <<= 1; // Shift left to make space for the new bit
            if (counter > 16) {
                dht11_data[j / 8] |= 1; // If pulse is longer than 16us, it's a 1
            }
            j++;
        }
    }

    // Validate the checksum
    if ((j >= 40) && (dht11_data[4] == ((dht11_data[0] + dht11_data[1] + dht11_data[2] + dht11_data[3]) & 0xFF))) {
        // Data is valid
        printf("Humidity: %d.%d %%\n", dht11_data[0], dht11_data[1]);
        printf("Temperature: %d.%d *C\n", dht11_data[2], dht11_data[3]);
        return 1; // Success
    } else {
        // Checksum error or incomplete data
        fprintf(stderr, "Error: DHT11 data validation failed (Checksum error).\n");
        return 0; // Failure
    }
}

int main(void) {
    int attempts = MAX_ATTEMPTS;

    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: WiringPi initialization failed.\n");
        return 1; // Exit with error
    }

    printf("DHT11 sensor reader.\n");

    while (1) {
        // Attempt to read data from DHT11 with retries
        int attempt_count = 0;
        while (attempt_count < attempts) {
            if (read_dht11_data()) {
                break; // Data read successfully
            }
            attempt_count++;
            printf("Attempt %d failed. Retrying...\n", attempt_count);
            delay(1000); // Wait before retrying
        }

        if (attempt_count == attempts) {
            fprintf(stderr, "Error: Failed to read DHT11 data after %d attempts.\n", attempts);
        }

        delay(3000); // DHT11 requires at least 2 seconds between readings
    }

    return 0; // Exit normally
}

