    {1, 1, 1, 1, 1, 1, 1, 0}, // 8
    {1, 1, 1, 1, 0, 1, 1, 0}  // 9
};

// Function to display a digit on the 7-segment display
void displayDigit(int digit, const segment_pins_t *pins) {
    if (digit < 0 || digit > 9) {
        fprintf(stderr, "Error: Invalid digit. Must be between 0 and 9.\n");
        return;
    }

    digitalWrite(pins->a, digit_patterns[digit][0]);
    digitalWrite(pins->b, digit_patterns[digit][1]);
