    digitalWrite(pins->d, digit_patterns[digit][3]);
    digitalWrite(pins->e, digit_patterns[digit][4]);
    digitalWrite(pins->f, digit_patterns[digit][5]);
    digitalWrite(pins->g, digit_patterns[digit][6]);
    digitalWrite(pins->dp, digit_patterns[digit][7]);
}

