#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>

// Define GPIO pins for segment control
#define SEG_A 5
#define SEG_B 1
#define SEG_C 22
#define SEG_D 24
#define SEG_E 25
#define SEG_F 4
#define SEG_G 21
#define SEG_DP 23 // Decimal Point (Not used in this example)

// Define GPIO pins for digit selection
#define DIGIT_1 7
#define DIGIT_2 0
#define DIGIT_3 2
#define DIGIT_4 3

// Delay between digit refreshes (in milliseconds)
#define REFRESH_DELAY_MS 2

// Lookup table for 7-segment display patterns (0-9)
const int segmentPatterns[10] = {
    0b00111111, // 0
    0b00000110, // 1
    0b01011011, // 2
    0b01001111, // 3
    0b01100110, // 4
    0b01101101, // 5
    0b01111101, // 6
    0b00000111, // 7
    0b01111111, // 8
    0b01101111  // 9
};

// Function to set the segment pins based on the pattern
void setSegments(int pattern) {
    digitalWrite(SEG_A, (pattern >> 6) & 1);
    digitalWrite(SEG_B, (pattern >> 5) & 1);
    digitalWrite(SEG_C, (pattern >> 4) & 1);
    digitalWrite(SEG_D, (pattern >> 3) & 1);
    digitalWrite(SEG_E, (pattern >> 2) & 1);
    digitalWrite(SEG_F, (pattern >> 1) & 1);
    digitalWrite(SEG_G, pattern & 1);
}

// Function to select a digit
void selectDigit(int digit) {
    digitalWrite(DIGIT_1, (digit == 1) ? LOW : HIGH);
    digitalWrite(DIGIT_2, (digit == 2) ? LOW : HIGH);
    digitalWrite(DIGIT_3, (digit == 3) ? LOW : HIGH);
    digitalWrite(DIGIT_4, (digit == 4) ? LOW : HIGH);
}

// Function to display a digit on a specific digit position
void displayDigit(int digit, int number) {
    selectDigit(digit);
    setSegments(segmentPatterns[number]);
    delay(REFRESH_DELAY_MS);
    setSegments(0x00); // Turn off segments to prevent ghosting
    selectDigit(0);  //Deselect all digits
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed, exiting...\n");
        return 1;
    }

    // Set segment pins as output
    int segmentPins[] = {SEG_A, SEG_B, SEG_C, SEG_D, SEG_E, SEG_F, SEG_G, SEG_DP};
    for (int i = 0; i < sizeof(segmentPins) / sizeof(segmentPins[0]); i++) {
        pinMode(segmentPins[i], OUTPUT);
    }

    // Set digit selection pins as output
    int digitPins[] = {DIGIT_1, DIGIT_2, DIGIT_3, DIGIT_4};
    for (int i = 0; i < sizeof(digitPins) / sizeof(digitPins[0]); i++) {
        pinMode(digitPins[i], OUTPUT);
        digitalWrite(digitPins[i], HIGH); // Initially disable all digits
    }

    // Main loop
    unsigned int counter = 0;
    while (1) {
        // Extract digits
        int digit1 = (counter / 1000) % 10; // Thousands
        int digit2 = (counter / 100) % 10;  // Hundreds
        int digit3 = (counter / 10) % 10;   // Tens
        int digit4 = counter % 10;            // Ones

        // Display digits using multiplexing
        displayDigit(1, digit1);
        displayDigit(2, digit2);
        displayDigit(3, digit3);
        displayDigit(4, digit4);

        // Increment counter every second
        delay(1000 - (4 * REFRESH_DELAY_MS)); // Adjust delay for refresh time

        counter = (counter + 1) % 10000; // Increment and wrap around at 9999
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <stdint.h>

// Define GPIO pins connected to the 74HC595
#define DATA_PIN   17  // BCM GPIO 17
#define LATCH_PIN  22  // BCM GPIO 22
#define CLOCK_PIN  27  // BCM GPIO 27

// Define 7-segment display patterns for digits 0-9 (common cathode)
const uint8_t digitPatterns[] = {
    0x3F, // 0
    0x06, // 1
    0x5B, // 2
    0x4F, // 3
    0x66, // 4
    0x6D, // 5
    0x7D, // 6
    0x07, // 7
    0x7F, // 8
    0x6F  // 9
};

// Function to shift out data to the 74HC595
void shiftData(uint8_t data) {
    for (int i = 0; i < 8; i++) {
        // Set data pin based on the current bit
        digitalWrite(DATA_PIN, (data >> (7 - i)) & 0x01);

        // Clock the data in
        digitalWrite(CLOCK_PIN, HIGH);
        delayMicroseconds(1); // Small delay for reliable clocking
        digitalWrite(CLOCK_PIN, LOW);
    }
}

// Function to display a digit on the 7-segment display
void displayDigit(int digit) {
    if (digit < 0 || digit > 9) {
        fprintf(stderr, "Error: Invalid digit. Must be between 0 and 9.\n");
        return; // Exit if digit is out of range
    }

    // Latch low to start data transfer
    digitalWrite(LATCH_PIN, LOW);

    // Shift out the digit pattern
    shiftData(digitPatterns[digit]);

    // Latch high to display the data
    digitalWrite(LATCH_PIN, HIGH);
}

int main() {
    // Initialize WiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing WiringPi.\n");
        return 1; // Exit if WiringPi initialization fails
    }

    // Set pin modes
    pinMode(DATA_PIN, OUTPUT);
    pinMode(LATCH_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);

    // Main loop
    while (1) {
        for (int i = 0; i < 10; i++) {
            displayDigit(i);
            delay(1000); // Display each digit for 1 second
        }
    }

    return 0;
}

