#define LED_PIN 1  // GPIO pin for the LED (WiringPi numbering)
#define PWM_RANGE 1024 // PWM range (0-1023)
#define DELAY_MS 10    // Delay in milliseconds for each brightness step

// Function to handle errors and exit
void error_exit(const char *message) {
    fprintf(stderr, "Error: %s\n", message);
    perror("System error"); // Print system error message
    exit(EXIT_FAILURE);
}

int main(void) {
    int brightness;

    printf("Raspberry Pi Breathing LED Program\n");

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        error_exit("wiringPiSetup failed");
    }

    // Set the LED pin to PWM output mode
    pinMode(LED_PIN, PWM_OUTPUT);

    // Main loop for the breathing effect
    while (1) {
        // Fade in (0 to PWM_RANGE - 1)
        for (brightness = 0; brightness < PWM_RANGE; ++brightness) {
            pwmWrite(LED_PIN, brightness);
            //printf("Brightness: %d\n", brightness); // Optional: Print brightness value
            delay(DELAY_MS);
        }

        // Fade out (PWM_RANGE - 1 to 0)
        for (brightness = PWM_RANGE - 1; brightness >= 0; --brightness) {
            pwmWrite(LED_PIN, brightness);
            //printf("Brightness: %d\n", brightness); // Optional: Print brightness value
            delay(DELAY_MS);
        }
    }

    return 0;
