            sleep(YELLOW_DURATION);
        }
    }

    // Red light
    gpioWrite(RED_LED_PIN, PI_HIGH);
    printf("Red light ON for %d seconds\n", RED_DURATION);
    sleep(RED_DURATION);
    gpioWrite(RED_LED_PIN, PI_LOW);
}

