// Constants
#define NUM_LEDS 6
#define ON_DELAY_SEC 3
#define OFF_DELAY_SEC 1

// GPIO pins connected to the LEDs
const int led_gpio_pins[NUM_LEDS] = {16, 19, 26, 5, 6, 25};

// Global flag to signal program termination
volatile sig_atomic_t program_terminated = 0;

// Function prototypes
void signal_handler(int signal);
int initialize_gpio(void);
void cleanup_gpio(void);
void run_chase_light(void);

// Signal handler for SIGINT (Ctrl+C)
void signal_handler(int signal) {
    if (signal == SIGINT) {
        program_terminated = 1;
        printf("\nSIGINT received.  Stopping chase light and cleaning up...\n");
    }
}

// Initializes the pigpio library and sets the GPIO modes.
int initialize_gpio(void) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "ERROR: pigpio initialisation failed\n");
        return -1;
    }

    // Set all LED pins as output
    for (int i = 0; i < NUM_LEDS; ++i) {
        if (gpioSetMode(led_gpio_pins[i], PI_OUTPUT) != 0) {
            fprintf(stderr, "ERROR: Failed to set GPIO %d to output mode\n", led_gpio_pins[i]);
            cleanup_gpio();
            return -1;
        }
    }
    return 0;
}

// Cleans up the GPIO pins by setting them to input mode and terminating the pigpio library.
void cleanup_gpio(void) {
    // Set all LED pins as input (safer state)
    for (int i = 0; i < NUM_LEDS; ++i) {
        gpioSetMode(led_gpio_pins[i], PI_INPUT);
    }

    gpioTerminate();
}

// Runs the chase light effect.
void run_chase_light(void) {
    while (!program_terminated) {
        for (int i = 0; i < NUM_LEDS; ++i) {
            // Turn LED on
            gpioWrite(led_gpio_pins[i], PI_HIGH);
            sleep(ON_DELAY_SEC);

            // Turn LED off
            gpioWrite(led_gpio_pins[i], PI_LOW);
            sleep(OFF_DELAY_SEC);

            // Check for termination signal after each LED cycle
            if (program_terminated) break;
        }
    }
}

int main(void) {
    // Set up signal handler for Ctrl+C
    if (signal(SIGINT, signal_handler) == SIG_ERR) {
        perror("ERROR: Could not set signal handler");
        return EXIT_FAILURE;
    }

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        return EXIT_FAILURE;
    }

    printf("Chase light started. Press CTRL-C to exit.\n");

    // Run the chase light
    run_chase_light();

    // Cleanup GPIO before exiting
    cleanup_gpio();

    printf("Exiting.\n");
    return EXIT_SUCCESS;
}

