// Define GPIO pins for button and LED
#define BUTTON_PIN 6
#define LED_PIN 16

// Debounce delay in seconds
#define DEBOUNCE_DELAY 0.2

// Global flag to handle program termination via signal
volatile sig_atomic_t program_running = 1;

// Signal handler for SIGINT (Ctrl+C)
void signal_handler(int signal) {
    if (signal == SIGINT) {
        program_running = 0;
        printf("\nExiting gracefully...\n");
    }
}

int main() {
    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "ERROR: pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(BUTTON_PIN, PI_INPUT);
    gpioSetMode(LED_PIN, PI_OUTPUT);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Press the button to toggle the LED. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Read button state
        int button_state = gpioRead(BUTTON_PIN);

        // Check if the button is pressed (LOW)
        if (button_state == PI_LOW) {
            // Debounce delay
            gpioDelay(DEBOUNCE_DELAY * 1000000); // Convert seconds to microseconds

            // Re-read button state after debounce
            if (gpioRead(BUTTON_PIN) == PI_LOW) {
                // Toggle LED state
                int led_state = gpioRead(LED_PIN);
                gpioWrite(LED_PIN, !led_state); // Invert the LED state

                // Wait for button release to avoid multiple toggles
                while (gpioRead(BUTTON_PIN) == PI_LOW) {
                    gpioDelay(50000); // Small delay to avoid busy-waiting
                }
            }
        }

        // Small delay to reduce CPU usage
        gpioDelay(10000); // 10ms
    }

    // Cleanup: Turn off LED and terminate pigpio
    gpioWrite(LED_PIN, PI_LOW);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
