    {SEG_A, SEG_B, SEG_C, SEG_D, SEG_E, SEG_F, -1, -1},       // 0
    {SEG_B, SEG_C, -1, -1, -1, -1, -1, -1},                  // 1
    {SEG_A, SEG_B, SEG_D, SEG_E, SEG_G, -1, -1, -1},       // 2
    {SEG_A, SEG_B, SEG_C, SEG_D, SEG_G, -1, -1, -1},       // 3
    {SEG_B, SEG_C, SEG_F, SEG_G, -1, -1, -1, -1},             // 4
    {SEG_A, SEG_C, SEG_D, SEG_F, SEG_G, -1, -1, -1},       // 5
    {SEG_A, SEG_C, SEG_D, SEG_E, SEG_F, SEG_G, -1, -1},    // 6
    {SEG_A, SEG_B, SEG_C, -1, -1, -1, -1, -1},              // 7
    {SEG_A, SEG_B, SEG_C, SEG_D, SEG_E, SEG_F, SEG_G, -1}, // 8
    {SEG_A, SEG_B, SEG_C, SEG_F, SEG_G, -1, -1, -1}        // 9
};

// Array of all segment pins for easy iteration
const int all_segments[] = {SEG_A, SEG_B, SEG_C, SEG_D, SEG_E, SEG_F, SEG_G, SEG_DP};

// Global flag to handle program termination via signal
volatile sig_atomic_t program_running = 1;

// Signal handler for SIGINT (Ctrl+C)
void signal_handler(int signal) {
    program_running = 0;
    printf("\nExiting program...\n");
}

// Function to set the state of a GPIO pin (safer wrapper)
int set_gpio_output(int pin, int value) {
    if (gpioWrite(pin, value) != 0) {
        fprintf(stderr, "Error: Failed to write value %d to GPIO %d\n", value, pin);
        return -1; // Indicate failure
    }
    return 0; // Indicate success
}

// Function to display a digit on the 7-segment display
int display_digit(int digit) {
    if (digit < 0 || digit > 9) {
        fprintf(stderr, "Error: Invalid digit: %d. Must be between 0 and 9.\n", digit);
        return -1; // Indicate failure
    }

    // Turn off all segments first
    for (size_t i = 0; i < sizeof(all_segments) / sizeof(all_segments[0]); ++i) {
        if (set_gpio_output(all_segments[i], PI_LOW) != 0) return -1; // Exit if error
    }

    // Turn on the required segments for the digit
    for (int i = 0; i < 8; ++i) {
        int segment_pin = digit_patterns[digit][i];
        if (segment_pin != -1) { // -1 indicates end of segment list for this digit
            if (set_gpio_output(segment_pin, PI_HIGH) != 0) return -1; // Exit if error
        }
    }
    return 0; // Indicate success
}

int main() {
    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Register the signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Set all segment pins as output
    for (size_t i = 0; i < sizeof(all_segments) / sizeof(all_segments[0]); ++i) {
        gpioSetMode(all_segments[i], PI_OUTPUT);
    }

    printf("7-Segment Display Demo. Press Ctrl+C to exit.\n");

    // Main loop to display digits 0-9 repeatedly
    while (program_running) {
        for (int digit = 0; digit < 10; ++digit) {
            if (display_digit(digit) != 0) {
                fprintf(stderr, "Error displaying digit %d. Exiting.\n", digit);
                program_running = 0; // Stop the loop if there's an error
                break;
            }
            sleep(1); // Display each digit for 1 second
        }
    }

    // Cleanup: Set all segments to LOW and terminate pigpio
    for (size_t i = 0; i < sizeof(all_segments) / sizeof(all_segments[0]); ++i) {
        gpioWrite(all_segments[i], PI_LOW);
        gpioSetMode(all_segments[i], PI_INPUT); // Reset to input mode
    }

    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <piFace.h>

// Constants
#define PIFACE_BASE 200          // Base pin number for PiFace
#define NUM_BUTTONS 4            // Number of buttons to monitor
#define NUM_OUTPUTS 4            // Number of output LEDs to control

// Global Variables
static int outputStates[NUM_OUTPUTS] = {0}; // Array to store the state of each output (0 = off, 1 = on)

// Function Prototypes
int initializePiFace();
void scanButton(int buttonNumber);
void cleanup();

/*
 * main: Main program entry point.
 *********************************************************************************
 */
int main(void) {
    printf("Raspberry Pi PiFace Button/LED Control Program\n");
    printf("==============================================\n");
    printf("This program reads buttons on the PiFace and toggles corresponding LEDs.\n");

    // Initialize PiFace and wiringPi
    if (initializePiFace() != 0) {
        fprintf(stderr, "Failed to initialize PiFace. Exiting.\n");
        return 1;
    }

    // Main loop
    while (1) {
        for (int buttonNumber = 0; buttonNumber < NUM_BUTTONS; ++buttonNumber) {
            scanButton(buttonNumber);
        }
        delay(5); // Small delay to prevent busy-waiting
    }

    // Program should never reach here in normal operation.
    cleanup();
    return 0;
}

/*
 * initializePiFace: Initializes wiringPi and the PiFace board.
 * Returns 0 on success, -1 on failure.
 *********************************************************************************
 */
int initializePiFace() {
    // Initialize wiringPi using the Sys mode (no root required)
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "wiringPiSetupSys failed. Ensure wiringPi is installed and configured correctly.\n");
        return -1;
    }

    // Setup PiFace
    if (piFaceSetup(PIFACE_BASE) == -1) {
        fprintf(stderr, "piFaceSetup failed. Check the PiFace is properly connected.\n");
        return -1;
    }

    // Configure pins (internal pull-ups for inputs, outputs initially off)
    for (int pin = 0; pin < 8; ++pin) {
        pullUpDnControl(PIFACE_BASE + pin, PUD_UP); // Enable pull-up resistors on input pins
        digitalWrite(PIFACE_BASE + pin, 0);         // Set all outputs to LOW (off)
    }

    return 0;
}

/*
 * scanButton: Reads a button and toggles the corresponding LED.
 * buttonNumber: The button number to scan (0-3).
 *********************************************************************************
 */
void scanButton(int buttonNumber) {
    if (buttonNumber < 0 || buttonNumber >= NUM_BUTTONS) {
        fprintf(stderr, "Error: Invalid button number: %d\n", buttonNumber);
        return;
    }

    int buttonPin = PIFACE_BASE + buttonNumber;
    int outputPin = PIFACE_BASE + buttonNumber; // Assuming button X controls LED X

    // Check if the button is pressed (LOW signal)
    if (digitalRead(buttonPin) == LOW) {
        // Toggle the output state
        outputStates[buttonNumber] ^= 1; // XOR with 1 to toggle (0 to 1, 1 to 0)

        // Set the output pin to the new state
        digitalWrite(outputPin, outputStates[buttonNumber]);

        printf("Button %d pushed - Output %d now: %s\n",
               buttonNumber,
               buttonNumber,
               (outputStates[buttonNumber] == 0) ? "Off" : "On");

        // Debounce: Wait for the button to be released
        while (digitalRead(buttonPin) == LOW) {
            delay(1); // Small delay
        }
    }
}

/*
 * cleanup:  Placeholder for any cleanup routines (e.g., turning off LEDs).
 *********************************************************************************
 */
void cleanup() {
    // In a more complex application, you might turn off all LEDs here.
    printf("Cleaning up and exiting.\n");
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// Define GPIO pins for data, latch, and clock
#define DATA_PIN   16
#define LATCH_PIN  5
#define CLOCK_PIN  6

// Define the number of LEDs in the display (assuming 8 for simplicity)
#define NUM_LEDS   8

// Global flag to handle program termination via signal
volatile sig_atomic_t program_running = 1;

// Function prototypes
void signal_handler(int signal);
int initialize_gpio(void);
void clear_leds(void);
int set_led_pattern(const char *pattern);
void cleanup_gpio(void);


// Signal handler for graceful exit
void signal_handler(int signal) {
    if (signal == SIGINT) {
        program_running = 0;
        printf("\nSIGINT received.  Exiting gracefully.\n");
    }
}

// Initializes the pigpio library and sets pin modes.
int initialize_gpio(void) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "ERROR: pigpio initialisation failed\n");
        return -1; // Indicate failure
    }

    gpioSetMode(DATA_PIN, PI_OUTPUT);
    gpioSetMode(LATCH_PIN, PI_OUTPUT);
    gpioSetMode(CLOCK_PIN, PI_OUTPUT);

    return 0; // Indicate success
}

// Clears all LEDs by setting all data bits to 0.
void clear_leds(void) {
    gpioWrite(LATCH_PIN, PI_LOW); // Begin data transmission

    for (int i = 0; i < NUM_LEDS; ++i) {
        gpioWrite(DATA_PIN, PI_LOW); // Send a '0' bit
        gpioWrite(CLOCK_PIN, PI_HIGH); // Clock the bit in
        gpioDelay(1); // Small delay for reliable clocking
        gpioWrite(CLOCK_PIN, PI_LOW);
    }

    gpioWrite(LATCH_PIN, PI_HIGH); // Latch the data to the LEDs
}

// Sets the LED pattern based on an 8-character string of '0's and '1's.
// Returns 0 on success, -1 on error.
int set_led_pattern(const char *pattern) {
    if (pattern == NULL) {
        fprintf(stderr, "ERROR: Null pattern passed to set_led_pattern\n");
        return -1;
    }

    gpioWrite(LATCH_PIN, PI_LOW);

    for (int i = 0; i < NUM_LEDS; ++i) {
        if (pattern[i] != '0' && pattern[i] != '1') {
            fprintf(stderr, "ERROR: Invalid character in pattern at position %d: '%c'\n", i, pattern[i]);
            gpioWrite(LATCH_PIN, PI_HIGH);
            return -1;
        }

        gpioWrite(DATA_PIN, pattern[i] - '0');
        gpioWrite(CLOCK_PIN, PI_HIGH);
        gpioDelay(1); // Small delay for reliable clocking
        gpioWrite(CLOCK_PIN, PI_LOW);
    }

    gpioWrite(LATCH_PIN, PI_HIGH);
    return 0;
}

// Resets GPIO pins to input mode and terminates the pigpio library.
void cleanup_gpio(void) {
    gpioWrite(LATCH_PIN, PI_INPUT);
    gpioWrite(DATA_PIN, PI_INPUT);
    gpioWrite(CLOCK_PIN, PI_INPUT);

    gpioTerminate();
}

int main() {
    // Register the signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        return 1; // Exit if initialization fails
    }

    printf("LED Multiplexing Demo. Press CTRL-C to exit.\n");

    while (program_running) {
        // Clear LEDs
        clear_leds();
        gpioDelay(1000); // 1 second delay

        // Display pattern '11111111'
        if (set_led_pattern("11111111") != 0) {
            break; // Exit loop on error
        }
        gpioDelay(1000);

        // Cycle through some patterns
        for (int i = 0; i < 10 && program_running; ++i) {
            if (set_led_pattern("10101010") != 0) {
                program_running = 0;
                break;
            }
            gpioDelay(500);
            if (set_led_pattern("01010101") != 0) {
                program_running = 0;
                break;
            }
            gpioDelay(500);
        }
    }

    // Cleanup and exit
    cleanup_gpio();

    return 0;
}

#include <signal.h>
#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>

// Define the dimensions of the LED matrix
#define MATRIX_SIZE 8

// Define GPIO pins for columns (anodes, sink current)
const int column_pins[MATRIX_SIZE] = {17, 7, 1, 23, 16, 18, 27, 14};

// Define GPIO pins for rows (cathodes, source current)
const int row_pins[MATRIX_SIZE] = {24, 22, 20, 15, 25, 21, 8, 12};

// Global flag to handle program termination via signal
volatile sig_atomic_t program_running = 1;

// Function prototypes
void cleanup_gpio();
void signal_handler(int signal);
int initialize_gpio();
void clear_matrix();
void display_pattern();

// Signal handler to gracefully terminate the program
void signal_handler(int signal) {
    if (signal == SIGINT) {
        program_running = 0;
        printf("\nCaught SIGINT.  Exiting gracefully.\n");
    }
}

// Initializes the GPIO library and sets pin modes
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "ERROR: pigpio initialisation failed\n");
        return -1; // Indicate failure
    }

    // Set column pins as outputs (sinking current, active low)
    for (int i = 0; i < MATRIX_SIZE; ++i) {
        if (gpioSetMode(column_pins[i], PI_OUTPUT) != 0) {
            fprintf(stderr, "ERROR: Failed to set column pin %d as output\n", column_pins[i]);
            cleanup_gpio();
            return -1;
        }
        gpioWrite(column_pins[i], PI_HIGH); // Initially off
    }

    // Set row pins as outputs (sourcing current, active high)
    for (int i = 0; i < MATRIX_SIZE; ++i) {
        if (gpioSetMode(row_pins[i], PI_OUTPUT) != 0) {
            fprintf(stderr, "ERROR: Failed to set row pin %d as output\n", row_pins[i]);
            cleanup_gpio();
            return -1;
        }
        gpioWrite(row_pins[i], PI_LOW); // Initially off
    }

    return 0; // Indicate success
}

// Clears the LED matrix (turns all LEDs off)
void clear_matrix() {
    for (int i = 0; i < MATRIX_SIZE; ++i) {
        gpioWrite(row_pins[i], PI_LOW);
        gpioWrite(column_pins[i], PI_HIGH);
    }
}

// Displays a simple pattern on the LED matrix
void display_pattern() {
    // Example pattern: Light up LEDs diagonally
    for (int i = 0; i < MATRIX_SIZE; ++i) {
        gpioWrite(row_pins[i], PI_HIGH);
        gpioWrite(column_pins[i], PI_LOW);
        usleep(1000); // 1 millisecond delay
        gpioWrite(row_pins[i], PI_LOW);
        gpioWrite(column_pins[i], PI_HIGH);
    }

     int x = 0;
        for (int i = 7; i >= 0; i--) {
            gpioWrite(row_pins[i], PI_HIGH);
            gpioWrite(column_pins[x], PI_LOW);
            usleep(1000); // Sleep for 1 ms
            gpioWrite(row_pins[i], PI_LOW);
            gpioWrite(column_pins[x], PI_HIGH);
            x++;
        }
}

// Releases GPIO resources and terminates the pigpio library
void cleanup_gpio() {
    // Set all pins to INPUT to avoid short circuits
    for (int i = 0; i < MATRIX_SIZE; ++i) {
        gpioSetMode(row_pins[i], PI_INPUT);
        gpioSetMode(column_pins[i], PI_INPUT);
    }
    gpioTerminate();
}

int main() {
    // Register the signal handler for SIGINT (Ctrl+C)
    signal(SIGINT, signal_handler);

    // Initialize the GPIO library and pins
    if (initialize_gpio() != 0) {
        fprintf(stderr, "Failed to initialize GPIO. Exiting.\n");
        return 1;
    }

    printf("LED Matrix Control - Press Ctrl+C to exit.\n");

    // Main loop: display the pattern repeatedly until a signal is received
    while (program_running) {
        display_pattern();
    }

    // Clean up GPIO resources before exiting
    cleanup_gpio();

    return 0;
}

