#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <softPwm.h>
#include <errno.h>

// Define the GPIO pins connected to the RGB LED
#define RED_PIN   0
#define GREEN_PIN 1
#define BLUE_PIN  2

// Define the PWM range (0-100)
#define PWM_RANGE 100

// Function prototypes
int initialize_leds(void);
int set_led_color(int red_intensity, int green_intensity, int blue_intensity);

/**
 * @brief Initializes the RGB LED pins using softPwm.
 *
 * @return 0 on success, -1 on failure.
 */
int initialize_leds(void) {
    if (softPwmCreate(RED_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "Error creating softPwm for RED_PIN: %s\n", strerror(errno));
        return -1;
    }
    if (softPwmCreate(GREEN_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "Error creating softPwm for GREEN_PIN: %s\n", strerror(errno));
        return -1;
    }
    if (softPwmCreate(BLUE_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "Error creating softPwm for BLUE_PIN: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

/**
 * @brief Sets the color of the RGB LED.
 *
 * @param red_intensity   Intensity of the red component (0-100).
 * @param green_intensity Intensity of the green component (0-100).
 * @param blue_intensity  Intensity of the blue component (0-100).
 * @return 0 on success, -1 on failure (if intensity is out of range).
 */
int set_led_color(int red_intensity, int green_intensity, int blue_intensity) {
    if (red_intensity < 0 || red_intensity > PWM_RANGE ||
        green_intensity < 0 || green_intensity > PWM_RANGE ||
        blue_intensity < 0 || blue_intensity > PWM_RANGE) {
        fprintf(stderr, "Error: Color intensity values must be between 0 and %d\n", PWM_RANGE);
        return -1;
    }

    softPwmWrite(RED_PIN, red_intensity);
    softPwmWrite(GREEN_PIN, green_intensity);
    softPwmWrite(BLUE_PIN, blue_intensity);
    return 0;
}

int main(void) {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize the RGB LED pins
    if (initialize_leds() != 0) {
        fprintf(stderr, "RGB LED initialization failed.\n");
        return 1;
    }

    // Main loop: cycle through different colors
    while (1) {
        printf("Red\n");
        if (set_led_color(100, 0, 0) != 0) return 1; // Red
        delay(500);

        printf("Green\n");
        if (set_led_color(0, 100, 0) != 0) return 1; // Green
        delay(500);

        printf("Blue\n");
        if (set_led_color(0, 0, 100) != 0) return 1;   // Blue
        delay(500);

        printf("Yellow\n");
        if (set_led_color(100, 100, 0) != 0) return 1; // Yellow
        delay(500);

        printf("Purple\n");
        if (set_led_color(100, 0, 100) != 0) return 1; // Purple
        delay(500);

        printf("Cyan\n");
        if (set_led_color(60, 100, 24) != 0) return 1;  // Cyan
        delay(500);
    }

    return 0;
}

#include <wiringPi.h>
