#include <stdint.h>
#include <signal.h>
#include <unistd.h>
#include <wiringPi.h>

// Define GPIO pins connected to the shift register and digit selection
#define SHIFT_DATA_PIN   5  // SDI (Serial Data In)
#define SHIFT_CLOCK_PIN  1  // SRCLK (Shift Register Clock)
#define LATCH_CLOCK_PIN  4  // RCLK (Register Clock/Latch)

// Define GPIO pins for digit selection (common cathode pins)
const int digitSelectPins[] = {12, 3, 2, 0};
const int numDigits = sizeof(digitSelectPins) / sizeof(digitSelectPins[0]);

// Define segment patterns for digits 0-9 (common cathode configuration)
const uint8_t digitPatterns[] = {
    0xC0, // 0
    0xF9, // 1
    0xA4, // 2
    0xB0, // 3
    0x99, // 4
    0x92, // 5
    0x82, // 6
    0xF8, // 7
    0x80, // 8
    0x90  // 9
};

// Global variable for the counter
volatile unsigned int counter = 0;

// Function prototypes
void displayDigit(int digit, int value);
void shiftOut(uint8_t data);
void clearDisplay(void);
void timerHandler(int signal);
void initialize(void);

// Interrupt handler for the timer signal
void timerHandler(int signal) {
    if (signal == SIGALRM) {
        counter++;
        printf("Counter: %d\n", counter);
        alarm(1); // Schedule the next alarm in 1 second
    }
}

// Function to shift out data to the 74HC595 shift register
void shiftOut(uint8_t data) {
    for (int i = 0; i < 8; i++) {
        // Set the data pin based on the current bit
        digitalWrite(SHIFT_DATA_PIN, (data >> i) & 0x01);

        // Clock the data into the shift register
        digitalWrite(SHIFT_CLOCK_PIN, HIGH);
        delayMicroseconds(1); // Small delay for stable clocking
        digitalWrite(SHIFT_CLOCK_PIN, LOW);
    }

    // Latch the data to the output register
    digitalWrite(LATCH_CLOCK_PIN, HIGH);
    delayMicroseconds(1); // Small delay for stable latching
    digitalWrite(LATCH_CLOCK_PIN, LOW);
}

// Function to clear the display (turn off all segments)
void clearDisplay(void) {
    // Shift out all 1s to turn off all segments (common cathode)
    shiftOut(0xFF);
}

// Function to display a digit on a specific digit position
void displayDigit(int digit, int value) {
    if (digit < 0 || digit >= numDigits) {
        fprintf(stderr, "Error: Invalid digit position: %d\n", digit);
        return;
    }

    if (value < 0 || value > 9) {
        fprintf(stderr, "Error: Invalid digit value: %d\n", value);
        return;
    }

    // Clear the display before displaying the new digit
    clearDisplay();

    // Select the digit by setting the corresponding pin HIGH
    digitalWrite(digitSelectPins[digit], HIGH);

    // Shift out the digit pattern
    shiftOut(digitPatterns[value]);

    // Deselect the digit by setting the corresponding pin LOW
    digitalWrite(digitSelectPins[digit], LOW);
}


// Main loop
int main(void) {
    // Initialize WiringPi and GPIO pins
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: Unable to initialize WiringPi.\n");
        return 1; // Exit with an error code
    }

    initialize();

    // Set up the timer signal handler
    signal(SIGALRM, timerHandler);
    alarm(1); // Set the initial alarm

    // Main loop to display the counter value
    while (1) {
        // Extract the digits from the counter value
        int digit0 = counter % 10;
        int digit1 = (counter / 10) % 10;
        int digit2 = (counter / 100) % 10;
        int digit3 = (counter / 1000) % 10;

        // Display the digits on the 7-segment display
        displayDigit(0, digit3);
        delay(2); // Small delay for multiplexing
        displayDigit(1, digit2);
        delay(2);
        displayDigit(2, digit1);
        delay(2);
        displayDigit(3, digit0);
        delay(2);
    }

    return 0; // Exit normally (though the loop never ends)
}

void initialize(void) {
    // Set pin modes
    pinMode(SHIFT_DATA_PIN, OUTPUT);
    pinMode(SHIFT_CLOCK_PIN, OUTPUT);
    pinMode(LATCH_CLOCK_PIN, OUTPUT);

    for (int i = 0; i < numDigits; i++) {
        pinMode(digitSelectPins[i], OUTPUT);
        digitalWrite(digitSelectPins[i], LOW); //Initialize to LOW (Common cathode)
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>

// Define GPIO pins connected to the shift registers
#define DATA_PIN   0  // Serial Data Input (SDI)
#define LATCH_PIN  1  // Register Clock (RCLK / STCP)
#define CLOCK_PIN  2  // Shift Register Clock (SRCLK / SHCP)

// Define LED matrix dimensions
#define MATRIX_SIZE 20

// Predefined patterns for the LED matrix (adjust as needed)
const unsigned char high_byte[MATRIX_SIZE] = {
    0x01, 0xff, 0x80, 0xff, 0x01, 0x02, 0x04, 0x08, 0x10, 0x20, 0x40, 0x80, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff
};

const unsigned char low_byte[MATRIX_SIZE] = {
    0x00, 0x7f, 0x00, 0xfe, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0xfe, 0xfd, 0xfb, 0xf7, 0xef, 0xdf, 0xbf, 0x7f
};

// Function to initialize the GPIO pins
int initialize_gpio() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return -1; // Indicate failure
    }

    pinMode(DATA_PIN, OUTPUT);
    pinMode(LATCH_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);

    digitalWrite(DATA_PIN, LOW);
    digitalWrite(LATCH_PIN, LOW);
    digitalWrite(CLOCK_PIN, LOW);

    return 0; // Indicate success
}

// Function to shift out a byte of data to the 74HC595
void shift_out(unsigned char data) {
    for (int i = 0; i < 8; i++) {
        // Determine the bit value (MSB first)
        int bit_value = (data & (0x80 >> i)) ? HIGH : LOW;

        // Set the data pin
        digitalWrite(DATA_PIN, bit_value);

        // Pulse the clock pin to shift the bit
        digitalWrite(CLOCK_PIN, HIGH);
        delayMicroseconds(1); // Small delay for reliable clocking
        digitalWrite(CLOCK_PIN, LOW);
    }
}

// Function to latch the data to the output of the 74HC595
void latch_data() {
    digitalWrite(LATCH_PIN, HIGH);
    delayMicroseconds(1); // Small delay for reliable latching
    digitalWrite(LATCH_PIN, LOW);
}

// Function to display a frame on the LED matrix
void display_frame(unsigned char high_byte_data, unsigned char low_byte_data) {
    shift_out(low_byte_data);
    shift_out(high_byte_data);
    latch_data();
}

int main() {
    if (initialize_gpio() != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return EXIT_FAILURE;
    }

    while (1) {
        // Display patterns forward
        for (int i = 0; i < MATRIX_SIZE; i++) {
            display_frame(high_byte[i], low_byte[i]);
            delay(100); // Adjust delay for desired speed
        }

       // Display patterns backward
        for (int i = MATRIX_SIZE - 1; i >= 0; i--) {
            display_frame(high_byte[i], low_byte[i]);
            delay(100);
        }
    }

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <unistd.h>
#include <wiringPiI2C.h>

// Define LCD I2C address and backlight control
#define LCD_ADDR   0x27
#define LCD_BACKLIGHT_ON  0x08
#define LCD_BACKLIGHT_OFF 0x00

// LCD command definitions
#define LCD_CLEARDISPLAY   0x01
#define LCD_RETURNHOME     0x02
#define LCD_ENTRYMODESET   0x04
#define LCD_DISPLAYCONTROL 0x08
#define LCD_CURSORSHIFT    0x10
#define LCD_FUNCTIONSET    0x20
#define LCD_SETCGRAMADDR   0x40
#define LCD_SETDDRAMADDR   0x80

// Flags for display control
#define LCD_DISPLAYON  0x04
#define LCD_CURSORON   0x02
#define LCD_BLINKON    0x01

// Flags for entry mode
#define LCD_ENTRYRIGHT 0x00
#define LCD_ENTRYLEFT  0x02
#define LCD_ENTRYSHIFTINCREMENT 0x01
#define LCD_ENTRYSHIFTDECREMENT 0x00

// I2C file descriptor
static int i2c_fd;

// Function prototypes
int lcd_init();
void lcd_send_command(uint8_t command);
void lcd_send_data(uint8_t data);
void lcd_write_char(char character);
void lcd_write_string(const char *string);
void lcd_set_cursor(uint8_t row, uint8_t col);
void lcd_clear();
void lcd_backlight(int on);
void lcd_send_nibble(uint8_t nibble, int rs);

// Initialize LCD
int lcd_init() {
  // Initialize wiringPi I2C
  if ((i2c_fd = wiringPiI2CSetup(LCD_ADDR)) < 0) {
    fprintf(stderr, "Error: Failed to initialize I2C communication.\n");
    return -1;
  }

  // Initialization sequence
  lcd_send_command(0x33); // Initialize
  usleep(5000);           // Wait 5ms
  lcd_send_command(0x32); // Initialize
  usleep(5000);           // Wait 5ms
  lcd_send_command(0x28); // 4-bit mode, 2 lines, 5x8 font
  usleep(5000);           // Wait 5ms
  lcd_send_command(LCD_DISPLAYCONTROL | LCD_DISPLAYON); // Display on, cursor off, blink off
  usleep(5000);           // Wait 5ms
  lcd_clear();              // Clear display
  usleep(5000);           // Wait 5ms
  lcd_send_command(LCD_ENTRYMODESET | LCD_ENTRYLEFT);   // Set entry mode
  usleep(5000);           // Wait 5ms
  lcd_backlight(1); //Turn on backlight

  return 0;
}

// Send command to LCD
void lcd_send_command(uint8_t command) {
  lcd_send_nibble(command >> 4, 0);  // Send upper nibble
  lcd_send_nibble(command & 0x0F, 0); // Send lower nibble
}

// Send data to LCD
void lcd_send_data(uint8_t data) {
  lcd_send_nibble(data >> 4, 1);  // Send upper nibble
  lcd_send_nibble(data & 0x0F, 1); // Send lower nibble
}

// Send a nibble to the LCD
void lcd_send_nibble(uint8_t nibble, int rs) {
  uint8_t data = (nibble << 4) | (rs << 0) | LCD_BACKLIGHT_ON | 0x04; // E=1, RS = rs
  wiringPiI2CWrite(i2c_fd, data);
  usleep(1); // Enable pulse width >= 300ns
  data &= ~0x04; // E=0
  wiringPiI2CWrite(i2c_fd, data);
  usleep(100);
}

// Write a character to the LCD
void lcd_write_char(char character) {
  lcd_send_data(character);
}

// Write a string to the LCD
void lcd_write_string(const char *string) {
  for (int i = 0; string[i] != '\0'; i++) {
    lcd_write_char(string[i]);
  }
}

// Set the cursor position
void lcd_set_cursor(uint8_t row, uint8_t col) {
  uint8_t address;
  if (row == 0) {
    address = 0x00 + col;
  } else {
    address = 0x40 + col;
  }
  lcd_send_command(LCD_SETDDRAMADDR | address);
}

// Clear the LCD display
void lcd_clear() {
  lcd_send_command(LCD_CLEARDISPLAY);
  usleep(2000); // Wait for clear command to complete
}

// Control the LCD backlight
void lcd_backlight(int on) {
    uint8_t backlight_bit = on ? LCD_BACKLIGHT_ON : LCD_BACKLIGHT_OFF;
    uint8_t data = backlight_bit; // Only control the backlight bit

    // Send any nibble with the updated backlight status
    lcd_send_nibble(0, 0); //RS = 0

}

int main() {
  // Initialize the LCD
  if (lcd_init() < 0) {
    fprintf(stderr, "LCD initialization failed.\n");
    return 1;
  }

  // Write a greeting message
  lcd_set_cursor(0, 0);
  lcd_write_string("Hello, RPi!");

  lcd_set_cursor(1, 0);
  lcd_write_string("LCD 1602 Test");

  sleep(5);
  lcd_clear();
  lcd_set_cursor(0,0);
  lcd_write_string("Backlight Off");
  lcd_backlight(0);
  sleep(5);
  lcd_backlight(1);
  lcd_clear();
  lcd_write_string("Backlight On");
  sleep(2);

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>

// Define the GPIO pin connected to the buzzer
#define BUZZER_PIN 0

// Function to initialize the buzzer pin
int initializeBuzzer() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return -1; // Indicate failure
    }

    pinMode(BUZZER_PIN, OUTPUT);
    digitalWrite(BUZZER_PIN, HIGH); // Initially turn the buzzer off

    printf("Buzzer initialized on pin %d\n", BUZZER_PIN);
    return 0; // Indicate success
}

// Function to turn the buzzer on
void turnBuzzerOn() {
    digitalWrite(BUZZER_PIN, LOW);
    printf("Buzzer ON\n");
}

// Function to turn the buzzer off
void turnBuzzerOff() {
    digitalWrite(BUZZER_PIN, HIGH);
    printf("Buzzer OFF\n");
}

int main() {
    // Initialize the buzzer
    if (initializeBuzzer() == -1) {
        fprintf(stderr, "Buzzer initialization failed. Exiting.\n");
        return EXIT_FAILURE; // Exit if initialization fails
    }

    // Main loop to toggle the buzzer
    while (1) {
        turnBuzzerOn();
        delay(100); // Delay for 100ms

        turnBuzzerOff();
        delay(100); // Delay for 100ms
    }

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <time.h>
#include <math.h>

#include <wiringPi.h>
#include <lcd128x64.h>

// Constants
#ifndef TRUE
#  define TRUE  (1==1)
#  define FALSE (1==2)
#endif

// Global variables
double clock_radius;
double hand_thickness;
double indicator_length;
int screen_width, screen_height;

// Function prototypes
double degrees_to_radians(double degrees);
void draw_clock_hands(void);
void draw_clock_face(void);
int initialize(void);

/**
 * @brief Converts degrees to radians.
 *
 * @param degrees Angle in degrees.
 * @return Angle in radians.
 */
double degrees_to_radians(double degrees) {
  return degrees * M_PI / 180.0;
}

/**
 * @brief Draws the clock hands (hour, minute, and second).
 */
void draw_clock_hands(void) {
  time_t current_time;
  struct tm *time_info;
  double angle, x0, y0, x1, y1;
  int hour_24, hour_12, minute, second;
  char time_string[40];
  char date_string[40];

  time(&current_time);
  time_info = localtime(&current_time);

  hour_24 = time_info->tm_hour;
  minute = time_info->tm_min;
  second = time_info->tm_sec;

  hour_12 = hour_24;
  if (hour_12 > 12) {
    hour_12 -= 12;
  }

  // Hour hand
  angle = hour_12 * 30 + minute * 0.5;
  x0 = sin(degrees_to_radians(angle)) * (clock_radius * 0.75);
  y0 = cos(degrees_to_radians(angle)) * (clock_radius * 0.75);
  for (double p = -3.0; p <= 3.0; p += 0.2) {
    x1 = sin(degrees_to_radians(angle + p)) * (clock_radius * 0.7);
    y1 = cos(degrees_to_radians(angle + p)) * (clock_radius * 0.7);
    lcd128x64line(0, 0, x1, y1, 1);
    lcd128x64lineTo(x0, y0, 1);
  }

  // Minute hand
  angle = minute * 6;
  x0 = sin(degrees_to_radians(angle)) * (clock_radius * 0.9);
  y0 = cos(degrees_to_radians(angle)) * (clock_radius * 0.9);
  for (double p = -1.0; p <= 1.0; p += 0.2) {
    x1 = sin(degrees_to_radians(angle + p)) * (clock_radius * 0.85);
    y1 = cos(degrees_to_radians(angle + p)) * (clock_radius * 0.85);
    lcd128x64line(0, 0, x1, y1, 1);
    lcd128x64lineTo(x0, y0, 1);
  }

  // Second hand
  angle = second * 6;
  x0 = sin(degrees_to_radians(angle)) * (clock_radius * 0.2);
  y0 = cos(degrees_to_radians(angle)) * (clock_radius * 0.2);
  x1 = sin(degrees_to_radians(angle)) * (clock_radius * 0.95);
  y1 = cos(degrees_to_radians(angle)) * (clock_radius * 0.95);
  lcd128x64line(0 - x0, 0 - y0, x1, y1, 1);
  lcd128x64circle(0, 0, clock_radius * 0.1, 0, 1);
  lcd128x64circle(0, 0, clock_radius * 0.05, 1, 1);

  // Display Time and Date
  snprintf(time_string, sizeof(time_string), "%02d:%02d:%02d", hour_24, minute, second);
  lcd128x64puts(32, 24, time_string, 0, 1);

  snprintf(date_string, sizeof(date_string), "%2d/%2d/%2d", time_info->tm_mday, time_info->tm_mon + 1, time_info->tm_year - 100);
  lcd128x64puts(32, -23, date_string, 0, 1);
}

/**
 * @brief Draws the clock face with indicators and ticks.
 */
void draw_clock_face(void) {
  int minute_mark;
  double px1, py1, px2, py2, indicator_distance;

  lcd128x64clear(0);
  lcd128x64circle(0, 0, clock_radius, 1, TRUE);
  lcd128x64circle(0, 0, clock_radius - hand_thickness, 0, TRUE);

  // Major indicators (12, 3, 6, 9)
  lcd128x64rectangle(-3, clock_radius - indicator_length, 3, clock_radius, 1, TRUE);  // 12
  lcd128x64rectangle(clock_radius - indicator_length, 3, clock_radius, -3, 1, TRUE);  // 3
  lcd128x64rectangle(-3, -clock_radius + indicator_length, 3, -clock_radius, 1, TRUE); // 6
  lcd128x64rectangle(-clock_radius + indicator_length, 3, -clock_radius, -3, 1, TRUE); // 9

  // Minor ticks (1 and 5 minute marks)
  for (minute_mark = 0; minute_mark < 60; ++minute_mark) {
    px1 = sin(degrees_to_radians(minute_mark * 6)) * clock_radius;
    py1 = cos(degrees_to_radians(minute_mark * 6)) * clock_radius;

    indicator_distance = (minute_mark % 5 == 0) ? indicator_length : indicator_length / 2.0;

    px2 = sin(degrees_to_radians(minute_mark * 6)) * (clock_radius - indicator_distance);
    py2 = cos(degrees_to_radians(minute_mark * 6)) * (clock_radius - indicator_distance);
    lcd128x64line(px1, py1, px2, py2, 1);
  }
}

/**
 * @brief Initializes the LCD and clock parameters.
 * @return 0 on success, -1 on failure.
 */
int initialize(void) {
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
    return -1;
  }

  if (lcd128x64setup() == -1) {
        fprintf(stderr, "LCD128x64 setup failed.\n");
        return -1;
  }

  lcd128x64getScreenSize(&screen_width, &screen_height);
  clock_radius = screen_height / 2 - 1;
  hand_thickness = screen_width / 48;
  indicator_length = hand_thickness * 4;
  lcd128x64setOrigin(32, 32);
  return 0;
}

/**
 * @brief Main function.
 *
 * @param argc Argument count.
 * @param argv Argument vector.
 * @return Exit status.
 */
int main(int argc, char *argv[]) {
  if (initialize() != 0) {
    fprintf(stderr, "Initialization failed. Exiting.\n");
    return EXIT_FAILURE;
  }

  time_t current_time;

  while (TRUE) {
    draw_clock_face();
    draw_clock_hands();
    lcd128x64update();

    current_time = time(NULL);
    while (time(NULL) == current_time) {
      delay(10);
    }
  }

  return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <errno.h>

// Define GPIO pins for motor control
#define MOTOR_PIN_1   0  // GPIO pin connected to Motor Pin 1
#define MOTOR_PIN_2   2  // GPIO pin connected to Motor Pin 2
#define MOTOR_ENABLE  3  // GPIO pin connected to Motor Enable

// Function prototypes
int motor_init(void);
void motor_clockwise(void);
void motor_anticlockwise(void);
void motor_stop(void);
void safe_delay(unsigned int milliseconds);

int main(void) {
    // Initialize WiringPi and motor control pins
    if (motor_init() != 0) {
        fprintf(stderr, "Motor initialization failed. Exiting.\n");
        return EXIT_FAILURE; // Exit if initialization fails
    }

    printf("Motor control program started.\n");

    // Main loop to control motor direction and state
    while (1) {
        printf("Clockwise...\n");
        safe_delay(100); // Small delay for stability
        motor_clockwise();
        safe_delay(3000); // Run clockwise for 3 seconds

        printf("Stop...\n");
        safe_delay(100); // Small delay for stability
        motor_stop();
        safe_delay(3000); // Stop for 3 seconds

        printf("Anti-clockwise...\n");
        safe_delay(100); // Small delay for stability
        motor_anticlockwise();
        safe_delay(3000); // Run anti-clockwise for 3 seconds

        printf("Stop...\n");
        safe_delay(100); // Small delay for stability
        motor_stop();
        safe_delay(3000); // Stop for 3 seconds
    }

    return EXIT_SUCCESS; // Program should not reach here in normal execution
}

// Initializes WiringPi and configures motor control pins.
int motor_init(void) {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi setup failed: %s\n", strerror(errno));
        return -1; // Indicate failure
    }

    // Configure motor control pins as output
    pinMode(MOTOR_PIN_1, OUTPUT);
    pinMode(MOTOR_PIN_2, OUTPUT);
    pinMode(MOTOR_ENABLE, OUTPUT);

    // Ensure motor is initially stopped
    motor_stop();

    printf("Motor initialized successfully.\n");
    return 0; // Indicate success
}

// Sets the motor to rotate in the clockwise direction.
void motor_clockwise(void) {
    digitalWrite(MOTOR_ENABLE, HIGH); // Enable the motor
    digitalWrite(MOTOR_PIN_1, HIGH);  // Set Pin 1 High
    digitalWrite(MOTOR_PIN_2, LOW);   // Set Pin 2 Low
    printf("Motor rotating clockwise.\n");
}

// Sets the motor to rotate in the anti-clockwise direction.
void motor_anticlockwise(void) {
    digitalWrite(MOTOR_ENABLE, HIGH); // Enable the motor
    digitalWrite(MOTOR_PIN_1, LOW);   // Set Pin 1 Low
    digitalWrite(MOTOR_PIN_2, HIGH);  // Set Pin 2 High
    printf("Motor rotating anti-clockwise.\n");
}

// Stops the motor.
void motor_stop(void) {
    digitalWrite(MOTOR_ENABLE, LOW); // Disable the motor
    printf("Motor stopped.\n");
}

// A safer delay function using nanosleep to avoid blocking signals
void safe_delay(unsigned int milliseconds) {
    delay(milliseconds);
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <softPwm.h>

// Define the GPIO pin connected to the servo motor
#define SERVO_PIN 1

// Define the minimum and maximum pulse widths (in milliseconds) for the servo
#define SERVO_MIN_PULSE_WIDTH 5   // 1ms
#define SERVO_MAX_PULSE_WIDTH 25  // 2ms

// Define the refresh rate for the servo (20ms = 50Hz)
#define SERVO_REFRESH_RATE 200

// Function to map a value from one range to another
float map(float value, float from_low, float from_high, float to_low, float to_high) {
    return (value - from_low) * (to_high - to_low) / (from_high - from_low) + to_low;
}

// Function to set the angle of the servo motor
int set_servo_angle(int pin, int angle) {
    // Check if the angle is within the valid range
    if (angle < 0 || angle > 180) {
        fprintf(stderr, "Error: Angle must be between 0 and 180 degrees.\n");
        return -1; // Indicate an error
    }

    // Map the angle to the corresponding pulse width
    float pulse_width = map(angle, 0, 180, SERVO_MIN_PULSE_WIDTH, SERVO_MAX_PULSE_WIDTH);

    // Set the pulse width using softPwmWrite
    softPwmWrite(pin, (int)pulse_width);
    return 0; // Indicate success
}

int main(void) {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: Failed to initialize wiringPi.\n");
        return 1; // Indicate an error
    }

    // Create a software PWM channel for the servo pin
    if (softPwmCreate(SERVO_PIN, 0, SERVO_REFRESH_RATE) != 0) {
        fprintf(stderr, "Error: Failed to create software PWM channel.\n");
        return 1; // Indicate an error
    }

    // Main loop to sweep the servo back and forth
    while (1) {
        // Sweep from 0 to 180 degrees
        for (int angle = 0; angle <= 180; angle++) {
            if (set_servo_angle(SERVO_PIN, angle) != 0) {
                fprintf(stderr, "Error: Failed to set servo angle.\n");
                return 1; // Indicate an error
            }
            delay(10); // Delay for smooth movement
        }

        delay(1000); // Delay at the end of the sweep

        // Sweep from 180 to 0 degrees
        for (int angle = 180; angle >= 0; angle--) {
            if (set_servo_angle(SERVO_PIN, angle) != 0) {
                fprintf(stderr, "Error: Failed to set servo angle.\n");
                return 1; // Indicate an error
            }
            delay(10); // Delay for smooth movement
        }

        delay(1000); // Delay at the end of the sweep
    }

    return 0; // Indicate success
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>

// Define motor control pins (GPIO numbers)
const int MOTOR_PINS[] = {1, 4, 5, 6};
const int NUM_PINS = sizeof(MOTOR_PINS) / sizeof(MOTOR_PINS[0]);

// Motor parameters
const int STEPS_PER_REVOLUTION = 2048; // Adjust based on your motor
const int DEFAULT_RPM = 15;             // Default rotations per minute

// Function prototypes
void initialize_gpio();
void set_motor_speed(int rpm);
void rotate_motor(char direction);
void cleanup_gpio();

// Global variable for step delay (microseconds)
unsigned int step_delay_us;

int main() {
    // Initialize wiringPi and GPIO pins
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPi setup failed!\n");
        return EXIT_FAILURE;
    }

    initialize_gpio();
    set_motor_speed(DEFAULT_RPM);

    char direction;

    while (1) {
        printf("Select motor direction (a=anticlockwise, c=clockwise, q=quit): ");
        fflush(stdout); // Ensure prompt is displayed
        if (scanf(" %c", &direction) != 1) {
            fprintf(stderr, "Error reading input. Exiting.\n");
            break;
        }

        if (direction == 'c' || direction == 'a') {
            printf("Motor running %s\n", (direction == 'c') ? "clockwise" : "anti-clockwise");
            while (1) {
                rotate_motor(direction);
            }
        } else if (direction == 'q') {
            printf("Exiting program.\n");
            break;
        } else {
            printf("Invalid input. Please try again!\n");
        }

        // Consume any remaining characters in the input buffer
        while (getchar() != '\n');
    }

    cleanup_gpio();
    return EXIT_SUCCESS;
}

void initialize_gpio() {
    for (int i = 0; i < NUM_PINS; i++) {
        pinMode(MOTOR_PINS[i], OUTPUT);
    }
}

void set_motor_speed(int rpm) {
    if (rpm <= 0) {
        fprintf(stderr, "Invalid RPM value. Using default RPM.\n");
        rpm = DEFAULT_RPM;
    }
    step_delay_us = 60000000 / ((unsigned int)rpm * STEPS_PER_REVOLUTION); // Calculate delay in microseconds
    printf("Step delay: %u us\n", step_delay_us);
}

void rotate_motor(char direction) {
    // Stepping sequence (full step drive)
    static const int step_sequence[] = {0b1001, 0b0011, 0b0110, 0b1100}; // Example sequence
    const int num_steps = sizeof(step_sequence) / sizeof(step_sequence[0]);
    static int current_step = 0;

    if (direction == 'c') {
        current_step = (current_step + 1) % num_steps; // Clockwise
    } else {
        current_step = (current_step - 1 + num_steps) % num_steps; // Anti-clockwise
    }

    int step_pattern = step_sequence[current_step];

    for (int i = 0; i < NUM_PINS; i++) {
        digitalWrite(MOTOR_PINS[i], (step_pattern >> (NUM_PINS - 1 - i)) & 1);
    }
    delayMicroseconds(step_delay_us);
}

void cleanup_gpio() {
    // Optionally, turn off all motor pins during cleanup
    for (int i = 0; i < NUM_PINS; i++) {
        digitalWrite(MOTOR_PINS[i], LOW);
    }
}

#include <stdio.h>
