#define MIN_RPM 4000       // Minimum RPM value
#define MAX_RPM 8000       // Maximum RPM value
#define RPM_INCREMENT 100  // Increment/decrement step for RPM

// Global Variables
static volatile int current_rpm = MIN_RPM; // Current RPM value (volatile because it's accessed in an ISR)
static pthread_mutex_t rpm_mutex = PTHREAD_MUTEX_INITIALIZER; // Mutex for protecting RPM variable

// Function Declarations
void *control_rpm(void *arg);
void button_interrupt_handler(void);
int get_current_rpm(void);
void set_current_rpm(int new_rpm);

// Function to control the RPM (simulated)
void *control_rpm(void *arg) {
    (void)arg; // Suppress unused parameter warning

    while (1) {
        int rpm_value = get_current_rpm();
        printf("Current RPM: %d\n", rpm_value);
        // In a real application, you would use 'rpm_value' to control
        // a motor or other device.
        delay(1000); // Simulate some processing time
    }
    return NULL;
}

// Button interrupt handler
void button_interrupt_handler(void) {
    pthread_mutex_lock(&rpm_mutex);
    current_rpm += RPM_INCREMENT;
    if (current_rpm > MAX_RPM) {
        current_rpm = MIN_RPM;
    }
    pthread_mutex_unlock(&rpm_mutex);
    printf("Button pressed.  New RPM set to %d\n", current_rpm);
}

// Getter for current_rpm with mutex protection
int get_current_rpm(void) {
    pthread_mutex_lock(&rpm_mutex);
    int rpm = current_rpm;
    pthread_mutex_unlock(&rpm_mutex);
    return rpm;
}

// Setter for current_rpm with mutex protection
void set_current_rpm(int new_rpm) {
    pthread_mutex_lock(&rpm_mutex);
    current_rpm = new_rpm;
    pthread_mutex_unlock(&rpm_mutex);
}

int main(void) {
    // Initialize WiringPi using GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return EXIT_FAILURE;
    }

    // Configure the button GPIO pin as an input with a pull-down resistor
    pinMode(BUTTON_GPIO_PIN, INPUT);
    pullUpDnControl(BUTTON_GPIO_PIN, PUD_DOWN);

    // Set up the interrupt handler for the button (rising edge detection)
    if (wiringPiISR(BUTTON_GPIO_PIN, INT_EDGE_RISING, &button_interrupt_handler) < 0) {
        fprintf(stderr, "Unable to setup ISR: %s\n", strerror(errno));
        return EXIT_FAILURE;
    }

    // Create a thread to control the RPM
    pthread_t rpm_thread;
    if (pthread_create(&rpm_thread, NULL, control_rpm, NULL) != 0) {
        perror("Failed to create RPM control thread");
        return EXIT_FAILURE;
    }

    printf("RPM control application started. Press the button to increase RPM.\n");

    // Keep the main thread running
    while (1) {
        pause(); // Suspend execution until a signal arrives
    }

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <math.h>
#include <wiringPi.h>
#include <pigpio.h>

// --- Constants and Pin Definitions ---
#define MAIN_ROTOR_ENCODER_A_PIN 3
#define MAIN_ROTOR_ENCODER_B_PIN 5
#define TAIL_ROTOR_ENCODER_A_PIN 2
#define TAIL_ROTOR_ENCODER_B_PIN 6
#define MAIN_ROTOR_ESC_PIN 9
#define TAIL_ROTOR_ESC_PIN 10

// --- PID Parameters (Tunable) ---
#define MAIN_ROTOR_KP 5.0f
#define MAIN_ROTOR_KI 0.5f
#define MAIN_ROTOR_KD 0.5f

#define TAIL_ROTOR_KP 0.1f
#define TAIL_ROTOR_KI 1.0f
#define TAIL_ROTOR_KD 0.4f

// --- SMC Parameters (Tunable) ---
#define SMC_LAMBDA 10.0f
#define SMC_ETA 8.0f
#define SMC_EPSILON 0.4f

// --- Target States (Tunable) ---
#define TARGET_MAIN_ROTOR_ANGLE 45.0f
#define TARGET_MAIN_ROTOR_VELOCITY 0.0f

#define TARGET_TAIL_ROTOR_ANGLE 40.0f
#define TARGET_TAIL_ROTOR_VELOCITY 0.0f

// --- ESC Throttle Limits ---
#define MAX_THROTTLE 2000
#define MIN_THROTTLE 1000
#define INITIAL_THROTTLE 1200

// --- Angle Limits ---
#define MAX_ANGLE 150.0f

// --- Global Variables ---
// Encoder Counts
volatile int mainRotorEncoderCount = 0;
volatile int tailRotorEncoderCount = 0;

// Rotor State Variables
float mainRotorAngle = 0.0f;
float mainRotorVelocity = 0.0f;
float tailRotorAngle = 0.0f;
float tailRotorVelocity = 0.0f;

// PID Integrators and Previous Errors
float mainRotorIntegral = 0.0f;
float mainRotorPrevError = 0.0f;
float tailRotorIntegral = 0.0f;
float tailRotorPrevError = 0.0f;

// Throttle Values
int mainRotorThrottle = INITIAL_THROTTLE;
int tailRotorThrottle = INITIAL_THROTTLE;

// --- Function Prototypes ---
void setupGPIO();
void setupESC(int escPin);
void updateMainRotorEncoder();
void updateTailRotorEncoder();
void updateRotorControl(
    volatile int *encoderCount,
    float *angle,
    float *velocity,
    float targetAngle,
    float targetVelocity,
    float *integral,
    float *prevError,
    int *throttle,
    int escPin,
    float kp, float ki, float kd
);
float saturation(float s);
float calculateAngle(int encoderCount);

int main()
{
    if (wiringPiSetupGpio() == -1 || gpioInitialise() < 0)
    {
        fprintf(stderr, "Error: Unable to initialize wiringPi or pigpio.\n");
        return 1;
    }

    setupGPIO();
    setupESC(MAIN_ROTOR_ESC_PIN);
    setupESC(TAIL_ROTOR_ESC_PIN);

    printf("Helicopter Rotor Control System Initialized.\n");

    while (1)
    {
        updateRotorControl(
            &mainRotorEncoderCount,
            &mainRotorAngle,
            &mainRotorVelocity,
            TARGET_MAIN_ROTOR_ANGLE,
            TARGET_MAIN_ROTOR_VELOCITY,
            &mainRotorIntegral,
            &mainRotorPrevError,
            &mainRotorThrottle,
            MAIN_ROTOR_ESC_PIN,
            MAIN_ROTOR_KP, MAIN_ROTOR_KI, MAIN_ROTOR_KD
        );

        updateRotorControl(
            &tailRotorEncoderCount,
            &tailRotorAngle,
            &tailRotorVelocity,
            TARGET_TAIL_ROTOR_ANGLE,
            TARGET_TAIL_ROTOR_VELOCITY,
            &tailRotorIntegral,
            &tailRotorPrevError,
            &tailRotorThrottle,
            TAIL_ROTOR_ESC_PIN,
            TAIL_ROTOR_KP, TAIL_ROTOR_KI, TAIL_ROTOR_KD
        );

        usleep(10000); // 10ms delay
    }

    gpioTerminate();
    return 0;
}

// --- GPIO Setup Function ---
void setupGPIO()
{
    pinMode(MAIN_ROTOR_ENCODER_A_PIN, INPUT);
    pinMode(MAIN_ROTOR_ENCODER_B_PIN, INPUT);
    pinMode(TAIL_ROTOR_ENCODER_A_PIN, INPUT);
    pinMode(TAIL_ROTOR_ENCODER_B_PIN, INPUT);

    wiringPiISR(MAIN_ROTOR_ENCODER_A_PIN, INT_EDGE_BOTH, updateMainRotorEncoder);
    wiringPiISR(TAIL_ROTOR_ENCODER_A_PIN, INT_EDGE_BOTH, updateTailRotorEncoder);
}

// --- ESC Setup Function ---
void setupESC(int escPin)
{
    gpioSetPWMfrequency(escPin, 50);  // 50 Hz PWM frequency
    gpioSetPWMrange(escPin, 20000);   // PWM range for throttle values
    gpioPWM(escPin, MIN_THROTTLE);    // Initialize to minimum throttle
    sleep(2);                          // Allow ESC to initialize
}

// --- Main Rotor Encoder Update Function ---
void updateMainRotorEncoder()
{
    static int lastStateA = 0;
    int stateA = digitalRead(MAIN_ROTOR_ENCODER_A_PIN);
    int stateB = digitalRead(MAIN_ROTOR_ENCODER_B_PIN);

    if (stateA != lastStateA)
    {
        mainRotorEncoderCount += (stateA == stateB) ? -1 : 1;
        lastStateA = stateA;
    }
}

// --- Tail Rotor Encoder Update Function ---
void updateTailRotorEncoder()
{
    static int lastStateA = 0;
    int stateA = digitalRead(TAIL_ROTOR_ENCODER_A_PIN);
    int stateB = digitalRead(TAIL_ROTOR_ENCODER_B_PIN);

    if (stateA != lastStateA)
    {
        tailRotorEncoderCount += (stateA == stateB) ? 1 : -1; //Inverted direction
        lastStateA = stateA;
    }
}

// --- Rotor Control Update Function (PID + SMC) ---
void updateRotorControl(
    volatile int *encoderCount,
    float *angle,
    float *velocity,
    float targetAngle,
    float targetVelocity,
    float *integral,
    float *prevError,
    int *throttle,
    int escPin,
    float kp, float ki, float kd
)
{
    // Calculate current angle
    float currentAngle = calculateAngle(*encoderCount);

    // Calculate angular velocity (crude approximation)
    float dt = 0.01f; // 10ms loop
    float angularVelocity = (*angle - currentAngle) / dt;

    // Update angle with the calculated value
    *angle = currentAngle;
    *velocity = angularVelocity;

    // PID Error Calculation
    float error = targetAngle - *angle;

    // Integral Term (with anti-windup)
    *integral += error * dt;
    *integral = fmax(-100.0f, fmin(*integral, 100.0f)); // Clamp integral term

    // Derivative Term
    float derivative = (error - *prevError) / dt;

    // PID Output
    float pidOutput = (kp * error) + (ki * (*integral)) + (kd * derivative);

    // SMC Calculation
    float slidingSurface = SMC_LAMBDA * (error) + (*velocity - targetVelocity);
    float smcOutput = -SMC_ETA * saturation(slidingSurface);

    // Combine PID and SMC
    float controlOutput = pidOutput + smcOutput;

    // Throttle Mapping
    *throttle = (int)(INITIAL_THROTTLE + controlOutput);
    *throttle = fmax(MIN_THROTTLE, fmin(*throttle, MAX_THROTTLE)); // Clamp throttle

    // Send Throttle to ESC
    gpioPWM(escPin, *throttle);

    // Update previous error
    *prevError = error;

    // Debug Output (Optional)
    printf("Angle: %.2f, Velocity: %.2f, Target: %.2f, Throttle: %d\n", *angle, *velocity, targetAngle, *throttle);
}

// --- Saturation Function ---
float saturation(float s)
{
    if (fabs(s) <= SMC_EPSILON)
    {
        return s / SMC_EPSILON;
    }
    return (s > 0) ? 1.0f : -1.0f;
}

// --- Angle Calculation from Encoder Counts ---
float calculateAngle(int encoderCount)
{
    // Assuming 1200 counts per revolution (adjust if different)
    float angle = (float)(encoderCount % 1200) * (360.0f / 1200.0f);
    return angle;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <errno.h>

// Constants for button matrix dimensions
#define NUM_ROWS 4
#define NUM_COLS 4

// GPIO pin numbers for rows and columns.  Ensure these are correct for your wiring.
const int ROW_PINS[NUM_ROWS] = {13, 15, 29, 31}; // Physical pin numbers
const int COL_PINS[NUM_COLS] = {22, 37, 35, 33}; // Physical pin numbers

// Function prototypes
int setupButtonMatrix();
int readButtonMatrix();
void cleanupButtonMatrix();

int main(int argc, char *argv[]) {
    if (wiringPiSetupPhys() == -1) {
        fprintf(stderr, "WiringPi setup failed: %s\n", strerror(errno));
        return 1;
    }

    if (setupButtonMatrix() != 0) {
        fprintf(stderr, "Button matrix setup failed.\n");
        return 1;
    }

    printf("Button matrix initialized. Press a button.\n");

    int pressedKey;
    while (1) {
        pressedKey = readButtonMatrix();
        if (pressedKey != 0) {
            printf("Key pressed: %d\n", pressedKey);
            delay(200); // Debounce delay
        }
        delay(10); // Short delay to prevent busy-waiting
    }

    cleanupButtonMatrix(); // This will never be reached in the current loop, but good practice
    return 0;
}

// Initializes the GPIO pins for the button matrix.
int setupButtonMatrix() {
    int row, col;

    // Set column pins as output and initially high
    for (col = 0; col < NUM_COLS; col++) {
        pinMode(COL_PINS[col], OUTPUT);
        digitalWrite(COL_PINS[col], HIGH);
    }

    // Set row pins as input with pull-up resistors
    for (row = 0; row < NUM_ROWS; row++) {
        pinMode(ROW_PINS[row], INPUT);
        pullUpDnControl(ROW_PINS[row], PUD_UP);
    }

    return 0; // Return 0 on success
}

// Reads the button matrix and returns the key number (1-16) or 0 if no key is pressed.
int readButtonMatrix() {
    int row, col;

    for (col = 0; col < NUM_COLS; col++) {
        digitalWrite(COL_PINS[col], LOW);
        delayMicroseconds(1); // Small delay for the signal to propagate

        for (row = 0; row < NUM_ROWS; row++) {
            if (digitalRead(ROW_PINS[row]) == LOW) {
                // Key press detected
                digitalWrite(COL_PINS[col], HIGH); // Reset column before returning
                return row * NUM_COLS + col + 1; // Calculate key number
            }
        }
        digitalWrite(COL_PINS[col], HIGH);
    }
    return 0; // No key pressed
}

//Cleanup GPIO pins - sets all pins to input to prevent shorts.
void cleanupButtonMatrix() {
    int i;
    for (i = 0; i < NUM_ROWS; i++) {
        pinMode(ROW_PINS[i], INPUT);
    }
    for (i = 0; i < NUM_COLS; i++) {
        pinMode(COL_PINS[i], INPUT);
    }
}

