#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <unistd.h>
#include <time.h>

// Define GPIO pins connected to the ultrasonic sensor
#define TRIGGER_PIN 23 // GPIO pin for triggering the sensor
#define ECHO_PIN 24    // GPIO pin for receiving the echo

// Constants for distance calculation
#define SOUND_SPEED_CM_US 0.0343 // Speed of sound in cm/us
#define SOUND_SPEED_INCH_US 0.0135 // Speed of sound in inch/us

// Function prototypes
float measure_distance_cm();
float measure_distance_inch();
void setup_gpio();

int main()
{
    // Initialize WiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed!\n");
        return 1;
    }

    setup_gpio();

    printf("Ultrasonic Distance Sensor Demo\n");

    while (1) {
        float distance_cm = measure_distance_cm();
        float distance_inch = measure_distance_inch();

        if (distance_cm > 0) {
            printf("Distance: %.2f cm / %.2f inch\n", distance_cm, distance_inch);
        } else {
            fprintf(stderr, "Error: Could not read distance. Check sensor connection.\n");
        }

        delay(1000); // Delay for 1 second
    }

    return 0;
}

void setup_gpio()
{
    // Set GPIO pin modes
    pinMode(TRIGGER_PIN, OUTPUT);
    pinMode(ECHO_PIN, INPUT);

    // Ensure trigger pin is low initially
    digitalWrite(TRIGGER_PIN, LOW);
    delay(500); // Allow sensor to settle
}

float measure_distance_cm()
{
    // Trigger the sensor
    digitalWrite(TRIGGER_PIN, HIGH);
    delayMicroseconds(10);
    digitalWrite(TRIGGER_PIN, LOW);

    // Measure echo pulse duration
    struct timespec start, end;
    long long start_time, end_time, pulse_duration;

    // Wait for echo to start (with timeout)
    int timeout = 1000; // 1ms timeout
    while (digitalRead(ECHO_PIN) == LOW && timeout > 0) {
        timeout--;
        delayMicroseconds(1); // Wait 1 us
    }

    if (timeout <= 0) {
        fprintf(stderr, "Error: Echo start timeout.\n");
        return -1.0; // Indicate error
    }

    clock_gettime(CLOCK_MONOTONIC_RAW, &start);

    // Wait for echo to end (with timeout)
    timeout = 10000; // 10ms timeout
    while (digitalRead(ECHO_PIN) == HIGH && timeout > 0) {
        timeout--;
        delayMicroseconds(1); // Wait 1 us
    }

    if (timeout <= 0) {
        fprintf(stderr, "Error: Echo end timeout.\n");
        return -1.0; // Indicate error
    }

    clock_gettime(CLOCK_MONOTONIC_RAW, &end);

    start_time = start.tv_sec * 1000000000LL + start.tv_nsec;
    end_time = end.tv_sec * 1000000000LL + end.tv_nsec;
    pulse_duration = end_time - start_time;

    // Calculate distance in centimeters
    return (float)pulse_duration * SOUND_SPEED_CM_US / 2000.0;
}

float measure_distance_inch()
{
    // Reuse cm measurement and convert
    float distance_cm = measure_distance_cm();
    if (distance_cm > 0) {
        return distance_cm / 2.54; // Convert cm to inches
    } else {
        return -1.0; // Propagate error
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/time.h>
#include <errno.h>

#define NUM_CYCLES 1000

// Function to calculate the time difference in microseconds
long time_difference_us(struct timeval start, struct timeval end) {
    return ((end.tv_sec - start.tv_sec) * 1000000L) + (end.tv_usec - start.tv_usec);
}

int main() {
    int delay_us;
    struct timeval start_time, end_time;
    long measured_delay_us;
    int max_delay_us, min_delay_us;
    int under_runs, over_runs, exact_runs, deschedules;
    long total_delay_us;
    double average_delay_us;
    int return_code;

    // Baseline test: Measure the overhead of gettimeofday calls
    if (gettimeofday(&start_time, NULL) == -1 || gettimeofday(&end_time, NULL) == -1) {
        perror("Error getting time");
        return EXIT_FAILURE;
    }
    long baseline_overhead = time_difference_us(start_time, end_time);
    printf("Baseline overhead: %ld us\n", baseline_overhead);

    // Loop through different delay values
    for (delay_us = 1; delay_us <= 200; ++delay_us) {
        under_runs = 0;
        over_runs = 0;
        exact_runs = 0;
        deschedules = 0;
        total_delay_us = 0;
        max_delay_us = 0;
        min_delay_us = 1000; // Initialize to a large value

        // Timing loop
        for (int i = 0; i < NUM_CYCLES; ++i) {
            // Retry loop to handle descheduling
            for (;;) {
                if (gettimeofday(&start_time, NULL) == -1) {
                    perror("Error getting start time");
                    return EXIT_FAILURE;
                }

                return_code = usleep(delay_us);
                if (return_code != 0 && errno == EINTR) {
                  //Interrupted by a signal, retry
                  continue;
                } else if (return_code != 0) {
                  perror("usleep error");
                  return EXIT_FAILURE;
                }

                if (gettimeofday(&end_time, NULL) == -1) {
                    perror("Error getting end time");
                    return EXIT_FAILURE;
                }

                measured_delay_us = time_difference_us(start_time, end_time);

                if (measured_delay_us > 999) {
                    ++deschedules;
                    continue; // Retry if descheduled
                } else {
                    break; // Exit retry loop
                }
            }

            // Update statistics
            if (measured_delay_us == delay_us) {
                ++exact_runs;
            } else if (measured_delay_us < delay_us) {
                ++under_runs;
            } else {
                ++over_runs;
            }

            if (measured_delay_us > max_delay_us) {
                max_delay_us = measured_delay_us;
            }
            if (measured_delay_us < min_delay_us) {
                min_delay_us = measured_delay_us;
            }

            total_delay_us += measured_delay_us;
        }

        // Calculate average delay
        average_delay_us = (double)total_delay_us / NUM_CYCLES;

        // Print results
        printf("Delay: %3d us, Min: %3d us, Max: %3d us, Unders: %3d, Overs: %3d, Exacts: %3d, Average: %.2f us, Deschedules: %2d\n",
               delay_us, min_delay_us, max_delay_us, under_runs, over_runs, exact_runs, average_delay_us, deschedules);
        fflush(stdout); // Ensure output is flushed
        usleep(1000); // Small delay between tests
    }

    return EXIT_SUCCESS;
}

