// Register definitions
#define RTC_SECS  0
#define RTC_MINS  1
#define RTC_HOURS 2
#define RTC_DATE  3
#define RTC_MONTH 4
#define RTC_DAY   5
#define RTC_YEAR  6
#define RTC_WP    7
#define RTC_TC    8
#define RTC_BM    31

// Constants
#define CENTURY_OFFSET 2000 // Offset to convert year from RTC (0-99) to full year

// Masks for BCD conversion (ensuring valid ranges)
static const unsigned int masks[] = {0x7F, 0x7F, 0x3F, 0x3F, 0x1F, 0x07, 0xFF};

// Function prototypes
static int bcdToDecimal(unsigned int bcd_value, unsigned int mask);
static unsigned int decimalToBcd(unsigned int decimal_value);
static int rtc_ram_test(void);
static int set_linux_clock_from_rtc(void);
static int set_rtc_from_linux_clock(void);
static int read_rtc_time(int clock[]);

/**
 * @brief Converts a BCD (Binary Coded Decimal) value to decimal.
 *
 * @param bcd_value The BCD value to convert.
 * @param mask The mask to apply before conversion.
 * @return The decimal representation of the BCD value.
 */
static int bcdToDecimal(unsigned int bcd_value, unsigned int mask) {
  bcd_value &= mask;
  return (bcd_value & 0x0F) + ((bcd_value >> 4) * 10);
}

/**
 * @brief Converts a decimal value to BCD (Binary Coded Decimal).
 *
 * @param decimal_value The decimal value to convert.
 * @return The BCD representation of the decimal value.
 */
static unsigned int decimalToBcd(unsigned int decimal_value) {
  return ((decimal_value / 10) << 4) + (decimal_value % 10);
}

/**
 * @brief Tests the DS1302's internal RAM.
 *
 * Writes a series of test values to each RAM address and verifies the data.
 * @return 0 on success, -1 on failure.
 */
static int rtc_ram_test(void) {
  int addr, got, i = 0, errors = 0;
  int test_values[] = {0x00, 0xFF, 0xAA, 0x55, 0x01, 0x02, 0x04, 0x08, 0x10, 0x20, 0x40, 0x80, 0x00, 0xF0, 0x0F, -1};

  printf("DS1302 RAM TEST\n");

  while (test_values[i] != -1) {
    int test_val = test_values[i];

    for (addr = 0; addr < 31; ++addr) {
      ds1302ramWrite(addr, test_val);
    }

    for (addr = 0; addr < 31; ++addr) {
      got = ds1302ramRead(addr);
      if (got != test_val) {
        fprintf(stderr, "DS1302 RAM Failure: Address: %2d, Expected: 0x%02X, Got: 0x%02X\n", addr, test_val, got);
        ++errors;
      }
    }
    ++i;
  }

  // Restore RAM to a known state (address = value)
  for (addr = 0; addr < 31; ++addr) {
    ds1302ramWrite(addr, addr);
  }

  for (addr = 0; addr < 31; ++addr) {
    got = ds1302ramRead(addr);
    if (got != addr) {
      fprintf(stderr, "DS1302 RAM Failure: Address: %2d, Expected: 0x%02X, Got: 0x%02X\n", addr, addr, got);
      ++errors;
    }
  }

  if (errors == 0) {
    printf("-- DS1302 RAM TEST: OK\n");
    return 0; // Success
  } else {
    fprintf(stderr, "-- DS1302 RAM TEST FAILURE. %d errors.\n", errors);
    return -1; // Failure
  }
}

/**
 * @brief Sets the Linux system clock from the DS1302 RTC.
 *
 * Reads the time from the RTC, formats it into a string, and uses the `date` command to set the system clock.
 * @return 0 on success, -1 on failure.
 */
static int set_linux_clock_from_rtc(void) {
  char date_time_str[20];
  char command[64];
  int clock[8];

  printf("Setting the Linux Clock from the DS1302... ");
  fflush(stdout);

  if (read_rtc_time(clock) != 0) {
    fprintf(stderr, "Error reading RTC time.\n");
    return -1;
  }

  // Format: MMDDhhmm[[CC]YY][.ss]
  snprintf(date_time_str, sizeof(date_time_str), "%02d%02d%02d%02d20%02d.%02d",
           bcdToDecimal(clock[RTC_MONTH], masks[RTC_MONTH]),
           bcdToDecimal(clock[RTC_DATE], masks[RTC_DATE]),
           bcdToDecimal(clock[RTC_HOURS], masks[RTC_HOURS]),
           bcdToDecimal(clock[RTC_MINS], masks[RTC_MINS]),
           bcdToDecimal(clock[RTC_YEAR], masks[RTC_YEAR]),
           bcdToDecimal(clock[RTC_SECS], masks[RTC_SECS]));

  snprintf(command, sizeof(command), "/bin/date %s", date_time_str);
  int result = system(command);
  if (result == -1) {
    perror("system");
    fprintf(stderr, "Error executing date command.\n");
    return -1;
  }

  printf("OK\n");
  return 0;
}

/**
 * @brief Sets the DS1302 RTC from the Linux system clock.
 *
 * Gets the current system time, converts it to BCD, and writes it to the RTC.
 * @return 0 on success, -1 on failure.
 */
static int set_rtc_from_linux_clock(void) {
  struct tm time_info;
  time_t current_time;
  int rtc_clock_data[8];

  printf("Setting the clock in the DS1302 from Linux time... ");
  fflush(stdout);

  current_time = time(NULL);
  if (current_time == (time_t)-1) {
    perror("time");
    fprintf(stderr, "Error getting current time.\n");
    return -1;
  }

  if (localtime_r(&current_time, &time_info) == NULL) {
    perror("localtime_r");
    fprintf(stderr, "Error converting time.\n");
    return -1;
  }

  rtc_clock_data[RTC_SECS] = decimalToBcd(time_info.tm_sec);
  rtc_clock_data[RTC_MINS] = decimalToBcd(time_info.tm_min);
  rtc_clock_data[RTC_HOURS] = decimalToBcd(time_info.tm_hour);
  rtc_clock_data[RTC_DATE] = decimalToBcd(time_info.tm_mday);
  rtc_clock_data[RTC_MONTH] = decimalToBcd(time_info.tm_mon + 1); // Months are 0-11 in struct tm
  rtc_clock_data[RTC_DAY] = decimalToBcd(time_info.tm_wday);   // Weekdays (Sun is 0)
  rtc_clock_data[RTC_YEAR] = decimalToBcd(time_info.tm_year % 100); // Years since 1900
  rtc_clock_data[RTC_WP] = 0; // Write protect off

  ds1302clockWrite(rtc_clock_data);

  printf("OK\n");
  return 0;
}

/**
 * @brief Reads the current time from the DS1302 RTC.
 *
 * @param clock An array to store the RTC values (seconds, minutes, hours, etc.).
 * @return 0 on success, -1 on failure.
 */
static int read_rtc_time(int clock[]) {
  if (clock == NULL) {
    fprintf(stderr, "Error: clock array is NULL.\n");
    return -1;
  }
  ds1302clockRead(clock);
  return 0;
}

int main(int argc, char *argv[]) {
  int clock_data[8];
  int read_count = 0;

  if (wiringPiSetup() == -1) {
    fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
    return EXIT_FAILURE;
  }

  // Define your CE, IO, and SCLK pins here
  int ce_pin = 0;  // Example pin
  int io_pin = 1;  // Example pin
  int sclk_pin = 2; // Example pin

  ds1302setup(ce_pin, io_pin, sclk_pin);

  if (argc == 2) {
    if (strcmp(argv[1], "-slc") == 0) {
      return set_linux_clock_from_rtc();
    } else if (strcmp(argv[1], "-sdsc") == 0) {
      return set_rtc_from_linux_clock();
    } else if (strcmp(argv[1], "-rtest") == 0) {
      return rtc_ram_test();
    } else {
      fprintf(stderr, "Usage: %s [-slc | -sdsc | -rtest]\n", argv[0]);
      return EXIT_FAILURE;
    }
  }

  // Main loop to continuously read and print the time
  for (;;) {
    if (read_rtc_time(clock_data) != 0) {
      fprintf(stderr, "Error reading RTC time.\n");
      return EXIT_FAILURE;
    }

    printf("%5d: %02d:%02d:%02d  %02d/%02d/%04d\n",
           read_count++,
           bcdToDecimal(clock_data[RTC_HOURS], masks[RTC_HOURS]),
           bcdToDecimal(clock_data[RTC_MINS], masks[RTC_MINS]),
           bcdToDecimal(clock_data[RTC_SECS], masks[RTC_SECS]),
           bcdToDecimal(clock_data[RTC_DATE], masks[RTC_DATE]),
           bcdToDecimal(clock_data[RTC_MONTH], masks[RTC_MONTH]),
           bcdToDecimal(clock_data[RTC_YEAR], masks[RTC_YEAR]) + CENTURY_OFFSET);

    delay(200); // Reduced delay for responsiveness
  }

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <unistd.h>
#include <stdint.h>
#include <errno.h>
#include <string.h>

// MPU6050 register addresses
#define MPU6050_ADDR 0x68
#define MPU6050_REG_PWR_MGMT_1 0x6B
#define MPU6050_REG_TEMP_OUT_H 0x41
#define MPU6050_REG_ACCEL_XOUT_H 0x3B
#define MPU6050_REG_GYRO_XOUT_H 0x43

// Function to read a 2-byte value from the MPU6050
int16_t read_word(int file_descriptor, uint8_t register_address) {
    int16_t value;
    uint8_t buffer[2];

    // Write the register address to be read
    if (write(file_descriptor, &register_address, 1) != 1) {
        fprintf(stderr, "Error writing to I2C device: %s\n", strerror(errno));
        return -1;
    }

    // Read 2 bytes from the specified register
    if (read(file_descriptor, buffer, 2) != 2) {
        fprintf(stderr, "Error reading from I2C device: %s\n", strerror(errno));
        return -1;
    }

    // Combine the two bytes into a single 16-bit value
    value = (buffer[0] << 8) | buffer[1];
    return value;
}

int main() {
    int file_descriptor;
    const char *i2c_device = "/dev/i2c-1"; // I2C device file

    // Open the I2C device
    file_descriptor = open(i2c_device, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Failed to open I2C device: %s\n", strerror(errno));
        return 1;
    }

    // Specify the address of the MPU6050
    if (ioctl(file_descriptor, I2C_SLAVE, MPU6050_ADDR) < 0) {
        fprintf(stderr, "Failed to acquire bus access or talk to slave: %s\n", strerror(errno));
        close(file_descriptor);
        return 1;
    }

    // Wake up the MPU6050 (clear sleep mode bit)
    uint8_t power_management_data = 0; // Set to 0 to wake up the sensor
    if (write(file_descriptor, &power_management_data, 1) != 1) {
        fprintf(stderr, "Failed to write to I2C device: %s\n", strerror(errno));
        close(file_descriptor);
        return 1;
    }

    while (1) {
        // Read accelerometer data
        int16_t accelerometer_x = read_word(file_descriptor, MPU6050_REG_ACCEL_XOUT_H);
        int16_t accelerometer_y = read_word(file_descriptor, MPU6050_REG_ACCEL_XOUT_H + 2);
        int16_t accelerometer_z = read_word(file_descriptor, MPU6050_REG_ACCEL_XOUT_H + 4);

        // Read gyroscope data
        int16_t gyroscope_x = read_word(file_descriptor, MPU6050_REG_GYRO_XOUT_H);
        int16_t gyroscope_y = read_word(file_descriptor, MPU6050_REG_GYRO_XOUT_H + 2);
        int16_t gyroscope_z = read_word(file_descriptor, MPU6050_REG_GYRO_XOUT_H + 4);

        // Read temperature data
        int16_t temperature_raw = read_word(file_descriptor, MPU6050_REG_TEMP_OUT_H);
        float temperature = (temperature_raw / 340.0f) + 36.53f; // Convert to degrees Celsius

        // Print the data
        printf("Temperature: %.2f °C\n", temperature);
        printf("Accelerometer X: %d, Y: %d, Z: %d\n", accelerometer_x, accelerometer_y, accelerometer_z);
        printf("Gyroscope X: %d, Y: %d, Z: %d\n", gyroscope_x, gyroscope_y, gyroscope_z);
        printf("\n");

        sleep(1); // Wait for 1 second
    }

    // Close the I2C device
    close(file_descriptor);
    return 0;
}

