#include <math.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <wiringPi.h>
#include <gertboard.h>

// Constants
#define BUFFER_SIZE 256
#define ANALOG_BASE_PIN 100 // Base pin for Gertboard analog functions
#define DELAY_MS 2          // Delay between samples in milliseconds

// Function prototypes
int initialize();
void generateSineWave(int *buffer, int bufferSize);
void displayWave(int inputValue, int terminalWidth);

int main(void) {
    int sineWaveBuffer[BUFFER_SIZE];
    int terminalWidth;
    int analogInputValue;
    int i;

    printf("Raspberry Pi Gertboard Sine Wave Display\n");
    printf("========================================\n");

    // Initialize
    if (initialize() != 0) {
        fprintf(stderr, "Initialization failed. Exiting.\n");
        return 1;
    }

    // Get terminal width
    struct winsize terminalSize;
    ioctl(fileno(stdin), TIOCGWINSZ, &terminalSize);
    terminalWidth = terminalSize.ws_col - 2;

    // Generate the sine wave
    generateSineWave(sineWaveBuffer, BUFFER_SIZE);

    // Main loop: output sine wave, read analog input, and display
    while (1) {
        for (i = 0; i < BUFFER_SIZE; ++i) {
            // Output to D/A
            analogWrite(ANALOG_BASE_PIN, sineWaveBuffer[i]);

            // Read from A/D
            analogInputValue = analogRead(ANALOG_BASE_PIN);

            // Display on terminal
            displayWave(analogInputValue, terminalWidth);

            // Delay
            delay(DELAY_MS);
        }
    }

    return 0;
}

// Initializes wiringPi and Gertboard analog functions.
int initialize() {
    // wiringPiSetupSys returns 0 on success, -1 on failure
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "wiringPiSetupSys failed.\n");
        return -1;
    }

    // gertboardAnalogSetup doesn't return a value, but it initializes the SPI
    // communication.  We'll assume it works if wiringPiSetupSys works.
    gertboardAnalogSetup(ANALOG_BASE_PIN);

    return 0;
}

// Generates a sine wave and stores it in the provided buffer.
void generateSineWave(int *buffer, int bufferSize) {
    double angle;
    int i;

    for (i = 0; i < bufferSize; ++i) {
        angle = ((double)i / (double)bufferSize) * M_PI * 2.0;
        buffer[i] = (int)rint((sin(angle)) * 127.0 + 128.0);
    }
}

// Displays the analog input value on the terminal as a scrolling oscilloscope.
void displayWave(int inputValue, int terminalWidth) {
    // Scale the analog input value to the terminal width
    int scaledValue = (inputValue * terminalWidth) / 1023;

    // Print the asterisk at the scaled position
    printf("%*s\n", scaledValue, "*");
}

