#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <errno.h>

// Define GPIO pins using WiringPi numbering
#define BUTTON_UP_PIN   37  // Button to control the buzzer
#define BUTTON_DOWN_PIN 33  // Button to control the vibration module
#define BUZZER_PIN      12  // Buzzer output pin
#define VIBRATION_PIN   13  // Vibration module output pin

// Function prototypes
int initialize_gpio(void);
void control_outputs(void);

int main()
{
    // Initialize WiringPi and GPIO pins
    if (initialize_gpio() != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return 1; // Exit with an error code
    }

    printf("\nRaspberry Pi Vibration and Buzzer Control\n");
    printf("Press BUTTON UP to activate the buzzer, BUTTON DOWN to activate the vibration module.\n");
    printf("Press CTRL+C to exit.\n");

    // Main control loop
    while (1) {
        control_outputs();
    }

    return 0;
}

// Function to initialize GPIO pins
int initialize_gpio(void)
{
    // Initialize WiringPi using physical pin numbering
    if (wiringPiSetupPhys() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return -1; // Indicate initialization failure
    }

    // Set pin modes
    pinMode(BUTTON_UP_PIN, INPUT);        // Button UP as input
    pinMode(BUTTON_DOWN_PIN, INPUT);      // Button DOWN as input
    pinMode(BUZZER_PIN, OUTPUT);          // Buzzer as output
    pinMode(VIBRATION_PIN, OUTPUT);       // Vibration module as output

    // Initial state: Turn off buzzer and vibration module
    digitalWrite(BUZZER_PIN, LOW);
    digitalWrite(VIBRATION_PIN, LOW);

    return 0; // Indicate success
}

// Function to control the buzzer and vibration module based on button presses
void control_outputs(void)
{
    // Check if BUTTON UP is pressed (active low)
    if (digitalRead(BUTTON_UP_PIN) == LOW) {
        digitalWrite(BUZZER_PIN, HIGH); // Activate buzzer
    } else {
        digitalWrite(BUZZER_PIN, LOW);  // Deactivate buzzer
    }

    // Check if BUTTON DOWN is pressed (active low)
    if (digitalRead(BUTTON_DOWN_PIN) == LOW) {
        digitalWrite(VIBRATION_PIN, HIGH); // Activate vibration module
    } else {
        digitalWrite(VIBRATION_PIN, LOW);  // Deactivate vibration module
    }
}

#include <fcntl.h>
#include <i2c/smbus.h>
#include <linux/i2c-dev.h>
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <sys/ioctl.h>
#include <unistd.h>
#include <errno.h>
#include <string.h>

// Define constants for the I2C device and registers
#define I2C_DEVICE_PATH "/dev/i2c-1"  // I2C device path
#define HTS221_ADDRESS 0x5F            // HTS221 I2C address

// HTS221 Register Addresses
#define WHO_AM_I_REG 0x0F
#define CTRL_REG1 0x20
#define CTRL_REG2 0x21

#define T0_OUT_L 0x3C
#define T0_OUT_H 0x3D
#define T1_OUT_L 0x3E
#define T1_OUT_H 0x3F
#define T0_degC_x8 0x32
#define T1_degC_x8 0x33
#define T1_T0_MSB 0x35

#define TEMP_OUT_L 0x2A
#define TEMP_OUT_H 0x2B

#define H0_T0_OUT_L 0x36
#define H0_T0_OUT_H 0x37
#define H1_T0_OUT_L 0x3A
#define H1_T0_OUT_H 0x3B
#define H0_rH_x2 0x30
#define H1_rH_x2 0x31

#define H_T_OUT_L 0x28
#define H_T_OUT_H 0x29

// Function prototypes
int init_i2c(const char *device_path, int device_address);
int read_hts221_byte(int file_descriptor, uint8_t register_address);
int write_hts221_byte(int file_descriptor, uint8_t register_address, uint8_t data);
void trigger_measurement(int file_descriptor);
double calculate_temperature(int file_descriptor);
double calculate_humidity(int file_descriptor);

// Error handling macro
#define CHECK_ERROR(condition, message) \
    if (condition) {                     \
        fprintf(stderr, "Error: %s\n", message); \
        return EXIT_FAILURE;             \
    }

int main() {
    int i2c_file_descriptor;
    double temperature_celsius, humidity_percent;

    // Initialize I2C communication
    i2c_file_descriptor = init_i2c(I2C_DEVICE_PATH, HTS221_ADDRESS);
    if (i2c_file_descriptor == -1) {
        fprintf(stderr, "Failed to initialize I2C communication.\n");
        return EXIT_FAILURE;
    }

    // Verify the sensor
    if (read_hts221_byte(i2c_file_descriptor, WHO_AM_I_REG) != 0xBC) {
        fprintf(stderr, "HTS221 sensor not detected.\n");
        close(i2c_file_descriptor);
        return EXIT_FAILURE;
    }

    // Trigger a measurement
    trigger_measurement(i2c_file_descriptor);

    // Read temperature and humidity
    temperature_celsius = calculate_temperature(i2c_file_descriptor);
    humidity_percent = calculate_humidity(i2c_file_descriptor);

    // Print the results
    printf("Temperature: %.2f °C\n", temperature_celsius);
    printf("Humidity: %.2f %%\n", humidity_percent);

    // Close the I2C device
    close(i2c_file_descriptor);

    return EXIT_SUCCESS;
}

/**
 * @brief Initializes I2C communication with the specified device.
 *
 * @param device_path The path to the I2C device (e.g., "/dev/i2c-1").
 * @param device_address The I2C address of the device.
 * @return The file descriptor of the I2C device, or -1 on error.
 */
int init_i2c(const char *device_path, int device_address) {
    int file_descriptor = open(device_path, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Failed to open I2C device %s: %s\n", device_path, strerror(errno));
        return -1;
    }

    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Failed to set I2C slave address 0x%X: %s\n", device_address, strerror(errno));
        close(file_descriptor);
        return -1;
    }

    return file_descriptor;
}

/**
 * @brief Reads a byte from the specified register of the HTS221 sensor.
 *
 * @param file_descriptor The file descriptor of the I2C device.
 * @param register_address The address of the register to read from.
 * @return The byte read from the register, or -1 on error.
 */
int read_hts221_byte(int file_descriptor, uint8_t register_address) {
    int result = i2c_smbus_read_byte_data(file_descriptor, register_address);
    if (result < 0) {
        fprintf(stderr, "Failed to read byte from register 0x%X: %s\n", register_address, strerror(errno));
        return -1;
    }
    return result;
}

/**
 * @brief Writes a byte to the specified register of the HTS221 sensor.
 *
 * @param file_descriptor The file descriptor of the I2C device.
 * @param register_address The address of the register to write to.
 * @param data The byte to write to the register.
 * @return 0 on success, or -1 on error.
 */
int write_hts221_byte(int file_descriptor, uint8_t register_address, uint8_t data) {
    int result = i2c_smbus_write_byte_data(file_descriptor, register_address, data);
    if (result < 0) {
        fprintf(stderr, "Failed to write byte 0x%X to register 0x%X: %s\n", data, register_address, strerror(errno));
        return -1;
    }
    return 0;
}

/**
 * @brief Triggers a single measurement of temperature and humidity.
 *
 * @param file_descriptor The file descriptor of the I2C device.
 */
void trigger_measurement(int file_descriptor) {
    // Power down the device (clean start)
    if (write_hts221_byte(file_descriptor, CTRL_REG1, 0x00) == -1) {
        fprintf(stderr, "Failed to power down device.\n");
        exit(EXIT_FAILURE);
    }

    // Turn on the humidity sensor analog front end in single shot mode
    if (write_hts221_byte(file_descriptor, CTRL_REG1, 0x84) == -1) {
        fprintf(stderr, "Failed to configure CTRL_REG1.\n");
        exit(EXIT_FAILURE);
    }

    // Run one-shot measurement (temperature and humidity)
    if (write_hts221_byte(file_descriptor, CTRL_REG2, 0x01) == -1) {
        fprintf(stderr, "Failed to trigger one-shot measurement.\n");
        exit(EXIT_FAILURE);
    }

    // Wait until the measurement is completed (max 25ms)
    uint8_t status;
    do {
        usleep(25000); // 25 milliseconds
        status = read_hts221_byte(file_descriptor, CTRL_REG2);
        if (status == -1) {
            fprintf(stderr, "Failed to read CTRL_REG2 status.\n");
            exit(EXIT_FAILURE);
        }
    } while (status != 0);
}

/**
 * @brief Calculates the temperature in degrees Celsius from the sensor data.
 *
 * @param file_descriptor The file descriptor of the I2C device.
 * @return The temperature in degrees Celsius.
 */
double calculate_temperature(int file_descriptor) {
    // Read calibration data
    int16_t T0_OUT = (read_hts221_byte(file_descriptor, T0_OUT_H) << 8) | read_hts221_byte(file_descriptor, T0_OUT_L);
    int16_t T1_OUT = (read_hts221_byte(file_descriptor, T1_OUT_H) << 8) | read_hts221_byte(file_descriptor, T1_OUT_L);
    uint16_t T0_DegC_x8 = ((read_hts221_byte(file_descriptor, T1_T0_MSB) & 3) << 8) | read_hts221_byte(file_descriptor, T0_degC_x8);
    uint16_t T1_DegC_x8 = (((read_hts221_byte(file_descriptor, T1_T0_MSB) & 12) >> 2) << 8) | read_hts221_byte(file_descriptor, T1_degC_x8);

    // Calculate calibration values
    double T0_DegC = T0_DegC_x8 / 8.0;
    double T1_DegC = T1_DegC_x8 / 8.0;

    // Solve the linear equation 'y = mx + c' to give the calibration straight line graph for temperature
    double t_gradient_m = (T1_DegC - T0_DegC) / (T1_OUT - T0_OUT);
    double t_intercept_c = T1_DegC - (t_gradient_m * T1_OUT);

    // Read the ambient temperature measurement
    int16_t T_OUT = (read_hts221_byte(file_descriptor, TEMP_OUT_H) << 8) | read_hts221_byte(file_descriptor, TEMP_OUT_L);

    // Calculate ambient temperature
    return (t_gradient_m * T_OUT) + t_intercept_c;
}

/**
 * @brief Calculates the relative humidity in percent from the sensor data.
 *
 * @param file_descriptor The file descriptor of the I2C device.
 * @return The relative humidity in percent.
 */
double calculate_humidity(int file_descriptor) {
    // Read calibration data
    int16_t H0_T0_OUT = (read_hts221_byte(file_descriptor, H0_T0_OUT_H) << 8) | read_hts221_byte(file_descriptor, H0_T0_OUT_L);
    int16_t H1_T0_OUT = (read_hts221_byte(file_descriptor, H1_T0_OUT_H) << 8) | read_hts221_byte(file_descriptor, H1_T0_OUT_L);
    double H0_rH = read_hts221_byte(file_descriptor, H0_rH_x2) / 2.0;
    double H1_rH = read_hts221_byte(file_descriptor, H1_rH_x2) / 2.0;

    // Solve the linear equation 'y = mx + c' to give the calibration straight line graph for humidity
    double h_gradient_m = (H1_rH - H0_rH) / (H1_T0_OUT - H0_T0_OUT);
    double h_intercept_c = H1_rH - (h_gradient_m * H1_T0_OUT);

    // Read the ambient humidity measurement
    int16_t H_T_OUT = (read_hts221_byte(file_descriptor, H_T_OUT_H) << 8) | read_hts221_byte(file_descriptor, H_T_OUT_L);

    // Calculate ambient humidity
    double humidity = (h_gradient_m * H_T_OUT) + h_intercept_c;

    // Clamp the humidity value to be within the valid range of 0-100%
    if (humidity < 0.0) {
        humidity = 0.0;
    } else if (humidity > 100.0) {
        humidity = 100.0;
    }

    return humidity;
}

#include <fcntl.h>
#include <linux/fb.h>
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/ioctl.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <sys/types.h>
#include <unistd.h>
#include <errno.h>

// Constants
#define FB_DEVICE_PATH "/dev/fb1"
#define LED_MATRIX_WIDTH 8
#define LED_MATRIX_HEIGHT 8
#define NUM_PIXELS (LED_MATRIX_WIDTH * LED_MATRIX_HEIGHT)
#define FILE_SIZE (NUM_PIXELS * sizeof(uint16_t))

// Color definitions (RGB565 format)
#define COLOR_BLACK 0x0000
#define COLOR_RED 0xF800
#define COLOR_WHITE 0xFFFF

// Function prototypes
void delay_ms(int milliseconds);
int open_framebuffer(void);
void *map_framebuffer(int fd);
int unmap_framebuffer(void *map);
int close_framebuffer(int fd);
int clear_led_matrix(uint16_t *framebuffer);
int set_pixel_color(uint16_t *framebuffer, int x, int y, uint16_t color);
int check_sense_hat(int fd);

int main(void) {
    int framebuffer_fd = -1;       // File descriptor for the framebuffer
    uint16_t *framebuffer_ptr = NULL; // Pointer to the mapped framebuffer memory
    int i;

    // 1. Open the framebuffer device
    framebuffer_fd = open_framebuffer();
    if (framebuffer_fd == -1) {
        fprintf(stderr, "Error: Failed to open framebuffer: %s\n", strerror(errno));
        return EXIT_FAILURE;
    }

    // Check if the correct device is found
    if (check_sense_hat(framebuffer_fd) != 0) {
        fprintf(stderr, "Error: Sense HAT not found.\n");
        close_framebuffer(framebuffer_fd);
        return EXIT_FAILURE;
    }

    // 2. Map the framebuffer device into memory
    framebuffer_ptr = map_framebuffer(framebuffer_fd);
    if (framebuffer_ptr == MAP_FAILED) {
        fprintf(stderr, "Error: Failed to map framebuffer: %s\n", strerror(errno));
        close_framebuffer(framebuffer_fd);
        return EXIT_FAILURE;
    }

    // 3. Clear the LED matrix (set all pixels to black)
    if (clear_led_matrix(framebuffer_ptr) != 0) {
        fprintf(stderr, "Error: Failed to clear LED matrix.\n");
        unmap_framebuffer(framebuffer_ptr);
        close_framebuffer(framebuffer_fd);
        return EXIT_FAILURE;
    }

    // 4. Light up all LEDs in red
    for (i = 0; i < NUM_PIXELS; i++) {
        framebuffer_ptr[i] = COLOR_RED;
        delay_ms(25);
    }

    // 5. Flash the LED matrix white three times
    for (i = 0; i < 3; i++) {
        delay_ms(250);
        memset(framebuffer_ptr, 0xFF, FILE_SIZE); // White
        delay_ms(250);
        memset(framebuffer_ptr, 0x00, FILE_SIZE); // Black
    }
    delay_ms(250);

    // 6. Clear the LED matrix again
    if (clear_led_matrix(framebuffer_ptr) != 0) {
        fprintf(stderr, "Error: Failed to clear LED matrix.\n");
        unmap_framebuffer(framebuffer_ptr);
        close_framebuffer(framebuffer_fd);
        return EXIT_FAILURE;
    }

    // 7. Un-map the framebuffer from memory
    if (unmap_framebuffer(framebuffer_ptr) != 0) {
        fprintf(stderr, "Error: Failed to unmap framebuffer: %s\n", strerror(errno));
    }

    // 8. Close the framebuffer device
    if (close_framebuffer(framebuffer_fd) != 0) {
        fprintf(stderr, "Error: Failed to close framebuffer: %s\n", strerror(errno));
    }

    return EXIT_SUCCESS;
}

// Function to introduce a delay in milliseconds
void delay_ms(int milliseconds) {
    usleep(milliseconds * 1000);
}

// Function to open the framebuffer device
int open_framebuffer(void) {
    int fd = open(FB_DEVICE_PATH, O_RDWR);
    if (fd == -1) {
        perror("Error opening framebuffer device");
    }
    return fd;
}

// Function to map the framebuffer into memory
void *map_framebuffer(int fd) {
    void *map = mmap(NULL, FILE_SIZE, PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);
    if (map == MAP_FAILED) {
        perror("Error mapping framebuffer to memory");
    }
    return map;
}

// Function to unmap the framebuffer from memory
int unmap_framebuffer(void *map) {
    if (munmap(map, FILE_SIZE) == -1) {
        perror("Error unmapping framebuffer from memory");
        return -1;
    }
    return 0;
}

// Function to close the framebuffer device
int close_framebuffer(int fd) {
    if (close(fd) == -1) {
        perror("Error closing framebuffer device");
        return -1;
    }
    return 0;
}

// Function to clear the LED matrix (set all pixels to black)
int clear_led_matrix(uint16_t *framebuffer) {
    memset(framebuffer, 0, FILE_SIZE);
    return 0;
}

// Function to set the color of a specific pixel in the LED matrix
int set_pixel_color(uint16_t *framebuffer, int x, int y, uint16_t color) {
    if (x < 0 || x >= LED_MATRIX_WIDTH || y < 0 || y >= LED_MATRIX_HEIGHT) {
        fprintf(stderr, "Error: Pixel coordinates (%d, %d) are out of bounds.\n", x, y);
        return -1;
    }
    framebuffer[y * LED_MATRIX_WIDTH + x] = color;
    return 0;
}

int check_sense_hat(int fd) {
    struct fb_fix_screeninfo fix_info;

    if (ioctl(fd, FBIOGET_FSCREENINFO, &fix_info) == -1) {
        perror("Error (call to 'ioctl')");
        return -1;
    }

    /* now check the correct device has been found */
    if (strcmp(fix_info.id, "RPi-Sense FB") != 0) {
        printf("%s\n", "Error: RPi-Sense FB not found");
        return -1;
    }
    return 0;
}

#include <fcntl.h>
#include <i2c/smbus.h>
#include <linux/i2c-dev.h>
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <sys/ioctl.h>
#include <unistd.h>
#include <errno.h>
#include <string.h>

// Constants for the LPS25H sensor
#define LPS25H_DEVICE_ADDRESS 0x5c
#define I2C_DEVICE_PATH "/dev/i2c-1"
#define LPS25H_WHO_AM_I_REG 0x0F
#define LPS25H_CTRL_REG1 0x20
#define LPS25H_CTRL_REG2 0x21
#define LPS25H_PRESS_OUT_XL 0x28
#define LPS25H_PRESS_OUT_L 0x29
#define LPS25H_PRESS_OUT_H 0x2A
#define LPS25H_TEMP_OUT_L 0x2B
#define LPS25H_TEMP_OUT_H 0x2C

// Expected value for WHO_AM_I register
#define LPS25H_WHO_AM_I_VALUE 0xBD

// Function prototypes
int i2c_setup(int device_address, const char *device_path);
int read_sensor_data(int file_descriptor, int32_t *pressure, double *temperature);
void lps25h_power_down(int fd);

// Helper function for delays
void delay_ms(int milliseconds);

int main(void) {
    int i2c_file_descriptor = 0;
    int32_t pressure_reading = 0;
    double temperature_reading = 0.0;

    // Initialize I2C communication
    i2c_file_descriptor = i2c_setup(LPS25H_DEVICE_ADDRESS, I2C_DEVICE_PATH);
    if (i2c_file_descriptor == -1) {
        fprintf(stderr, "Failed to initialize I2C communication.\n");
        return EXIT_FAILURE;
    }

    // Read temperature and pressure
    if (read_sensor_data(i2c_file_descriptor, &pressure_reading, &temperature_reading) != 0) {
        fprintf(stderr, "Failed to read sensor data.\n");
        close(i2c_file_descriptor);
        return EXIT_FAILURE;
    }

    // Print the results
    printf("Temperature: %.2f °C\n", temperature_reading);
    printf("Pressure: %.0f hPa\n", (double)pressure_reading / 4096.0);

    // Power down the sensor
    lps25h_power_down(i2c_file_descriptor);

    // Close the I2C device
    close(i2c_file_descriptor);

    return EXIT_SUCCESS;
}


// Function to set up I2C communication
int i2c_setup(int device_address, const char *device_path) {
    int file_descriptor;

    // Open I2C device
    file_descriptor = open(device_path, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error opening I2C device %s: %s\n", device_path, strerror(errno));
        return -1;
    }

    // Configure I2C slave address
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error configuring I2C slave address 0x%02x: %s\n", device_address, strerror(errno));
        close(file_descriptor);
        return -1;
    }

    // Verify sensor identity
    if (i2c_smbus_read_byte_data(file_descriptor, LPS25H_WHO_AM_I_REG) != LPS25H_WHO_AM_I_VALUE) {
        fprintf(stderr, "Error: WHO_AM_I register returned incorrect value. Is the sensor connected?\n");
        close(file_descriptor);
        return -1;
    }

    return file_descriptor;
}

// Function to read temperature and pressure data from the sensor
int read_sensor_data(int file_descriptor, int32_t *pressure, double *temperature) {
    uint8_t temp_out_l, temp_out_h, press_out_xl, press_out_l, press_out_h;
    int16_t temp_out;

    // Power down the device before starting
    i2c_smbus_write_byte_data(file_descriptor, LPS25H_CTRL_REG1, 0x00);

    // Turn on the pressure sensor analog front end in single shot mode
    if (i2c_smbus_write_byte_data(file_descriptor, LPS25H_CTRL_REG1, 0x84) < 0) {
        fprintf(stderr, "Error writing to CTRL_REG1: %s\n", strerror(errno));
        return -1;
    }

    // Run one-shot measurement (temperature and pressure)
    if (i2c_smbus_write_byte_data(file_descriptor, LPS25H_CTRL_REG2, 0x01) < 0) {
        fprintf(stderr, "Error writing to CTRL_REG2: %s\n", strerror(errno));
        return -1;
    }

    // Wait until the measurement is complete
    uint8_t status;
    do {
        delay_ms(25); // 25 milliseconds
        status = i2c_smbus_read_byte_data(file_descriptor, LPS25H_CTRL_REG2);
        if (status == -1) {
            fprintf(stderr, "Error reading CTRL_REG2: %s\n", strerror(errno));
            return -1;
        }
    } while (status != 0);

    // Read temperature data
    temp_out_l = i2c_smbus_read_byte_data(file_descriptor, LPS25H_TEMP_OUT_L);
    temp_out_h = i2c_smbus_read_byte_data(file_descriptor, LPS25H_TEMP_OUT_H);

    // Read pressure data
    press_out_xl = i2c_smbus_read_byte_data(file_descriptor, LPS25H_PRESS_OUT_XL);
    press_out_l = i2c_smbus_read_byte_data(file_descriptor, LPS25H_PRESS_OUT_L);
    press_out_h = i2c_smbus_read_byte_data(file_descriptor, LPS25H_PRESS_OUT_H);

    // Combine temperature data
    temp_out = (int16_t)(temp_out_h << 8 | temp_out_l);

    // Combine pressure data
    *pressure = (int32_t)(press_out_h << 16 | press_out_l << 8 | press_out_xl);

    // Calculate temperature
    *temperature = 42.5 + (temp_out / 480.0);

    return 0;
}

void lps25h_power_down(int fd) {
    i2c_smbus_write_byte_data(fd, CTRL_REG1, 0x00);
}

// Function to provide a delay in milliseconds
void delay_ms(int milliseconds) {
    usleep(milliseconds * 1000);
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <unistd.h>
#include <errno.h>
#include <wiringPi.h>
#include <mcp23017.h>

// Constants
#define Q2W_BASE_PIN 100         // Base pin number for the MCP23017
#define MCP23017_I2C_ADDR 0x20   // I2C address of the MCP23017
#define NUM_OUTPUT_PINS 10       // Number of output pins used for the binary counter
#define INPUT_PIN_ONBOARD 0      // Onboard GPIO pin for input (e.g., button)
#define INPUT_PIN_MCP23017 (Q2W_BASE_PIN + 15) // MCP23017 pin for input

// Function prototypes
bool setup_gpio();
void binary_counter();

int main(void) {
    if (!setup_gpio()) {
        fprintf(stderr, "GPIO setup failed. Exiting.\n");
        return EXIT_FAILURE;
    }

    printf("Raspberry Pi - quite2Wire MCP23017 Binary Counter\n");

    binary_counter();

    return EXIT_SUCCESS;
}

bool setup_gpio() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return false;
    }

    // Setup MCP23017
    int result = mcp23017Setup(Q2W_BASE_PIN, MCP23017_I2C_ADDR);
    if (result == -1) {
        fprintf(stderr, "mcp23017Setup failed: %s\n", strerror(errno));
        return false;
    }

    // On-board button Input:
    pinMode(INPUT_PIN_ONBOARD, INPUT);

    // First NUM_OUTPUT_PINS pins on q2w board as outputs:
    for (int i = 0; i < NUM_OUTPUT_PINS; ++i) {
        pinMode(Q2W_BASE_PIN + i, OUTPUT);
    }

    // Last pin as an input with the internal pull-up enabled
    pinMode(INPUT_PIN_MCP23017, INPUT);
    pullUpDnControl(INPUT_PIN_MCP23017, PUD_UP);

    return true;
}

void binary_counter() {
    // Loop, outputting a binary number
    while (true) {
        for (int i = 0; i < 1024; ++i) {
            // Output the binary representation of 'i' to the MCP23017 pins
            for (int bit = 0; bit < NUM_OUTPUT_PINS; ++bit) {
                digitalWrite(Q2W_BASE_PIN + bit, (i >> bit) & 1);
            }

            // Delay based on input pins
            while (digitalRead(INPUT_PIN_ONBOARD) == HIGH) { // While pushed
                delay(1); // Short delay while onboard button is pressed
            }

            if (digitalRead(INPUT_PIN_MCP23017) == HIGH) { // Not Pushed
                delay(100); // Longer delay if MCP23017 button is not pressed
            }
        }
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <signal.h>
#include <unistd.h>
#include <wiringPi.h>

// Constants for GPIO pins
#define OUTPUT_PIN 0  // WiringPi pin 0 (GPIO17)
#define INPUT_PIN 1   // WiringPi pin 1 (GPIO18)

// Global variables
static volatile unsigned int interrupt_count = 0; // Counter for interrupts
static volatile sig_atomic_t program_running = 1; // Flag to control the main loop

// Function prototypes
void interrupt_handler(void);
void signal_handler(int signal);

// Interrupt handler function
void interrupt_handler(void) {
    // This function is called when a falling edge is detected on the input pin.
    digitalWrite(OUTPUT_PIN, HIGH); // Set output pin HIGH
    interrupt_count++;                 // Increment interrupt counter
    digitalWrite(OUTPUT_PIN, LOW);  // Set output pin LOW
}

// Signal handler function (for graceful shutdown)
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("\nCaught SIGINT, exiting gracefully.\n");
        program_running = 0; // Set the flag to exit the main loop
    }
}

int main(void) {
    unsigned int current_count = 0;
    unsigned int last_count = 0;
    unsigned int count_delta = 0;

    // Initialize WiringPi
    if (wiringPiSetup() < 0) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return 1;
    }

    // Set GPIO pin modes
    pinMode(OUTPUT_PIN, OUTPUT);
    pinMode(INPUT_PIN, INPUT);
    pullUpDnControl(INPUT_PIN, PUD_UP); // Enable pull-up resistor on the input pin

    // Register the interrupt handler
    if (wiringPiISR(INPUT_PIN, INT_EDGE_FALLING, &interrupt_handler) < 0) {
        fprintf(stderr, "Interrupt setup failed: %s\n", strerror(errno));
        return 1;
    }

    // Set up signal handling for Ctrl+C (SIGINT)
    signal(SIGINT, signal_handler);

    printf("Interrupt-driven GPIO toggling started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        printf("Waiting for interrupts...\n");
        delay(1000); // Wait for 1 second

        current_count = interrupt_count;
        count_delta = current_count - last_count;

        printf("Interrupt count: %u, Interrupts/second: %u\n", current_count, count_delta);

        last_count = current_count;
    }

    printf("Program terminated.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <signal.h>
#include <stdbool.h>
#include <errno.h>
#include <string.h>
#include <wiringPi.h>

// Constants
#define NUM_PINS 8

// Global variables
static volatile uint32_t interrupt_counts[NUM_PINS];
static volatile bool program_running = true;

// Function prototypes
void interrupt_handler(void);
void signal_handler(int signal);

// Interrupt handlers for each pin
void interrupt_handler_0(void) { ++interrupt_counts[0]; }
void interrupt_handler_1(void) { ++interrupt_counts[1]; }
void interrupt_handler_2(void) { ++interrupt_counts[2]; }
void interrupt_handler_3(void) { ++interrupt_counts[3]; }
void interrupt_handler_4(void) { ++interrupt_counts[4]; }
void interrupt_handler_5(void) { ++interrupt_counts[5]; }
void interrupt_handler_6(void) { ++interrupt_counts[6]; }
void interrupt_handler_7(void) { ++interrupt_counts[7]; }

// Array of interrupt handler function pointers
void (*interrupt_handlers[NUM_PINS])(void) = {
    interrupt_handler_0, interrupt_handler_1, interrupt_handler_2, interrupt_handler_3,
    interrupt_handler_4, interrupt_handler_5, interrupt_handler_6, interrupt_handler_7
};

int main(int argc, char *argv[]) {
    int pin;

    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing WiringPi: %s\n", strerror(errno));
        return EXIT_FAILURE;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Set interrupt edge and attach interrupt service routines
    for (pin = 0; pin < NUM_PINS; ++pin) {
        if (wiringPiISR(pin, INT_EDGE_FALLING, interrupt_handlers[pin]) < 0) {
            fprintf(stderr, "Error setting up ISR for pin %d: %s\n", pin, strerror(errno));
            return EXIT_FAILURE;
        }
        interrupt_counts[pin] = 0; // Initialize interrupt counts
    }

    printf("Interrupt monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Print interrupt counts
        for (pin = 0; pin < NUM_PINS; ++pin) {
            printf("Pin %d: Interrupt Count = %u\n", pin, interrupt_counts[pin]);
        }
        delay(1000); // Delay for 1 second
    }

    printf("\nExiting program.\n");
    return EXIT_SUCCESS;
}

// Signal handler to catch Ctrl+C and exit gracefully
void signal_handler(int signal) {
    printf("\nCaught signal %d, exiting...\n", signal);
    program_running = false;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <sys/time.h>
#include <wiringPi.h>

// Constants for GPIO pins
#define DEFAULT_IRQ_PIN 22
#define DEFAULT_OUTPUT_PIN 25

// Global variables (volatile for interrupt handling)
static volatile int interruptCounter = 0;
static volatile long long startTimeUs = 0;
static volatile long long endTimeUs = 0;

// Function prototypes
void interruptHandler();
double startSequence(int edgeType, int outputPin);
double measureInterruptDuration(int edgeType, int outputPin, int irqPin);
int parseArguments(int argc, char *argv[], int *irqPin, int *outputPin);

// Interrupt handler function
void interruptHandler() {
    struct timeval currentTime;

    gettimeofday(&currentTime, NULL);
    long long timestampUs = currentTime.tv_sec * 1000000LL + currentTime.tv_usec;

    if (startTimeUs == 0) {
        startTimeUs = timestampUs;
    } else {
        endTimeUs = timestampUs;
    }
    interruptCounter++;
}

// Function to generate a pulse sequence and check interrupt response
double startSequence(int edgeType, int outputPin) {
    int expectedInterrupts;
    double expectedTimeMs;

    startTimeUs = 0;
    endTimeUs = 0;
    interruptCounter = 0;

    printf("Starting pulse sequence...
");
    digitalWrite(outputPin, HIGH);
    delay(200);
    digitalWrite(outputPin, LOW);
    delay(100);
    digitalWrite(outputPin, HIGH);
    delay(200);
    digitalWrite(outputPin, LOW);
    delay(100);
    printf("Pulse sequence complete.
");

    if (edgeType == INT_EDGE_BOTH) {
        expectedInterrupts = 4;
        expectedTimeMs = 500;
    } else {
        expectedInterrupts = 2;
        expectedTimeMs = 300;
    }

    if (interruptCounter == expectedInterrupts) {
        double elapsedTimeSec = (double)(endTimeUs - startTimeUs) / 1000000.0;
        printf("Interrupt sequence successful: %lf sec (expected ~%lf sec)

", elapsedTimeSec, expectedTimeMs / 1000.0);
        return elapsedTimeSec;
    } else {
        printf("Interrupt sequence failed: %d interrupts received (expected %d)

", interruptCounter, expectedInterrupts);
        return 0.0;
    }
}

// Function to measure the duration of an interrupt
double measureInterruptDuration(int edgeType, int outputPin, int irqPin) {
    struct timeval currentTime;
    double elapsedTimeUs = 0.0;

    startTimeUs = 0;
    endTimeUs = 0;
    interruptCounter = 0;

    printf("Measuring interrupt duration...
");

    if (edgeType == INT_EDGE_RISING) {
        digitalWrite(outputPin, LOW);
        if (wiringPiISR(irqPin, INT_EDGE_RISING, &interruptHandler) < 0) {
            fprintf(stderr, "Unable to setup ISR: %s
", strerror(errno));
            return -1.0; // Indicate error
        }
        sleep(1);
        gettimeofday(&currentTime, NULL);
        startTimeUs = currentTime.tv_sec * 1000000LL + currentTime.tv_usec;
        digitalWrite(outputPin, HIGH);
        delay(20);
        digitalWrite(outputPin, LOW);
    } else if (edgeType == INT_EDGE_FALLING) {
        digitalWrite(outputPin, HIGH);
        if (wiringPiISR(irqPin, INT_EDGE_FALLING, &interruptHandler) < 0) {
            fprintf(stderr, "Unable to setup ISR: %s
", strerror(errno));
            return -1.0; // Indicate error
        }
        sleep(1);
        gettimeofday(&currentTime, NULL);
        startTimeUs = currentTime.tv_sec * 1000000LL + currentTime.tv_usec;
        digitalWrite(outputPin, LOW);
    } else {
        fprintf(stderr, "Invalid edge type specified.
");
        return -1.0; //Indicate error
    }

    sleep(1);
    elapsedTimeUs = (double)(endTimeUs - startTimeUs);
    printf("Interrupt detection time: %lf usec

", elapsedTimeUs);
    wiringPiISRStop(irqPin);

    return elapsedTimeUs;
}

// Function to parse command-line arguments
int parseArguments(int argc, char *argv[], int *irqPin, int *outputPin) {
    if (argc > 1) {
        *irqPin = atoi(argv[1]);
    }
    if (argc > 2) {
        *outputPin = atoi(argv[2]);
    }
    return 0;
}

int main(int argc, char *argv[]) {
    int irqPin = DEFAULT_IRQ_PIN;
    int outputPin = DEFAULT_OUTPUT_PIN;
    int wiringPiMajor, wiringPiMinor;

    // Parse command-line arguments
    if (parseArguments(argc, argv, &irqPin, &outputPin) != 0) {
        fprintf(stderr, "Error parsing arguments.
");
        return 1;
    }

    // Initialize WiringPi
    if (wiringPiSetupGpio() < 0) {
        fprintf(stderr, "WiringPi initialization failed: %s
", strerror(errno));
        return 1;
    }

    wiringPiVersion(&wiringPiMajor, &wiringPiMinor);
    printf("\nInterrupt Test (WiringPi %d.%d)\n", wiringPiMajor, wiringPiMinor);

    // Configure GPIO pins
    pinMode(irqPin, INPUT);
    pinMode(outputPin, OUTPUT);
    digitalWrite(outputPin, LOW);

    // Test interrupt handling for rising edge
    printf("Testing IRQ @ GPIO%d with trigger @ GPIO%d rising edge\n", irqPin, outputPin);
    if (wiringPiISR(irqPin, INT_EDGE_RISING, &interruptHandler) < 0) {
        fprintf(stderr, "Unable to setup ISR: %s
", strerror(errno));
        return 1;
    }
    sleep(1);
    startSequence(INT_EDGE_RISING, outputPin);
    wiringPiISRStop(irqPin);

    // Test interrupt handling for falling edge
    printf("Testing IRQ @ GPIO%d with trigger @ GPIO%d falling edge\n", irqPin, outputPin);
    if (wiringPiISR(irqPin, INT_EDGE_FALLING, &interruptHandler) < 0) {
        fprintf(stderr, "Unable to setup ISR: %s
", strerror(errno));
        return 1;
    }
    sleep(1);
    startSequence(INT_EDGE_FALLING, outputPin);
    wiringPiISRStop(irqPin);

    // Test interrupt handling for both edges
    printf("Testing IRQ @ GPIO%d with trigger @ GPIO%d both edges\n", irqPin, outputPin);
    if (wiringPiISR(irqPin, INT_EDGE_BOTH, &interruptHandler) < 0) {
        fprintf(stderr, "Unable to setup ISR: %s
", strerror(errno));
        return 1;
    }
    sleep(1);
    startSequence(INT_EDGE_BOTH, outputPin);
    wiringPiISRStop(irqPin);

    // Measure interrupt duration for rising and falling edges
    for (int i = 0; i < 2; i++) {
        printf("Measuring duration IRQ @ GPIO%d with trigger @ GPIO%d rising edge\n", irqPin, outputPin);
        measureInterruptDuration(INT_EDGE_RISING, outputPin, irqPin);

        printf("Measuring duration IRQ @ GPIO%d with trigger @ GPIO%d falling edge\n", irqPin, outputPin);
        measureInterruptDuration(INT_EDGE_FALLING, outputPin, irqPin);
    }

    // Reset output pin to input mode
    pinMode(outputPin, INPUT);

    printf("\nInterrupt tests completed.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <math.h>
#include <wiringPi.h>
#include <piFace.h>
#include <errno.h>

#ifndef TRUE
#define TRUE (1 == 1)
#define FALSE (1 == 2)
#endif

#define NUM_LEDS 8
#define PIFACE_BASE 200

// LED mapping to PiFace pins
const int ledMap[NUM_LEDS] = {
    PIFACE_BASE + 0, PIFACE_BASE + 1, PIFACE_BASE + 2, PIFACE_BASE + 3,
    PIFACE_BASE + 4, PIFACE_BASE + 5, PIFACE_BASE + 6, PIFACE_BASE + 7
};

// Circuit simulation constants
const double BATTERY_VOLTAGE = 9.0;   // Volts
const double CAPACITANCE = 0.001;     // Farads (1000uF)
const double CHARGE_RESISTANCE = 2200.0;  // Ohms
const double DISCHARGE_RESISTANCE = 68000.0; // Ohms
const double TIME_INCREMENT = 0.01;    // Seconds

// Global variables for capacitor voltage simulation
double chargeVoltage; // Charging voltage
double capacitorVoltage; // Current capacitor voltage
double previousCapacitorVoltage; // Previous capacitor voltage

// Function prototypes
int initialize();
void displayIntro();
void displayWinningSequence();
void chargeCapacitor();
void dischargeCapacitor();
void updateLedDisplay(double voltage, int topLedLit);
void handleButtonPress();
void handleButtonRelease();

int main()
{
    unsigned int ledOnTime = 1000;  // milliseconds
    unsigned int ledOffTime = 1000; // milliseconds
    unsigned int timeIncrementMs = (unsigned int)(1000.0 * TIME_INCREMENT);
    unsigned int startTime;

    // Initialize hardware and variables
    if (initialize() != 0) {
        fprintf(stderr, "Initialization failed. Exiting.\n");
        return 1;
    }

    displayIntro();

    // Main game loop
    while (TRUE) {
        // LED ON phase (charging)
        updateLedDisplay(capacitorVoltage, TRUE);
        startTime = millis();
        while (millis() - startTime < ledOnTime) {
            handleButtonPress();
            delay(timeIncrementMs);
        }

        // Check for win condition
        if (capacitorVoltage > ((double)(NUM_LEDS - 1) / (double)NUM_LEDS * chargeVoltage)) {
            displayWinningSequence();
            handleButtonRelease(); // Wait for button release to reset
            capacitorVoltage = previousCapacitorVoltage = 0.0; // Reset capacitor voltage
        }

        // LED OFF phase (discharging)
        updateLedDisplay(capacitorVoltage, FALSE);
        startTime = millis();
        while (millis() - startTime < ledOffTime) {
            handleButtonPress();
            dischargeCapacitor();
            delay(timeIncrementMs);
        }
    }

    return 0;
}

// Initializes wiringPi, PiFace, and calculates initial values
int initialize()
{
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "wiringPiSetupSys failed: %s\n", strerror(errno));
        return -1;
    }

    if (piFaceSetup(PIFACE_BASE) == -1) {
        fprintf(stderr, "piFaceSetup failed: %s\n", strerror(errno));
        return -1;
    }

    // Enable internal pull-ups for PiFace inputs
    for (int i = 0; i < 8; ++i) {
        pullUpDnControl(PIFACE_BASE + i, PUD_UP);
    }

    // Calculate the charging voltage based on the resistor divider
    chargeVoltage = DISCHARGE_RESISTANCE / (CHARGE_RESISTANCE + DISCHARGE_RESISTANCE) * BATTERY_VOLTAGE;

    // Initialize capacitor voltage to 0
    capacitorVoltage = previousCapacitorVoltage = 0.0;

    return 0;
}

// Displays an introductory LED sequence
void displayIntro()
{
    printf("Pi Ladder\n");
    printf("=========\n\n");
    printf("       vBatt: %6.2f volts\n", BATTERY_VOLTAGE);
    printf("     rCharge: %6.0f ohms\n", CHARGE_RESISTANCE);
    printf("  rDischarge: %6.0f ohms\n", DISCHARGE_RESISTANCE);
    printf("     vCharge: %6.2f volts\n", chargeVoltage);
    printf("   capacitor: %6.0f uF\n", CAPACITANCE * 1000000.0);

    // Flash LEDs 3 times
    for (int j = 0; j < 3; ++j) {
        for (int i = 0; i < NUM_LEDS; ++i) {
            digitalWrite(ledMap[i], HIGH);
        }
        delay(500);
        for (int i = 0; i < NUM_LEDS; ++i) {
            digitalWrite(ledMap[i], LOW);
        }
        delay(100);
    }

    // All LEDs on, then countdown
    for (int i = 0; i < NUM_LEDS; ++i) {
        digitalWrite(ledMap[i], HIGH);
    }
    delay(500);

    for (int i = NUM_LEDS - 1; i >= 0; --i) {
        digitalWrite(ledMap[i], LOW);
        delay(100);
    }
    delay(500);
}

// Displays a winning LED sequence
void displayWinningSequence()
{
    // Flash LEDs 3 times
    for (int j = 0; j < 3; ++j) {
        for (int i = 0; i < NUM_LEDS; ++i) {
            digitalWrite(ledMap[i], HIGH);
        }
        delay(500);
        for (int i = 0; i < NUM_LEDS; ++i) {
            digitalWrite(ledMap[i], LOW);
        }
        delay(100);
    }

    // All LEDs on, then count up
    for (int i = 0; i < NUM_LEDS; ++i) {
        digitalWrite(ledMap[i], HIGH);
    }
    delay(500);

    for (int i = 0; i < NUM_LEDS; ++i) {
        digitalWrite(ledMap[i], LOW);
        delay(100);
    }
    delay(500);
}

// Simulates charging the capacitor
void chargeCapacitor()
{
    capacitorVoltage = (previousCapacitorVoltage - chargeVoltage) *
                       exp(-TIME_INCREMENT / (CHARGE_RESISTANCE * CAPACITANCE)) + chargeVoltage;

    previousCapacitorVoltage = capacitorVoltage;
}

// Simulates discharging the capacitor
void dischargeCapacitor()
{
    capacitorVoltage = previousCapacitorVoltage *
                       exp(-TIME_INCREMENT / (DISCHARGE_RESISTANCE * CAPACITANCE));

    previousCapacitorVoltage = capacitorVoltage;
}

// Updates the LED display based on the capacitor voltage
void updateLedDisplay(double voltage, int topLedLit)
{
    int topLed = (int)floor(voltage / chargeVoltage * (double)NUM_LEDS);

    if (topLed >= NUM_LEDS) {
        topLed = NUM_LEDS -1;
    }
    if(topLed < 0){
        topLed = 0;
    }

    for (int i = 0; i < NUM_LEDS; ++i) {
        if (i <= topLed) {
            digitalWrite(ledMap[i], HIGH);
        } else {
            digitalWrite(ledMap[i], LOW);
        }
    }
}

// Handles button press action (charging)
void handleButtonPress()
{
    if (digitalRead(PIFACE_BASE) == LOW) {
        chargeCapacitor();
        updateLedDisplay(capacitorVoltage, TRUE);
    }
}

// Handles button release action (resetting if held too long)
void handleButtonRelease()
{
    // Wait for button release
    while (digitalRead(PIFACE_BASE) == LOW) {
        delay(10);
    }
}

