// Constants for LCD configuration
#define LCD_RS_PIN  11
#define LCD_ENABLE_PIN 10

// Custom character definition (example)
static unsigned char customChar[8] = {
    0b11111,
    0b10001,
    0b10001,
    0b10101,
    0b11111,
    0b10001,
    0b10001,
    0b11111
};

// Global LCD handle
static int lcdHandle = -1; // Initialize to -1 to indicate not initialized

// Function prototypes
int initLCD(int rows, int cols, int bits);
void displayMessage(int row, int col, const char *message);
void scrollMessage(int line, int width);
void pingPongEffect(int cols);
