// Error handling macro
#define CHECK_RESULT(result, message) \
    if (result < 0) { \
        fprintf(stderr, "Error: %s: %s\n", message, strerror(errno)); \
        cleanupLCD(); \
        return EXIT_FAILURE; \
    }

/*
 * Function: initLCD
 * ------------------
 * Initializes the LCD with the specified configuration.
 *
 * rows: Number of rows on the LCD.
 * cols: Number of columns on the LCD.
 * bits: Data bus width (4 or 8 bits).
 *
 * returns: 0 on success, -1 on failure.
 */
int initLCD(int rows, int cols, int bits) {
    if (lcdHandle != -1) {
        fprintf(stderr, "Warning: LCD already initialized.\n");
        return 0; // Already initialized, no error
    }

    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: wiringPiSetup failed: %s\n", strerror(errno));
        return -1;
    }

    if (bits == 4) {
        lcdHandle = lcdInit(rows, cols, 4, LCD_RS_PIN, LCD_ENABLE_PIN, 4, 5, 6, 7, 0, 0, 0, 0);
    } else if (bits == 8) {
        lcdHandle = lcdInit(rows, cols, 8, LCD_RS_PIN, LCD_ENABLE_PIN, 0, 1, 2, 3, 4, 5, 6, 7);
    } else {
        fprintf(stderr, "Error: Invalid bit mode. Must be 4 or 8.\n");
        return -1;
    }

    if (lcdHandle < 0) {
        fprintf(stderr, "Error: lcdInit failed.\n");
        return -1;
    }

    return 0;
}

/*
 * Function: displayMessage
 * ----------------------
 * Displays a message on the LCD at the specified row and column.
 *
 * row: Row number (0-based).
 * col: Column number (0-based).
 * message: The message to display.
 */
void displayMessage(int row, int col, const char *message) {
    if (lcdHandle == -1) {
        fprintf(stderr, "Error: LCD not initialized.\n");
        return;
    }
    lcdPosition(lcdHandle, col, row);
    lcdPuts(lcdHandle, message);
}

/*
 * Function: scrollMessage
 * ----------------------
 * Scrolls a message across the LCD.
 *
 * line: The line number to scroll the message on.
 * width: The width of the LCD in characters.
 */
void scrollMessage(int line, int width) {
    if (lcdHandle == -1) {
        fprintf(stderr, "Error: LCD not initialized.\n");
        return;
    }

    char buffer[32]; // Increased buffer size for safety
    static int position = 0;
    static unsigned long lastUpdate = 0;
    unsigned long currentTime = millis();

    if (currentTime - lastUpdate < 200) {
        return; // Limit scroll speed
    }

    lastUpdate = currentTime;

    // Copy a portion of the message to the buffer
    strncpy(buffer, &scrollingMessage[position], width);
    buffer[width] = '\0'; // Ensure null termination

    displayMessage(line, 0, buffer);

    position++;
    if (position > (int)strlen(scrollingMessage) - width) {
        position = 0;
    }
}

/*
 * Function: pingPongEffect
 * ----------------------
 * Creates a "ping pong" effect on the last line of the LCD.
 *
 * cols: The number of columns on the LCD.
 */
void pingPongEffect(int cols) {
    if (lcdHandle == -1) {
        fprintf(stderr, "Error: LCD not initialized.\n");
        return;
    }

    static int position = 0;
    static int direction = 1; // 1 for right, -1 for left
    static unsigned long lastUpdate = 0;
    unsigned long currentTime = millis();

    if (currentTime - lastUpdate < 100) {
        return; // Limit update speed
    }

    lastUpdate = currentTime;

    displayMessage(3, position, " "); // Clear the current position
    position += direction;

    if (position >= cols -1) {
        direction = -1;
        position = cols - 2;
    } else if (position <= 0) {
        direction = 1;
        position = 1;
    }

    displayMessage(3, position, "#"); // Draw the character at the new position
}

/*
 * Function: waitForEnter
 * ----------------------
 * Waits for the user to press Enter in the console.
 */
void waitForEnter(void) {
    printf("Press ENTER to continue: ");
    fflush(stdout); // Ensure the prompt is displayed
    while (getchar() != '\n'); // Consume characters until newline is encountered
}

/*
 * Function: cleanupLCD
 * --------------------
 * Cleans up the LCD and releases resources.
 *
 * returns: 0 on success, -1 on failure.
 */
int cleanupLCD(void) {
    if (lcdHandle != -1) {
        lcdClear(lcdHandle);
        // Optionally, you might want to turn off the display or reset it further
        lcdHandle = -1; // Mark as uninitialized
    }
    return 0;
}

/*
 * Function: main
 * ----------------
 * The main function of the program.
 *
 * argc: The number of command-line arguments.
 * argv: An array of command-line argument strings.
 *
 * returns: 0 on success, EXIT_FAILURE on failure.
 */
int main(int argc, char *argv[]) {
    int rows, cols, bits;
    time_t currentTime;
    struct tm *timeInfo;
    char timeString[32];

    printf("Raspberry Pi LCD test\n");
    printf("=====================\n");

    if (argc != 4) {
        fprintf(stderr, "Usage: %s <bits> <cols> <rows>\n", argv[0]);
        return EXIT_FAILURE;
    }

    bits = atoi(argv[1]);
    cols = atoi(argv[2]);
    rows = atoi(argv[3]);

    if (rows != 1 && rows != 2 && rows != 4) {
        fprintf(stderr, "Error: rows must be 1, 2, or 4\n");
        return EXIT_FAILURE;
    }

    if (cols != 16 && cols != 20) {
        fprintf(stderr, "Error: cols must be 16 or 20\n");
        return EXIT_FAILURE;
    }

    // Initialize LCD
    if (initLCD(rows, cols, bits) != 0) {
        return EXIT_FAILURE;
    }

    displayMessage(0, 0, "Hello World");
    displayMessage(1, 0, "  wiringpi  ");
    waitForEnter();

    if (rows > 1) {
        displayMessage(1, 0, "  wiringpi  ");

        if (rows == 4) {
            int i;
            char row2[32] = {0};
            char row3[32] = {0};
            for (i = 0; i < ((cols - 1) / 2); ++i) {
              strcat(row2, "=-");
              strcat(row3, "-=");
            }
            strcat(row2, "=3");
            strcat(row3, "-4");
            displayMessage(2, 0, row2);
            displayMessage(3, 0, row3);
        }
    }
    waitForEnter();

    lcdCharDef(lcdHandle, 2, customChar);
    lcdClear(lcdHandle);
    displayMessage(0, 0, "User Char: ");
    lcdPutchar(lcdHandle, 2);
    lcdCursor(lcdHandle, TRUE);
    lcdCursorBlink(lcdHandle, TRUE);
    waitForEnter();

    lcdCursor(lcdHandle, FALSE);
    lcdCursorBlink(lcdHandle, FALSE);
    lcdClear(lcdHandle);

    // Main loop
    while (1) {
        scrollMessage(0, cols);

        if (rows > 1) {
            currentTime = time(NULL);
            timeInfo = localtime(&currentTime);
            strftime(timeString, sizeof(timeString), "%H:%M:%S", timeInfo);
            displayMessage(1, (cols - 8) / 2, timeString);

            if (rows > 2) {
                strftime(timeString, sizeof(timeString), "%d/%m/%Y", timeInfo);
                displayMessage(2, (cols - 10) / 2, timeString);

                if (rows == 4) {
                    pingPongEffect(cols);
                }
            }
        }
        delay(10); // Small delay to reduce CPU usage
    }

    return 0;
}

