// Define the GPIO pin connected to the low power signal
#define LOW_POWER_PIN 35

// Define the maximum length of the timestamp string
#define TIMESTAMP_BUFFER_SIZE 30

// Function prototype for the low power detection interrupt service routine
void lowPowerDetected(void);

// Function to get the current timestamp as a string
char* getCurrentTimestamp(char* timestampBuffer, size_t bufferSize);

int main(void) {
    // Initialize wiringPi using the GPIO pin numbering scheme
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return 1; // Exit with an error code
    }

    // Set the low power pin as an input with a pull-up resistor (optional, adjust as needed)
    pinMode(LOW_POWER_PIN, INPUT);
pullUpDnControl(LOW_POWER_PIN, PUD_UP);

    // Attach an interrupt to the low power pin, triggering on falling edge
    if (wiringPiISR(LOW_POWER_PIN, INT_EDGE_FALLING, &lowPowerDetected) != 0) {
        fprintf(stderr, "Error attaching interrupt: %s\n", strerror(errno));
        return 1; // Exit with an error code
    }

    printf("Low power detection service started.  Waiting for falling edge on GPIO %d...\n", LOW_POWER_PIN);

    // Main loop: keep the program running and listening for interrupts
    while (1) {
        delay(1000); // Delay for 1 second (adjust as needed)
    }

    return 0; // Exit normally (shouldn't reach here in this example)
}

// Interrupt service routine (ISR) for low power detection
void lowPowerDetected(void) {
    char timestampBuffer[TIMESTAMP_BUFFER_SIZE];

    // Get the current timestamp
    if (getCurrentTimestamp(timestampBuffer, TIMESTAMP_BUFFER_SIZE) == NULL) {
        fprintf(stderr, "Error getting timestamp.\n");
        return; // Exit the ISR if timestamp retrieval fails
    }

    // Log the low power detection event with the timestamp
    printf("%s: LOW POWER DETECTED on GPIO %d\n", timestampBuffer, LOW_POWER_PIN);
    fflush(stdout); // Ensure the output is immediately written to the console/log
}

// Function to get the current timestamp as a string
char* getCurrentTimestamp(char* timestampBuffer, size_t bufferSize) {
    time_t rawtime;
    struct tm* timeinfo;

    // Get the current time
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    // Check for errors
    if (timeinfo == NULL) {
        perror("localtime");
        return NULL;
    }

    // Format the timestamp string
    if (strftime(timestampBuffer, bufferSize, "%Y-%m-%d %H:%M:%S", timeinfo) == 0) {
        fprintf(stderr, "Error formatting timestamp.\n");
        return NULL;
    }

    return timestampBuffer;
}

