int main(int argc, char *argv[]) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return 1;
    }

    if (initialize_spi() != 0) {
        fprintf(stderr, "SPI initialization failed.\n");
        return 1;
    }

    float internal_temp_c, thermocouple_temp_c;
    int fault_code;

    while (1) {
        if (read_max31855(SPI_CHANNEL, &internal_temp_c, &thermocouple_temp_c, &fault_code) == 0) {
            printf("Internal Temperature: %.2f C, %.2f F\n", internal_temp_c, internal_temp_c * 9.0 / 5.0 + 32.0);
            printf("Thermocouple Temperature: %.2f C, %.2f F\n", thermocouple_temp_c, thermocouple_temp_c * 9.0 / 5.0 + 32.0);
            if (fault_code != 0) {
                print_fault(fault_code);
            }
        } else {
            fprintf(stderr, "Failed to read MAX31855 data.\n");
        }

        delay(1000); // Read every 1 second
    }

    return 0;
}

// Initialize SPI
int initialize_spi() {
    int fd = wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED);
    if (fd == -1) {
        fprintf(stderr, "wiringPiSPISetup failed: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

// Read data from MAX31855
int read_max31855(int channel, float *internal_temp_c, float *thermocouple_temp_c, int *fault_code) {
    uint8_t data[MAX31855_DATA_SIZE];
    uint32_t raw_data;

    if (wiringPiSPIDataRW(channel, data, MAX31855_DATA_SIZE) == -1) {
        fprintf(stderr, "SPI data transfer failed: %s\n", strerror(errno));
        return -1;
    }

    // Combine the bytes into a 32-bit word
    raw_data = (data[0] << 24) | (data[1] << 16) | (data[2] << 8) | data[3];

    // Check for fault
    *fault_code = raw_data & 0x00000007; // Extract fault bits
    if (*fault_code) {
        return 0; // Return even on fault to print the error.
    }

    // Extract and convert thermocouple temperature
    *thermocouple_temp_c = raw_to_thermocouple_temp(raw_data);

    // Extract and convert internal temperature
    *internal_temp_c = raw_to_internal_temp(raw_data);

    return 0;
}

// Convert raw thermocouple data to temperature (Celsius)
float raw_to_thermocouple_temp(uint32_t raw) {
    int32_t thermocouple_data = (raw >> 18) & 0x3FFF; // Extract 14-bit thermocouple data
    if (thermocouple_data & 0x2000) {
        thermocouple_data |= 0xFFFFC000; // Sign extend if negative
    }
    return thermocouple_data * 0.25;
}

// Convert raw internal temperature data to temperature (Celsius)
float raw_to_internal_temp(uint32_t raw) {
    int32_t internal_data = (raw >> 4) & 0xFFF; // Extract 12-bit internal data
    if (internal_data & 0x800) {
        internal_data |= 0xFFFFF000; // Sign extend if negative
    }
    return internal_data * 0.0625;
}

// Print fault status
void print_fault(int fault_code) {
    fprintf(stderr, "Fault Detected: ");
    switch (fault_code) {
        case 0x01:
            fprintf(stderr, "Open Circuit\n");
            break;
        case 0x02:
            fprintf(stderr, "Short to GND\n");
            break;
        case 0x04:
            fprintf(stderr, "Short to VCC\n");
            break;
        default:
            fprintf(stderr, "Unknown Fault (Code: %d)\n", fault_code);
            break;
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <errno.h>
#include <wiringPi.h>
#include <piFace.h>

#define PIFACE_BASE 200
#define RELAY_1 (PIFACE_BASE + 0)
#define RELAY_2 (PIFACE_BASE + 1)

// Function prototypes
void playMiddleA();
void metronome(int bpm);

/**
 * @brief Plays a middle A note using the PiFace relays.
 *
 * This function continuously toggles the relays to produce a middle A note.
 */
void playMiddleA() {
    unsigned int next;

    while (1) {
        next = micros() + 1136;
        digitalWrite(RELAY_1, LOW);
        digitalWrite(RELAY_2, LOW);
        while (micros() < next) {
            delayMicroseconds(1);
        }

        next = micros() + 1137;
        digitalWrite(RELAY_1, HIGH);
        digitalWrite(RELAY_2, HIGH);
        while (micros() < next) {
            delayMicroseconds(1);
        }
    }
}

/**
 * @brief Implements the metronome functionality.
 *
 * @param bpm The beats per minute.
 */
void metronome(int bpm) {
    int msPerBeat;
    int state = LOW; // Initial state of the relays
    unsigned int endTime;

    msPerBeat = 60000 / bpm;

    // Main loop
    while (1) {
        endTime = millis() + msPerBeat;

        digitalWrite(RELAY_1, state);
        digitalWrite(RELAY_2, state);

        while (millis() < endTime) {
            delayMicroseconds(500); // Reduced delay for better accuracy
        }

        state ^= 1; // Toggle the state (HIGH/LOW)
    }
}

int main(int argc, char *argv[]) {
    int bpm;

    printf("Raspberry Pi PiFace Metronome\n");
    printf("=============================\n");

    // Initialize wiringPi and PiFace
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return 1;
    }

    if (piFaceSetup(PIFACE_BASE) == -1) {
        fprintf(stderr, "Error initializing PiFace: %s\n", strerror(errno));
        return 1;
    }

    piHiPri(50); // Set a higher priority for more accurate timing

    // Check command-line arguments
    if (argc != 2) {
        fprintf(stderr, "Usage: %s <beats per minute> or 'a' for middle A\n", argv[0]);
        return 1;
    }

    // Handle the 'a' argument for middle A
    if (strcmp(argv[1], "a") == 0) {
        printf("Playing middle A...\n");
        playMiddleA();
        return 0; // Exit after playing middle A
    }

    // Convert BPM from argument
    char *endptr;
    bpm = strtol(argv[1], &endptr, 10);

    // Check for conversion errors and empty input
    if (*endptr != '\0' || argv[1] == endptr) {
        fprintf(stderr, "Invalid BPM value: %s\n", argv[1]);
        return 1;
    }

    // Validate BPM range
    if (bpm < 40 || bpm > 208) {
        fprintf(stderr, "Error: BPM must be between 40 and 208\n");
        return 1;
    }

    printf("Metronome running at %d BPM\n", bpm);
    metronome(bpm);

    return 0; // This line will likely never be reached in the metronome function
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <unistd.h>
#include <wiringPi.h>
#include <piFace.h>
#include <softPwm.h>

// Constants
#define PIFACE_BASE_PIN  200
#define PWM_OUTPUT_PIN   204
#define PWM_INCREASE_PIN 202
#define PWM_DECREASE_PIN 203
#define NUM_RELAY_BUTTONS 2
#define PWM_RANGE        100

// Global Variables
bool relay_states[NUM_RELAY_BUTTONS] = {false, false};

// Function Prototypes
void initialize_gpio();
void handle_relay_button(int button_pin);
void handle_pwm_increase();
void handle_pwm_decrease();

// Function to initialize GPIO pins and PiFace
void initialize_gpio() {
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "WiringPi initialization failed!\n");
    exit(EXIT_FAILURE);
  }

  if (piFaceSetup(PIFACE_BASE_PIN) == -1) {
    fprintf(stderr, "PiFace initialization failed!\n");
    exit(EXIT_FAILURE);
  }

  if (softPwmCreate(PWM_OUTPUT_PIN, 0, PWM_RANGE) != 0) {
    fprintf(stderr, "SoftPWM creation failed!\n");
    exit(EXIT_FAILURE);
  }

  // Enable internal pull-ups for all input pins
  for (int pin = 0; pin < 8; ++pin) {
    pullUpDnControl(PIFACE_BASE_PIN + pin, PUD_UP);
  }

  // Ensure relays are initially off
  for (int pin = 0; pin < 8; ++pin) {
    digitalWrite(PIFACE_BASE_PIN + pin, LOW);
  }
}

// Function to handle relay button press
void handle_relay_button(int button_pin) {
  if (digitalRead(PIFACE_BASE_PIN + button_pin) == LOW) {
    relay_states[button_pin] = !relay_states[button_pin]; // Toggle state
    digitalWrite(PIFACE_BASE_PIN + button_pin, relay_states[button_pin] ? HIGH : LOW);

    printf("Button %d pressed - Relay output now: %s\n",
           button_pin,
           relay_states[button_pin] ? "On" : "Off");

    // Debounce the button
    while (digitalRead(PIFACE_BASE_PIN + button_pin) == LOW) {
      delay(1);
    }
  }
}

// Function to handle PWM increase button press
void handle_pwm_increase() {
  static int pwm_value = 0;
  if (digitalRead(PWM_INCREASE_PIN) == LOW) {
    pwm_value += 10;
    if (pwm_value > PWM_RANGE) {
      pwm_value = PWM_RANGE;
    }

    softPwmWrite(PWM_OUTPUT_PIN, pwm_value);
    printf("PWM -> %3d\n", pwm_value);

    // Debounce the button
    while (digitalRead(PWM_INCREASE_PIN) == LOW) {
      delay(5);
    }
  }
}

// Function to handle PWM decrease button press
void handle_pwm_decrease() {
  static int pwm_value = 0;
  if (digitalRead(PWM_DECREASE_PIN) == LOW) {
    pwm_value -= 10;
    if (pwm_value < 0) {
      pwm_value = 0;
    }

    softPwmWrite(PWM_OUTPUT_PIN, pwm_value);
    printf("PWM -> %3d\n", pwm_value);

    // Debounce the button
    while (digitalRead(PWM_DECREASE_PIN) == LOW) {
      delay(5);
    }
  }
}

int main() {
  printf("Raspberry Pi PiFace - Motor control\n");
  printf("==================================\n");
  printf("\n");
  printf("This program is designed to be used with a motor connected to the relays\n");
  printf("in an H-Bridge type configuration with optional speed control via PWM.\n");
  printf("\n");
  printf("Use the leftmost buttons to turn each relay on and off, and the rightmost\n");
  printf("buttons to increase or decrease the PWM output on the control pin (pin 4).\n\n");

  initialize_gpio();

  while (true) {
    // Handle relay buttons
    for (int button = 0; button < NUM_RELAY_BUTTONS; ++button) {
      handle_relay_button(button);
    }

    // Handle PWM control buttons
    handle_pwm_increase();
    handle_pwm_decrease();

    delay(5); // Small delay to prevent excessive CPU usage
  }

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
