    if (result == -1) {
        fprintf(stderr, "mcp23017Setup failed: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <wiringPi.h>

// Define NES button mappings (same as piNes.h, but included here for self-containment and clarity)
#define NES_A      1
#define NES_B      2
#define NES_SELECT 4
#define NES_START  8
#define NES_UP     16
#define NES_DOWN   32
#define NES_LEFT   64
#define NES_RIGHT  128

// GPIO pins connected to the NES controller (adjust as needed)
#define NES_DATA_PIN  2  // Data pin
#define NES_LATCH_PIN 1  // Latch pin
#define NES_CLOCK_PIN 0  // Clock pin

// Function prototypes
int setupNesController(int dataPin, int latchPin, int clockPin);
unsigned int readNesController();

// Error handling macro
#define FATAL_ERROR(msg) do { \
    fprintf(stderr, "Error: %s (%s:%d)\n", msg, __FILE__, __LINE__); \
    exit(EXIT_FAILURE); \
} while (0)

int main() {
    int controllerHandle;
    unsigned int buttonState;

    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        FATAL_ERROR("WiringPi initialization failed");
    }

    // Setup the NES controller
    controllerHandle = setupNesController(NES_DATA_PIN, NES_LATCH_PIN, NES_CLOCK_PIN);
    if (controllerHandle == -1) {
        FATAL_ERROR("NES controller setup failed");
    }

    // Main loop: read controller input and print button states
    while (1) {
        buttonState = readNesController();

        printf("Buttons: ");
        printf((buttonState & NES_UP)     ? "UP "     : "-- ");
        printf((buttonState & NES_DOWN)   ? "DOWN "   : "-- ");
        printf((buttonState & NES_LEFT)   ? "LEFT "   : "-- ");
        printf((buttonState & NES_RIGHT)  ? "RIGHT "  : "-- ");
        printf((buttonState & NES_SELECT) ? "SELECT " : "-- ");
        printf((buttonState & NES_START)  ? "START "  : "-- ");
        printf((buttonState & NES_A)      ? "A "      : "-- ");
        printf((buttonState & NES_B)      ? "B "      : "-- ");
        printf("\n");

        delay(50); // Small delay to avoid flooding the console
    }

    return 0;
}


// Function to set up the NES controller pins
int setupNesController(int dataPin, int latchPin, int clockPin) {
    // Set pin modes
    pinMode(dataPin, INPUT);
    pinMode(latchPin, OUTPUT);
    pinMode(clockPin, OUTPUT);

    // Initial state for clock and latch pins
    digitalWrite(latchPin, LOW);
    digitalWrite(clockPin, LOW);

    return 0; // Return 0 to indicate success
}


// Function to read the NES controller state
unsigned int readNesController() {
    unsigned int buttonData = 0;

    // Strobe the latch pin to load the button states
    digitalWrite(NES_LATCH_PIN, HIGH);
    delayMicroseconds(12); // Minimum 12us pulse
    digitalWrite(NES_LATCH_PIN, LOW);

    // Read the button states by clocking the data pin
    for (int i = 0; i < 8; i++) {
        digitalWrite(NES_CLOCK_PIN, HIGH);
        delayMicroseconds(6); // Minimum 6us pulse
        if (digitalRead(NES_DATA_PIN) == LOW) { // Active low
            buttonData |= (1 << i);
        }
        digitalWrite(NES_CLOCK_PIN, LOW);
        delayMicroseconds(6); // Minimum 6us pulse
    }

    return buttonData;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <errno.h>
#include <signal.h>
#include <wiringPi.h>
#include <softPwm.h>

// Define the GPIO pin for the OK LED (BCM 16)
#define OK_LED_PIN 16

// Define the path to the LED trigger file
#define LED_TRIGGER_PATH "/sys/class/leds/led0/trigger"

// Define PWM range
#define PWM_RANGE 100

// Global flag to handle program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for graceful exit
void signal_handler(int signal) {
    (void)signal; // Suppress unused parameter warning
    program_running = 0;
    printf("\nExiting gracefully...\n");
}

// Function to set the LED trigger to 'none'
int set_led_trigger_none() {
    int fd;
    ssize_t bytes_written;

    fd = open(LED_TRIGGER_PATH, O_WRONLY);
    if (fd < 0) {
        fprintf(stderr, "Error opening LED trigger file: %s\n", strerror(errno));
        return -1;
    }

    bytes_written = write(fd, "none", strlen("none"));
    if (bytes_written == -1) {
        fprintf(stderr, "Error writing to LED trigger file: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

int main() {
    int pwm_value;

    // Set up signal handling for SIGINT (Ctrl+C)
    signal(SIGINT, signal_handler);

    // Initialize wiringPi with GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "wiringPiSetupGpio failed: %s\n", strerror(errno));
        return 1;
    }

    // Disable the default LED trigger
    if (set_led_trigger_none() != 0) {
        fprintf(stderr, "Failed to set LED trigger to 'none'. Exiting.\n");
        return 1;
    }

    // Create a soft PWM controller on the OK_LED_PIN
    if (softPwmCreate(OK_LED_PIN, 0, PWM_RANGE) != 0) {
        fprintf(stderr, "softPwmCreate failed for pin %d. Exiting.\n", OK_LED_PIN);
        return 1;
    }

    printf("OK LED pulsation started. Press Ctrl+C to exit.\n");

    // Main loop to pulsate the LED
    while (program_running) {
        // Fade in
        for (pwm_value = 0; pwm_value <= PWM_RANGE; ++pwm_value) {
            softPwmWrite(OK_LED_PIN, pwm_value);
            delay(10);
        }

        delay(50);

        // Fade out
        for (pwm_value = PWM_RANGE; pwm_value >= 0; --pwm_value) {
            softPwmWrite(OK_LED_PIN, pwm_value);
            delay(10);
        }

        delay(10);
    }

    // Clean up: set LED to off and exit
    softPwmWrite(OK_LED_PIN, 0);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
