#include <sn3218.h>

#define LED_BASE 533
#define NUM_LEDS 18
#define DELAY_MS 5  // Reduced delay for smoother fading

// Function to safely initialize the SN3218
int initializePiGlow(int ledBase) {
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "Error: Unable to initialize WiringPi.\n");
        return -1;
    }

    if (sn3218Setup(ledBase) == -1) {
        fprintf(stderr, "Error: Unable to initialize SN3218.\n");
        return -1;
    }

    return 0; // Success
}

// Function to set the brightness of a single LED with error checking
void setLedBrightness(int led, int brightness) {
    if (led < 0 || led >= NUM_LEDS) {
        fprintf(stderr, "Error: Invalid LED number: %d\n", led);
        return;
    }

    if (brightness < 0 || brightness > 255) {
        fprintf(stderr, "Error: Invalid brightness value: %d\n", brightness);
        return;
    }

    analogWrite(LED_BASE + led, brightness);
}

int main() {
    int fadeValue;
    int ledIndex;

    // Initialize PiGlow and handle errors
    if (initializePiGlow(LED_BASE) != 0) {
        return 1; // Exit if initialization fails
    }

    while (1) {
        // Fade in
        for (fadeValue = 0; fadeValue <= 255; ++fadeValue) {
            for (ledIndex = 0; ledIndex < NUM_LEDS; ++ledIndex) {
                setLedBrightness(ledIndex, fadeValue);
            }
            delay(DELAY_MS); // Short delay for smoother fade
        }

        // Fade out
        for (fadeValue = 255; fadeValue >= 0; --fadeValue) {
            for (ledIndex = 0; ledIndex < NUM_LEDS; ++ledIndex) {
                setLedBrightness(ledIndex, fadeValue);
            }
            delay(DELAY_MS); // Short delay for smoother fade
        }
    }

    return 0;
}

