// Helper Functions

/*
 * isKeyPressed:
 *  Checks if a key has been pressed on stdin without blocking.
 *  Returns true if a key is pressed, false otherwise.
 */
static bool isKeyPressed(void) {
    struct pollfd polls;

    polls.fd = fileno(stdin);
    polls.events = POLLIN;  // Check for data to read

    // Poll stdin.  Return immediately.  Return > 0 if data available.
    if (poll(&polls, 1, 0) > 0) {
        return true;
    } else {
        return false;
    }
}

/*
 * clearKeyPressedBuffer:
 *  Clears the stdin buffer of any pending key presses.
 */
static void clearKeyPressedBuffer(void) {
    while (isKeyPressed()) {
        getchar(); // Consume the character
    }
}

/*
 * pulseLed:
 *  Pulses a single LED (specified by leg and ring) from off to MAX_BRIGHTNESS and back.
 *  Returns 0 on success, -1 on error.
 */
static int pulseLed(int leg, int ring) {
    if (leg < 0 || leg >= NUM_LEGS || ring < 0 || ring >= NUM_RINGS) {
        fprintf(stderr, "Error: Invalid leg or ring number in pulseLed\n");
        return -1;
    }

    // Fade in
    for (int brightness = 0; brightness <= MAX_BRIGHTNESS; ++brightness) {
        piGlow1(leg, ring, brightness);
        delay(DELAY_MS);
    }
    delay(10); //small pause at max brightness

    // Fade out
    for (int brightness = MAX_BRIGHTNESS; brightness >= 0; --brightness) {
        piGlow1(leg, ring, brightness);
        delay(DELAY_MS);
    }
    return 0;
}

/*
 * pulseLeg:
 *  Pulses an entire leg from off to MAX_BRIGHTNESS and back.
 *  Returns 0 on success, -1 on error.
 */
static int pulseLeg(int leg) {
    if (leg < 0 || leg >= NUM_LEGS) {
        fprintf(stderr, "Error: Invalid leg number in pulseLeg\n");
        return -1;
    }

    // Fade in
    for (int brightness = 0; brightness <= MAX_BRIGHTNESS; ++brightness) {
        piGlowLeg(leg, brightness);
        delay(DELAY_MS);
    }
    delay(10); //small pause at max brightness

    // Fade out
    for (int brightness = MAX_BRIGHTNESS; brightness >= 0; --brightness) {
        piGlowLeg(leg, brightness);
        delay(DELAY_MS);
    }
    return 0;
}

/*
 * pulseRing:
 *  Pulses an entire ring from off to MAX_BRIGHTNESS and back.
 *  Returns 0 on success, -1 on error.
 */
static int pulseRing(int ring) {
    if (ring < 0 || ring >= NUM_RINGS) {
        fprintf(stderr, "Error: Invalid ring number in pulseRing\n");
        return -1;
    }

    // Fade in
    for (int brightness = 0; brightness <= MAX_BRIGHTNESS; ++brightness) {
        piGlowRing(ring, brightness);
        delay(DELAY_MS);
    }
    delay(10); //small pause at max brightness

    // Fade out
    for (int brightness = MAX_BRIGHTNESS; brightness >= 0; --brightness) {
        piGlowRing(ring, brightness);
        delay(DELAY_MS);
    }
    return 0;
}

/*
 * runSequence:
 *  Runs a predefined sequence of LED patterns.
 *  Returns 0 on success, -1 if a key is pressed.
 */
static int runSequence(void) {
    int step, ring, leg, i;

    for (i = 0; i < 20; ++i)
        for (step = 0; step < LEG_STEPS; ++step)
        {
            for (leg = 0; leg < NUM_LEGS; ++leg)
                piGlowLeg (leg, legSequence [step * NUM_LEGS + leg]);
            delay (80);
        }

    for (i = 0; i < 10; ++i)
        for (step = 0; step < RING_STEPS; ++step)
        {
            for (ring = 0; ring < NUM_RINGS; ++ring)
                piGlowRing (ring, ringSequence [step * NUM_RINGS + ring]);
            delay (80);
        }

    for (i = 0; i < 1000; ++i)
    {
        leg  = random () % NUM_LEGS;
        ring = random () % NUM_RINGS;
        piGlow1 (leg, ring, random () % 256);
        delay (5);
        piGlow1 (leg, ring, 0);
    }

    return 0;
}

int main(void) {
    int leg, ring;

    // Initialize wiringPi
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "Error: Failed to initialize wiringPi.  Please ensure you are running as root, or use wiringPiSetup() instead.\n");
        return 1;
    }

    // Initialize piGlow
    if (piGlowSetup(1) == -1) {
        fprintf(stderr, "Error: Failed to initialize piGlow.  Please check your setup.\n");
        return 1;
    }

    // LEDs, one at a time
    printf("LEDs, one at a time. Press Enter to continue.\n");
    while (!isKeyPressed()) {
        for (leg = 0; leg < NUM_LEGS; ++leg) {
            for (ring = 0; ring < NUM_RINGS; ++ring) {
                if (pulseLed(leg, ring) != 0) {
                    fprintf(stderr, "Error pulsing LED (%d, %d)\n", leg, ring);
                }
                if (isKeyPressed()) break;
            }
            if (isKeyPressed()) break;
        }
    }
    clearKeyPressedBuffer();

    // Rings, one at a time
    printf("Rings, one at a time. Press Enter to continue.\n");
    while (!isKeyPressed()) {
        for (ring = 0; ring < NUM_RINGS; ++ring) {
            if (pulseRing(ring) != 0) {
                fprintf(stderr, "Error pulsing ring %d\n", ring);
            }
            if (isKeyPressed()) break;
        }
    }
    clearKeyPressedBuffer();

    // Legs, one at a time
    printf("Legs, one at a time. Press Enter to continue.\n");
    while (!isKeyPressed()) {
        for (leg = 0; leg < NUM_LEGS; ++leg) {
            if (pulseLeg(leg) != 0) {
                fprintf(stderr, "Error pulsing leg %d\n", leg);
            }
            if (isKeyPressed()) break;
        }
    }
    clearKeyPressedBuffer();

    delay(1000);

    // Sequence - alternating rings, legs and random
    printf("Sequence now. Press Enter to exit.\n");
    while (!isKeyPressed()) {
        if (runSequence() != 0) {
            fprintf(stderr, "Error running sequence\n");
        }
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>
#include <wiringPi.h>
#include <piGlow.h>

// Constants
#define MIN_PERCENT 0
#define MAX_PERCENT 100

// Function Prototypes
void printUsage(const char *programName);
int parsePercentage(const char *percentageString);
int parseInteger(const char *integerString, const char *argumentName, int minValue, int maxValue);
int mapPercentageToBrightness(int percentage);

int main(int argc, char *argv[]) {
    // Initialize wiringPi using the system call method (no root required)
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "Error: Unable to initialize wiringPi.\n");
        return EXIT_FAILURE;
    }

    // Initialize PiGlow library
    if (piGlowSetup(FALSE) == -1) {
        fprintf(stderr, "Error: Unable to initialize PiGlow library.\n");
        return EXIT_FAILURE;
    }

    // Handle no arguments or invalid number of arguments
    if (argc == 1) {
        printUsage(argv[0]);
        return EXIT_FAILURE;
    }

    // Turn off all LEDs
    if (argc == 2 && strcasecmp(argv[1], "off") == 0) {
        for (int leg = 0; leg < 3; ++leg) {
            piGlowLeg(leg, 0); // Turn off each leg
        }
        return EXIT_SUCCESS;
    }

    // Set brightness for a color or all
    if (argc == 3) {
        int brightness = parsePercentage(argv[2]);

        if (strcasecmp(argv[1], "red") == 0) {
            piGlowRing(PIGLOW_RED, brightness);
        } else if (strcasecmp(argv[1], "yellow") == 0) {
            piGlowRing(PIGLOW_YELLOW, brightness);
        } else if (strcasecmp(argv[1], "orange") == 0) {
            piGlowRing(PIGLOW_ORANGE, brightness);
        } else if (strcasecmp(argv[1], "green") == 0) {
            piGlowRing(PIGLOW_GREEN, brightness);
        } else if (strcasecmp(argv[1], "blue") == 0) {
            piGlowRing(PIGLOW_BLUE, brightness);
        } else if (strcasecmp(argv[1], "white") == 0) {
            piGlowRing(PIGLOW_WHITE, brightness);
        } else if (strcasecmp(argv[1], "all") == 0) {
            for (int ring = 0; ring < 6; ++ring) {
                piGlowRing(ring, brightness);
            }
        } else {
            fprintf(stderr, "Error: Invalid color specified.\n");
            printUsage(argv[0]);
            return EXIT_FAILURE;
        }
        return EXIT_SUCCESS;
    }

    // Set brightness for a leg or ring
    if (argc == 4) {
        if (strcasecmp(argv[1], "leg") == 0) {
            int leg = parseInteger(argv[2], "leg", 0, 2);
            int brightness = parsePercentage(argv[3]);
            piGlowLeg(leg, brightness);
        } else if (strcasecmp(argv[1], "ring") == 0) {
            int ring = parseInteger(argv[2], "ring", 0, 5);
            int brightness = parsePercentage(argv[3]);
            piGlowRing(ring, brightness);
        } else {
            printUsage(argv[0]);
            return EXIT_FAILURE;
        }
        return EXIT_SUCCESS;
    }

    // Set brightness for a single LED
    if (argc == 5) {
        if (strcasecmp(argv[1], "led") != 0) {
            printUsage(argv[0]);
            return EXIT_FAILURE;
        }

        int leg = parseInteger(argv[2], "leg", 0, 2);
        int ring = parseInteger(argv[3], "ring", 0, 5);
        int brightness = parsePercentage(argv[4]);
        piGlow1(leg, ring, brightness);
        return EXIT_SUCCESS;
    }

    // Invalid number of arguments
    printUsage(argv[0]);
    return EXIT_FAILURE;
}

// Function to print the usage instructions
void printUsage(const char *programName) {
    fprintf(stderr, "Usage: %s <command> [options]\n", programName);
    fprintf(stderr, "Commands:\n");
    fprintf(stderr, "  off                      Turn off all LEDs\n");
    fprintf(stderr, "  red <percent>            Set the brightness of the red ring (0-100)\n");
    fprintf(stderr, "  yellow <percent>         Set the brightness of the yellow ring (0-100)\n");
    fprintf(stderr, "  orange <percent>         Set the brightness of the orange ring (0-100)\n");
    fprintf(stderr, "  green <percent>          Set the brightness of the green ring (0-100)\n");
    fprintf(stderr, "  blue <percent>           Set the brightness of the blue ring (0-100)\n");
    fprintf(stderr, "  white <percent>          Set the brightness of the white ring (0-100)\n");
    fprintf(stderr, "  all <percent>            Set the brightness of all rings (0-100)\n");
    fprintf(stderr, "  leg <leg> <percent>      Set the brightness of a leg (0-2, 0-100)\n");
    fprintf(stderr, "  ring <ring> <percent>    Set the brightness of a ring (0-5, 0-100)\n");
    fprintf(stderr, "  led <leg> <ring> <percent> Set the brightness of a single LED (0-2, 0-5, 0-100)\n");
}

// Function to parse a percentage string and validate its value
int parsePercentage(const char *percentageString) {
    int percentage;
    char *endptr;

    // Use strtol to convert the string to an integer and check for errors
    percentage = strtol(percentageString, &endptr, 10);

    // Check for conversion errors
    if (*endptr != '\0') {
        fprintf(stderr, "Error: Invalid percentage value: %s\n", percentageString);
        exit(EXIT_FAILURE);
    }

    // Check if the percentage is within the valid range
    if (percentage < MIN_PERCENT || percentage > MAX_PERCENT) {
        fprintf(stderr, "Error: Percentage value out of range (0-100): %s\n", percentageString);
        exit(EXIT_FAILURE);
    }

    return mapPercentageToBrightness(percentage);
}

// Function to parse an integer string and validate its value within a given range
int parseInteger(const char *integerString, const char *argumentName, int minValue, int maxValue) {
    int value;
    char *endptr;

    // Use strtol to convert the string to an integer and check for errors
    value = strtol(integerString, &endptr, 10);

    // Check for conversion errors
    if (*endptr != '\0') {
        fprintf(stderr, "Error: Invalid %s value: %s\n", argumentName, integerString);
        exit(EXIT_FAILURE);
    }

    // Check if the value is within the valid range
    if (value < minValue || value > maxValue) {
        fprintf(stderr, "Error: %s value out of range (%d-%d): %s\n", argumentName, minValue, maxValue, integerString);
        exit(EXIT_FAILURE);
    }

    return value;
}

// Function to map a percentage value (0-100) to a brightness value (0-255)
int mapPercentageToBrightness(int percentage) {
    return (percentage * 255) / 100;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPi.h>

// Define the PWM pin (WiringPi pin number)
#define PWM_PIN 1
// Define the maximum PWM value (0-1023 for wiringPi PWM)
#define PWM_MAX 1024
// Define the delay between PWM changes (in milliseconds)
#define PWM_DELAY_MS 1

int main(void) {
  int brightness;

  // Print a message to the console
  printf("Raspberry Pi PWM LED Fader using wiringPi\n");

  // Initialize wiringPi library
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "wiringPiSetup failed. Please check permissions and wiring.\n");
    return EXIT_FAILURE;
  }

  // Set the PWM pin to PWM output mode
  pinMode(PWM_PIN, PWM_OUTPUT);

  // Main loop: fade the LED in and out continuously
  while (1) {
    // Fade in
    for (brightness = 0; brightness < PWM_MAX; ++brightness) {
      pwmWrite(PWM_PIN, brightness);
      delay(PWM_DELAY_MS);
    }

    // Fade out
    for (brightness = PWM_MAX - 1; brightness >= 0; --brightness) {
      pwmWrite(PWM_PIN, brightness);
      delay(PWM_DELAY_MS);
    }
  }

  // This return statement will never be reached in this example
  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <errno.h>
#include <wiringPi.h>
#include <piFace.h>

// Constants
#define PIFACE_BASE 200
#define NUM_BUTTONS 4
#define NUM_LEDS 4

// Global Variables
static int led_states[NUM_LEDS] = {0}; // Stores the current state of each LED (0 or 1)

// Function Prototypes
int init_piface();
void light_led_pair(int led_index, int value);
void light_all_leds(int on_off);
void wait_for_no_button_presses();
int get_button_pressed();
void reaction_game();

int main(void) {
    // Seed the random number generator
    srand(time(NULL));

    printf("Raspberry Pi PiFace Reaction Timer\n");
    printf("==================================\n");

    // Initialize PiFace
    if (init_piface() != 0) {
        fprintf(stderr, "PiFace initialization failed. Exiting.\n");
        return EXIT_FAILURE;
    }

    // Main game loop
    while (1) {
        reaction_game();
    }

    return EXIT_SUCCESS;
}

// Initialize PiFace interface
int init_piface() {
    if (piFaceSetup(PIFACE_BASE) == -1) {
        perror("piFaceSetup failed");
        return -1;
    }

    // Enable internal pull-ups for buttons
    for (int i = 0; i < NUM_BUTTONS; ++i) {
        pullUpDnControl(PIFACE_BASE + i, PUD_UP);
    }
    return 0;
}

// Light up a pair of LEDs associated with a given index
void light_led_pair(int led_index, int value) {
    if (led_index < 0 || led_index >= NUM_LEDS) {
        fprintf(stderr, "Error: Invalid LED index: %d\n", led_index);
        return;
    }

    int first_led_pin = PIFACE_BASE + (led_index * 2);
    digitalWrite(first_led_pin, value);
    digitalWrite(first_led_pin + 1, value);
    led_states[led_index] = value; // Update LED state
}

// Turn all LEDs on or off
void light_all_leds(int on_off) {
    for (int i = 0; i < NUM_LEDS; ++i) {
        light_led_pair(i, on_off);
    }
}

// Wait for all buttons to be released
void wait_for_no_button_presses() {
    while (1) {
        int button_pressed = 0;
        for (int i = 0; i < NUM_BUTTONS; ++i) {
            if (digitalRead(PIFACE_BASE + i) == LOW) {
                button_pressed = 1;
                break;
            }
        }
        if (!button_pressed) {
            break;
        }
        delay(10); // Small delay to prevent busy-waiting
    }
}

// Get the index of the first button pressed, or -1 if no button is pressed
int get_button_pressed() {
    for (int i = 0; i < NUM_BUTTONS; ++i) {
        if (digitalRead(PIFACE_BASE + i) == LOW) {
            return i;
        }
    }
    return -1;
}

// Implements the main reaction game logic
void reaction_game() {
    int led_to_light;
    int button_pressed;
    unsigned int start_time, end_time, reaction_time;

    printf("Press any button to start ... \n");
    fflush(stdout);

    // Wait for a button press to start the game
    while (get_button_pressed() == -1) {
        // Briefly flash a random LED to indicate waiting for input
        led_to_light = rand() % NUM_LEDS;
        light_led_pair(led_to_light, 1);
        delay(100);
        light_led_pair(led_to_light, 0);
        delay(100);
    }

    wait_for_no_button_presses();

    printf("Wait for it ... \n");
    fflush(stdout);

    // Choose a random LED and a random delay
    led_to_light = rand() % NUM_LEDS;
    delay(rand() % 500 + 1000); // Delay between 1 and 1.5 seconds
    light_led_pair(led_to_light, 1);

    // Measure the reaction time
    start_time = millis();
    while ((button_pressed = get_button_pressed()) == -1) {
        // Wait for a button press
        delay(1); // Small delay to prevent busy-waiting
    }
    end_time = millis();

    light_led_pair(led_to_light, 0);
    wait_for_no_button_presses();

    // Correct for the buttons/LEDs reversed (if needed, remove if not using reversed setup)
    button_pressed = 3 - button_pressed; //Assuming buttons are wired in reverse order

    // Determine if the player was correct
    if (button_pressed == led_to_light) {
        reaction_time = end_time - start_time;
        printf("You got it in %u mS\n", reaction_time);
    } else {
        printf("Missed: You pushed %d - LED was %d\n", button_pressed, led_to_light);
        // Flash the incorrect button's LEDs as feedback
        for (int i = 0; i < 5; ++i) {
            light_led_pair(button_pressed, 1);
            delay(100);
            light_led_pair(button_pressed, 0);
            delay(100);
        }
        wait_for_no_button_presses();
    }

    delay(2000); // Short delay before next round
}

#include <stdio.h>
#include <stdlib.h>
#include <sys/time.h>
#include <wiringPi.h>
#include <gertboard.h>

#define BUFFER_SIZE 40000
#define ANALOG_PIN_BASE 100

// Function to handle errors and exit
void error_exit(const char *message) {
    fprintf(stderr, "Error: %s\n", message);
    exit(EXIT_FAILURE);
}

int main() {
    int i;
    struct timeval start_time, end_time, elapsed_time;
    unsigned char *audio_buffer = NULL;

    printf("\nGertboard Audio Recorder/Player\n");
    printf("==============================\n");

    // Initialize wiringPi
    if (wiringPiSetupSys() == -1) {
        error_exit("Failed to initialize wiringPi");
    }

    // Initialize Gertboard analog functions
    if (gertboardAnalogSetup(ANALOG_PIN_BASE) == -1) {
        error_exit("Failed to initialize Gertboard analog functions");
    }

    // Allocate memory for the audio buffer
    audio_buffer = (unsigned char *)malloc(BUFFER_SIZE * sizeof(unsigned char));
    if (audio_buffer == NULL) {
        error_exit("Failed to allocate memory for audio buffer");
    }

    // Record audio
    printf("Recording audio...\n");
    gettimeofday(&start_time, NULL);

    for (i = 0; i < BUFFER_SIZE; ++i) {
        int analog_value = analogRead(ANALOG_PIN_BASE);
        if (analog_value == -1) {
            fprintf(stderr, "Warning: Failed to read analog value at index %d\n", i);
            audio_buffer[i] = 0; // Assign a default value
        } else {
            audio_buffer[i] = analog_value >> 2; // Right-shift to reduce resolution
        }
    }

    gettimeofday(&end_time, NULL);
    timersub(&end_time, &start_time, &elapsed_time);
    printf("Time taken for %d reads: %ld.%06ld seconds\n", BUFFER_SIZE, elapsed_time.tv_sec, elapsed_time.tv_usec);

    // Playback audio
    printf("Playing back audio...\n");
    gettimeofday(&start_time, NULL);

    for (i = 0; i < BUFFER_SIZE; ++i) {
        analogWrite(ANALOG_PIN_BASE, audio_buffer[i]);
    }

    gettimeofday(&end_time, NULL);
    timersub(&end_time, &start_time, &elapsed_time);
    printf("Time taken for %d writes: %ld.%06ld seconds\n", BUFFER_SIZE, elapsed_time.tv_sec, elapsed_time.tv_usec);

    // Free allocated memory
    free(audio_buffer);
    audio_buffer = NULL; // Prevent dangling pointer

    printf("Finished.\n");

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <wiringPi.h>
#include <maxdetect.h>

// Define the GPIO pin connected to the RHT03 sensor
#define RHT03_GPIO_PIN 7

// Function to safely read temperature and humidity from the RHT03 sensor
int read_rht03_data(int gpio_pin, float *temperature, float *humidity) {
    int temp_raw, humidity_raw;
    int result = readRHT03(gpio_pin, &temp_raw, &humidity_raw);

    if (result == 0) {
        return 0; // Indicate failure
    } else {
        *temperature = (float)temp_raw / 10.0;
        *humidity = (float)humidity_raw / 10.0;
        return 1; // Indicate success
    }
}

int main(void) {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed. Please check your setup.\n");
        return 1; // Exit if WiringPi initialization fails
    }

    // Set real-time priority (optional, but can improve timing accuracy)
    piHiPri(55);

    float min_temperature = 1000.0; // Initialize with a high value
    float max_temperature = -1000.0; // Initialize with a low value
    float min_humidity = 1000.0; // Initialize with a high value
    float max_humidity = -1000.0; // Initialize with a low value

    unsigned int num_good_reads = 0;
    unsigned int num_bad_reads = 0;

    // Main loop to continuously read and log data
    while (1) {
        float temperature, humidity;

        // Read data from the sensor
        if (read_rht03_data(RHT03_GPIO_PIN, &temperature, &humidity)) {
            num_good_reads++;

            // Update min/max values
            if (temperature < min_temperature) min_temperature = temperature;
            if (temperature > max_temperature) max_temperature = temperature;
            if (humidity < min_humidity) min_humidity = humidity;
            if (humidity > max_humidity) max_humidity = humidity;

            // Print the data to the console
            printf("\rGood Reads: %6u, Bad Reads: %6u | ", num_good_reads, num_bad_reads);
            printf("Temperature: %5.1f °C, Humidity: %5.1f %% | ", temperature, humidity);
            printf("Min Temp: %5.1f °C, Max Temp: %5.1f °C | ", min_temperature, max_temperature);
            printf("Min Humidity: %5.1f %%, Max Humidity: %5.1f %%", min_humidity, max_humidity);
            fflush(stdout); // Flush the output buffer
        } else {
            printf(".");
            fflush(stdout);
            num_bad_reads++;
        }

        // Delay for a short period (adjust as needed)
        delay(100); // 100 milliseconds
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <unistd.h>
#include <inttypes.h>
#include <errno.h>
#include <string.h>

// MPU6050 Register Addresses
#define MPU6050_ADDR 0x68        // I2C address of the MPU6050
#define MPU6050_REG_PWR_MGMT_1 0x6B // Power Management 1 register
#define MPU6050_REG_TEMP_OUT_H 0x41 // Temperature sensor output (high byte)
#define MPU6050_REG_ACCEL_XOUT_H 0x3B // Accelerometer X-axis output (high byte)
#define MPU6050_REG_GYRO_XOUT_H 0x43  // Gyroscope X-axis output (high byte)

// Helper macros for reading and combining high and low bytes
#define READ_HIGH_LOW(fd, high_reg, low_offset) ((int16_t)(((uint16_t)i2c_smbus_read_byte_data(fd, high_reg) << 8) | (uint16_t)i2c_smbus_read_byte_data(fd, (high_reg) + (low_offset))))

// Function to handle I2C errors
void i2c_error_handler(const char *message, int fd) {
    fprintf(stderr, "Error: %s (errno: %d, %s)\n", message, errno, strerror(errno));
    if (fd > 0) {
        close(fd);
    }
    exit(EXIT_FAILURE);
}

int main() {
    const char *i2c_device = "/dev/i2c-1"; // I2C device file
    int file_descriptor;                    // File descriptor for the I2C device

    // Open the I2C device
    if ((file_descriptor = open(i2c_device, O_RDWR)) < 0) {
        i2c_error_handler("Failed to open I2C device", 0);
    }

    // Specify the address of the slave device
    if (ioctl(file_descriptor, I2C_SLAVE, MPU6050_ADDR) < 0) {
        i2c_error_handler("Failed to acquire bus access and/or talk to slave", file_descriptor);
    }

    // Wake up the MPU6050 (clear sleep mode bit)
    if (i2c_smbus_write_byte_data(file_descriptor, MPU6050_REG_PWR_MGMT_1, 0) < 0) {
        i2c_error_handler("Failed to wake up MPU6050", file_descriptor);
    }

    // Main loop to read and print data
    while (1) {
        // Read temperature data
        int16_t temperature_raw = READ_HIGH_LOW(file_descriptor, MPU6050_REG_TEMP_OUT_H, 1);

        // Read accelerometer data
        int16_t accel_x = READ_HIGH_LOW(file_descriptor, MPU6050_REG_ACCEL_XOUT_H, 1);
        int16_t accel_y = READ_HIGH_LOW(file_descriptor, MPU6050_REG_ACCEL_XOUT_H + 2, 1);
        int16_t accel_z = READ_HIGH_LOW(file_descriptor, MPU6050_REG_ACCEL_XOUT_H + 4, 1);

        // Read gyroscope data
        int16_t gyro_x = READ_HIGH_LOW(file_descriptor, MPU6050_REG_GYRO_XOUT_H, 1);
        int16_t gyro_y = READ_HIGH_LOW(file_descriptor, MPU6050_REG_GYRO_XOUT_H + 2, 1);
        int16_t gyro_z = READ_HIGH_LOW(file_descriptor, MPU6050_REG_GYRO_XOUT_H + 4, 1);

        // Convert temperature to Celsius
        float temperature_celsius = (float)temperature_raw / 340.0f + 36.53f;

        // Print the data
        printf("Temperature: %.2f °C\n", temperature_celsius);
        printf("Accelerometer (X, Y, Z): %6d, %6d, %6d\n", accel_x, accel_y, accel_z);
        printf("Gyroscope (X, Y, Z):     %6d, %6d, %6d\n\n", gyro_x, gyro_y, gyro_z);

        sleep(1); // Delay for 1 second
    }

    close(file_descriptor); // Close the I2C device
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <unistd.h>
#include <errno.h>
#include <wiringPi.h>

// Define the GPIO pin connected to the LED (using WiringPi numbering)
#define LED_PIN 0

// Define the blink interval in milliseconds
#define BLINK_INTERVAL_MS 500

// Define the message printing interval in milliseconds
#define MESSAGE_INTERVAL_MS 600

// Thread function for blinking the LED
void *blinky_thread(void *arg) {
    (void)arg; // Suppress unused parameter warning

    while (1) {
        // Turn the LED on
        digitalWrite(LED_PIN, HIGH);
        delay(BLINK_INTERVAL_MS);

        // Turn the LED off
        digitalWrite(LED_PIN, LOW);
        delay(BLINK_INTERVAL_MS);
    }

    return NULL; // Will never reach here in normal operation
}

int main(void) {
    // Print a startup message
    printf("Raspberry Pi LED Blink with Threads\n");

    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return 1; // Exit with an error code
    }

    // Set the LED pin as output
    pinMode(LED_PIN, OUTPUT);

    // Create a thread for blinking the LED
    pthread_t blinky_thread_id;
    int result = pthread_create(&blinky_thread_id, NULL, blinky_thread, NULL);
    if (result != 0) {
        fprintf(stderr, "Failed to create blinky thread: %s\n", strerror(result));
        return 1; // Exit with an error code
    }

    // Main loop: print a message every MESSAGE_INTERVAL_MS
    while (1) {
        printf("Hello, world\n");
        delay(MESSAGE_INTERVAL_MS);
    }

    return 0; // Will never reach here in normal operation
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <ctype.h>
#include <wiringPi.h>\n#include <scrollPhat.h>

#define MIN_BRIGHTNESS 1
#define MAX_BRIGHTNESS 100

static const char *PROGRAM_NAME = "scrollphat_control";

// Function Prototypes
static void printUsage(void);
static int executeClear(void);
static int executeBrightness(int argc, char *argv[], int *argIndex);
static int executePlot(int argc, char *argv[], int *argIndex);
static int executeLine(int argc, char *argv[], int *argIndex);
static int executeLineTo(int argc, char *argv[], int *argIndex);
static int executeWait(int argc, char *argv[], int *argIndex);
static int executeSpeed(int argc, char *argv[], int *argIndex);
static int executeScroll(int argc, char *argv[], int *argIndex);
static int parseInteger(const char *str, int *value);

int main(int argc, char *argv[]) {
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "%s: Unable to initialize WiringPi: %s\n", PROGRAM_NAME, strerror(errno));
        return EXIT_FAILURE;
    }

    if (scrollPhatSetup() != 0) {
        fprintf(stderr, "%s: Unable to initialize Scroll pHAT: %s\n", PROGRAM_NAME, strerror(errno));
        return EXIT_FAILURE;
    }

    if (argc < 2) {
        fprintf(stderr, "%s: No command specified.\n", PROGRAM_NAME);
        printUsage();
        return EXIT_FAILURE;
    }

    int argIndex = 1;
    while (argIndex < argc) {
        const char *command = argv[argIndex];

        if (strcasecmp(command, "clear") == 0 || strcasecmp(command, "cls") == 0) {
            if (executeClear() != 0) return EXIT_FAILURE;
            argIndex++;
        } else if (strcasecmp(command, "bright") == 0) {
            if (executeBrightness(argc, argv, &argIndex) != 0) return EXIT_FAILURE;
        } else if (strcasecmp(command, "plot") == 0) {
            if (executePlot(argc, argv, &argIndex) != 0) return EXIT_FAILURE;
        } else if (strcasecmp(command, "line") == 0) {
            if (executeLine(argc, argv, &argIndex) != 0) return EXIT_FAILURE;
        } else if (strcasecmp(command, "lineto") == 0) {
            if (executeLineTo(argc, argv, &argIndex) != 0) return EXIT_FAILURE;
        } else if (strcasecmp(command, "wait") == 0 || strcasecmp(command, "delay") == 0) {
            if (executeWait(argc, argv, &argIndex) != 0) return EXIT_FAILURE;
        } else if (strcasecmp(command, "speed") == 0) {
            if (executeSpeed(argc, argv, &argIndex) != 0) return EXIT_FAILURE;
        } else if (strcasecmp(command, "scroll") == 0) {
            if (executeScroll(argc, argv, &argIndex) != 0) return EXIT_FAILURE;
        } else {
            fprintf(stderr, "%s: Unknown command: %s\n", PROGRAM_NAME, command);
            printUsage();
            return EXIT_FAILURE;
        }
    }

    return 0;
}

static int executeClear(void) {
    scrollPhatClear();
    return 0;
}

static int executeBrightness(int argc, char *argv[], int *argIndex) {
    if (*argIndex + 1 >= argc) {
        fprintf(stderr, "%s: Missing brightness value.\n", PROGRAM_NAME);
        printUsage();
        return 1;
    }

    int brightness;
    if (parseInteger(argv[*argIndex + 1], &brightness) != 0) {
        fprintf(stderr, "%s: Invalid brightness value: %s\n", PROGRAM_NAME, argv[*argIndex + 1]);
        return 1;
    }

    if (brightness < MIN_BRIGHTNESS || brightness > MAX_BRIGHTNESS) {
        fprintf(stderr, "%s: Brightness value must be between %d and %d.\n", PROGRAM_NAME, MIN_BRIGHTNESS, MAX_BRIGHTNESS);
        return 1;
    }

    scrollPhatIntensity(brightness);
    *argIndex += 2;
    return 0;
}

static int executePlot(int argc, char *argv[], int *argIndex) {
    if (*argIndex + 2 >= argc) {
        fprintf(stderr, "%s: Missing X and/or Y coordinate for plot command.\n", PROGRAM_NAME);
        printUsage();
        return 1;
    }

    int x, y;
    if (parseInteger(argv[*argIndex + 1], &x) != 0) {
        fprintf(stderr, "%s: Invalid X coordinate: %s\n", PROGRAM_NAME, argv[*argIndex + 1]);
        return 1;
    }
    if (parseInteger(argv[*argIndex + 2], &y) != 0) {
        fprintf(stderr, "%s: Invalid Y coordinate: %s\n", PROGRAM_NAME, argv[*argIndex + 2]);
        return 1;
    }

    scrollPhatPoint(x, y, 1);
    scrollPhatUpdate();
    *argIndex += 3;
    return 0;
}

static int executeLine(int argc, char *argv[], int *argIndex) {
    if (*argIndex + 4 >= argc) {
        fprintf(stderr, "%s: Missing coordinates for line command.\n", PROGRAM_NAME);
        printUsage();
        return 1;
    }

    int x1, y1, x2, y2;
    if (parseInteger(argv[*argIndex + 1], &x1) != 0 ||
        parseInteger(argv[*argIndex + 2], &y1) != 0 ||
        parseInteger(argv[*argIndex + 3], &x2) != 0 ||
        parseInteger(argv[*argIndex + 4], &y2) != 0) {
        fprintf(stderr, "%s: Invalid coordinate for line command.\n", PROGRAM_NAME);
        return 1;
    }

    scrollPhatLine(x1, y1, x2, y2, 1);
    scrollPhatUpdate();
    *argIndex += 5;
    return 0;
}

static int executeLineTo(int argc, char *argv[], int *argIndex) {
    if (*argIndex + 2 >= argc) {
        fprintf(stderr, "%s: Missing coordinates for lineto command.\n", PROGRAM_NAME);
        printUsage();
        return 1;
    }

    int x, y;
    if (parseInteger(argv[*argIndex + 1], &x) != 0 ||
        parseInteger(argv[*argIndex + 2], &y) != 0) {
        fprintf(stderr, "%s: Invalid coordinate for lineto command.\n", PROGRAM_NAME);
        return 1;
    }

    scrollPhatLineTo(x, y, 1);
    scrollPhatUpdate();
    *argIndex += 3;
    return 0;
}

static int executeWait(int argc, char *argv[], int *argIndex) {
    if (*argIndex + 1 >= argc) {
        fprintf(stderr, "%s: Missing wait time.\n", PROGRAM_NAME);
        printUsage();
        return 1;
    }

    int waitTime;
    if (parseInteger(argv[*argIndex + 1], &waitTime) != 0) {
        fprintf(stderr, "%s: Invalid wait time: %s\n", PROGRAM_NAME, argv[*argIndex + 1]);
        return 1;
    }

    delay(waitTime * 100);
    scrollPhatUpdate();
    *argIndex += 2;
    return 0;
}

static int executeSpeed(int argc, char *argv[], int *argIndex) {
    if (*argIndex + 1 >= argc) {
        fprintf(stderr, "%s: Missing speed value.\n", PROGRAM_NAME);
        printUsage();
        return 1;
    }

    int speed;
    if (parseInteger(argv[*argIndex + 1], &speed) != 0) {
        fprintf(stderr, "%s: Invalid speed value: %s\n", PROGRAM_NAME, argv[*argIndex + 1]);
        return 1;
    }

    scrollPhatPrintSpeed(speed);
    *argIndex += 2;
    return 0;
}

static int executeScroll(int argc, char *argv[], int *argIndex) {
    if (*argIndex + 1 >= argc) {
        fprintf(stderr, "%s: Missing scroll text.\n", PROGRAM_NAME);
        printUsage();
        return 1;
    }

    scrollPhatPuts(argv[*argIndex + 1]);
    *argIndex += 2;
    return 0;
}

static int parseInteger(const char *str, int *value) {
    char *endptr;
    long val = strtol(str, &endptr, 10);
    if (endptr == str || *endptr != '\0' || ((val == LONG_MIN || val == LONG_MAX) && errno == ERANGE) || val > INT_MAX || val < INT_MIN) {
        return 1; // Error: Not a valid integer
    }
    *value = (int)val;
    return 0; // Success
}

static void printUsage(void) {
    fprintf(stderr, "Usage: %s command [parameters] ...\n", PROGRAM_NAME);
    fprintf(stderr, "Commands:\n");
    fprintf(stderr, "  clear/cls        - Clear the display\n");
    fprintf(stderr, "  bright N         - Set display brightness; %d-%d\n", MIN_BRIGHTNESS, MAX_BRIGHTNESS);
    fprintf(stderr, "  plot X Y         - Set a single pixel at location X Y; 0-10, 0-4\n");
    fprintf(stderr, "  line X1 Y1 X2 Y2 - Draw a line from the 2 points\n");
    fprintf(stderr, "  lineto X2 Y2     - Draw a line from the last point to the new one\n");
    fprintf(stderr, "  wait/delay N     - Wait for N 10ths seconds\n");
    fprintf(stderr, "  speed N          - Set scrolling speed (cps)\n");
    fprintf(stderr, "  scroll S         - Scroll the given string\n");
    fprintf(stderr, "\n");
    fprintf(stderr, "Example: %s plot 0 0 wait 50 scroll \"  Hello  \"\n", PROGRAM_NAME);
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <fcntl.h>
#include <termios.h>

#define SERIAL_PORT "/dev/ttyAMA0"
#define BAUD_RATE B115200

int main() {
    int serial_fd;
    struct termios serial_options;

    // Open the serial port
    serial_fd = open(SERIAL_PORT, O_RDWR | O_NOCTTY | O_NDELAY);
    if (serial_fd == -1) {
        fprintf(stderr, "Error opening serial port %s: %s\n", SERIAL_PORT, strerror(errno));
        return EXIT_FAILURE;
    }

    // Get the current serial port options
    if (tcgetattr(serial_fd, &serial_options) != 0) {
        fprintf(stderr, "Error getting serial port options: %s\n", strerror(errno));
        close(serial_fd);
        return EXIT_FAILURE;
    }

    // Set the baud rate
    cfsetispeed(&serial_options, BAUD_RATE);
    cfsetospeed(&serial_options, BAUD_RATE);

    // Configure the serial port
    serial_options.c_cflag &= ~PARENB; // No parity
    serial_options.c_cflag &= ~CSTOPB; // 1 stop bit
    serial_options.c_cflag &= ~CSIZE;  // Clear size bits
    serial_options.c_cflag |= CS8;   // 8 data bits
    serial_options.c_cflag &= ~CRTSCTS; // Disable hardware flow control
    serial_options.c_cflag |= CREAD | CLOCAL; // Enable read and ignore control lines

    serial_options.c_iflag &= ~(IXON | IXOFF | IXANY); // Disable software flow control
    serial_options.c_iflag &= ~(IGNBRK | BRKINT | PARMRK | ISTRIP | INLCR | IGNCR | ICRNL); //Disable special handling of received bytes

    serial_options.c_oflag &= ~OPOST; //Raw output

    serial_options.c_lflag &= ~ICANON; // Disable canonical mode
    serial_options.c_lflag &= ~ECHO;   // Disable echo
    serial_options.c_lflag &= ~ECHOE;  // Disable erasure
    serial_options.c_lflag &= ~ECHONL; // Disable new-line echo
    serial_options.c_lflag &= ~ISIG;   // Disable interpretation of INTR, QUIT and SUSP

    serial_options.c_cc[VMIN] = 0;  // Read at least 0 characters
    serial_options.c_cc[VTIME] = 10; // Wait for up to 1 second (10 deciseconds)

    // Apply the serial port options
    if (tcsetattr(serial_fd, TCSANOW, &serial_options) != 0) {
        fprintf(stderr, "Error setting serial port options: %s\n", strerror(errno));
        close(serial_fd);
        return EXIT_FAILURE;
    }

    // Main loop: read and print data
    unsigned char read_buffer[256];
    ssize_t bytes_read;

    while (1) {
        bytes_read = read(serial_fd, read_buffer, sizeof(read_buffer));
        if (bytes_read > 0) {
            // Print the received data
            for (ssize_t i = 0; i < bytes_read; ++i) {
                putchar(read_buffer[i]);
            }
            fflush(stdout); // Flush the output buffer
        } else if (bytes_read < 0) {
            fprintf(stderr, "Error reading from serial port: %s\n", strerror(errno));
            break; // Exit the loop on error
        } else {
            //No data received, sleep to avoid busy-waiting
            usleep(10000); // Sleep for 10ms
        }
    }

    // Close the serial port
    close(serial_fd);

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <wiringPi.h>
#include <wiringSerial.h>

#define SERIAL_PORT "/dev/ttyAMA0" // Define serial port
#define BAUD_RATE 115200          // Define baud rate

// Function to safely open the serial port
int safeSerialOpen(const char *device, int baud)
{
    int fileDescriptor = serialOpen(device, baud);
    if (fileDescriptor < 0)
    {
        fprintf(stderr, "Error opening serial device %s: %s\n", device, strerror(errno));
        return -1; // Return -1 to indicate failure
    }
    return fileDescriptor;
}

// Function to safely initialize wiringPi
int safeWiringPiSetup(void)
{
    if (wiringPiSetup() == -1)
    {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return -1; // Return -1 to indicate failure
    }
    return 0;
}

int main()
{
    int serialFileDescriptor; // File descriptor for the serial port
    int loopCount;             // Loop counter
    unsigned int nextTime;    // Next time to send data

    // Initialize wiringPi
    if (safeWiringPiSetup() == -1)
    {
        return 1; // Exit if wiringPi initialization fails
    }

    // Open the serial port
    serialFileDescriptor = safeSerialOpen(SERIAL_PORT, BAUD_RATE);
    if (serialFileDescriptor == -1)
    {
        return 1; // Exit if serial port opening fails
    }

    nextTime = millis() + 300; // Initialize nextTime

    // Main loop to send and receive data
    for (loopCount = 0; loopCount < 256;)
    {
        // Send data every 300 milliseconds
        if (millis() > nextTime)
        {
            printf("\nOut: %3d: ", loopCount);
            fflush(stdout);
            serialPutchar(serialFileDescriptor, loopCount);
            nextTime += 300;
            ++loopCount;
        }

        delay(3); // Small delay to avoid busy-waiting

        // Read available data from the serial port
        while (serialDataAvail(serialFileDescriptor))
        {
            printf(" -> %3d", serialGetchar(serialFileDescriptor));
            fflush(stdout);
        }
    }

    printf("\nTest complete.\n");
    serialClose(serialFileDescriptor); //close serial port
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <string.h>
#include <unistd.h>
#include <signal.h>
#include <wiringPi.h>
#include <softServo.h>

#define NUM_SERVOS 8
#define BASE_PIN 0

static volatile int keepRunning = 1;
static int servoPins[NUM_SERVOS] = {0, 1, 2, 3, 4, 5, 6, 7}; // GPIO pins for servos

// Signal handler to gracefully exit the program
void interruptHandler(int signal)
{
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
    keepRunning = 0;
}

int initializeWiringPi()
{
    if (wiringPiSetup() == -1)
    {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

int initializeSoftServo()
{
    int result = softServoSetup(BASE_PIN, servoPins[0], servoPins[1], servoPins[2], servoPins[3], servoPins[4], servoPins[5], servoPins[6], servoPins[7]);
    if (result != 0) {
        fprintf(stderr, "Soft Servo setup failed. Check pin configuration.\n");
        return -1;
    }
    return 0;
}

int main()
{
    // Register the interrupt handler for Ctrl+C
    signal(SIGINT, interruptHandler);

    if (initializeWiringPi() != 0) {
        return 1;
    }

    if (initializeSoftServo() != 0) {
        return 1;
    }

    printf("Servo control program started. Press Ctrl+C to exit.\n");

    // Initial servo positions (example)
    for (int i = 0; i < NUM_SERVOS; i++) {
        softServoWrite(i, 1500); // Set all servos to center position
    }

    while (keepRunning)
    {
        // Example servo control loop - sweeps servo 0
        for (int pos = 500; pos <= 2500; pos += 10) {
            softServoWrite(0, pos);
            delay(5);
            if (!keepRunning) break; // Check for exit signal
        }
        if (!keepRunning) break;
        for (int pos = 2500; pos >= 500; pos -= 10) {
            softServoWrite(0, pos);
            delay(5);
            if (!keepRunning) break; // Check for exit signal
        }

        delay(100); // Small delay between sweeps
    }

    // Optionally, disable servos or set to a safe position before exiting
    for (int i = 0; i < NUM_SERVOS; i++) {
        softServoWrite(i, 0); // Disable servo
    }

    printf("Exiting program.\n");
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <errno.h>
#include <string.h>
#include <unistd.h>
#include <signal.h>

#include <wiringPi.h>
#include <softPwm.h>

// Constants
#define PWM_RANGE       100
#define NUM_LEDS        8
#define DELAY_MS        10

// Pin mapping (BCM numbering)
const int led_gpio_pins[NUM_LEDS] = {17, 18, 27, 22, 23, 24, 25, 4};

// Global variables
volatile sig_atomic_t program_running = 1;

// Function prototypes
void cleanup(int signal);
int initialize_leds(void);
void chasing_lights(void);

// Signal handler for clean exit
void cleanup(int signal)
{
    (void)signal; // Suppress unused parameter warning
    printf("\nCleaning up and exiting...\n");
    program_running = 0;

    // Disable PWM and set pins to input to avoid leaving LEDs on
    for (int i = 0; i < NUM_LEDS; ++i)
    {
        softPwmStop(led_gpio_pins[i]);
        pinMode(led_gpio_pins[i], INPUT); // Set as input to avoid leaving them on
    }

    wiringPiSetup();

    exit(0);
}

// Initialize LEDs with software PWM
int initialize_leds(void)
{
    int pin;
    for (int i = 0; i < NUM_LEDS; ++i)
    {
        pin = led_gpio_pins[i];
        if (softPwmCreate(pin, 0, PWM_RANGE) != 0)
        {
            fprintf(stderr, "Error creating PWM on pin %d: %s\n", pin, strerror(errno));
            return -1;
        }
        printf("LED %d initialized on GPIO %d\n", i, pin);
    }
    return 0;
}

// Chasing lights effect
void chasing_lights(void)
{
    int values[NUM_LEDS] = {0, 25, 50, 75, 100, 75, 50, 25};
    int i, j, temp;

    while (program_running)
    {
        for (i = 0; i < NUM_LEDS; ++i)
        {
            softPwmWrite(led_gpio_pins[i], values[i]);
        }

        delay(50);

        // Rotate the values array for the chasing effect
        temp = values[0];
        for (j = 0; j < NUM_LEDS - 1; ++j)
        {
            values[j] = values[j + 1];
        }
        values[NUM_LEDS - 1] = temp;
    }
}

int main(void)
{
    // Setup signal handler for Ctrl+C
    signal(SIGINT, cleanup);

    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1)
    {
        fprintf(stderr, "wiringPiSetupGpio failed: %s\n", strerror(errno));
        return 1;
    }

    printf("Raspberry Pi Soft PWM LED Control\n");

    // Initialize LEDs
    if (initialize_leds() != 0)
    {
        fprintf(stderr, "LED initialization failed.\n");
        cleanup(0); // Clean up before exiting
        return 1;
    }

    // Run the chasing lights effect
    chasing_lights();

    cleanup(0);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <wiringPi.h>
#include <softTone.h>

// Define the GPIO pin connected to the piezo speaker
#define PIEZO_PIN 3

// Define the notes in the musical scale (frequencies in Hz)
const int musicalScale[] = { 262, 294, 330, 349, 392, 440, 494, 523 }; // C4, D4, E4, F4, G4, A4, B4, C5

// Number of notes in the scale
#define SCALE_SIZE (sizeof(musicalScale) / sizeof(musicalScale[0]))

// Function to handle errors and exit
void errorExit(const char *message) {
  fprintf(stderr, "Error: %s - %s\n", message, strerror(errno));
  exit(EXIT_FAILURE);
}

int main() {
  // Initialize wiringPi
  if (wiringPiSetup() == -1) {
    errorExit("wiringPiSetup failed");
  }

  // Initialize softTone on the specified pin
  if (softToneCreate(PIEZO_PIN) != 0) {
    errorExit("softToneCreate failed");
  }

  printf("Playing musical scale on pin %d...\n", PIEZO_PIN);

  // Main loop to play the scale repeatedly
  while (1) {
    // Iterate through each note in the scale
    for (int i = 0; i < SCALE_SIZE; ++i) {
      printf("Playing note %d: %d Hz\n", i + 1, musicalScale[i]);
      softToneWrite(PIEZO_PIN, musicalScale[i]); // Play the note
      delay(500); // Delay for 500 milliseconds
    }
  }

  // The program will run indefinitely, so this return statement is never reached.
  // However, it's good practice to include it.
  return EXIT_SUCCESS;
}

