// Constants for test parameters
#define FAST_COUNT 10000000
#define SLOW_COUNT  1000000
#define PASSES        5

// Function to measure the execution time
double time_diff(struct timespec start, struct timespec end)
{
    return (end.tv_sec - start.tv_sec) + (end.tv_nsec - start.tv_nsec) / 1e9;
}

// Function to perform the speed test for a given pin and iteration count
int speedTest(int gpioPin, int maxCount, const char *testName)
{
    int count, i;
    double totalTime = 0.0;
    struct timespec startTime, endTime;

    printf("\n%s: (%8d iterations)\n", testName, maxCount);

    for (i = 0; i < PASSES; ++i)
    {
        if (clock_gettime(CLOCK_MONOTONIC, &startTime) == -1) {
            fprintf(stderr, "Error getting start time: %s\n", strerror(errno));
            return 1; // Indicate failure
        }

        for (count = 0; count < maxCount; ++count)
        {
            digitalWrite(gpioPin, HIGH); // Set the pin high
            digitalWrite(gpioPin, LOW);  // Set the pin low
        }

        if (clock_gettime(CLOCK_MONOTONIC, &endTime) == -1) {
            fprintf(stderr, "Error getting end time: %s\n", strerror(errno));
            return 1; // Indicate failure
        }

        double elapsedTime = time_diff(startTime, endTime);
        printf(" %9.6f", elapsedTime);
        fflush(stdout);
        totalTime += elapsedTime;
    }

    double avgTime = totalTime / PASSES;
    printf(". Avg: %9.6fs", avgTime);
    int perSec = (int)((double)maxCount / avgTime);
    printf(": %9d/sec\n", perSec);

    return 0; // Indicate success
}

int main(void)
{
    printf("Raspberry Pi wiringPi GPIO speed test program\n");
    printf("=============================================\n");

    int result;

    // Native wiringPi method
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed, exiting.\n");
        return 1;
    }
    pinMode(0, OUTPUT);
    result = speedTest(0, FAST_COUNT, "Native wiringPi method");
    if (result != 0) return result;

    // Native GPIO method
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "wiringPiSetupGpio failed, exiting.\n");
        return 1;
    }
    pinMode(17, OUTPUT);
    result = speedTest(17, FAST_COUNT, "Native GPIO method");
    if (result != 0) return result;

    // Physical pin GPIO method
    if (wiringPiSetupPhys() == -1) {
        fprintf(stderr, "wiringPiSetupPhys failed, exiting.\n");
        return 1;
    }
    pinMode(11, OUTPUT);
    result = speedTest(11, FAST_COUNT, "Physical pin GPIO method");
    if (result != 0) return result;

    // /sys/class/gpio method
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "wiringPiSetupSys failed, exiting.\n");
