#include <gertboard.h>

// Constants
#define ADC_BASE_PIN 100  // Base pin for Gertboard ADC
#define NUM_CHANNELS 2   // Number of ADC channels used
#define VREF 3.3          // Reference voltage of the ADC
#define ADC_RESOLUTION 1024 // ADC resolution (2^10)
#define LM35_SCALE_FACTOR 100.0 // LM35 output: 10mV/°C, so 1V/100°C

// Function prototypes
int initialize_wiringpi();
float read_temperature(int channel);

int main() {
    // Initialize wiringPi and Gertboard
    if (initialize_wiringpi() != 0) {
        fprintf(stderr, "Failed to initialize wiringPi. Exiting.\n");
        return 1;
    }

    gertboardAnalogSetup(ADC_BASE_PIN);

    printf("\nGertboard Thermometer Demo\n");
    printf("==========================\n\n");
    printf("| Channel | Voltage (V) | Temperature (°C) |\n");
    printf("|---------|-------------|--------------------|\n");

    while (1) {
        for (int channel = 0; channel < NUM_CHANNELS; channel++) {
            float temperature = read_temperature(channel);
            printf("| %7d | %11.3f | %18.1f |\n", channel, temperature / LM35_SCALE_FACTOR, temperature);
        }
        printf("\r"); // Carriage return to overwrite the previous line
        fflush(stdout); // Flush the output buffer to ensure immediate display
        usleep(200000);   // Wait for 0.2 seconds (200ms) for the next reading
    }

    return 0;
}

// Function to initialize wiringPi
int initialize_wiringpi() {
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

// Function to read temperature from a given ADC channel
float read_temperature(int channel) {
    int adc_value;
    float voltage;

    // Read the analog value from the specified channel
    adc_value = analogRead(ADC_BASE_PIN + channel);

    // Check for invalid ADC readings
    if (adc_value < 0 || adc_value > 1023) {
        fprintf(stderr, "Error: Invalid ADC reading for channel %d: %d\n", channel, adc_value);
        return -1000.0; // Return a large negative value to indicate an error
    }

    // Convert ADC value to voltage
    voltage = ((float)adc_value / (ADC_RESOLUTION - 1)) * VREF;

    // Convert voltage to temperature (LM35 outputs 10mV/°C)
    return voltage * LM35_SCALE_FACTOR;
}

