// Global flag to handle Ctrl+C
volatile sig_atomic_t terminate = 0;

// Signal handler for Ctrl+C
void sigint_handler(int signal)
{
    terminate = 1;
    printf("\nCtrl+C detected. Exiting gracefully...\n");
}

// Function to handle errors and exit
void error_exit(const char *message)
{
    fprintf(stderr, "Error: %s: %s\n", message, strerror(errno));
    scrollPhatClear();
    scrollPhatUpdate();
    scrollPhatIntensity(10); // Reset intensity
    scrollPhatClose(); // Properly close the device
    exit(EXIT_FAILURE);
}

// Function to display a prompt and wait for user input
void prompt(const char *message)
{
    printf("    %s. Press ENTER: ", message);
    fflush(stdout);
    while (getchar() != '\n'); // Consume the entire input buffer
}

// Function to perform basic display tests
void basic_display_tests()
{
    int x, y;

    prompt("Display ought to be blank");

    // Light all pixels one by one
    for (y = 0; y < 5; ++y)
    {
        for (x = 0; x < 12; ++x)
        {
            if (scrollPhatPoint(x, y, 1) != 0) {
              error_exit("Failed to set pixel");
            }
        }
    }
    if (scrollPhatUpdate() != 0) {
      error_exit("Failed to update display");
    }

    prompt("Display ought to be all lit-up");

    // Draw a rectangle
    if (scrollPhatClear() != 0) {
      error_exit("Failed to clear display");
    }
    if (scrollPhatRectangle(0, 0, 11, 4, 1, 0) != 0) {
      error_exit("Failed to draw rectangle");
    }
    if (scrollPhatUpdate() != 0) {
      error_exit("Failed to update display");
    }

    prompt("There should now be a rectangle round the outside");

    // Draw diagonal lines
    if (scrollPhatLine(0, 0, 11, 4, 1) != 0) {
      error_exit("Failed to draw line");
    }
    if (scrollPhatLine(0, 4, 11, 0, 1) != 0) {
      error_exit("Failed to draw line");
    }
    if (scrollPhatUpdate() != 0) {
      error_exit("Failed to update display");
    }

    prompt("Diagonal lines");

    // Test intensity levels
    if (scrollPhatIntensity(1) != 0) {
      error_exit("Failed to set intensity");
    }

    prompt("Minimum brightness");

    if (scrollPhatIntensity(100) != 0) {
      error_exit("Failed to set intensity");
    }

    prompt("Maximum brightness");

    if (scrollPhatIntensity(10) != 0) {
      error_exit("Failed to set intensity");
    }

    prompt("Default brightness");

    if (scrollPhatClear() != 0) {
      error_exit("Failed to clear display");
    }
}

// Function to scroll text across the display
void message_test()
{
    printf("    Message Test...Press Ctrl-C to exit: ");
    fflush(stdout);

    if (scrollPhatPrintSpeed(DEFAULT_SCROLL_SPEED) != 0) {
      error_exit("Failed to set print speed");
    }

    while (!terminate)
    {
        if (scrollPhatPuts("  Welcome to the scroll phat from Pimoroni  ") != 0) {
          fprintf(stderr, "Scroll Phat puts error, continuing...");
