    printf("========================\n");

    // Initialize Scroll pHAT
    if (scrollPhatSetup() != 0)
    {
        error_exit("Unable to initialize the scrollPhat");
    }

    printf("-> Scroll Phat initialized OK\n");
    printf("... Basic display tests.\n\n");

    // Set up signal handler for Ctrl+C
    signal(SIGINT, sigint_handler);

