    printf("========================\n");
    printf("| Channel 0 | Channel 1 |\n");

    // Main loop to continuously read and display voltages
    while (1) {
        // Read voltage from channel 0
        double voltage_channel_0 = read_voltage(0);

        // Read voltage from channel 1
        double voltage_channel_1 = read_voltage(1);

        // Print the voltages with formatting
        printf("|    %6.3f |    %6.3f |\r", voltage_channel_0, voltage_channel_1);
        fflush(stdout); // Ensure output is displayed immediately

        // Delay for a short period
        usleep(100000); // 100ms delay
    }

    return EXIT_SUCCESS;
}

// Function to initialize Gertboard and wiringPi
int initialize_gertboard() {
    // Initialize wiringPi using the system call method
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "Error initializing wiringPi.\n");
        return -1;
    }

    // Initialize the Gertboard analog hardware
    if (gertboardAnalogSetup(ADC_BASE_PIN) == -1) {
        fprintf(stderr, "Error initializing Gertboard analog hardware.\n");
        return -1;
    }

    return 0; // Success
}

// Function to read voltage from a specified channel
double read_voltage(int channel) {
    // Calculate the ADC pin number based on the channel
    int adc_pin = ADC_BASE_PIN + channel;

    // Read the analog value from the specified channel
    int adc_value = analogRead(adc_pin);

    // Check for errors during analog read
    if (adc_value == -1) {
        fprintf(stderr, "Error reading analog value from channel %d.\n", channel);
        return -1.0; // Indicate an error with a negative voltage
    }

    // Convert the ADC value to a voltage
    double voltage = ((double)adc_value / ADC_MAX_VALUE) * VREF;

    return voltage;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <wiringPi.h>
#include <pcf8591.h>

// Constants
#define LED_PIN         1       // GPIO pin for the on-board LED
#define PCF8591_BASE    120     // Base address for the PCF8591 chip
#define PCF8591_ADDRESS 0x48    // I2C address of the PCF8591 chip
#define NUM_ANALOG_PINS 4       // Number of analog input pins on PCF8591
#define VREF            3.3     // Reference voltage of the ADC (in volts)
#define ADC_MAX_VALUE   255.0   // Maximum ADC value (2^8 - 1)

// Function prototypes
int initialize();
float readVoltage(int pin);
void cleanup();

int main(void) {
    // Initialize WiringPi and PCF8591
    if (initialize() != 0) {
        fprintf(stderr, "Initialization failed. Exiting.\n");
        return 1;
    }

    printf("Raspberry Pi - Quick2Wire Voltmeter\n");

    // Main loop: read and display voltages continuously
    while (1) {
        // Read and print voltages from each analog pin
        for (int pin = 0; pin < NUM_ANALOG_PINS; ++pin) {
            float voltage = readVoltage(pin);
            printf("  %5.2f", voltage);
        }
        printf("\r"); // Carriage return to overwrite the previous line
        fflush(stdout); // Flush output buffer to ensure immediate display

        // Toggle the LED and delay for a short period
        digitalWrite(LED_PIN, !digitalRead(LED_PIN));
        delay(100); // Reduced delay for better responsiveness
    }

    // Code will never reach here in normal operation due to the infinite loop
    cleanup(); //Cleanup resources before exiting
    return 0;
}

// Initializes WiringPi and PCF8591
int initialize() {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed.\n");
        return -1;
    }

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);

    // Initialize PCF8591
    pcf8591Setup(PCF8591_BASE, PCF8591_ADDRESS);

    return 0;
}

// Reads the voltage from the specified analog pin
float readVoltage(int pin) {
    // Read the analog value from the PCF8591
    int analogValue = analogRead(PCF8591_BASE + pin);

    // Convert the analog value to voltage
    float voltage = (float)analogValue * VREF / ADC_MAX_VALUE;

    return voltage;
}

// Cleanup resources
void cleanup() {
    // Set LED pin to low (off)
    digitalWrite(LED_PIN, LOW);
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <sys/time.h>
#include <wiringPi.h>
#include <gertboard.h>

// Constants
#define SAMPLE_RATE 1000  // Samples per second
#define FILTER_DEPTH 1000  // Number of samples for low-pass filter
#define DISPLAY_SAMPLES 128 // Number of samples to average for display
#define ANALOG_CHANNEL 0   // Analog channel on Gertboard
#define LED_COUNT 8          // Number of LEDs for display

// Global Variables
static int16_t audioBuffer[FILTER_DEPTH]; // Circular buffer for audio samples
static volatile uint16_t bufferIndex = 0; // Index to the current position in the audio buffer
static int16_t quietLevel = 0;          // DC offset of the input signal

// Function Prototypes
static bool initialize();
static void calibrate();
static int16_t readAnalogInput(uint8_t channel);
static void updateAudioBuffer(int16_t sample);
static int16_t calculateAverageLevel(uint16_t numSamples);
static void displayLevel(int16_t level);
static unsigned int getCurrentMicros();

int main() {
    if (!initialize()) {
        fprintf(stderr, "Initialization failed. Exiting.\n");
        return EXIT_FAILURE;
    }

    calibrate();

    printf("VU Meter running...\n");

    while (true) {
        // Sample the audio input
        int16_t audioSample = readAnalogInput(ANALOG_CHANNEL);

        // Update the circular buffer
        updateAudioBuffer(audioSample);

        // Calculate the average audio level
        int16_t averageLevel = calculateAverageLevel(DISPLAY_SAMPLES);

        // Display the level on the LEDs
        displayLevel(averageLevel);
    }

    return EXIT_SUCCESS;
}

// Initializes the Raspberry Pi and Gertboard
static bool initialize() {
    printf("Initializing...");
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi initialization failed.\n");
        return false;
    }

    // Initialize Gertboard SPI
    if (gertboardSPISetup() == -1) {
        fprintf(stderr, "Gertboard SPI initialization failed.\n");
        return false;
    }

    // Configure LED pins as output
    for (int i = 0; i < LED_COUNT; ++i) {
        pinMode(i, OUTPUT);
    }
    printf("Done.\n");
    return true;
}

// Calibrates the VU meter by measuring the quiet level
static void calibrate() {
    printf("Calibrating... (stay quiet)\n");
    const int calibrationSamples = FILTER_DEPTH;
    int32_t sum = 0;

    // Discard initial samples to let ADC settle
    for (int i = 0; i < 100; ++i) {
        readAnalogInput(ANALOG_CHANNEL);
        delayMicroseconds(1000); // Short delay
    }

    // Read calibration samples
    for (int i = 0; i < calibrationSamples; ++i) {
        sum += readAnalogInput(ANALOG_CHANNEL);
        delayMicroseconds(1000); // Maintain sample rate
    }

    // Calculate the average quiet level
    quietLevel = (int16_t)(sum / calibrationSamples);

    printf("Calibration complete. Quiet level: %d\n", quietLevel);
}

// Reads the analog input from the specified channel on the Gertboard
static int16_t readAnalogInput(uint8_t channel) {
    return gertboardAnalogRead(channel);
}

// Updates the audio buffer with a new sample
static void updateAudioBuffer(int16_t sample) {
    audioBuffer[bufferIndex] = sample;
    bufferIndex = (bufferIndex + 1) % FILTER_DEPTH;
}

// Calculates the average audio level from the audio buffer
static int16_t calculateAverageLevel(uint16_t numSamples) {
    int32_t sum = 0;
    uint16_t start = bufferIndex;

    for (uint16_t i = 0; i < numSamples; ++i) {
        // Calculate index, wrapping around the circular buffer
        uint16_t index = (start + FILTER_DEPTH - numSamples + i) % FILTER_DEPTH;
        sum += abs(audioBuffer[index] - quietLevel); // Use absolute difference from quiet level
    }

    return (int16_t)(sum / numSamples);
}

// Displays the audio level on the LEDs
static void displayLevel(int16_t level) {
    // Scale the audio level to the number of LEDs
    // Adjust scaling factor as needed for sensitivity
    int scaledLevel = level / 50; // Experiment with different scaling factors

    // Ensure the scaled level is within the valid range
    if (scaledLevel < 0) {
        scaledLevel = 0;
    } else if (scaledLevel > LED_COUNT) {
        scaledLevel = LED_COUNT;
    }

    // Set the LEDs
    for (int i = 0; i < LED_COUNT; ++i) {
        digitalWrite(i, (i < scaledLevel) ? HIGH : LOW);
    }
}

// Gets the current time in microseconds
static unsigned int getCurrentMicros() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return tv.tv_sec * 1000000 + tv.tv_usec;
}

