// Constants
#define BUTTON_GPIO_PIN 17          // BCM GPIO pin for the button
#define DEBOUNCE_DELAY_MS 100       // Debounce delay in milliseconds
#define INTERRUPT_PRIORITY 50       // Priority of the interrupt thread (1-99, higher is more important)

// Global variables
static volatile uint32_t interrupt_count = 0; // Counter for interrupts
static pthread_mutex_t interrupt_mutex = PTHREAD_MUTEX_INITIALIZER; // Mutex for interrupt counter
static volatile uint32_t last_interrupt_time = 0; // Last interrupt time

// Function prototypes
void* interrupt_handler_thread(void* arg);
int initialize_gpio(int pin);


// Interrupt handler thread function
void* interrupt_handler_thread(void* arg) {
    (void)arg; // Suppress unused parameter warning

    if (piHiPri(INTERRUPT_PRIORITY) != 0) {
        fprintf(stderr, "Error: Failed to set thread priority: %s\n", strerror(errno));
        pthread_exit(NULL);
    }

    while (true) {
        if (waitForInterrupt(BUTTON_GPIO_PIN, -1) < 0) {
            fprintf(stderr, "Error: waitForInterrupt failed: %s\n", strerror(errno));
            delay(100); // Prevent busy-waiting on error
            continue;
        }

        uint32_t current_time = millis();
        if (current_time - last_interrupt_time > DEBOUNCE_DELAY_MS) {
            // Debounced interrupt
            pthread_mutex_lock(&interrupt_mutex);
            interrupt_count++;
            pthread_mutex_unlock(&interrupt_mutex);
            last_interrupt_time = current_time;

            // Wait for button release (optional, but prevents multiple counts from a single press)
            while (digitalRead(BUTTON_GPIO_PIN) == LOW) {
                delay(1); // Small delay to avoid busy-waiting
            }
        }
    }
    return NULL;
}

// Initialize GPIO pin for interrupt
int initialize_gpio(int pin) {
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "Error: wiringPiSetup failed: %s\n", strerror(errno));
        return -1;
    }

    pinMode(pin, INPUT);
    pullUpDnControl(pin, PUD_UP); // Enable pull-up resistor

    // Export GPIO pin for edge detection (using system calls for broader compatibility)
    char command[64];
    snprintf(command, sizeof(command), "gpio edge %d falling", pin);
    if (system(command) != 0) {
        fprintf(stderr, "Error: Failed to set edge detection for GPIO %d\n", pin);
        return -1;
    }

    return 0;
}

int main() {
    pthread_t interrupt_thread;
    int return_code = EXIT_FAILURE;
    uint32_t previous_count = 0;

    // Initialize GPIO
    if (initialize_gpio(BUTTON_GPIO_PIN) != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return EXIT_FAILURE;
    }

    // Create interrupt handler thread
    if (pthread_create(&interrupt_thread, NULL, interrupt_handler_thread, NULL) != 0) {
        fprintf(stderr, "Error: Failed to create interrupt thread: %s\n", strerror(errno));
        return EXIT_FAILURE;
    }

    printf("Interrupt counter started. Press button on GPIO %d to increment counter.\n", BUTTON_GPIO_PIN);

    // Main loop to print the interrupt count
    while (true) {
        delay(1000);
        pthread_mutex_lock(&interrupt_mutex);
        uint32_t current_count = interrupt_count;
        pthread_mutex_unlock(&interrupt_mutex);

        if (current_count != previous_count) {
            printf("Interrupt count: %u\n", current_count);
            previous_count = current_count;
        }
    }

    // Cleanup (This part is unreachable in this example but good practice)
    pthread_cancel(interrupt_thread);
    pthread_join(interrupt_thread, NULL);
    pthread_mutex_destroy(&interrupt_mutex);

    return return_code;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <errno.h>
#include <wiringPi.h>

// Define GPIO pins (using BCM numbering)
#define TEMP_SENSOR_PIN 17 // Example: GPIO17
#define FAN_PIN 18        // Example: GPIO18

// Temperature threshold in Celsius
#define TEMPERATURE_THRESHOLD 30

// Function prototypes
int read_temperature();
int control_fan(int temperature);
int initialize_gpio();

/**
 * @brief Reads a mock temperature value.
 *
 * @return The mock temperature in Celsius.
 */
int read_temperature()
{
    // Seed the random number generator with the current time
    unsigned int seed = time(NULL);
    srand(seed);

    // Generate a random temperature between 10 and 40 degrees Celsius
    int temperature = (rand() % 31) + 10;

    return temperature;
}

/**
 * @brief Controls the fan based on the given temperature.
 *
 * @param temperature The temperature in Celsius.
 * @return 0 on success, -1 on error.
 */
int control_fan(int temperature)
{
    if (temperature > TEMPERATURE_THRESHOLD)
    {
        // Turn on the fan
        if (digitalWrite(FAN_PIN, HIGH) == -1)
        {
            fprintf(stderr, "Error setting FAN_PIN HIGH: %s\n", strerror(errno));
            return -1;
        }
        printf("Fan turned ON\n");
    }
    else
    {
        // Turn off the fan
        if (digitalWrite(FAN_PIN, LOW) == -1)
        {
            fprintf(stderr, "Error setting FAN_PIN LOW: %s\n", strerror(errno));
            return -1;
        }
        printf("Fan turned OFF\n");
    }
    return 0;
}

/**
 * @brief Initializes the wiringPi library and sets the GPIO pin modes.
 *
 * @return 0 on success, -1 on error.
 */
int initialize_gpio()
{
    // Initialize wiringPi using BCM GPIO numbering
    if (wiringPiSetupGpio() == -1)
    {
        fprintf(stderr, "WiringPi setup failed: %s\n", strerror(errno));
        return -1;
    }

    // Set the temperature sensor pin as input
    pinMode(TEMP_SENSOR_PIN, INPUT);

    // Set the fan pin as output
    pinMode(FAN_PIN, OUTPUT);

    return 0;
}

int main()
{
    // Initialize GPIO
    if (initialize_gpio() == -1)
    {
        return 1;
    }

    printf("Temperature-controlled fan started. Press Ctrl+C to exit.\n");

    // Main loop
    while (1)
    {
        // Read the temperature
        int temperature = read_temperature();
        if (temperature == -1)
        {
            fprintf(stderr, "Error reading temperature.\n");
            return 1;
        }

        // Print the current temperature
        printf("Current Temperature: %d Celsius\n", temperature);

        // Control the fan
        if (control_fan(temperature) == -1)
        {
            fprintf(stderr, "Error controlling fan.\n");
            return 1;
        }

        // Wait for 1 second
        delay(1000);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <unistd.h>
#include <inttypes.h>
#include <errno.h>
#include <string.h>

// MPU6050 Register Addresses
#define MPU6050_ADDR 0x68        // MPU6050 default I2C address
#define MPU6050_REG_PWR_MGMT_1 0x6B // Power Management 1 register
#define MPU6050_REG_TEMP_OUT_H 0x41 // Temperature sensor MSB register
#define MPU6050_REG_ACCEL_XOUT_H 0x3B // Accel X MSB register
#define MPU6050_REG_GYRO_XOUT_H 0x43  // Gyro X MSB register

// Helper function to read a 16-bit value from two 8-bit registers
static int16_t read_word_2c(int file, uint8_t reg)
{
    int16_t high, low, value;
    high = i2c_smbus_read_byte_data(file, reg);          // Read high byte
    low = i2c_smbus_read_byte_data(file, reg + 1);      // Read low byte
    value = (high << 8) | low;
    return value;
}

int main()
{
    const char *i2c_device = "/dev/i2c-1"; // I2C device file
    int file;

    // Open I2C device
    if ((file = open(i2c_device, O_RDWR)) < 0) {
        fprintf(stderr, "Error: Could not open file %s: %s\n", i2c_device, strerror(errno));
        return 1;
    }

    // Specify the address of the slave device
    if (ioctl(file, I2C_SLAVE, MPU6050_ADDR) < 0) {
        fprintf(stderr, "Error: Could not set I2C slave address: %s\n", strerror(errno));
        close(file);
        return 1;
    }

    // Wake up the MPU6050 (clear sleep mode bit)
    if (i2c_smbus_write_byte_data(file, MPU6050_REG_PWR_MGMT_1, 0) < 0) {
        fprintf(stderr, "Error: Could not wake up MPU6050: %s\n", strerror(errno));
        close(file);
        return 1;
    }

    // Main loop to read and print data
    while (1) {
        // Read temperature
        int16_t temperature = read_word_2c(file, MPU6050_REG_TEMP_OUT_H);
        float temperature_celsius = (float)temperature / 340.0f + 36.53f;

        // Read accelerometer values
        int16_t accel_x = read_word_2c(file, MPU6050_REG_ACCEL_XOUT_H);
        int16_t accel_y = read_word_2c(file, MPU6050_REG_ACCEL_XOUT_H + 2);
        int16_t accel_z = read_word_2c(file, MPU6050_REG_ACCEL_XOUT_H + 4);

        // Read gyroscope values
        int16_t gyro_x = read_word_2c(file, MPU6050_REG_GYRO_XOUT_H);
        int16_t gyro_y = read_word_2c(file, MPU6050_REG_GYRO_XOUT_H + 2);
        int16_t gyro_z = read_word_2c(file, MPU6050_REG_GYRO_XOUT_H + 4);

        // Print the data
        printf("Temperature: %.2f °C\n", temperature_celsius);
        printf("Accelerometer: X = %d, Y = %d, Z = %d\n", accel_x, accel_y, accel_z);
        printf("Gyroscope: X = %d, Y = %d, Z = %d\n\n", gyro_x, gyro_y, gyro_z);

        sleep(1); // Wait for 1 second
    }

    close(file);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <ncurses.h>
#include <errno.h>
#include <string.h>

// PCF8591 I2C address
#define PCF8591_I2C_ADDR 0x48

// I2C device file
#define I2C_DEV "/dev/i2c-1"

// Number of ADC channels to read
#define NUM_CHANNELS 4

// Function to initialize the I2C device
int init_i2c(int *file_descriptor, const char *device_name, int device_address) {
    *file_descriptor = open(device_name, O_RDWR);
    if (*file_descriptor < 0) {
        fprintf(stderr, "Error opening I2C device %s: %s\n", device_name, strerror(errno));
        return -1;
    }

    if (ioctl(*file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error setting I2C slave address 0x%02x: %s\n", device_address, strerror(errno));
        close(*file_descriptor);
        return -1;
    }

    return 0;
}

// Function to read data from the PCF8591
int read_pcf8591(int file_descriptor, int channel, unsigned char *value) {
    unsigned char command[2];

    // Construct the command byte: Enable output, auto-increment, and select channel
    command[0] = 0x40 | ((channel + 1) & 0x03); // Output enable | read input channel
    command[1] = 0; //Dummy value

    if (write(file_descriptor, command, 2) != 2) {
        fprintf(stderr, "Error writing to I2C device: %s\n", strerror(errno));
        return -1;
    }

    usleep(20000); // Short delay for conversion

    if (read(file_descriptor, value, 1) != 1) {
        fprintf(stderr, "Error reading from I2C device: %s\n", strerror(errno));
        return -1;
    }

    return 0;
}

int main() {
    int i2c_file_descriptor;
    unsigned char adc_values[NUM_CHANNELS];
    int key;
    int aout_value = 32; // Initial DAC output value

    // Initialize ncurses
    initscr();
    noecho();
cbreak();
nodelay(stdscr, TRUE);
curs_set(0);

    // Initialize I2C
    if (init_i2c(&i2c_file_descriptor, I2C_DEV, PCF8591_I2C_ADDR) != 0) {
        endwin(); // Clean up ncurses
        return 1;
    }

    printw("PCF8591 ADC Reader\n");
    printw("+ or - to change DAC output, any other key to quit.\n");

    mvaddstr(10, 0, "Brightness:");
    mvaddstr(12, 0, "Temperature:");
    mvaddstr(14, 0, "Channel 2:");
    mvaddstr(16, 0, "Resistor:");

    refresh();

    while (1) {
        // Read ADC values from all channels
        for (int channel = 0; channel < NUM_CHANNELS; channel++) {
            if (read_pcf8591(i2c_file_descriptor, channel, &adc_values[channel]) != 0) {
                mvprintw(20 + channel, 0, "Error reading channel %d", channel);
            } else {
                char value_str[4];
                sprintf(value_str, "%3d", adc_values[channel]);
                mvaddstr(10 + channel + channel, 12, value_str);

                // Create a simple bar graph
                move(10 + channel + channel, 16);
                for (int j = 0; j < 64; j++) {
                    if (j < adc_values[channel] / 4) {
                        addch('*');
                    } else {
                        addch(' ');
                    }
                }
            }
        }

        refresh();

        key = getch();

        if ((key == '+') || (key == '=')) {
            aout_value++;
            if (aout_value > 255) aout_value = 255;
        } else if ((key == '-') || (key == '_')) {
            aout_value--;
            if (aout_value < 0) aout_value = 0;
        } else if (key != ERR) {
            break; // Exit loop on any other key press
        }
    }

    // Clean up ncurses
    endwin();

    // Close I2C file descriptor
    close(i2c_file_descriptor);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <unistd.h>
#include <time.h>
#include <sys/time.h>
#include <fcntl.h>
#include <errno.h>
#include <string.h>

#include "pigpio.h"

// Define the size of the gpioReport_t structure
#define REPORT_SIZE (sizeof(gpioReport_t))

// Define states for SCL and SDA lines
#define SCL_FALLING 0
#define SCL_RISING  1
#define SCL_STEADY  2

#define SDA_FALLING 0
#define SDA_RISING  4
#define SDA_STEADY  8

// Function to get a timestamp for logging
static char *get_timestamp()
{
    static char timestamp_str[32];
    struct timeval current_time;
    struct tm *time_info;

    gettimeofday(&current_time, NULL);
    time_info = localtime(&current_time.tv_sec);

    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", time_info);
    return timestamp_str;
}

// Function to parse I2C data based on SCL and SDA transitions
void parse_i2c_data(int scl_level, int sda_level)
{
    static int in_data = 0;      // Flag to indicate if we are currently receiving data
    static int current_byte = 0;  // The current byte being assembled
    static int bit_count = 0;     // The number of bits received for the current byte
    static int old_scl_level = 1; // Previous SCL level (initially high)
    static int old_sda_level = 1; // Previous SDA level (initially high)

    int scl_transition, sda_transition;

    // Determine SCL transition
    if (scl_level != old_scl_level)
    {
        old_scl_level = scl_level;
        scl_transition = (scl_level) ? SCL_RISING : SCL_FALLING;
    } else {
        scl_transition = SCL_STEADY;
    }

    // Determine SDA transition
    if (sda_level != old_sda_level)
    {
        old_sda_level = sda_level;
        sda_transition = (sda_level) ? SDA_RISING : SDA_FALLING;
    } else {
        sda_transition = SDA_STEADY;
    }

    // Process I2C state changes
    switch (scl_transition + sda_transition)
    {
        case SCL_RISING + SDA_RISING:
        case SCL_RISING + SDA_FALLING:
        case SCL_RISING + SDA_STEADY:
            // SCL rising edge
            if (in_data)
            {
                if (bit_count++ < 8)
                {
                    current_byte <<= 1;
                    current_byte |= sda_level; // Sample SDA on SCL rising edge
                }
                else
                {
                    // Byte complete
                    printf("%02X", current_byte);
                    printf((sda_level) ? "-" : "+"); // Indicate ACK/NACK
                    bit_count = 0;
                    current_byte = 0;
                }
            }
            break;

        case SCL_FALLING + SDA_RISING:
        case SCL_FALLING + SDA_FALLING:
        case SCL_FALLING + SDA_STEADY:
            // SCL falling edge (do nothing)
            break;

        case SCL_STEADY + SDA_RISING:
            // SDA rising edge
            if (scl_level)
            {
                // Stop condition
                in_data = 0;
                current_byte = 0;
                bit_count = 0;
                printf("]\n"); // Stop
                fflush(stdout);
            }
            break;

        case SCL_STEADY + SDA_FALLING:
            // SDA falling edge
            if (scl_level)
            {
                // Start condition
                in_data = 1;
                current_byte = 0;
                bit_count = 0;
                printf("[ %s: ", get_timestamp()); // Start
            }
            break;

        case SCL_STEADY + SDA_STEADY:
            // No change (do nothing)
            break;
    }
}

int main(int argc, char *argv[])
{
    int scl_gpio, sda_gpio;
    int scl_level, sda_level;
    int read_result;
    uint32_t level_mask, scl_mask, sda_mask;
    gpioReport_t report;
    uint32_t previous_level = 0; // Store the previous level to detect changes

    // Check command line arguments
    if (argc != 3)
    {
        fprintf(stderr, "Usage: %s <SCL_GPIO> <SDA_GPIO>\n", argv[0]);
        return EXIT_FAILURE;
    }

    // Parse GPIO numbers from arguments
    scl_gpio = atoi(argv[1]);
    sda_gpio = atoi(argv[2]);

    // Create bit masks for SCL and SDA
    scl_mask = (1 << scl_gpio);
    sda_mask = (1 << sda_gpio);
    level_mask = scl_mask | sda_mask;

    // Initialize SCL and SDA levels to high (default state)
    scl_level = 1;
    sda_level = 1;

    // Main loop to read pigpio reports from stdin
    while ((read_result = read(STDIN_FILENO, &report, REPORT_SIZE)) == REPORT_SIZE)
    {
        // Mask out irrelevant bits from the report level
        report.level &= level_mask;

        // Check if the level has changed since the last report
        if (report.level != previous_level)
        {
            // Update SCL and SDA levels based on the report
            scl_level = (report.level & scl_mask) ? 1 : 0;
            sda_level = (report.level & sda_mask) ? 1 : 0;

            // Parse the I2C data based on the current SCL and SDA levels
            parse_i2c_data(scl_level, sda_level);

            // Update the previous level
            previous_level = report.level;
        }
    }

    // Handle read errors
    if (read_result < 0)
    {
        perror("Error reading from stdin");
        return EXIT_FAILURE;
    }

    // Handle partial read (should not normally happen)
    if (read_result > 0)
    {
        fprintf(stderr, "Partial read from stdin (%d bytes)\n", read_result);
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>

// Constants
#define CAPACITOR_GPIO 25          // GPIO pin connected to the capacitor
#define MAX_READING 1000           // Maximum acceptable reading
#define DRAIN_DELAY_US 200         // Delay to discharge the capacitor (microseconds)
#define MEASUREMENT_DELAY_US 5000  // Delay between measurements (microseconds)
#define SMOOTHING_FACTOR 0.2       // Smoothing factor for exponential moving average
#define MIN_TICK_DIFF 3            // Minimum tick difference for valid reading

// Global Variables
static volatile uint32_t recharge_start_tick = 0; // Timestamp of recharge start
static volatile double smoothed_reading = 0;      // Smoothed reading using EMA
static volatile int reading_count = 0;              // Reading counter

// Function prototypes
void capacitor_charge_callback(int gpio, int level, uint32_t tick);
int initialize_gpio();
void cleanup_gpio();

/**
 * @brief Callback function triggered when the capacitor GPIO changes state.
 *
 * This function calculates the recharge time and smooths the readings.
 *
 * @param gpio  The GPIO pin number.
 * @param level The new level of the GPIO (0 or 1).
 * @param tick  The current tick count.
 */
void capacitor_charge_callback(int gpio, int level, uint32_t tick) {
  if (level == 1) {
    reading_count++;
    uint32_t raw_reading;

    if (recharge_start_tick) {
      raw_reading = tick - recharge_start_tick;

      if (raw_reading < MAX_READING) {
        smoothed_reading = SMOOTHING_FACTOR * raw_reading + (1 - SMOOTHING_FACTOR) * smoothed_reading;
        printf("%d %u %.2f\n", reading_count, raw_reading, smoothed_reading);
      } else {
        // Outlier reading
        printf("%d %d %.2f (Outlier)\n", reading_count, 40, smoothed_reading);
      }
    } else {
      // Reschedule ignored
      printf("%d %d %.2f (Reschedule)\n", reading_count, 20, smoothed_reading);
    }
  }
}

/**
 * @brief Initializes the pigpio library and sets up the GPIO pin.
 *
 * @return 0 on success, -1 on failure.
 */
int initialize_gpio() {
  if (gpioInitialise() < 0) {
    fprintf(stderr, "pigpio initialisation failed\n");
    return -1;
  }

  gpioSetAlertFunc(CAPACITOR_GPIO, capacitor_charge_callback);

  return 0;
}

/**
 * @brief Cleans up the pigpio library.
 */
void cleanup_gpio() {
  gpioTerminate();
}

int main(int argc, char *argv[]) {
  uint32_t discharge_start_tick, set_input_tick;
  int32_t tick_difference;

  if (initialize_gpio() != 0) {
    return 1;
  }

  while (1) {
    // Discharge the capacitor
    gpioWrite(CAPACITOR_GPIO, PI_OFF);
    gpioDelay(DRAIN_DELAY_US);

    discharge_start_tick = gpioTick();

    // Set GPIO to input mode to allow capacitor to charge
    gpioSetMode(CAPACITOR_GPIO, PI_INPUT);

    set_input_tick = gpioTick();

    // Validate the tick difference
    tick_difference = (int32_t)(set_input_tick - discharge_start_tick);

    if (tick_difference < MIN_TICK_DIFF) {
      recharge_start_tick = discharge_start_tick;
    } else {
      recharge_start_tick = 0; // Invalidate the reading
    }

    gpioDelay(MEASUREMENT_DELAY_US);
  }

  cleanup_gpio();
  return 0;
}

