    {2, 1, 100},
    {3, 0, 0},
    {1, 1, 100},
    {2, 0, 0},
    {0, 1, 100},
    {1, 0, 100},
    {0, 0, 100},
    {0, 0, 100},

    {-1, 0, 0} // End marker
};

// Function to initialize GPIO pins
int initialize_gpio(void) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return -1;
    }

    for (int i = 0; i < NUM_LEDS; ++i) {
        pinMode(led_pins[i], OUTPUT);
        digitalWrite(led_pins[i], LOW); // Initialize all LEDs to OFF
    }

    return 0;
}

int main(void) {
    printf("Raspberry Pi - Improved LED Sequence\n");
    printf("==================================\n");
    printf("Controlling LEDs connected to GPIO pins: 0, 1, 2, 3, 4, 5, 6, 7, 11, 10, 13, 12\n");

    if (initialize_gpio() == -1) {
        return 1;
    }

    // Main loop to run the LED sequence
    const led_sequence_t *current_sequence = led_sequence;
    while (1) {
        // Check for the end marker
        if (current_sequence->led_index == -1) {
            current_sequence = led_sequence; // Reset to the beginning
            continue;
        }

        // Get the LED index, state, and duration from the current sequence
        int led_index = current_sequence->led_index;
        int led_state = current_sequence->state;
        int duration_ms = current_sequence->duration_ms;

        // Error check the LED index
        if (led_index < 0 || led_index >= NUM_LEDS) {
            fprintf(stderr, "Error: Invalid LED index: %d\n", led_index);
            return 1;
        }

        // Set the LED state
        digitalWrite(led_pins[led_index], led_state);

        // Delay for the specified duration
        delay(duration_ms);

        // Move to the next sequence element
        current_sequence++;
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdarg.h>
#include <unistd.h>
#include <string.h>
#include <time.h>
#include <sys/time.h>
#include <stdint.h>
#include <pigpio.h>

// Configuration parameters (can be overridden by command-line arguments)
#define DEFAULT_GPIO_PIN 4         // GPIO pin for PPS output
#define DEFAULT_PULSE_LEVEL 1      // Pulse level (1 for high, 0 for low)
#define DEFAULT_PULSE_WIDTH_US 200   // Pulse width in microseconds
#define DEFAULT_INTERVAL_SEC 1       // Interval between pulses in seconds
#define SLACK_US 5000              // Slack time in microseconds for adjustments

#define MILLION 1000000UL

// Global variables (using descriptive names)
static int pps_gpio_pin = DEFAULT_GPIO_PIN;
static int pulse_level = DEFAULT_PULSE_LEVEL;
static int pulse_width_us = DEFAULT_PULSE_WIDTH_US;
static int interval_seconds = DEFAULT_INTERVAL_SEC;
static unsigned long interval_us; // Interval in microseconds

static uint32_t *slack_address; // Pointer to slack time in the waveform

// Function prototypes
void error_exit(const char *format, ...);
void print_usage(const char *program_name);
void parse_command_line_options(int argc, char *argv[]);
void pps_callback(int gpio, int level, uint32_t tick);
int create_and_send_waveform();

// Error handling function
void error_exit(const char *format, ...) {
    va_list args;
    va_start(args, format);
    fprintf(stderr, "Error: ");
vfprintf(stderr, format, args);
    va_end(args);
    fprintf(stderr, "\n");
gpioTerminate();
    exit(EXIT_FAILURE);
}

// Usage information
void print_usage(const char *program_name) {
    fprintf(stderr, "Usage: sudo %s [OPTIONS]\n", program_name);
    fprintf(stderr, "  -g <gpio>   GPIO pin for PPS output (default: %d)\n", DEFAULT_GPIO_PIN);
    fprintf(stderr, "  -l <level>  Pulse level (0 or 1, default: %d)\n", DEFAULT_PULSE_LEVEL);
    fprintf(stderr, "  -w <width>  Pulse width in microseconds (default: %d)\n", DEFAULT_PULSE_WIDTH_US);
    fprintf(stderr, "  -i <interval> Interval between pulses in seconds (default: %d)\n", DEFAULT_INTERVAL_SEC);
    fprintf(stderr, "Example:\n");
    fprintf(stderr, "  sudo %s -g 23 -i 5\n", program_name);
    fprintf(stderr, "  Generates a PPS signal every 5 seconds on GPIO 23.\n");
}

// Parse command-line options
void parse_command_line_options(int argc, char *argv[]) {
    int opt;

    while ((opt = getopt(argc, argv, "g:l:w:i:")) != -1) {
        switch (opt) {
            case 'g':
                pps_gpio_pin = atoi(optarg);
                if (pps_gpio_pin < 0 || pps_gpio_pin > 31) {
                    error_exit("Invalid GPIO pin: %d", pps_gpio_pin);
                }
                break;
            case 'l':
                pulse_level = atoi(optarg);
                if (pulse_level != 0 && pulse_level != 1) {
                    error_exit("Invalid pulse level: %d", pulse_level);
                }
                break;
            case 'w':
                pulse_width_us = atoi(optarg);
                if (pulse_width_us <= 0 || pulse_width_us > 5000) {
                    error_exit("Invalid pulse width: %d", pulse_width_us);
                }
                break;
            case 'i':
                interval_seconds = atoi(optarg);
                if (interval_seconds <= 0 || interval_seconds > 60) {
                    error_exit("Invalid interval: %d", interval_seconds);
                }
                break;
            default:
                print_usage(argv[0]);
                exit(EXIT_FAILURE);
        }
    }
}

// PPS callback function (called on each pulse)
void pps_callback(int gpio, int level, uint32_t tick) {
    static int initialized = 0;
    static int drift = 0;  // Accumulated drift in microseconds
    static int count = 0;  // Pulse count

    int i;
    int slack_us;          // Slack time for correction
    int offset_us;         // Offset from the ideal time
    uint32_t pulse_start_tick; // System tick at pulse start
    uint32_t now_tick;         // Current system tick
    uint32_t tick1, tick2, tick_diff; // Ticks for clock synchronization
    uint32_t next_pulse_us, next_pulse_tick, delay_ticks, fixed_ticks;
    struct timespec time_spec;

    if (level == pulse_level) {
        // Seconds boundary has arrived

        pulse_start_tick = rawWaveGetIn(0); // Get tick at pulse start
        now_tick = gpioTick();            // Get current tick (for scheduling delay)

        tick_diff = 10000000; // Initialize with a large value

        // Attempt to synchronize with the system clock
        for (i = 0; i < 10; i++) {
            tick1 = gpioTick();
            if (clock_gettime(CLOCK_REALTIME, &time_spec) == -1) {
                perror("clock_gettime");
                continue; // Try again
            }
            tick2 = gpioTick();

            if ((tick2 - tick1) < tick_diff) {
                tick_diff = tick2 - tick1;
                //Best estimate
                uint64_t sec = time_spec.tv_sec % interval_seconds;
                uint64_t nsec = time_spec.tv_nsec;

                next_pulse_us = (sec * MILLION) + (nsec / 1000UL);

                stamp_tick = tick1;

                if (tick_diff == 0) break; // Can't improve further
            }
        }

        if (initialized) {
            // Correct for early arrival
            if (next_pulse_us > (interval_us / 2)) next_pulse_us -= interval_us;
            offset_us = next_pulse_us - (stamp_tick - pulse_start_tick);
            drift += offset_us / 2; // Correct drift with some lag
        } else {
            offset_us = 0;
            drift = 0;
        }

        next_pulse_us = interval_us - next_pulse_us;
        next_pulse_tick = stamp_tick + next_pulse_us - drift;

        delay_ticks = next_pulse_tick - pulse_start_tick;

        fixed_ticks = interval_us - SLACK_US;
        slack_us = delay_ticks - fixed_ticks;

        if (slack_us < 0) slack_us += interval_us;
        if (!slack_us) slack_us = 1;
        *slack_address = (slack_us * 4); // Update slack in waveform

        if (initialized) {
            printf("%8d %5d %5d %5d %5d\n",
                   count++, drift, offset_us, now_tick - pulse_start_tick, slack_us);
        } else {
            printf("#  count drift offset sched slack\n");
            initialized = 1;
        }
    }
}

// Create and send the waveform
int create_and_send_waveform() {
    int off_us;
    int wave_id;
    rawWave_t wave[3];
    rawWaveInfo_t wave_info;

    off_us = interval_us - (pulse_width_us + SLACK_US);

    printf("# gpio=%d, level=%d slack=%dus, off=%dus\n",
           pps_gpio_pin, pulse_level, SLACK_US, off_us);

    gpioSetMode(pps_gpio_pin, PI_OUTPUT);

    // Define the waveform
    if (pulse_level) { // Pulse is high
        wave[0].gpioOn = 0;
        wave[0].gpioOff = (1 << pps_gpio_pin);
        wave[0].usDelay = SLACK_US;
        wave[0].flags = 0;

        wave[1].gpioOn = (1 << pps_gpio_pin);
        wave[1].gpioOff = 0;
        wave[1].usDelay = pulse_width_us;
        wave[1].flags = WAVE_FLAG_TICK; // Read tick at start of pulse

        wave[2].gpioOn = 0;
        wave[2].gpioOff = (1 << pps_gpio_pin);
        wave[2].usDelay = off_us;
        wave[2].flags = 0;
    } else { // Pulse is low
        wave[0].gpioOn = (1 << pps_gpio_pin);
        wave[0].gpioOff = 0;
        wave[0].usDelay = SLACK_US;
        wave[0].flags = 0;

        wave[1].gpioOn = 0;
        wave[1].gpioOff = (1 << pps_gpio_pin);
        wave[1].usDelay = pulse_width_us;
        wave[1].flags = WAVE_FLAG_TICK; // Read tick at start of pulse

        wave[2].gpioOn = (1 << pps_gpio_pin);
        wave[2].gpioOff = 0;
        wave[2].usDelay = off_us;
        wave[2].flags = 0;
    }

    gpioWaveClear();            // Clear all waveforms
    rawWaveAddGeneric(3, wave); // Add data to waveform
    wave_id = gpioWaveCreate(); // Create waveform from added data

    if (wave_id >= 0) {
        gpioWaveTxSend(wave_id, PI_WAVE_MODE_REPEAT); // Start waveform transmission

        wave_info = rawWaveInfo(wave_id);
        slack_address = &(rawWaveCBAdr(wave_info.botCB + 2)->length); // Get slack address

        return 0; // Success
    } else {
        fprintf(stderr, "Error creating waveform: %d\n", wave_id);
        return -1; // Failure
    }
}

int main(int argc, char *argv[]) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    parse_command_line_options(argc, argv);

    interval_us = interval_seconds * MILLION;

    gpioSetAlertFunc(pps_gpio_pin, pps_callback); // Set PPS callback

    if (create_and_send_waveform() != 0) {
        gpioTerminate();
        return 1;
    }

    // Keep the program running
    while (1) {
        sleep(1);
    }

    gpioTerminate();
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>

// Constants for GPIO pins
#define SERVO_PIN 4
#define PWM_PIN 17
#define OUTPUT_PIN 18
#define INPUT_PIN 23
#define MIRROR_PIN 24

// Constants for PWM and Servo values
#define SERVO_MID_PULSE_WIDTH 1500  // microseconds
#define PWM_DUTYCYCLE 192           // out of 255 (75%)

// Constants for timing
#define SLEEP_DURATION 0.5          // seconds
#define RUN_DURATION 60.0           // seconds

int main(int argc, char *argv[]) {
    double startTime;

    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "ERROR: pigpio initialisation failed\n");
        return 1; // Exit with an error code
    }

    // Set GPIO modes
    if (gpioSetMode(SERVO_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "ERROR: Failed to set mode for SERVO_PIN\n");
        gpioTerminate();
        return 1;
    }
    if (gpioSetMode(PWM_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "ERROR: Failed to set mode for PWM_PIN\n");
        gpioTerminate();
        return 1;
    }
    if (gpioSetMode(OUTPUT_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "ERROR: Failed to set mode for OUTPUT_PIN\n");
        gpioTerminate();
        return 1;
    }
    if (gpioSetMode(INPUT_PIN, PI_INPUT) != 0) {
        fprintf(stderr, "ERROR: Failed to set mode for INPUT_PIN\n");
        gpioTerminate();
        return 1;
    }
    if (gpioSetMode(MIRROR_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "ERROR: Failed to set mode for MIRROR_PIN\n");
        gpioTerminate();
        return 1;
    }

    // Start 1500 us servo pulses on SERVO_PIN
    if (gpioServo(SERVO_PIN, SERVO_MID_PULSE_WIDTH) != 0) {
        fprintf(stderr, "ERROR: Failed to set servo pulse width\n");
        gpioTerminate();
        return 1;
    }

    // Start PWM on PWM_PIN
    if (gpioPWM(PWM_PIN, PWM_DUTYCYCLE) != 0) {
        fprintf(stderr, "ERROR: Failed to set PWM duty cycle\n");
        gpioTerminate();
        return 1;
    }

    startTime = time_time();

    // Main loop: Toggle OUTPUT_PIN and mirror INPUT_PIN to MIRROR_PIN
    while ((time_time() - startTime) < RUN_DURATION) {
        // Set OUTPUT_PIN high
        if (gpioWrite(OUTPUT_PIN, 1) != 0) {
            fprintf(stderr, "ERROR: Failed to write to OUTPUT_PIN\n");
            gpioTerminate();
            return 1;
        }

        // Sleep for SLEEP_DURATION seconds
        time_sleep(SLEEP_DURATION);

        // Set OUTPUT_PIN low
        if (gpioWrite(OUTPUT_PIN, 0) != 0) {
            fprintf(stderr, "ERROR: Failed to write to OUTPUT_PIN\n");
            gpioTerminate();
            return 1;
        }

        // Sleep for SLEEP_DURATION seconds
        time_sleep(SLEEP_DURATION);

        // Mirror INPUT_PIN to MIRROR_PIN
        int input_value = gpioRead(INPUT_PIN);
        if (input_value >= 0) {
            if (gpioWrite(MIRROR_PIN, input_value) != 0) {
                fprintf(stderr, "ERROR: Failed to write to MIRROR_PIN\n");
                gpioTerminate();
                return 1;
            }
        } else {
            fprintf(stderr, "ERROR: Failed to read from INPUT_PIN\n");
            gpioTerminate();
            return 1;
        }
    }

    // Clean up and terminate the pigpio library
    gpioTerminate();

    return 0; // Exit successfully
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <pigpio.h>
#include <time.h>

// Configuration
#define SPI_SS_PIN 25          // GPIO for slave select
#define NUM_ADCS 5             // Number of connected MCP3008 ADCs
#define BITS_PER_READING 10    // Bits per ADC reading
#define BUFFER_SIZE 250        // Size of the DMA buffer (increase for stability)
#define REPEAT_MICROSECONDS 40 // Delay between SPI transactions (must be > transaction time)
#define NUM_SAMPLES 2000000    // Number of samples to collect

// ADC MISO Pins (one per ADC)
#define MISO1_PIN 6
#define MISO2_PIN 26
#define MISO3_PIN 13
#define MISO4_PIN 23
#define MISO5_PIN 24

// SPI Configuration
#define SPI_CLK_PIN 5
#define SPI_MOSI_PIN 12

// Global Variables
int miso_pins[NUM_ADCS] = {MISO1_PIN, MISO2_PIN, MISO3_PIN, MISO4_PIN, MISO5_PIN};

// Function Prototypes
void read_adc_values(int adcs, int *miso_pins, int ool_start, int bytes_per_adc, int bits_per_reading, char *buffer);
int initialize_gpio();
int setup_spi_wave(int *wave_id);

int main(int argc, char *argv[]) {
    int i, wave_id, offset;
    char spi_tx_buffer[2];
    char adc_rx_buffer[8]; // 2 bytes per ADC
    int sample_count, adc_value;
    int current_cb, bottom_cb, top_ool, current_reading, previous_reading;
    float cbs_per_reading;
    rawWaveInfo_t wave_info;
    double start_time, end_time;
    int pause_duration = 0; // Pause before starting (for debugging)

    // Parse command-line arguments
    if (argc > 1) {
        pause_duration = atoi(argv[1]);
    }

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        fprintf(stderr, "GPIO initialization failed.\n");
        return 1;
    }

    // Setup SPI Wave
    if (setup_spi_wave(&wave_id) != 0) {
        fprintf(stderr, "SPI wave setup failed.\n");
        gpioTerminate();
        return 1;
    }

    // Get Wave Information
    wave_info = rawWaveInfo(wave_id);

    printf("# cb %d-%d ool %d-%d del=%d ncb=%d nb=%d nt=%d\n",
           wave_info.botCB, wave_info.topCB, wave_info.botOOL, wave_info.topOOL, wave_info.deleted,
           wave_info.numCB, wave_info.numBOOL, wave_info.numTOOL);

    bottom_cb = wave_info.botCB;
    cbs_per_reading = (float)wave_info.numCB / (float)BUFFER_SIZE;

    printf("# cbs=%d per read=%.1f base=%d\n",
           wave_info.numCB, cbs_per_reading, bottom_cb);

    top_ool = wave_info.topOOL;

    fprintf(stderr, "Starting data acquisition...\n");

    if (pause_duration) {
        time_sleep(pause_duration); // Allow time to attach a debugger
    }

    gpioWaveTxSend(wave_id, PI_WAVE_MODE_REPEAT); // Start DMA transmission

    previous_reading = 0;
    sample_count = 0;

    start_time = time_time();

    while (sample_count < NUM_SAMPLES) {
        // Calculate the current reading
        current_cb = rawWaveCB() - bottom_cb;
        current_reading = (float)current_cb / cbs_per_reading;

        // Process new readings
        while (current_reading != previous_reading) {
            read_adc_values(
                NUM_ADCS,
                miso_pins,
                top_ool - ((previous_reading % BUFFER_SIZE) * BITS_PER_READING) - 1,
                2, // Bytes per ADC (2 bytes)
                BITS_PER_READING,
                adc_rx_buffer);

            printf("%d", ++sample_count);

            for (i = 0; i < NUM_ADCS; i++) {
                // Combine the two bytes to get the 10-bit ADC value
                adc_value = (adc_rx_buffer[i * 2] << 2) + (adc_rx_buffer[(i * 2) + 1] >> 6);
                printf(" %d", adc_value);
            }

            printf("\n");

            if (++previous_reading >= BUFFER_SIZE) {
                previous_reading = 0;
            }
        }
        usleep(1000); // Reduce CPU usage
    }

    end_time = time_time();

    printf("# %d samples in %.1f seconds (%.0f/s)\n",
           NUM_SAMPLES, end_time - start_time, (float)NUM_SAMPLES / (end_time - start_time));

    fprintf(stderr, "Data acquisition complete.\n");

    if (pause_duration) {
        time_sleep(pause_duration);
    }

    gpioTerminate(); // Release GPIO resources

    return 0;
}

// Reads ADC values from the DMA buffer
void read_adc_values(
    int adcs,          // Number of attached ADCs
    int *miso_pins,     // The GPIO connected to the ADCs data out
    int ool_start,      // Address of first OOL for this reading
    int bytes_per_adc, // Bytes between readings
    int bits_per_reading, // Bits per reading
    char *buffer) {
    int i, a, p;
    uint32_t level;

    p = ool_start;

    for (i = 0; i < bits_per_reading; i++) {
        level = rawWaveGetOut(p);

        for (a = 0; a < adcs; a++) {
            putBitInBytes(i, buffer + (bytes_per_adc * a), level & (1 << miso_pins[a]));
        }

        p--;
    }
}

// Initializes GPIO pins
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    // Set GPIO modes
    gpioSetMode(SPI_CLK_PIN, PI_OUTPUT);
    gpioSetMode(SPI_MOSI_PIN, PI_OUTPUT);
    gpioSetMode(SPI_SS_PIN, PI_OUTPUT);

    return 0;
}

// Sets up the SPI wave for DMA transmission
int setup_spi_wave(int *wave_id) {
    int i, offset;
    char spi_tx_buffer[2];
    gpioPulse_t final_pulse[2];
    rawSPI_t raw_spi_config = {
        .clk = SPI_CLK_PIN,  // GPIO for SPI clock
        .mosi = SPI_MOSI_PIN, // GPIO for SPI MOSI
        .ss_pol = 1,         // Slave select resting level
        .ss_us = 1,          // Wait 1 micro after asserting slave select
        .clk_pol = 0,        // Clock resting level
        .clk_pha = 0,        // 0 sample on first edge, 1 sample on second edge
        .clk_us = 1           // 2 clocks needed per bit so 500 kbps
    };

    gpioWaveAddNew(); // Flush any old wave data

    offset = 0;

    // Construct SPI reads for each ADC
    for (i = 0; i < BUFFER_SIZE; i++) {
        spi_tx_buffer[0] = 0xC0; // Start bit, single ended, channel 0
        rawWaveAddSPI(&raw_spi_config, offset, SPI_SS_PIN, spi_tx_buffer, 2, 8, 17, 17); //Modified bit positions
        offset += REPEAT_MICROSECONDS;
    }

    // Force the same delay after the last reading
    final_pulse[0].gpioOn = 0;
    final_pulse[0].gpioOff = 0;
    final_pulse[0].usDelay = offset;

    final_pulse[1].gpioOn = 0; // Need a dummy to force the final delay
    final_pulse[1].gpioOff = 0;
    final_pulse[1].usDelay = 0;

    gpioWaveAddGeneric(2, final_pulse);

    *wave_id = gpioWaveCreate(); // Create the wave from added data

    if (*wave_id < 0) {
        fprintf(stderr, "Can't create wave, %d too many?\n", BUFFER_SIZE);
        return -1;
    }

    return 0;
}

