// Helper function to extract a bit from a byte array
int get_bit(const char *buf, int bit_index) {
    int byte_index = bit_index / 8;
    int bit_offset = bit_index % 8;
    return (buf[byte_index] >> (7 - bit_offset)) & 1;
}

// Helper function to set a bit in a byte array
void set_bit(char *buf, int bit_index, int value) {
    int byte_index = bit_index / 8;
    int bit_offset = bit_index % 8;
    if (value) {
        buf[byte_index] |= (1 << (7 - bit_offset));
    } else {
        buf[byte_index] &= ~(1 << (7 - bit_offset));
    }
}


int main(int argc, char *argv[]) {
    int wave_id = -1; // Initialize to an invalid value
    int pause_duration = 0;

    if (argc > 1) {
        pause_duration = atoi(argv[1]);
    }

    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO pins
    if (setup_gpio() != 0) {
        fprintf(stderr, "GPIO setup failed\n");
        cleanup_gpio();
        return 1;
    }

    // Set up the SPI wave for DMA transfer
    if (setup_spi_wave(&wave_id) != 0) {
        fprintf(stderr, "SPI wave setup failed\n");
        cleanup_gpio();
        return 1;
    }

    rawWaveInfo_t rwi = rawWaveInfo(wave_id);
    float cbs_per_reading = (float)rwi.numCB / (float)WAVE_BUFFER_SIZE;
    int top_ool = rwi.topOOL;

    fprintf(stderr, "Starting data acquisition...\n");

    if (pause_duration) {
        time_sleep(pause_duration);
    }

    // Start the wave transmission in repeat mode
    gpioWaveTxSend(wave_id, PI_WAVE_MODE_REPEAT);

    // Read data from the ADCs
    read_adc_data(wave_id, top_ool, cbs_per_reading);

    fprintf(stderr, "Ending data acquisition...\n");

    if (pause_duration) {
        time_sleep(pause_duration);
    }

    // Clean up and terminate the pigpio library
    cleanup_gpio();

    return 0;
}

// Function to set up the GPIO pins
int setup_gpio() {
    // Set MOSI, CLK, and SS as outputs
    if (gpioSetMode(spi_config.mosi_gpio, PI_OUTPUT) != 0 ||
        gpioSetMode(spi_config.clk_gpio, PI_OUTPUT) != 0 ||
        gpioSetMode(spi_config.ss_gpio, PI_OUTPUT) != 0) {
        fprintf(stderr, "Failed to set MOSI, CLK, or SS as outputs\n");
        return 1;
    }

    // Set MISO pins as inputs
    for (int i = 0; i < NUM_ADCS; ++i) {
        if (gpioSetMode(miso_gpios[i], PI_INPUT) != 0) {
            fprintf(stderr, "Failed to set MISO %d as input\n", i + 1);
            return 1;
        }
    }

    return 0;
}

// Function to set up the SPI wave for DMA transfer
int setup_spi_wave(int *wave_id_ptr) {
    int offset = 0;
    char spi_data[2];
    gpioPulse_t final_pulse[2];

    gpioWaveAddNew(); // Clear any existing wave data

    // Construct the SPI wave for reading data from the MCP3202 ADCs
    for (int i = 0; i < WAVE_BUFFER_SIZE; ++i) {
        // MCP3202 configuration: Start bit, single-ended, channel 0
        spi_data[0] = 0xC0; // 11000000

        if (rawWaveAddSPI(&(rawSPI_t){spi_config.clk_gpio, spi_config.mosi_gpio, spi_config.ss_polarity, spi_config.ss_delay_us, spi_config.clk_polarity, spi_config.clk_phase, spi_config.clk_delay_us}, offset, spi_config.ss_gpio, spi_data, 2, DATA_BIT_START, ADC_BITS + DATA_BIT_START -1, ADC_BITS + DATA_BIT_START -1) != 0) {
            fprintf(stderr, "Failed to add SPI data to wave\n");
            return 1;
        }

        offset += SAMPLE_INTERVAL_US; // Increment the offset for the next reading
    }

    // Add a final delay to ensure consistent timing
    final_pulse[0].gpioOn = 0;
    final_pulse[0].gpioOff = 0;
    final_pulse[0].usDelay = offset;

    final_pulse[1].gpioOn = 0; // Dummy pulse to force the final delay
    final_pulse[1].gpioOff = 0;
    final_pulse[1].usDelay = 0;

    gpioWaveAddGeneric(2, final_pulse);

    // Create the wave from the added data
    int wave_id = gpioWaveCreate();
    if (wave_id < 0) {
        fprintf(stderr, "Failed to create wave: %d (too much data?)\n", wave_id);
        return 1;
    }

    *wave_id_ptr = wave_id; // Store the wave ID
    return 0;
}

// Function to read data from the ADCs using DMA transfer
void read_adc_data(int wave_id, int top_ool, float cbs_per_reading) {
    double start_time, end_time;
    int current_sample = 0;
    int reading_index = 0;
    char raw_data[NUM_ADCS * 2]; // Buffer to store raw ADC data (2 bytes per ADC)
    int adc_values[NUM_ADCS];      // Array to store converted ADC values

    start_time = time_time();

    while (current_sample < NUM_SAMPLES) {
        // Calculate the current reading index based on the control block position
        int current_cb = rawWaveCB() - rawWaveInfo(wave_id).botCB;
        int now_reading_index = (float)current_cb / cbs_per_reading;

        // Process new readings
        while (now_reading_index != reading_index) {
            // Calculate the offset into the OOL data for the current reading
            int ool_offset = top_ool - ((reading_index % WAVE_BUFFER_SIZE) * ADC_BITS) - 1;

            // Read raw data from the OOL buffer
            for (int adc_index = 0; adc_index < NUM_ADCS; ++adc_index) {
                // Initialize the raw data buffer for each ADC
                for (int i = 0; i < 2; ++i) {
                    raw_data[adc_index * 2 + i] = 0;
                }

                // Extract the bits for each ADC from the wave buffer
                for (int bit_index = 0; bit_index < ADC_BITS; ++bit_index) {
                    uint32_t level = rawWaveGetOut(ool_offset - bit_index);
                    int bit_value = (level >> miso_gpios[adc_index]) & 1;
                    set_bit(&raw_data[adc_index * 2], bit_index, bit_value);
                }

                // Convert the raw data to an integer value
                adc_values[adc_index] = ((raw_data[adc_index * 2] & 0xFF) << 4) | ((raw_data[adc_index * 2 + 1] & 0xFF) >> 4);
            }

            // Print the sample number and ADC values
            printf("%d", ++current_sample);
            for (int i = 0; i < NUM_ADCS; ++i) {
                printf(" %d", adc_values[i]);
            }
            printf("\n");

            // Update the reading index
            reading_index = (reading_index + 1) % WAVE_BUFFER_SIZE;
        }
        usleep(1000); // Reduce CPU usage
    }

    end_time = time_time();

    printf("# %d samples in %.1f seconds (%.0f/s)\n",
           NUM_SAMPLES, end_time - start_time, (float)NUM_SAMPLES / (end_time - start_time));
}

// Function to clean up the GPIO pins
void cleanup_gpio() {
    gpioTerminate();
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <pigpio.h>

// Configuration Constants
#define SPI_SS_GPIO 25          // GPIO pin for Slave Select (Chip Select)
#define NUM_ADCS 5              // Number of connected MCP3XXX ADCs
#define BITS_PER_READING 12     // Number of bits per ADC reading
#define DATA_BIT_POSITION 6     // Bit position of the most significant data bit (B11)
#define BUFFER_SIZE 250         // Size of the wave buffer (adjust for needs)
#define REPEAT_INTERVAL_US 40   // Time between ADC readings (microseconds)
#define NUM_SAMPLES 2000000     // Total number of samples to acquire

// ADC MISO Pin Assignments
#define MISO1_GPIO 6   // MISO pin for ADC 1
#define MISO2_GPIO 26  // MISO pin for ADC 2
#define MISO3_GPIO 13  // MISO pin for ADC 3
#define MISO4_GPIO 23  // MISO pin for ADC 4
#define MISO5_GPIO 24  // MISO pin for ADC 5

// Global Variables
int miso_gpios[NUM_ADCS] = {MISO1_GPIO, MISO2_GPIO, MISO3_GPIO, MISO4_GPIO, MISO5_GPIO};

// SPI Configuration Structure
rawSPI_t spi_config = {
    .clk = 5,            // GPIO pin for SPI Clock (SCLK)
    .mosi = 12,           // GPIO pin for SPI Master Out Slave In (MOSI)
    .ss_pol = 1,          // Slave Select polarity (1 = active low)
    .ss_us = 1,           // Delay after asserting Slave Select (microseconds)
    .clk_pol = 0,         // Clock polarity (0 = resting low)
    .clk_pha = 0,         // Clock phase (0 = sample on rising edge)
    .clk_us = 1            // Clock period (microseconds, determines SPI speed)
};


// Function Prototypes
void extract_adc_readings(int num_adcs, int *miso_gpios, int ool_start, int bytes_per_adc, int bits_per_reading, char *buffer);


// Function to extract MISO bits and collate ADC readings
void extract_adc_readings(
    int num_adcs,          // Number of connected ADCs
    int *miso_gpios,         // Array of MISO GPIO pins
    int ool_start,         // Starting address of OOL (Out-of-line memory)
    int bytes_per_adc,     // Number of bytes per ADC in the buffer
    int bits_per_reading,    // Number of bits in each ADC reading
    char *buffer           // Buffer to store the extracted readings
) {
    int i, a, p;
    uint32_t level;

    p = ool_start;

    for (i = 0; i < bits_per_reading; i++) {
        level = rawWaveGetOut(p);

        for (a = 0; a < num_adcs; a++) {
            putBitInBytes(i, buffer + (bytes_per_adc * a), level & (1 << miso_gpios[a]));
        }

        p--;
    }
}


int main(int argc, char *argv[]) {
    int i, wave_id, offset;
    char spi_tx_buffer[2];
    gpioPulse_t final_pulse_sequence[2];
    char adc_data[8];
    int sample_count;
    int adc_value;
    int current_cb, bottom_cb, top_ool, current_reading, previous_reading;
    float cbs_per_reading;
    rawWaveInfo_t wave_info;
    double start_time, end_time;
    int sleep_duration;

    // Parse optional sleep duration argument
    if (argc > 1) {
        sleep_duration = atoi(argv[1]);
    } else {
        sleep_duration = 0;
    }

    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO pins for output
    gpioSetMode(spi_config.clk, PI_OUTPUT);   // SPI clock
    gpioSetMode(spi_config.mosi, PI_OUTPUT);  // SPI MOSI
    gpioSetMode(SPI_SS_GPIO, PI_OUTPUT);      // Slave Select

    // Initialize wave data
    gpioWaveAddNew();  // Clear any existing wave data

    offset = 0;

    // Construct bit-banged SPI reads for each ADC
    for (i = 0; i < BUFFER_SIZE; i++) {
        spi_tx_buffer[0] = 0xC0;  // Start bit, single-ended mode, channel 0

        // Add SPI transaction to the wave
        rawWaveAddSPI(&spi_config, offset, SPI_SS_GPIO, spi_tx_buffer, 2, DATA_BIT_POSITION, 0 + DATA_BIT_POSITION + BITS_PER_READING - 1, 0 + DATA_BIT_POSITION + BITS_PER_READING - 1);

        offset += REPEAT_INTERVAL_US;  // Increment offset for next reading
    }

    // Force the same delay after the last reading
    final_pulse_sequence[0].gpioOn = 0;
    final_pulse_sequence[0].gpioOff = 0;
    final_pulse_sequence[0].usDelay = offset;

    final_pulse_sequence[1].gpioOn = 0;  // Dummy pulse to ensure final delay
    final_pulse_sequence[1].gpioOff = 0;
    final_pulse_sequence[1].usDelay = 0;

    gpioWaveAddGeneric(2, final_pulse_sequence);  // Add final delay to the wave

    // Create the wave
    wave_id = gpioWaveCreate();

    if (wave_id < 0) {
        fprintf(stderr, "Error: Could not create wave.  Wave ID: %d (Too many?)\n", wave_id);
        gpioTerminate();
        return 1;
    }

    // Get wave information
    wave_info = rawWaveInfo(wave_id);

    printf("# cb %d-%d ool %d-%d del=%d ncb=%d nb=%d nt=%d\n",
           wave_info.botCB, wave_info.topCB, wave_info.botOOL, wave_info.topOOL, wave_info.deleted,
           wave_info.numCB, wave_info.numBOOL, wave_info.numTOOL);

    bottom_cb = wave_info.botCB;
    cbs_per_reading = (float)wave_info.numCB / (float)BUFFER_SIZE;

    printf("# cbs=%d per read=%.1f base=%d\n", wave_info.numCB, cbs_per_reading, bottom_cb);

    top_ool = wave_info.topOOL;

    fprintf(stderr, "Starting data acquisition...\n");

    if (sleep_duration) {
        time_sleep(sleep_duration);
    }

    gpioWaveTxSend(wave_id, PI_WAVE_MODE_REPEAT);  // Start transmitting the wave in repeat mode

    previous_reading = 0;
    sample_count = 0;

    start_time = time_time();  // Record start time

    while (sample_count < NUM_SAMPLES) {
        // Determine the current reading
        current_cb = rawWaveCB() - bottom_cb;
        current_reading = (float)current_cb / cbs_per_reading;

        // Process new readings
        while (current_reading != previous_reading) {
            // Extract ADC readings from the wave buffer
            extract_adc_readings(
                NUM_ADCS,
                miso_gpios,
                top_ool - ((int)(previous_reading) % BUFFER_SIZE) * BITS_PER_READING - 1,
                2,
                BITS_PER_READING,
                adc_data
            );

            printf("%d", ++sample_count);

            for (i = 0; i < NUM_ADCS; i++) {
                // Combine bytes to form the ADC value
                adc_value = (adc_data[i * 2] << 4) + (adc_data[(i * 2) + 1] >> 4);

                // Scale 10-bit ADC values to 12-bit range
                if (i > 1) {
                    adc_value = (adc_value & 0x3FF) << 2;
                }

                printf(" %d", adc_value);
            }

            printf("\n");

            previous_reading++;
            if (previous_reading >= BUFFER_SIZE) {
                previous_reading = 0;
            }
        }
        usleep(1000); //prevent the loop from hogging the CPU
    }

    end_time = time_time();  // Record end time

    printf("# %d samples in %.1f seconds (%.0f/s)\n",
           NUM_SAMPLES, end_time - start_time, (float)NUM_SAMPLES / (end_time - start_time));

    fprintf(stderr, "Data acquisition complete.\n");

    if (sleep_duration) {
        time_sleep(sleep_duration);
    }

    // Clean up and terminate
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <time.h>
#include <pigpio.h>

// Constants
#define NUM_GPIO 32
#define MIN_SERVO_WIDTH 1000  // Minimum servo pulse width (us)
#define MAX_SERVO_WIDTH 2000  // Maximum servo pulse width (us)
#define DEFAULT_PULSE_WIDTH 1500 // Default pulse width

// Global variables
volatile sig_atomic_t program_running = 1; // Flag to control program execution
int servo_gpio[NUM_GPIO];                  // Array to store GPIO pins used for servos
int servo_pulse_width[NUM_GPIO];           // Array to store current pulse widths for each servo
int servo_step_size[NUM_GPIO];             // Array to store step sizes for pulse width adjustments
bool servo_used[NUM_GPIO];                 // Array to track which GPIOs are used

// Function prototypes
void signal_handler(int signal);
int generate_random_number(int min, int max);
int initialize_gpio(void);
void cleanup_gpio(void);
int parse_gpio_arguments(int argc, char *argv[]);

/**
 * @brief Signal handler to gracefully terminate the program.
 *
 * @param signal The signal received.
 */
void signal_handler(int signal) {
  if (signal == SIGINT) {
    program_running = 0;
    fprintf(stderr, "\nCaught signal SIGINT. Exiting gracefully...\n");
  }
}

/**
 * @brief Generates a pseudo-random integer within a specified range.
 *
 * @param min The minimum value (inclusive).
 * @param max The maximum value (inclusive).
 * @return A pseudo-random integer between min and max.
 */
int generate_random_number(int min, int max) {
  return (rand() % (max - min + 1)) + min;
}

/**
 * @brief Initializes the pigpio library.
 *
 * @return 0 on success, -1 on failure.
 */
int initialize_gpio(void) {
  if (gpioInitialise() < 0) {
    fprintf(stderr, "pigpio initialisation failed\n");
    return -1;
  }
  return 0;
}

/**
 * @brief Terminates the pigpio library and cleans up GPIO settings.
 */
void cleanup_gpio(void) {
  printf("Cleaning up GPIO...\n");
  for (int gpio = 0; gpio < NUM_GPIO; gpio++) {
    if (servo_used[gpio]) {
      gpioServo(gpio, 0); // Disable servo pulses
    }
  }
  gpioTerminate(); // Terminate pigpio
}

/**
 * @brief Parses command-line arguments to determine which GPIOs to use for servos.
 *
 * @param argc The number of command-line arguments.
 * @param argv An array of command-line argument strings.
 * @return 0 on success, -1 on failure.
 */
int parse_gpio_arguments(int argc, char *argv[]) {
  if (argc == 1) {
    servo_used[4] = true; // Default to GPIO 4 if no arguments are provided
  } else {
    for (int i = 1; i < argc; i++) {
      int gpio = atoi(argv[i]);
      if (gpio >= 0 && gpio < NUM_GPIO) {
        servo_used[gpio] = true;
      } else {
        fprintf(stderr, "Invalid GPIO: %d\n", gpio);
        return -1; // Indicate an error
      }
    }
  }
  return 0;
}

int main(int argc, char *argv[]) {
  // Seed the random number generator
  srand(time(NULL));

  // Initialize pigpio
  if (initialize_gpio() != 0) {
    return 1; // Exit if initialization fails
  }

  // Set the signal handler for Ctrl+C (SIGINT)
  signal(SIGINT, signal_handler);

  // Parse command-line arguments to determine which GPIOs to use
  if (parse_gpio_arguments(argc, argv) != 0) {
    cleanup_gpio(); // Clean up before exiting
    return 1;       // Exit if argument parsing fails
  }

  printf("Sending servo pulses to GPIO(s): ");
  for (int gpio = 0; gpio < NUM_GPIO; gpio++) {
    if (servo_used[gpio]) {
      printf("%d ", gpio);
      servo_gpio[gpio] = gpio;                                    // Store the GPIO number
      servo_step_size[gpio] = generate_random_number(5, 25);       // Random step size
      if ((servo_step_size[gpio] % 2) == 0) servo_step_size[gpio] = -servo_step_size[gpio]; // Ensure step size alternates direction
      servo_pulse_width[gpio] = generate_random_number(MIN_SERVO_WIDTH, MAX_SERVO_WIDTH); // Initial pulse width
    }
  }
  printf("\nPress Ctrl+C to stop.\n");

  // Main loop to control servo positions
  while (program_running) {
    for (int gpio = 0; gpio < NUM_GPIO; gpio++) {
      if (servo_used[gpio]) {
        gpioServo(gpio, servo_pulse_width[gpio]); // Set the servo pulse width

        servo_pulse_width[gpio] += servo_step_size[gpio]; // Adjust pulse width

        // Reverse direction if pulse width reaches limits
        if (servo_pulse_width[gpio] < MIN_SERVO_WIDTH || servo_pulse_width[gpio] > MAX_SERVO_WIDTH) {
          servo_step_size[gpio] = -servo_step_size[gpio];
          servo_pulse_width[gpio] += servo_step_size[gpio]; // Ensure it is still in range
        }
      }
    }

    gpioDelay(100000); // Wait 0.1 seconds (100 ms) using a pigpio function
  }

  // Clean up and exit
  cleanup_gpio();
  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>

// Define a structure to hold rotary encoder data
typedef struct {
    int gpioA;
    int gpioB;
    void (*callback)(int);
    int levelA;
    int levelB;
    int lastGpio;
} RotaryEncoder;

// Forward declaration of the interrupt handler
static void rotaryInterruptHandler(int gpio, int level, uint32_t tick, void *user);

// Global variable to store the current position
static volatile int currentPosition = 0;

// Callback function to handle rotary encoder changes
void updatePosition(int direction)
{
    currentPosition += direction;
    printf("Position: %d\n", currentPosition);
}

// Initialize the rotary encoder
RotaryEncoder *rotaryEncoderSetup(int gpioA, int gpioB, void (*callback)(int))
{
    RotaryEncoder *encoder = malloc(sizeof(RotaryEncoder));
    if (encoder == NULL) {
        perror("Failed to allocate memory for rotary encoder");
        return NULL;
    }

    encoder->gpioA = gpioA;
    encoder->gpioB = gpioB;
    encoder->callback = callback;
    encoder->levelA = 0;
    encoder->levelB = 0;
    encoder->lastGpio = -1;

    // Set GPIO modes and pull-ups
    if (gpioSetMode(gpioA, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set GPIO %d mode\n", gpioA);
        free(encoder);
        return NULL;
    }
    if (gpioSetMode(gpioB, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set GPIO %d mode\n", gpioB);
        free(encoder);
        return NULL;
    }

    if (gpioSetPullUpDown(gpioA, PI_PUD_UP) != 0) {
        fprintf(stderr, "Failed to set GPIO %d pull-up\n", gpioA);
        free(encoder);
        return NULL;
    }
    if (gpioSetPullUpDown(gpioB, PI_PUD_UP) != 0) {
        fprintf(stderr, "Failed to set GPIO %d pull-up\n", gpioB);
        free(encoder);
        return NULL;
    }

    // Set interrupt handlers
    if (gpioSetAlertFuncEx(gpioA, rotaryInterruptHandler, encoder) != 0) {
        fprintf(stderr, "Failed to set interrupt handler for GPIO %d\n", gpioA);
        free(encoder);
        return NULL;
    }
    if (gpioSetAlertFuncEx(gpioB, rotaryInterruptHandler, encoder) != 0) {
        fprintf(stderr, "Failed to set interrupt handler for GPIO %d\n", gpioB);
        free(encoder);
        return NULL;
    }

    return encoder;
}

// Interrupt handler for rotary encoder changes
static void rotaryInterruptHandler(int gpio, int level, uint32_t tick, void *user)
{
    RotaryEncoder *encoder = (RotaryEncoder *)user;

    if (gpio == encoder->gpioA) {
        encoder->levelA = level;
    } else {
        encoder->levelB = level;
    }

    if (gpio != encoder->lastGpio) {
        encoder->lastGpio = gpio;

        if ((gpio == encoder->gpioA) && (level == 1)) {
            if (encoder->levelB) {
                encoder->callback(1); // Clockwise
            }
        } else if ((gpio == encoder->gpioB) && (level == 1)) {
            if (encoder->levelA) {
                encoder->callback(-1); // Counter-clockwise
            }
        }
    }
}

// Clean up and release resources
void rotaryEncoderCleanup(RotaryEncoder *encoder)
{
    if (encoder) {
        gpioSetAlertFunc(encoder->gpioA, NULL);
        gpioSetAlertFunc(encoder->gpioB, NULL);
        free(encoder);
    }
}

int main()
{
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Setup the rotary encoder
    RotaryEncoder *encoder = rotaryEncoderSetup(7, 8, updatePosition);
    if (encoder == NULL) {
        gpioTerminate();
        return 1;
    }

    // Keep the program running for a while
    sleep(300);

    // Cleanup
    rotaryEncoderCleanup(encoder);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
