// PCF8591 I2C Address
#define PCF8591_I2C_ADDR 0x48

// Function to initialize the I2C connection
int initI2C(int adapter_nr, int device_address) {
    int file_desc;
    char filename[20];

    snprintf(filename, 19, "/dev/i2c-%d", adapter_nr);
    file_desc = open(filename, O_RDWR);
    if (file_desc < 0) {
        perror("Error opening I2C device");
        return -1;
    }

    if (ioctl(file_desc, I2C_SLAVE, device_address) < 0) {
        perror("Error acquiring I2C bus access or setting slave address");
        close(file_desc);
        return -1;
    }

    return file_desc;
}

// Function to read data from PCF8591
int readPCF8591(int file_desc, int channel) {
    unsigned char command[1];
    unsigned char value;

    // Construct the command byte (enable output, select channel)
    command[0] = 0x40 | (channel & 0x03);

    // Write the command to the device
    if (write(file_desc, command, 1) != 1) {
        perror("Error writing to I2C device");
        return -1;
    }

    // Small delay to allow the ADC to convert
    usleep(20000);

    // Read the result
    if (read(file_desc, &value, 1) != 1) {
        perror("Error reading from I2C device");
        return -1;
    }

    return value;
}

int main(int argc, char *argv[]) {
    int i2c_file_desc;
    int channel_values[4];
    int key;
    int i,j;
