    char value_str[4];

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Initialize ncurses
    initscr();
    noecho(); // Do not echo user input
