    nodelay(stdscr, TRUE); // Non-blocking getch()
    curs_set(0); // Hide the cursor

    printw("PCF8591 Analog Reader - Press + or - to change DAC output, any other key to quit.\n");
    mvaddstr(2, 0, "Channel 0: Brightness");
    mvaddstr(4, 0, "Channel 1: Temperature");
    mvaddstr(6, 0, "Channel 2: (Potentiometer?)");
    mvaddstr(8, 0, "Channel 3: (Another Sensor?)");
    mvaddstr(10, 0, "DAC Output:");

    refresh();

    // Initialize I2C
    i2c_file_desc = initI2C(1, PCF8591_I2C_ADDR);
    if (i2c_file_desc < 0) {
        endwin(); // End ncurses
        gpioTerminate(); // Terminate pigpio
        return 1;
    }

    // Main loop
    while (1) {
        // Read values from each channel
        for (i = 0; i < 4; i++) {
            channel_values[i] = readPCF8591(i2c_file_desc, i);
            if (channel_values[i] < 0) {
                mvprintw(12, 0, "Error reading channel %d", i);
                refresh();
                continue; // Continue to the next channel
            }

            sprintf(value_str, "%3d", channel_values[i]);
            mvaddstr(2 + i + i, 20, value_str);
            move(2 + i + i, 25);

            int bar_length = channel_values[i] / 4; // Scale to fit 64 characters
            for(j = 0; j < 64; j++)
                if(j < bar_length) addch('*'); else addch(' ');
        }

        // Update DAC output
        unsigned char dac_command[2];
        dac_command[0] = 0x40; // Enable DAC output
        dac_command[1] = aout_value;
        if (write(i2c_file_desc, dac_command, 2) != 2) {
            mvprintw(12, 0, "Error writing to DAC");
            refresh();
        } else {
            sprintf(value_str, "%3d", aout_value);
            mvaddstr(10, 20, value_str);
        }


        refresh();

        // Handle user input
        key = getch();
        if (key == '+' || key == '=') {
            aout_value++;
            if (aout_value > 255) aout_value = 255; //Clamp value
        } else if (key == '-' || key == '_') {
            aout_value--;
            if (aout_value < 0) aout_value = 0; //Clamp value
        } else if (key != ERR) {
            break; // Exit on any other key press
        }

        usleep(50000); // Small delay to prevent excessive CPU usage
    }

    // Clean up
    endwin();
    close(i2c_file_desc);
    gpioTerminate();

    return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <stdint.h>
#include <string.h>
#include <fcntl.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <sys/types.h>
#include <errno.h>
#include <stdlib.h>

// GPIO register offsets
#define GPSET0_OFFSET 7
#define GPSET1_OFFSET 8

#define GPCLR0_OFFSET 10
#define GPCLR1_OFFSET 11

#define GPLEV0_OFFSET 13
#define GPLEV1_OFFSET 14

#define GPPUD_OFFSET     37
#define GPPUDCLK0_OFFSET 38
#define GPPUDCLK1_OFFSET 39

// GPIO modes
#define GPIO_INPUT  0
#define GPIO_OUTPUT 1
#define GPIO_ALT0   4
#define GPIO_ALT1   5
#define GPIO_ALT2   6
#define GPIO_ALT3   7
#define GPIO_ALT4   3
#define GPIO_ALT5   2

// Pull-up/down resistor control values
#define GPIO_PUD_OFF  0
#define GPIO_PUD_DOWN 1
#define GPIO_PUD_UP   2

// Global variables
static unsigned int raspberryPiModel = 0;
static unsigned int raspberryPiRevision = 0;
static volatile uint32_t *gpioRegisters = MAP_FAILED;

// Helper macros
#define GPIO_BANK(gpio) ((gpio) >> 5)
#define GPIO_BIT(gpio)  (1 << ((gpio) & 0x1F))

// Function prototypes
int initializeGPIO();
void terminateGPIO();
unsigned int getHardwareRevision();

void setGPIOFunction(unsigned int gpio, unsigned int function);
unsigned int getGPIOFunction(unsigned int gpio);

void setGPIOPullUpDown(unsigned int gpio, unsigned int pudControl);
int readGPIO(unsigned int gpio);
void writeGPIO(unsigned int gpio, unsigned int level);
void triggerGPIO(unsigned int gpio, unsigned int pulseLengthUs, unsigned int level);

uint32_t readGPIOBank1();
uint32_t readGPIOBank2();
void clearGPIOBank1(uint32_t bitsToClear);
void clearGPIOBank2(uint32_t bitsToClear);
void setGPIOBank1(uint32_t bitsToSet);
void setGPIOBank2(uint32_t bitsToSet);


int main()
{
    int i;

    if (initializeGPIO() != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return 1;
    }

    printf("Raspberry Pi Model: %u, Revision: %u\n", raspberryPiModel, raspberryPiRevision);

    for (i = 0; i < 54; i++) {
        printf("GPIO %d: Mode = %u, Level = %d\n", i, getGPIOFunction(i), readGPIO(i));
    }

    terminateGPIO();
    return 0;
}


/*
 * Initializes the GPIO memory mapping.
 * Returns 0 on success, -1 on failure.
 */
int initializeGPIO()
{
    int fileDescriptor;

    raspberryPiRevision = getHardwareRevision(); // Sets raspberryPiModel and raspberryPiRevision

    fileDescriptor = open("/dev/gpiomem", O_RDWR | O_SYNC);
    if (fileDescriptor < 0) {
        fprintf(stderr, "Failed to open /dev/gpiomem: %s\n", strerror(errno));
        return -1;
    }

    gpioRegisters = (uint32_t *)mmap(NULL, 0xB4, PROT_READ | PROT_WRITE, MAP_SHARED, fileDescriptor, 0);
    if (gpioRegisters == MAP_FAILED) {
        fprintf(stderr, "mmap failed: %s\n", strerror(errno));
        close(fileDescriptor);
        return -1;
    }

    close(fileDescriptor);
    return 0;
}

/*
 * Unmaps the GPIO memory mapping.
 */
void terminateGPIO()
{
    if (gpioRegisters != MAP_FAILED) {
        if (munmap((void *)gpioRegisters, 0xB4) != 0) {
            fprintf(stderr, "munmap failed: %s\n", strerror(errno));
        }
        gpioRegisters = MAP_FAILED;
    }
}

/*
 * Gets the hardware revision of the Raspberry Pi.
 * Returns the revision number.
 */
unsigned int getHardwareRevision()
{
    static unsigned int revision = 0;
    FILE *filePointer;
    char buffer[512];
    char term;
    int chars = 4; // Number of characters in revision string

    if (revision) return revision;

    raspberryPiModel = 0;

    filePointer = fopen("/proc/cpuinfo", "r");
    if (filePointer == NULL) {
        fprintf(stderr, "Failed to open /proc/cpuinfo: %s\n", strerror(errno));
        return 0; // Unable to determine revision
    }

    while (fgets(buffer, sizeof(buffer), filePointer) != NULL) {
        if (raspberryPiModel == 0) {
            if (!strncasecmp("model name", buffer, 10)) {
                if (strstr(buffer, "ARMv6") != NULL) {
                    raspberryPiModel = 1;
                    chars = 4;
                } else if (strstr(buffer, "ARMv7") != NULL) {
                    raspberryPiModel = 2;
                    chars = 6;
                } else if (strstr(buffer, "ARMv8") != NULL) {
                    raspberryPiModel = 2;
                    chars = 6;
                }
            }
        }

        if (!strncasecmp("revision", buffer, 8)) {
            if (sscanf(buffer + strlen(buffer) - (chars + 1), "%x%c", &revision, &term) == 2) {
                if (term != '\n') revision = 0;
            }
        }
    }

    fclose(filePointer);
    return revision;
}

/*
 * Sets the function of a GPIO pin (input, output, alt0-5).
 * gpio: The GPIO pin number (0-53).
 * function: The desired function (GPIO_INPUT, GPIO_OUTPUT, GPIO_ALT0, etc.).
 */
void setGPIOFunction(unsigned int gpio, unsigned int function)
{
    if (gpio >= 54) {
        fprintf(stderr, "Invalid GPIO pin number: %u\n", gpio);
        return;
    }

    if (gpioRegisters == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return;
    }

    int registerIndex = gpio / 10;
    int shift = (gpio % 10) * 3;

    gpioRegisters[registerIndex] = (gpioRegisters[registerIndex] & ~(7 << shift)) | (function << shift);
}

/*
 * Gets the function of a GPIO pin.
 * gpio: The GPIO pin number (0-53).
 * Returns the function (GPIO_INPUT, GPIO_OUTPUT, GPIO_ALT0, etc.).
 */
unsigned int getGPIOFunction(unsigned int gpio)
{
    if (gpio >= 54) {
        fprintf(stderr, "Invalid GPIO pin number: %u\n", gpio);
        return 0; // Or some other error code
    }

    if (gpioRegisters == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return 0; // Or some other error code
    }

    int registerIndex = gpio / 10;
    int shift = (gpio % 10) * 3;

    return (gpioRegisters[registerIndex] >> shift) & 7;
}

/*
 * Sets the pull-up/down resistor control for a GPIO pin.
 * gpio: The GPIO pin number (0-53).
 * pudControl: The pull-up/down control value (GPIO_PUD_OFF, GPIO_PUD_DOWN, GPIO_PUD_UP).
 */
void setGPIOPullUpDown(unsigned int gpio, unsigned int pudControl)
{
    if (gpio >= 54) {
        fprintf(stderr, "Invalid GPIO pin number: %u\n", gpio);
        return;
    }

    if (gpioRegisters == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return;
    }

    gpioRegisters[GPPUD_OFFSET] = pudControl;
    usleep(20); // Short delay
    gpioRegisters[GPPUDCLK0_OFFSET + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    usleep(20); // Short delay
    gpioRegisters[GPPUD_OFFSET] = 0;
    gpioRegisters[GPPUDCLK0_OFFSET + GPIO_BANK(gpio)] = 0;
}

/*
 * Reads the level of a GPIO pin.
 * gpio: The GPIO pin number (0-53).
 * Returns 1 if the pin is high, 0 if the pin is low.
 */
int readGPIO(unsigned int gpio)
{
    if (gpio >= 54) {
        fprintf(stderr, "Invalid GPIO pin number: %u\n", gpio);
        return 0; // Or some other error code
    }

    if (gpioRegisters == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return 0; // Or some other error code
    }

    return (gpioRegisters[GPLEV0_OFFSET + GPIO_BANK(gpio)] & GPIO_BIT(gpio)) ? 1 : 0;
}

/*
 * Writes a level to a GPIO pin.
 * gpio: The GPIO pin number (0-53).
 * level: The level to write (0 or 1).
 */
void writeGPIO(unsigned int gpio, unsigned int level)
{
    if (gpio >= 54) {
        fprintf(stderr, "Invalid GPIO pin number: %u\n", gpio);
        return;
    }

    if (gpioRegisters == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return;
    }

    if (level == 0) {
        gpioRegisters[GPCLR0_OFFSET + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    } else {
        gpioRegisters[GPSET0_OFFSET + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    }
}

/*
 * Triggers a GPIO pin with a pulse of a specified length.
 * gpio: The GPIO pin number (0-53).
 * pulseLengthUs: The length of the pulse in microseconds.
 * level: The initial level of the pulse (0 or 1).
 */
void triggerGPIO(unsigned int gpio, unsigned int pulseLengthUs, unsigned int level)
{
    if (gpio >= 54) {
        fprintf(stderr, "Invalid GPIO pin number: %u\n", gpio);
        return;
    }

    if (gpioRegisters == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return;
    }

    if (level == 0) {
        gpioRegisters[GPCLR0_OFFSET + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    } else {
        gpioRegisters[GPSET0_OFFSET + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    }

    usleep(pulseLengthUs);

    if (level != 0) {
        gpioRegisters[GPCLR0_OFFSET + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    } else {
        gpioRegisters[GPSET0_OFFSET + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    }
}

/*
 * Reads the level of all GPIO pins in bank 1 (GPIO 0-31).
 * Returns a 32-bit value where each bit represents the level of a GPIO pin.
 */
uint32_t readGPIOBank1()
{
    if (gpioRegisters == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return 0; // Or some other error code
    }
    return gpioRegisters[GPLEV0_OFFSET];
}

/*
 * Reads the level of all GPIO pins in bank 2 (GPIO 32-53).
 * Returns a 32-bit value where each bit represents the level of a GPIO pin.
 */
uint32_t readGPIOBank2()
{
    if (gpioRegisters == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return 0; // Or some other error code
    }
    return gpioRegisters[GPLEV1_OFFSET];
}

/*
 * Clears the specified bits in bank 1 (GPIO 0-31).
 * bitsToClear: A 32-bit value where each bit set to 1 will clear the corresponding GPIO pin.
 */
void clearGPIOBank1(uint32_t bitsToClear)
{
    if (gpioRegisters == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return;
    }
    gpioRegisters[GPCLR0_OFFSET] = bitsToClear;
}

/*
 * Clears the specified bits in bank 2 (GPIO 32-53).
 * bitsToClear: A 32-bit value where each bit set to 1 will clear the corresponding GPIO pin.
 */
void clearGPIOBank2(uint32_t bitsToClear)
{
    if (gpioRegisters == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return;
    }
    gpioRegisters[GPCLR1_OFFSET] = bitsToClear;
}

/*
 * Sets the specified bits in bank 1 (GPIO 0-31).
 * bitsToSet: A 32-bit value where each bit set to 1 will set the corresponding GPIO pin.
 */
void setGPIOBank1(uint32_t bitsToSet)
{
    if (gpioRegisters == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return;
    }
    gpioRegisters[GPSET0_OFFSET] = bitsToSet;
}

/*
 * Sets the specified bits in bank 2 (GPIO 32-53).
 * bitsToSet: A 32-bit value where each bit set to 1 will set the corresponding GPIO pin.
 */
void setGPIOBank2(uint32_t bitsToSet)
{
    if (gpioRegisters == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return;
    }
    gpioRegisters[GPSET1_OFFSET] = bitsToSet;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <unistd.h>
#include <errno.h>
#include <string.h>
#include <wiringPi.h>
#include <drcSerial.h>

// Constants
#define GERTBOARD_BASE_PIN 100
#define NUM_LEDS 12
#define DEFAULT_BAUD_RATE 115200
#define SERIAL_PORT "/dev/ttyAMA0"

// Pin mapping: Raspberry Pi native pins and Gertboard pins
static const int led_pins[NUM_LEDS] = {
    0, 1, 2, 3,                             // Pi Native GPIO pins
    GERTBOARD_BASE_PIN + 2, GERTBOARD_BASE_PIN + 3, GERTBOARD_BASE_PIN + 4, GERTBOARD_BASE_PIN + 5,
    GERTBOARD_BASE_PIN + 6, GERTBOARD_BASE_PIN + 7, GERTBOARD_BASE_PIN + 8, GERTBOARD_BASE_PIN + 9
};

// Structure for sequence data
typedef struct {
    int led_index;
    int state;
    int duration_ms;
} sequence_step_t;

// Sequence data: LED index, state (0 or 1), duration in milliseconds
static const sequence_step_t sequence[] = {
    {0, 1, 100},    // LED 0 ON for 100ms
    {1, 1, 100},    // LED 1 ON for 100ms

    {0, 0, 0},    {2, 1, 100},    // LED 0 OFF, LED 2 ON for 100ms
    {1, 0, 0},    {3, 1, 100},    // LED 1 OFF, LED 3 ON for 100ms
    {2, 0, 0},    {4, 1, 100},    // ...
    {3, 0, 0},    {5, 1, 100},
    {4, 0, 0},    {6, 1, 100},
    {5, 0, 0},    {7, 1, 100},
    {6, 0, 0},    {8, 1, 100},
    {7, 0, 0},    {9, 1, 100},
    {8, 0, 0},    {10, 1, 100},
    {9, 0, 0},    {11, 1, 100},
    {10, 0, 100},  // LED 10 OFF for 100ms
    {11, 0, 100},  // LED 11 OFF for 100ms

    {0, 0, 100},   // Extra delay

    {11, 1, 100},  // Back again
    {10, 1, 100},
    {11, 0, 0},   {9, 1, 100},
    {10, 0, 0},   {8, 1, 100},
    {9, 0, 0},    {7, 1, 100},
    {8, 0, 0},    {6, 1, 100},
    {7, 0, 0},    {5, 1, 100},
    {6, 0, 0},    {4, 1, 100},
    {5, 0, 0},    {3, 1, 100},
    {4, 0, 0},    {2, 1, 100},
    {3, 0, 0},    {1, 1, 100},
    {2, 0, 0},    {0, 1, 100},
    {1, 0, 100},
    {0, 0, 100},

    {0, 0, 100},   // Extra delay

    {-1, 0, 0}     // End marker: led_index = -1
};

// Function to initialize GPIO pins
int initialize_gpio(void) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing WiringPi: %s\n", strerror(errno));
        return -1;
    }

    // Set all LED pins as output
    for (int i = 0; i < NUM_LEDS; ++i) {
        pinMode(led_pins[i], OUTPUT);
    }
    return 0;
}

// Function to initialize DRC serial communication
int initialize_drc(void) {
    if (drcSetupSerial(GERTBOARD_BASE_PIN, 20, SERIAL_PORT, DEFAULT_BAUD_RATE) == -1) {
        fprintf(stderr, "Error initializing DRC serial communication.\n");
        return -1;
    }
    return 0;
}

int main(void) {
    printf("Raspberry Pi - 12-LED Sequence with Gertboard Control\n");
    printf("======================================================\n");
    printf("Connect LEDs to the specified GPIO pins and Gertboard pins.\n");
    printf("\n");

    // Initialize WiringPi and GPIO pins
    if (initialize_gpio() == -1) {
        return 1;
    }

    // Initialize DRC serial communication
    if (initialize_drc() == -1) {
        return 1;
    }

    // Main loop: iterate through the sequence
    const sequence_step_t *step = sequence;
    while (1) {
        // Check for end marker
        if (step->led_index == -1) {
            step = sequence; // Restart sequence
            continue;
        }

        // Validate LED index
        if (step->led_index < 0 || step->led_index >= NUM_LEDS) {
            fprintf(stderr, "Error: Invalid LED index: %d\n", step->led_index);
            return 1; // Exit on error
        }

        // Set LED state
        digitalWrite(led_pins[step->led_index], step->state);

        // Delay, scaled by Gertboard analog input
        int analog_value = analogRead(GERTBOARD_BASE_PIN);
        int delay_ms = (step->duration_ms * analog_value) / 4;  //Scale the delay based on the analog read value

        delay(delay_ms);

        // Move to the next step in the sequence
        step++;
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdint.h>
#include <errno.h>
#include <string.h>

// ADXL345 I2C address
#define ADXL345_I2C_ADDR 0x53

// ADXL345 Registers
#define ADXL345_REG_POWER_CTL 0x2D
#define ADXL345_REG_DATA_FORMAT 0x31
#define ADXL345_REG_DATAX0 0x32

// Scaling factor (assuming +/- 16g range and full resolution)
#define SCALE_FACTOR (9.80665 / 256.0) // Earth's gravity in m/s^2 divided by values.

// Function to select the I2C device
int select_i2c_device(int file_descriptor, int device_address, const char *device_name) {
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not select I2C device 0x%02x (%s): %s\n", device_address, device_name, strerror(errno));
        return -1;
    }
    return 0;
}

// Function to write a single byte to an I2C register
int write_i2c_register(int file_descriptor, uint8_t register_address, uint8_t value) {
    uint8_t buffer[2];
    buffer[0] = register_address;
    buffer[1] = value;

    if (write(file_descriptor, buffer, 2) != 2) {
        fprintf(stderr, "Error: Could not write to I2C register 0x%02x: %s\n", register_address, strerror(errno));
        return -1;
    }
    return 0;
}

// Function to read multiple bytes from an I2C register
int read_i2c_registers(int file_descriptor, uint8_t register_address, uint8_t *data, int length) {
    if (write(file_descriptor, &register_address, 1) != 1) {
        fprintf(stderr, "Error: Could not write register address for reading: %s\n", strerror(errno));
        return -1;
    }

    if (read(file_descriptor, data, length) != length) {
        fprintf(stderr, "Error: Could not read data from I2C: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

int main(int argc, char **argv) {
    int i2c_bus = 1; // Default I2C bus
    int file_descriptor; // File descriptor for the I2C device
    char i2c_device_name[20];
    int16_t x, y, z; // Raw accelerometer values
    float x_g, y_g, z_g; // Acceleration values in g
    uint8_t data_buffer[6]; // Buffer to store raw data

    // Optionally, allow the user to specify the I2C bus
    if (argc > 1) {
        i2c_bus = atoi(argv[1]);
    }

    // Construct the I2C device name
    snprintf(i2c_device_name, sizeof(i2c_device_name), "/dev/i2c-%d", i2c_bus);

    // Open the I2C device
    file_descriptor = open(i2c_device_name, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error: Could not open I2C device %s: %s\n", i2c_device_name, strerror(errno));
        return 1;
    }

    // Select the ADXL345 device
    if (select_i2c_device(file_descriptor, ADXL345_I2C_ADDR, "ADXL345") < 0) {
        close(file_descriptor);
        return 1;
    }

    // Initialize the ADXL345
    if (write_i2c_register(file_descriptor, ADXL345_REG_POWER_CTL, 0) < 0) { // Reset POWER_CTL
        close(file_descriptor);
        return 1;
    }
    if (write_i2c_register(file_descriptor, ADXL345_REG_POWER_CTL, 8) < 0) { // Set POWER_CTL to measure
        close(file_descriptor);
        return 1;
    }
    if (write_i2c_register(file_descriptor, ADXL345_REG_DATA_FORMAT, 0) < 0) { // Reset DATA_FORMAT
        close(file_descriptor);
        return 1;
    }
    if (write_i2c_register(file_descriptor, ADXL345_REG_DATA_FORMAT, 0x0B) < 0) { // Set DATA_FORMAT for full resolution and +/- 16g range
        close(file_descriptor);
        return 1;
    }

    // Main loop to read and print accelerometer data
    while (1) {
        // Read the accelerometer data
        if (read_i2c_registers(file_descriptor, ADXL345_REG_DATAX0, data_buffer, 6) < 0) {
            fprintf(stderr, "Error reading accelerometer data. Retrying...");
            usleep(100000); // Wait before retrying
            continue;
        }

        // Combine the high and low bytes to get the signed 16-bit values
        x = (int16_t)((data_buffer[1] << 8) | data_buffer[0]);
        y = (int16_t)((data_buffer[3] << 8) | data_buffer[2]);
        z = (int16_t)((data_buffer[5] << 8) | data_buffer[4]);

        // Convert raw values to g
        x_g = x * SCALE_FACTOR;
        y_g = y * SCALE_FACTOR;
        z_g = z * SCALE_FACTOR;

        // Print the acceleration values
        printf("X: %.3f g, Y: %.3f g, Z: %.3f g\n", x_g, y_g, z_g);

        // Wait before the next reading
        usleep(100000); // 100ms
    }

    // Close the I2C device (this will never be reached in the current loop)
    close(file_descriptor);
    return 0;
}

#include <stdio.h>
