// Structure to hold GPIO data
typedef struct {
    uint32_t first_tick;
    uint32_t last_tick;
    uint32_t pulse_count;
    pthread_mutex_t mutex;
} GpioData;

// Global variables
static GpioData gpio_data[MAX_GPIOS];
