static int num_monitored_gpios = 0;
static uint32_t gpio_mask = 0;
static int sample_rate_us = DEFAULT_SAMPLE_RATE_US;
static int report_interval_ds = DEFAULT_REPORT_INTERVAL_DS;
static volatile int program_running = 1;

// Function prototypes
void signal_handler(int signal);
void gpio_interrupt_handler(int gpio, int level, uint32_t tick);
void *reporting_thread(void *arg);
void cleanup();

// Signal handler to gracefully exit the program
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("\nExiting program...\n");
        program_running = 0;
    }
}

// Interrupt handler for GPIO level changes
void gpio_interrupt_handler(int gpio, int level, uint32_t tick) {
    pthread_mutex_lock(&gpio_data[gpio].mutex);
    if (level == 1) {
        gpio_data[gpio].pulse_count++;
    }

    if (gpio_data[gpio].first_tick == 0) {
        gpio_data[gpio].first_tick = tick;
    }
    gpio_data[gpio].last_tick = tick;
    pthread_mutex_unlock(&gpio_data[gpio].mutex);
}

// Reporting thread function
void *reporting_thread(void *arg) {
    while (program_running) {
        gpioDelay(report_interval_ds * 100000); // Convert deciseconds to microseconds

        for (int i = 0; i < num_monitored_gpios; i++) {
            int gpio = monitored_gpios[i];
            pthread_mutex_lock(&gpio_data[gpio].mutex);
            uint32_t first_tick = gpio_data[gpio].first_tick;
            uint32_t last_tick = gpio_data[gpio].last_tick;
            uint32_t pulse_count = gpio_data[gpio].pulse_count;
            gpio_data[gpio].first_tick = 0;
            gpio_data[gpio].last_tick = 0;
            gpio_data[gpio].pulse_count = 0;
            pthread_mutex_unlock(&gpio_data[gpio].mutex);

            if (first_tick != 0 && last_tick != 0) {
                uint32_t diff = last_tick - first_tick;
                if (diff == 0) diff = 1; // Avoid division by zero
                float frequency = 1000000.0 * pulse_count / diff; // Calculate frequency
                printf("GPIO %d: Frequency = %.2f Hz (%d pulses / %d ticks)\n", gpio, frequency, pulse_count, diff);
            } else {
                printf("GPIO %d: No pulses detected.\n", gpio);
            }
        }
    }
    return NULL;
}

// Cleanup function to release resources
void cleanup() {
    printf("Cleaning up resources...\n");
    for (int i = 0; i < num_monitored_gpios; i++) {
        gpioSetAlertFunc(monitored_gpios[i], NULL); // Disable interrupts
        gpioSetMode(monitored_gpios[i], PI_INPUT);    // Reset GPIO mode
        pthread_mutex_destroy(&gpio_data[monitored_gpios[i]].mutex);
    }
    gpioTerminate();
}

int main(int argc, char *argv[]) {
    // Install signal handler for graceful exit
    signal(SIGINT, signal_handler);

    // Parse command line arguments
    int opt;
    while ((opt = getopt(argc, argv, "s:r:")) != -1) {
        switch (opt) {
            case 's':
                sample_rate_us = atoi(optarg);
                if (sample_rate_us < 1 || sample_rate_us > 10) {
                    fprintf(stderr, "Invalid sample rate. Must be between 1 and 10.\n");
                    return 1;
                }
                break;
            case 'r':
                report_interval_ds = atoi(optarg);
                if (report_interval_ds < 1 || report_interval_ds > 300) {
                    fprintf(stderr, "Invalid report interval. Must be between 1 and 300.\n");
                    return 1;
                }
                break;
            default:
                fprintf(stderr, "Usage: %s [-s sample_rate] [-r report_interval] GPIO1 GPIO2 ...\n", argv[0]);
                return 1;
        }
    }

    // Get the GPIOs to monitor
    for (int i = optind; i < argc; i++) {
        int gpio = atoi(argv[i]);
        if (gpio >= 0 && gpio < MAX_GPIOS) {
            monitored_gpios[num_monitored_gpios++] = gpio;
            gpio_mask |= (1 << gpio);
        } else {
            fprintf(stderr, "Invalid GPIO number: %d\n", gpio);
            return 1;
        }
    }

    if (num_monitored_gpios == 0) {
        fprintf(stderr, "At least one GPIO must be specified.\n");
        return 1;
    }

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure clock and interrupts
    gpioCfgClock(sample_rate_us, 1, 1);

    // Initialize GPIO data and set interrupt handlers
    for (int i = 0; i < num_monitored_gpios; i++) {
        int gpio = monitored_gpios[i];
        gpio_data[gpio].first_tick = 0;
        gpio_data[gpio].last_tick = 0;
        gpio_data[gpio].pulse_count = 0;
        pthread_mutex_init(&gpio_data[gpio].mutex, NULL);
        gpioSetMode(gpio, PI_INPUT); // Set GPIO to input mode
        gpioSetAlertFunc(gpio, gpio_interrupt_handler); // Set interrupt handler
    }

    // Create and start the reporting thread
    pthread_t report_thread;
    if (pthread_create(&report_thread, NULL, reporting_thread, NULL) != 0) {
        perror("Failed to create reporting thread");
        cleanup();
        return 1;
    }

    // Wait for the reporting thread to finish (until program_running is set to 0)
    pthread_join(report_thread, NULL);

    // Cleanup and exit
    cleanup();

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdarg.h>
#include <unistd.h>
#include <string.h>
#include <pigpio.h>

// Constants
#define MAX_GPIOS 32

#define OPT_P_MIN 1
#define OPT_P_MAX 1000
#define OPT_P_DEFAULT 20

#define OPT_R_MIN 1
#define OPT_R_MAX 10
#define OPT_R_DEFAULT 5

#define OPT_S_MIN 1
#define OPT_S_MAX 10
#define OPT_S_DEFAULT 5

// Global Variables
static volatile int g_pulse_count[MAX_GPIOS]; // Pulse counts for each GPIO
static volatile int g_update_counts = 0;       // Flag to update counts
static uint32_t g_gpio_mask = 0;                // Mask of monitored GPIOs

static int g_num_gpios = 0;                   // Number of monitored GPIOs
static int g_gpio[MAX_GPIOS];                  // Array of monitored GPIOs

static int g_opt_p = OPT_P_DEFAULT;           // Pulse width (microseconds)
static int g_opt_r = OPT_R_DEFAULT;           // Report period (deciseconds)
static int g_opt_s = OPT_S_DEFAULT;           // Sample rate (microseconds)
static int g_opt_t = 0;                       // Flag for wave generation (testing)

static uint32_t report_interval_us = OPT_R_DEFAULT * 100000; // Report interval in microseconds

// Function Prototypes
void usage(const char *program_name);
void fatal(int show_usage, const char *fmt, ...);
int parse_options(int argc, char *argv[]);
void sample_callback(const gpioSample_t *samples, int num_samples);
int initialize_gpio();

// Function Implementations

// Displays usage information
void usage(const char *program_name)
{
    fprintf(stderr,
            "\n"
            "Usage: sudo %s gpio ... [OPTION] ...\n"
            "   -p value, sets pulses every p micros, %d-%d, TESTING only\n"
            "   -r value, sets refresh period in deciseconds, %d-%d, default %d\n"
            "   -s value, sets sampling rate in micros, %d-%d, default %d\n"
            "\nEXAMPLE\n"
            "sudo %s 4 7 -r2 -s2\n"
            "Monitor gpios 4 and 7.  Refresh every 0.2 seconds.  Sample rate 2 micros.\n"
            "\n",
            program_name,
            OPT_P_MIN, OPT_P_MAX,
            OPT_R_MIN, OPT_R_MAX, OPT_R_DEFAULT,
            OPT_S_MIN, OPT_S_MAX, OPT_S_DEFAULT,
            program_name);
}

// Prints an error message and exits
void fatal(int show_usage, const char *fmt, ...)
{
    char buf[256];
    va_list ap;

    va_start(ap, fmt);
    vsnprintf(buf, sizeof(buf), fmt, ap);
    va_end(ap);

    fprintf(stderr, "Error: %s\n", buf);

    if (show_usage) usage(program_name);

    fflush(stderr);
    gpioTerminate(); // Cleanly terminate pigpio
    exit(EXIT_FAILURE);
}

// Parses command-line options
int parse_options(int argc, char *argv[])
{
    int opt;
    int temp_int;
    program_name = argv[0];

    while ((opt = getopt(argc, argv, "p:r:s:")) != -1)
    {
        switch (opt)
        {
        case 'p':
            temp_int = atoi(optarg);
            if ((temp_int >= OPT_P_MIN) && (temp_int <= OPT_P_MAX))
            {
                g_opt_p = temp_int;
            }
            else
            {
                fatal(1, "Invalid -p option (%d)", temp_int);
            }
            g_opt_t = 1; // Enable wave generation
            break;

        case 'r':
            temp_int = atoi(optarg);
            if ((temp_int >= OPT_R_MIN) && (temp_int <= OPT_R_MAX))
            {
                g_opt_r = temp_int;
                report_interval_us = g_opt_r * 100000; // Update report interval
            }
            else
            {
                fatal(1, "Invalid -r option (%d)", temp_int);
            }
            break;

        case 's':
            temp_int = atoi(optarg);
            if ((temp_int >= OPT_S_MIN) && (temp_int <= OPT_S_MAX))
            {
                g_opt_s = temp_int;
            }
            else
            {
                fatal(1, "Invalid -s option (%d)", temp_int);
            }
            break;

        case '?':
            usage(program_name);
            exit(EXIT_FAILURE);
        default:
            usage(program_name);
            exit(EXIT_FAILURE);
        }
    }
    return optind;
}

// Callback function for GPIO samples
void sample_callback(const gpioSample_t *samples, int num_samples)
{
    static int initialized = 0;
    static uint32_t last_level;    // Last GPIO level
    static uint32_t last_report_tick; // Last report timestamp
    static int count[MAX_GPIOS];    // Pulse count for each GPIO

    uint32_t high, level; // Current GPIO level information
    int i, g, s, tick_diff;  // Loop counters and time difference

    if (!initialized)
    {
        initialized = 1;
        last_level = samples[0].level;
        last_report_tick = samples[0].tick;
        memset(count, 0, sizeof(count)); // Initialize counts to zero
    }

    for (s = 0; s < num_samples; s++)
    {
        tick_diff = samples[s].tick - last_report_tick;
        if (tick_diff >= report_interval_us)
        {
            last_report_tick = samples[s].tick;

            // Update global pulse counts for printing
            if (g_update_counts)
            {
                for (i = 0; i < g_num_gpios; i++)
                {
                    g_pulse_count[i] = count[i];
                }
                g_update_counts = 0;
            }

            memset(count, 0, sizeof(count)); // Reset local counts
        }

        level = samples[s].level;
        high = ((last_level ^ level) & g_gpio_mask) & level; // Detect rising edges
        last_level = level;

        // Increment count for each GPIO with a rising edge
        if (high)
        {
            for (g = 0; g < g_num_gpios; g++)
            {
                if (high & (1 << g_gpio[g]))
                {
                    count[g]++;
                }
            }
        }
    }
}

// Initializes the pigpio library and sets up GPIO modes
int initialize_gpio()
{
    gpioCfgClock(g_opt_s, 1, 1); // Configure clock

    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    gpioWaveClear(); // Clear any existing waves

    // Generate a square wave if -p option is used (testing only)
    if (g_opt_t)
    {
        gpioPulse_t pulse[2];
        pulse[0].gpioOn = g_gpio_mask;
        pulse[0].gpioOff = 0;
        pulse[0].usDelay = g_opt_p;

        pulse[1].gpioOn = 0;
        pulse[1].gpioOff = g_gpio_mask;
        pulse[1].usDelay = g_opt_p;

        gpioWaveAddGeneric(2, pulse);
        int wave_id = gpioWaveCreate();

        if (wave_id >= 0)
        {
            gpioWaveTxSend(wave_id, PI_WAVE_MODE_REPEAT); // Transmit wave repeatedly
        } else {
          fprintf(stderr, "Failed to create wave\n");
          return -1;
        }
    }

    // Set GPIO modes and callback
    gpioSetGetSamplesFunc(sample_callback, g_gpio_mask); // Set callback function
    for (int i = 0; i < g_num_gpios; i++)
    {
        gpioSetMode(g_gpio[i], g_opt_t ? PI_OUTPUT : PI_INPUT); // Set GPIO mode
    }

    return 0;
}

int main(int argc, char *argv[])
{
    int i, rest, g; // Loop counters and GPIO number
    float pulses_per_second;       // Calculated pulses per second

    // Parse command-line options
    rest = parse_options(argc, argv);

    // Get the GPIOs to monitor
    g_num_gpios = 0;
    for (i = rest; i < argc; i++)
    {
        g = atoi(argv[i]);
        if ((g >= 0) && (g < 32))
        {
            g_gpio[g_num_gpios++] = g;
            g_gpio_mask |= (1 << g); // Set the bit in the mask
        }
        else
        {
            fatal(1, "%d is not a valid GPIO number", g);
        }
    }

    if (g_num_gpios == 0)
    {
        fatal(1, "At least one GPIO must be specified");
    }

    // Print configuration information
    printf("Monitoring GPIOs");
    for (i = 0; i < g_num_gpios; i++)
    {
        printf(" %d", g_gpio[i]);
    }
    printf("\nSample rate %d micros, refresh rate %d deciseconds\n", g_opt_s, g_opt_r);

    // Initialize GPIO
    if (initialize_gpio() != 0) {
      gpioTerminate();
      return 1;
    }

    pulses_per_second = 10.0 / g_opt_r; // Calculate pulses per second

    // Main loop
    while (1)
    {
        usleep(50000); // Sleep for 50ms
        if (!g_update_counts)
        {
            for (i = 0; i < g_num_gpios; i++)
            {
                printf(" %2d=%.0f", g_gpio[i], pulses_per_second * g_pulse_count[i]); // Print frequency
            }
            printf("\n");
            g_update_counts = 1; // Signal that counts have been updated
        }
    }

    gpioTerminate(); // Terminate pigpio
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <pigpio.h>

// Define the GPIO pin connected to the Hall effect sensor
#define HALL_SENSOR_PIN 14

// Function prototype for the Hall sensor interrupt handler
void hallSensorInterrupt(int gpio, int level, uint32_t tick);

// Global variable to store the timestamp of the last state change
static uint32_t lastTick = 0;

// Hall sensor interrupt handler function
void hallSensorInterrupt(int gpio, int level, uint32_t tick) {
  // Calculate the time difference since the last state change
  double timeDiff;
  if (lastTick != 0) {
    timeDiff = (double)(tick - lastTick) / 1000000.0; // Convert to seconds
  } else {
    timeDiff = 0.0;
  }

  // Print the current level and the time difference
  printf("%d %.6f\n", level, timeDiff);

  // Update the last tick timestamp
  lastTick = tick;
}

int main(int argc, char *argv[]) {
  int run_duration_seconds = 60; // Default run duration

  // Check if a custom run duration is provided as a command-line argument
  if (argc > 1) {
    run_duration_seconds = atoi(argv[1]);
    if (run_duration_seconds <= 0 || run_duration_seconds > 3600) {
      fprintf(stderr, "Error: Invalid run duration. Using default (60 seconds).\n");
      run_duration_seconds = 60; // Revert to default if invalid
    }
  }

  // Initialize the pigpio library
  if (gpioInitialise() < 0) {
    fprintf(stderr, "Error: pigpio initialisation failed.\n");
    return 1;
  }

  // Set the GPIO pin mode to input
  gpioSetMode(HALL_SENSOR_PIN, PI_INPUT);

  // Enable internal pull-up resistor
  gpioSetPullUpDown(HALL_SENSOR_PIN, PI_PUD_UP);

  // Set the interrupt handler function for the Hall sensor pin
  if (gpioSetAlertFunc(HALL_SENSOR_PIN, hallSensorInterrupt) != 0) {
    fprintf(stderr, "Error: Failed to set alert function.\n");
    gpioTerminate();
    return 1;
  }

  // Run the program for the specified duration
  printf("Running for %d seconds...\n", run_duration_seconds);
  time_sleep(run_duration_seconds); // Using time_sleep for better compatibility and precision

  // Terminate the pigpio library
  gpioTerminate();

  printf("Program finished.\n");
  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdarg.h>
#include <unistd.h>
#include <stdint.h>
#include <string.h>
#include <fcntl.h>
#include <errno.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <sys/types.h>

// Define Raspberry Pi hardware register offsets
#define GPIO_BASE  0x200000  // GPIO base address
#define CLK_BASE   0x101000  // Clock controller base address
#define SYST_BASE  0x003000  // System Timer base address

// Define register lengths for memory mapping
#define GPIO_LEN   0xB4
#define CLK_LEN    0xA8
#define SYST_LEN   0x1C

// GPIO pin function select modes
#define GPIO_MODE_INPUT  0
#define GPIO_MODE_OUTPUT 1
#define GPIO_MODE_ALT0   4

// GPIO pin pull-up/down control
#define GPIO_PUD_OFF  0
#define GPIO_PUD_DOWN 1
#define GPIO_PUD_UP   2

// Clock source definitions
#define CLK_SRC_OSC  1  // 19.2 MHz oscillator
#define CLK_SRC_PLLC 5  // 1000 MHz PLLC
#define CLK_SRC_PLLD 6  // 500 MHz PLLD
#define CLK_SRC_HDMI 7  // 216 MHz HDMI auxiliary

// Clock control register bits
#define CLK_CTL_MASH(x) ((x) << 9)
#define CLK_CTL_BUSY    (1 << 7)
#define CLK_CTL_KILL    (1 << 5)
#define CLK_CTL_ENAB    (1 << 4)
#define CLK_CTL_SRC(x)  ((x) << 0)

// Clock divider register bits
#define CLK_DIV_DIVI(x) ((x) << 12)
#define CLK_DIV_DIVF(x) ((x) << 0)

// Clock password for write access
#define CLK_PASSWD  (0x5A << 24)

// Clock registers (GP0, GP2)
#define CLK_GP0_CTL 28
#define CLK_GP0_DIV 29
#define CLK_GP2_CTL 32
#define CLK_GP2_DIV 33

// Pointers to memory-mapped registers
static volatile uint32_t *gpioReg = MAP_FAILED;
static volatile uint32_t *clkReg  = MAP_FAILED;
static volatile uint32_t *systReg = MAP_FAILED;

// Function prototypes
int  gpioInitialise(void);
void gpioTerminate(void);
void gpioSetMode(unsigned int gpioPin, unsigned int mode);
int  gpioGetMode(unsigned int gpioPin);
void gpioSetPullUpDown(unsigned int gpioPin, unsigned int pud);
int  initClock(int clockId, int source, int divI, int divF, int mash);
int  termClock(int clockId);
void fatal(int show_usage, const char *fmt, ...);
void usage(void);
int  initOpts(int argc, char *argv[]);

// Global option variables
static int opt_clock = 0;  // Default clock is GPCLK0
static int opt_mash  = 0;  // Default MASH value is 0
static int opt_source = 0; // Default clock source is PLLD
static int opt_quiet = 0;  // Default is to disable clock on exit

// Helper function to map physical memory to virtual memory
static uint32_t *mapPeripheral(uint32_t baseAddr, uint32_t len)
{
    int fd = open("/dev/mem", O_RDWR | O_SYNC);
    if (fd < 0) {
        fprintf(stderr, "Failed to open /dev/mem.  Try using sudo.\n");
        return MAP_FAILED;
    }

    uint32_t *map = (uint32_t *)mmap(NULL, len, PROT_READ | PROT_WRITE, MAP_SHARED, fd, baseAddr);
    close(fd);

    if (map == MAP_FAILED) {
        fprintf(stderr, "mmap failed.\n");
    }
    return map;
}

// Initializes the GPIO, clock, and system timer registers
int gpioInitialise(void)
{
    // Map GPIO registers
    gpioReg = mapPeripheral(GPIO_BASE, GPIO_LEN);
    if (gpioReg == MAP_FAILED) return -1;

    // Map Clock registers
    clkReg = mapPeripheral(CLK_BASE, CLK_LEN);
    if (clkReg == MAP_FAILED) {
        gpioTerminate(); // Clean up already mapped memory
        return -1;
    }

    // Map System Timer registers
    systReg = mapPeripheral(SYST_BASE, SYST_LEN);
    if (systReg == MAP_FAILED) {
        gpioTerminate(); // Clean up already mapped memory
        return -1;
    }

    return 0;
}

// Unmaps the GPIO, clock, and system timer registers
void gpioTerminate(void)
{
    if (gpioReg != MAP_FAILED) {
        munmap((void *)gpioReg, GPIO_LEN);
        gpioReg = MAP_FAILED;
    }
    if (clkReg != MAP_FAILED) {
        munmap((void *)clkReg, CLK_LEN);
        clkReg = MAP_FAILED;
    }
    if (systReg != MAP_FAILED) {
        munmap((void *)systReg, SYST_LEN);
        systReg = MAP_FAILED;
    }
}

// Sets the mode of a GPIO pin (input, output, alt0, etc.)
void gpioSetMode(unsigned int gpioPin, unsigned int mode)
{
    if (gpioReg == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return;
    }

    int reg = gpioPin / 10;
    int shift = (gpioPin % 10) * 3;
    gpioReg[reg] = (gpioReg[reg] & ~(7 << shift)) | (mode << shift);
}

// Gets the mode of a GPIO pin
int gpioGetMode(unsigned int gpioPin)
{
    if (gpioReg == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return -1; // Indicate error
    }

    int reg = gpioPin / 10;
    int shift = (gpioPin % 10) * 3;
    return (gpioReg[reg] >> shift) & 7;
}

// Sets the pull-up/down resistor for a GPIO pin
void gpioSetPullUpDown(unsigned int gpioPin, unsigned int pud)
{
    if (gpioReg == MAP_FAILED) {
        fprintf(stderr, "GPIO registers not initialized.\n");
        return;
    }

    gpioReg[37] = pud; // GPPUD register
    usleep(20);
    gpioReg[38 + (gpioPin / 32)] = (1 << (gpioPin % 32)); // GPPUDCLK register
    usleep(20);
    gpioReg[37] = 0; // Reset GPPUD register
    gpioReg[38 + (gpioPin / 32)] = 0; // Reset GPPUDCLK register
}

// Initializes the clock with the given parameters
int initClock(int clockId, int source, int divI, int divF, int mash)
{
    if (clkReg == MAP_FAILED) {
        fprintf(stderr, "Clock registers not initialized.\n");
        return -1;
    }

    if (clockId != 0 && clockId != 1) {
        fprintf(stderr, "Invalid clock ID. Must be 0 (GPCLK0) or 1 (GPCLK2).\n");
        return -1;
    }

    if (source < 0 || source > 3) {
        fprintf(stderr, "Invalid clock source. Must be 0-3.\n");
        return -1;
    }

    if (divI < 2 || divI > 4095) {
        fprintf(stderr, "Invalid integer divider. Must be between 2 and 4095.\n");
        return -1;
    }

    if (divF < 0 || divF > 4095) {
        fprintf(stderr, "Invalid fractional divider. Must be between 0 and 4095.\n");
        return -1;
    }

    if (mash < 0 || mash > 3) {
        fprintf(stderr, "Invalid MASH value. Must be between 0 and 3.\n");
        return -1;
    }

    // Determine the control and divider register offsets based on clockId
    int clkCtlReg = (clockId == 0) ? CLK_GP0_CTL : CLK_GP2_CTL;
    int clkDivReg = (clockId == 0) ? CLK_GP0_DIV : CLK_GP2_DIV;

    // Kill the clock first
    clkReg[clkCtlReg] = CLK_PASSWD | CLK_CTL_KILL;

    // Wait for the clock to stop
    while (clkReg[clkCtlReg] & CLK_CTL_BUSY) {
        usleep(10);
    }

    // Set the divider
    clkReg[clkDivReg] = CLK_PASSWD | CLK_DIV_DIVI(divI) | CLK_DIV_DIVF(divF);
    usleep(10);

    // Set the source and MASH
    clkReg[clkCtlReg] = CLK_PASSWD | CLK_CTL_MASH(mash) | CLK_CTL_SRC(source);
    usleep(10);

    // Enable the clock
    clkReg[clkCtlReg] |= (CLK_PASSWD | CLK_CTL_ENAB);

    return 0;
}

// Terminates the clock, disabling it
int termClock(int clockId)
{
    if (clkReg == MAP_FAILED) {
        fprintf(stderr, "Clock registers not initialized.\n");
        return -1;
    }

    if (clockId != 0 && clockId != 1) {
        fprintf(stderr, "Invalid clock ID. Must be 0 (GPCLK0) or 1 (GPCLK2).\n");
        return -1;
    }

    // Determine the control register offset based on clockId
    int clkCtlReg = (clockId == 0) ? CLK_GP0_CTL : CLK_GP2_CTL;

    // Kill the clock
    clkReg[clkCtlReg] = CLK_PASSWD | CLK_CTL_KILL;

    // Wait for the clock to stop
    while (clkReg[clkCtlReg] & CLK_CTL_BUSY) {
        usleep(10);
    }

    return 0;
}

// Prints usage information
void usage(void)
{
    fprintf(stderr,
            "Usage: minimal_clk x.x[KM] [OPTIONS]\n"
            "       minimal_clk x.xD [OPTIONS]\n"
            "\n"
            "  x.x  Frequency in Hz, kHz, or MHz.  Must be between 4.6875 kHz and 500 MHz.\n"
            "       K  kilo multiplier (x1000)\n"
            "       M  mega multiplier (x1000000)\n"
            "\n"
            "  x.xD Divider.  Must be >= 2.0 and < 4096.  Integer and fractional parts are used as dividers.\n"
            "\n"
            "Options:\n"
            "  -c <clock>   Clock to configure: 0=GPCLK0 (default), 1=GPCLK2\n"
            "  -s <source>  Clock source: 0=PLLD (default), 1=OSC, 2=HDMI, 3=PLLC\n"
            "  -m <mash>    MASH value: 0-3 (default=0)\n"
            "  -q           Quiet mode: Leave clock enabled on exit (default: disable clock)\n"
            "\n"
            "Examples:\n"
            "  minimal_clk 36.23M        # Set frequency to 36.23 MHz\n"
            "  minimal_clk 234.179D      # Set divider to 234.179 (I=234, F=0.179*4096)\n"
           );
}

// Prints an error message and exits
void fatal(int show_usage, const char *fmt, ...)
{
    va_list args;
    va_start(args, fmt);
    vfprintf(stderr, fmt, args);
    va_end(args);
    fprintf(stderr, "\n");
    if (show_usage) usage();
    exit(EXIT_FAILURE);
}

// Parses command-line options
int initOpts(int argc, char *argv[])
{
    int opt;
    while ((opt = getopt(argc, argv, "c:m:s:q")) != -1) {
        switch (opt) {
            case 'c':
                opt_clock = atoi(optarg);
                if (opt_clock != 0 && opt_clock != 1) {
                    fatal(1, "Invalid clock ID: %s", optarg);
                }
                break;
            case 'm':
                opt_mash = atoi(optarg);
                if (opt_mash < 0 || opt_mash > 3) {
                    fatal(1, "Invalid MASH value: %s", optarg);
                }
                break;
            case 's':
                opt_source = atoi(optarg);
                if (opt_source < 0 || opt_source > 3) {
                    fatal(1, "Invalid clock source: %s", optarg);
                }
                break;
            case 'q':
                opt_quiet = 1;
                break;
            default:
                usage();
                exit(EXIT_FAILURE);
        }
    }
    return optind;
}

int main(int argc, char *argv[])
{
    int non_options;
    double freq, div;
    char *endptr;

    // Clock source frequencies
    double clockFrequencies[] = {500e6, 19.2e6, 216e6, 1000e6};
    char *clockNames[] = {"PLLD", "OSC", "HDMI", "PLLC"};
    int divI, divF;

    // Parse command-line options
    non_options = initOpts(argc, argv);

    // Check if a frequency or divider value was provided
    if (non_options == (argc - 1)) {
        // Get the frequency/divider argument
        errno = 0;
        freq = strtod(argv[non_options], &endptr);
        if (errno) fatal(1, "Invalid frequency/divider value: %s", argv[non_options]);
        if (endptr == argv[non_options]) fatal(1, "Invalid frequency/divider value: %s", argv[non_options]);

        // Determine if it's a frequency or divider value
        switch (*endptr) {
            case 'm':
            case 'M':
                freq *= 1000000.0; // MHz
                break;
            case 'k':
            case 'K':
                freq *= 1000.0;    // kHz
                break;
            case 'd':
            case 'D':
                // Divider value
                if (freq < 2.0 || freq >= 4096.0) fatal(1, "Divider must be >= 2.0 and < 4096.0");
                divI = (int)freq;
                divF = (int)((freq - divI) * 4096.0);

                printf("Setting clock with divider: Integer=%d, Fractional=%d\n", divI, divF);

                // Initialize hardware and set clock
                if (gpioInitialise() < 0) {
                    fprintf(stderr, "Failed to initialize GPIO.\n");
                    return 1;
                }

                if (initClock(opt_clock, opt_source, divI, divF, opt_mash) < 0) {
                    fprintf(stderr, "Failed to initialize clock.\n");
                    gpioTerminate();
                    return 1;
                }

                // Set GPIO pin mode (GPCLK0=GPIO4, GPCLK2=GPIO6)
                if (opt_clock == 0) gpioSetMode(4, GPIO_MODE_ALT0);
                else gpioSetMode(6, GPIO_MODE_ALT0);

                // Wait for user input or terminate immediately
                if (!opt_quiet) {
                    printf("Press Enter to exit and disable clock...\n");
                    getchar();
                    if (opt_clock == 0) gpioSetMode(4, GPIO_MODE_INPUT);
                    else gpioSetMode(6, GPIO_MODE_INPUT);
                    termClock(opt_clock);
                }

                gpioTerminate();
                return 0;
            case '\0':
                // Frequency value
                if (freq < 4687.5 || freq > 500e6) fatal(1, "Frequency must be between 4.6875 kHz and 500 MHz");
                break;
            default:
                usage();
                exit(EXIT_FAILURE);
        }

         div = clockFrequencies[opt_source] / freq;
         divI = div;         
         divF = (div-divI) * 4096;

         if (gpioInitialise() < 0) {
             fprintf(stderr, "Failed to initialize GPIO.\n");
             return 1;
         }

         if (initClock(opt_clock, opt_source, divI, divF, opt_mash) < 0) {
             fprintf(stderr, "Failed to initialize clock.\n");
             gpioTerminate();
             return 1;
         }

         // Set GPIO pin mode (GPCLK0=GPIO4, GPCLK2=GPIO6)
         if (opt_clock == 0) gpioSetMode(4, GPIO_MODE_ALT0);
         else gpioSetMode(6, GPIO_MODE_ALT0);

         // Wait for user input or terminate immediately
         if (!opt_quiet) {
             printf("Press Enter to exit and disable clock...\n");
             getchar();
             if (opt_clock == 0) gpioSetMode(4, GPIO_MODE_INPUT);
             else gpioSetMode(6, GPIO_MODE_INPUT);
             termClock(opt_clock);
         }

         gpioTerminate();
         return 0;

    } else {
        usage();
        return 1;
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <stdint.h>
#include <string.h>
#include <fcntl.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <sys/types.h>
#include <errno.h>

// Base addresses for peripherals (adjust for different Raspberry Pi models)
static volatile uint32_t peripheralBase = 0xFE000000; // Default for Pi 4/5
static int isRaspberryPi2711 = 0;

// Register offsets
#define GPIO_OFFSET  0x00200000
#define SYST_OFFSET  0x00003000
#define BSCS_OFFSET  0x00214000

// Register lengths
#define GPIO_LENGTH  0xF4
#define SYST_LENGTH  0x1C
#define BSCS_LENGTH  0x40

// GPIO register offsets
#define GPFSEL0 0  // GPIO Function Select 0
#define GPSET0  7  // GPIO Pin Output Set 0
#define GPCLR0  10 // GPIO Pin Output Clear 0
#define GPLEV0  13 // GPIO Pin Level 0
#define GPPUD   37 // GPIO Pin Pull-up/down Enable
#define GPPUDCLK0 38 // GPIO Pin Pull-up/down Clock Enable 0

// BCM2711 Pull-up/down register offsets
#define GPPUPPDN0 57

// SYST register offsets
#define SYST_CS  0  // System Timer Control/Status
#define SYST_CLO 1  // System Timer Counter Lower 32 bits
#define SYST_CHI 2  // System Timer Counter Upper 32 bits

// Pointers to memory mapped registers
static volatile uint32_t *gpioRegisters = MAP_FAILED;
static volatile uint32_t *systRegisters = MAP_FAILED;
static volatile uint32_t *bscsRegisters = MAP_FAILED;

// Helper macros
#define GPIO_BANK(gpio) ((gpio) >> 5)
#define GPIO_BIT(gpio)  (1 << ((gpio) & 0x1F))

// GPIO modes
enum {
    GPIO_MODE_INPUT  = 0,
    GPIO_MODE_OUTPUT = 1,
    GPIO_MODE_ALT0   = 4,
    GPIO_MODE_ALT1   = 5,
    GPIO_MODE_ALT2   = 6,
    GPIO_MODE_ALT3   = 7,
    GPIO_MODE_ALT4   = 3,
    GPIO_MODE_ALT5   = 2
};

// Pull-up/down resistor options
enum {
    GPIO_PULL_OFF  = 0,
    GPIO_PULL_DOWN = 1,
    GPIO_PULL_UP   = 2
};

// Function to set the GPIO pin mode (input, output, alt function)
int gpioSetMode(unsigned int gpio, unsigned int mode) {
    if (gpio > 53 || mode > 7) {
        fprintf(stderr, "gpioSetMode: Invalid GPIO %u or mode %u\n", gpio, mode);
        return -1; // Indicate error
    }

    int registerIndex = gpio / 10;
    int shift = (gpio % 10) * 3;
    uint32_t mask = 0x7 << shift;
    uint32_t value = mode << shift;

    gpioRegisters[registerIndex] = (gpioRegisters[registerIndex] & ~mask) | value;
    return 0; // Indicate success
}

// Function to get the GPIO pin mode
int gpioGetMode(unsigned int gpio) {
    if (gpio > 53) {
        fprintf(stderr, "gpioGetMode: Invalid GPIO %u\n", gpio);
        return -1; //Indicate error
    }

    int registerIndex = gpio / 10;
    int shift = (gpio % 10) * 3;
    return (gpioRegisters[registerIndex] >> shift) & 0x7;
}

// Function to set the GPIO pin pull-up/down resistor
int gpioSetPullUpDown(unsigned int gpio, unsigned int pud) {
    if (gpio > 53 || pud > 2) {
        fprintf(stderr, "gpioSetPullUpDown: Invalid GPIO %u or pud %u\n", gpio, pud);
        return -1; // Indicate error
    }

    if (isRaspberryPi2711) {
        // BCM2711 uses different registers for pull-up/down control
        uint32_t pull = 0;
        switch (pud) {
            case GPIO_PULL_OFF:  pull = 0; break;
            case GPIO_PULL_UP:   pull = 1; break;
            case GPIO_PULL_DOWN: pull = 2; break;
            default: return -1;
        }

        int shift = (gpio & 0xf) << 1;
        uint32_t bits = gpioRegisters[GPPUPPDN0 + (gpio >> 4)];
        bits &= ~(3 << shift);
        bits |= (pull << shift);
        gpioRegisters[GPPUPPDN0 + (gpio >> 4)] = bits;
    } else {
        // Older Raspberry Pi models
        gpioRegisters[GPPUD] = pud;
        usleep(20); // Wait for 20 microseconds
        gpioRegisters[GPPUDCLK0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
        usleep(20); // Wait for 20 microseconds
        gpioRegisters[GPPUD] = 0;
        gpioRegisters[GPPUDCLK0 + GPIO_BANK(gpio)] = 0;
    }
    return 0; // Indicate success
}

// Function to read the level of a GPIO pin
int gpioRead(unsigned int gpio) {
    if (gpio > 53) {
        fprintf(stderr, "gpioRead: Invalid GPIO %u\n", gpio);
        return -1; // Indicate error
    }

    return (gpioRegisters[GPLEV0 + GPIO_BANK(gpio)] & GPIO_BIT(gpio)) ? 1 : 0;
}

// Function to write a value to a GPIO pin
int gpioWrite(unsigned int gpio, unsigned int level) {
    if (gpio > 53 || level > 1) {
        fprintf(stderr, "gpioWrite: Invalid GPIO %u or level %u\n", gpio, level);
        return -1; // Indicate error
    }

    if (level == 0) {
        gpioRegisters[GPCLR0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    } else {
        gpioRegisters[GPSET0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    }
    return 0; // Indicate success
}

// Function to trigger a GPIO pin with a pulse
int gpioTrigger(unsigned int gpio, unsigned int pulseLengthUs, unsigned int level) {
    if (gpio > 53 || level > 1) {
        fprintf(stderr, "gpioTrigger: Invalid GPIO %u or level %u\n", gpio, level);
        return -1; // Indicate error
    }

    if (level == 0) {
        gpioRegisters[GPCLR0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    } else {
        gpioRegisters[GPSET0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    }

    usleep(pulseLengthUs);

    if (level == 0) {
        gpioRegisters[GPSET0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    } else {
        gpioRegisters[GPCLR0 + GPIO_BANK(gpio)] = GPIO_BIT(gpio);
    }
    return 0; // Indicate success
}

// Function to read the system timer (microseconds since boot)
uint32_t gpioTick(void) {
    return systRegisters[SYST_CLO];
}

// Function to map physical memory into virtual memory
static uint32_t *mapPeripheral(int fileDescriptor, uint32_t physicalAddress, uint32_t length) {
    uint32_t *virtualAddress = (uint32_t *)mmap(NULL, length, PROT_READ | PROT_WRITE, MAP_SHARED, fileDescriptor, physicalAddress);
    if (virtualAddress == MAP_FAILED) {
        fprintf(stderr, "Memory mapping failed at address 0x%X with length 0x%X: %s\n", physicalAddress, length, strerror(errno));
        return MAP_FAILED;
    }
    return virtualAddress;
}

// Function to initialize the GPIO library
int gpioInitialise(void) {
    int fileDescriptor = open("/dev/mem", O_RDWR | O_SYNC);
    if (fileDescriptor < 0) {
        fprintf(stderr, "Failed to open /dev/mem: %s\n", strerror(errno));
        fprintf(stderr, "This program requires root privileges.  Try using sudo.\n");
        return -1;
    }

    // Determine Raspberry Pi hardware revision and peripheral base address
    FILE *cpuinfo = fopen("/proc/cpuinfo", "r");
    if (cpuinfo != NULL) {
        char line[256];
        while (fgets(line, sizeof(line), cpuinfo)) {
            if (strstr(line, "Revision")) {
                unsigned int revision;
                if (sscanf(line, "Revision\t: %x", &revision) == 1) {
                    // Basic check for Pi 4/5 (more robust checks might be needed)
                    if ((revision & 0x10) == 0x10) {
                        peripheralBase = 0xFE000000; // Confirmed for Pi4/5
                    } else {
                        peripheralBase = 0x3F000000; // Older Pis
                    }
                    break;
                }
            }
        }
        fclose(cpuinfo);
    } else {
        perror("Failed to open /proc/cpuinfo");
        close(fileDescriptor);
        return -1;
    }

    // Map the GPIO, System Timer, and BSC registers into memory
    gpioRegisters = mapPeripheral(fileDescriptor, peripheralBase + GPIO_OFFSET, GPIO_LENGTH);
    systRegisters = mapPeripheral(fileDescriptor, peripheralBase + SYST_OFFSET, SYST_LENGTH);
    bscsRegisters = mapPeripheral(fileDescriptor, peripheralBase + BSCS_OFFSET, BSCS_LENGTH);

    close(fileDescriptor);

    // Check if any of the memory mappings failed
    if (gpioRegisters == MAP_FAILED || systRegisters == MAP_FAILED || bscsRegisters == MAP_FAILED) {
        fprintf(stderr, "One or more memory mappings failed.\n");
        //Unmap any successfully mapped memory
        if (gpioRegisters != MAP_FAILED) munmap((void*)gpioRegisters, GPIO_LENGTH);
        if (systRegisters != MAP_FAILED) munmap((void*)systRegisters, SYST_LENGTH);
        if (bscsRegisters != MAP_FAILED) munmap((void*)bscsRegisters, BSCS_LENGTH);

        return -1;
    }

    return 0;
}

// Function to de-initialize the GPIO library and unmap memory
void gpioTerminate(void) {
    if (gpioRegisters != MAP_FAILED) {
        if (munmap((void*)gpioRegisters, GPIO_LENGTH) != 0) {
            perror("Failed to unmap GPIO memory");
        }
        gpioRegisters = MAP_FAILED; // Set to MAP_FAILED to prevent further access
    }
    if (systRegisters != MAP_FAILED) {
        if (munmap((void*)systRegisters, SYST_LENGTH) != 0) {
            perror("Failed to unmap System Timer memory");
        }
        systRegisters = MAP_FAILED;
    }
    if (bscsRegisters != MAP_FAILED) {
        if (munmap((void*)bscsRegisters, BSCS_LENGTH) != 0) {
            perror("Failed to unmap BSC memory");
        }
        bscsRegisters = MAP_FAILED;
    }
}

int main(int argc, char *argv[]) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "GPIO initialization failed.\n");
        return 1;
    }

    // Example usage: Read and print the state of GPIO pins 0-53
    for (int i = 0; i < 54; i++) {
        int mode = gpioGetMode(i);
        int level = gpioRead(i);
        if (mode == -1 || level == -1) {
            fprintf(stderr, "Error reading GPIO %d, skipping.\n", i);
            continue;
        }
        printf("GPIO %d: Mode = %d, Level = %d, Tick = %u\n", i, mode, level, gpioTick());
    }

    // Example usage: Print the values of the first 16 BSC registers
    for (int i = 0; i < 16; i++) {
        printf("BSC Register %d: Value = 0x%08X\n", i, bscsRegisters[i]);
    }

    gpioTerminate(); // Unmap memory before exiting
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <fcntl.h>
#include <time.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <sys/types.h>
#include <unistd.h>
#include <errno.h>
#include <string.h>

// Hardware Definitions
#define CLK_BASE  0x20101000
#define GPIO_BASE 0x20200000
#define PWM_BASE  0x2020C000

#define CLK_LEN   0xA8
#define GPIO_LEN  0xB4
#define PWM_LEN   0x28

// PWM Registers
#define PWM_CTL      0
#define PWM_STA      1
#define PWM_RNG1     4
#define PWM_FIFO     6

// PWM Control Bits
#define PWM_CTL_CLRF1 (1 << 6)
#define PWM_CTL_USEF1 (1 << 5)
#define PWM_CTL_MODE1 (1 << 1)
#define PWM_CTL_PWEN1 (1 << 0)

#define PWM_STA_EMPT1 (1 << 1)

// Clock Defines
#define CLK_PASSWD  (0x5A << 24)

#define CLK_CTL_MASH(x) ((x) << 9)
#define CLK_CTL_BUSY    (1 << 7)
#define CLK_CTL_KILL    (1 << 5)
#define CLK_CTL_ENAB    (1 << 4)
#define CLK_CTL_SRC(x) ((x) << 0)

#define CLK_CTL_SRC_PLLD 6  /* 500.0 MHz */

#define CLK_DIV_DIVI(x) ((x) << 12)
#define CLK_DIV_DIVF(x) ((x) << 0)

#define CLK_PWMCTL 40
#define CLK_PWMDIV 41

#define MAX_BITS 224

// PWM Clock Configuration Structure
typedef struct {
    unsigned divider;
    unsigned bits;
} pwm_clock_config_t;

// Predefined base nanosecond values
static const unsigned base_nanos[] = {4, 8, 10, 20, 40, 80, 100, 200, 250, 500, 1000};
static const size_t num_base_nanos = sizeof(base_nanos) / sizeof(base_nanos[0]);

// Global Variables for Memory Mapped Registers
static volatile uint32_t *clk_registers = MAP_FAILED;
static volatile uint32_t *gpio_registers = MAP_FAILED;
static volatile uint32_t *pwm_registers = MAP_FAILED;

// Function Prototypes
static int map_peripheral_memory(unsigned base, unsigned len, volatile uint32_t **addr);
static void unmap_peripheral_memory(volatile uint32_t **addr, unsigned len);
static void precise_nanosleep(unsigned nanos);
static int gpio_set_mode(unsigned gpio, unsigned mode);
static int gpio_get_mode(unsigned gpio);
static int initialize_pwm(unsigned divider);
static int send_pulse(unsigned bits);
static pwm_clock_config_t calculate_pwm_config(unsigned target_nanos);
static void cleanup();

// Error Handling Macro
#define CHECK_MAP(addr, name) \
    if (addr == MAP_FAILED) { \
        fprintf(stderr, "Error: Could not map %s registers. %s\n", name, strerror(errno)); \
        cleanup(); \
        return EXIT_FAILURE; \
    }

// Function to perform a precise nanosleep
static void precise_nanosleep(unsigned nanos) {
    struct timespec ts;
    ts.tv_sec = 0;
    ts.tv_nsec = nanos;
    if (nanosleep(&ts, NULL) != 0) {
        perror("nanosleep");
    }
}

// Function to set the GPIO mode
static int gpio_set_mode(unsigned gpio, unsigned mode) {
    if (gpio > 53) {
        fprintf(stderr, "Error: Invalid GPIO pin %u\n", gpio);
        return -1; // Indicate error
    }
    unsigned reg = gpio / 10;
    unsigned shift = (gpio % 10) * 3;
    gpio_registers[reg] = (gpio_registers[reg] & ~(7 << shift)) | (mode << shift);
    return 0;
}

// Function to get the GPIO mode
static int gpio_get_mode(unsigned gpio) {
    if (gpio > 53) {
        fprintf(stderr, "Error: Invalid GPIO pin %u\n", gpio);
        return -1; // Indicate error
    }
    unsigned reg = gpio / 10;
    unsigned shift = (gpio % 10) * 3;
    return (gpio_registers[reg] >> shift) & 7;
}

// Function to initialize the PWM module
static int initialize_pwm(unsigned divider) {
    // Reset PWM clock
    clk_registers[CLK_PWMCTL] = CLK_PASSWD | CLK_CTL_KILL;
    precise_nanosleep(10000);

    // Set PWM clock source as 500 MHz PLLD
    clk_registers[CLK_PWMCTL] = CLK_PASSWD | CLK_CTL_SRC(CLK_CTL_SRC_PLLD);
    precise_nanosleep(10000);

    // Set PWM clock divider
    clk_registers[CLK_PWMDIV] = CLK_PASSWD | CLK_DIV_DIVI(divider) | CLK_DIV_DIVF(0);
    precise_nanosleep(10000);

    // Enable PWM clock
    clk_registers[CLK_PWMCTL] = CLK_PASSWD | CLK_CTL_ENAB | CLK_CTL_SRC(CLK_CTL_SRC_PLLD);
    precise_nanosleep(100000);

    // Reset PWM
    pwm_registers[PWM_CTL] = 0;

    // Clear PWM status bits
    pwm_registers[PWM_STA] = -1;
    precise_nanosleep(10000);

    return 0;
}

// Function to send a pulse via PWM
static int send_pulse(unsigned bits) {
    if (bits == 0) {
        bits = 1;
    } else if (bits > MAX_BITS) {
        bits = MAX_BITS;
    }

    // Clear PWM FIFO
    pwm_registers[PWM_CTL] = PWM_CTL_CLRF1;
    precise_nanosleep(10000);

    // Fill FIFO with data
    unsigned i;
    uint32_t word;
    while (bits >= 32) {
        pwm_registers[PWM_FIFO] = -1; // All bits set
        bits -= 32;
    }

    if (bits > 0) {
        word = 0;
        for (i = 0; i < bits; ++i) {
            word |= (1 << (31 - i)); // Set the most significant bits
        }
        pwm_registers[PWM_FIFO] = word;
    }

    pwm_registers[PWM_FIFO] = 0; // Trailing zero

    // Enable PWM for serialised data from FIFO
    pwm_registers[PWM_CTL] = PWM_CTL_USEF1 | PWM_CTL_MODE1 | PWM_CTL_PWEN1;

    return 0;
}

// Function to calculate PWM clock configuration
static pwm_clock_config_t calculate_pwm_config(unsigned target_nanos) {
    pwm_clock_config_t config;
    unsigned best_error = -1; // Initialize with a large value
    unsigned best_base = 0;
    unsigned best_bits = 0;

    for (size_t i = 0; i < num_base_nanos; ++i) {
        unsigned bits = target_nanos / base_nanos[i];
        if (bits > MAX_BITS) {
            bits = MAX_BITS;
        }

        unsigned error = target_nanos - (bits * base_nanos[i]);

        if (error < best_error) {
            best_error = error;
            best_base = base_nanos[i];
            best_bits = bits;
        }
    }

    config.divider = best_base / 2;
    config.bits = best_bits;

    return config;
}

// Function to map peripheral memory
static int map_peripheral_memory(unsigned base, unsigned len, volatile uint32_t **addr) {
    int fd = open("/dev/mem", O_RDWR | O_SYNC);
    if (fd < 0) {
        fprintf(stderr, "Error: Could not open /dev/mem.  Did you forget sudo? %s\n", strerror(errno));
        return -1;
    }

    *addr = (uint32_t *)mmap(0, len, PROT_READ | PROT_WRITE | PROT_EXEC, MAP_SHARED | MAP_LOCKED, fd, base);
    close(fd);

    if (*addr == MAP_FAILED) {
        return -1;
    }
    return 0;
}

// Function to unmap peripheral memory
static void unmap_peripheral_memory(volatile uint32_t **addr, unsigned len) {
    if (*addr != MAP_FAILED) {
        if (munmap((void *)*addr, len) != 0) {
            perror("munmap");
        }
        *addr = MAP_FAILED; // Ensure the pointer is reset
    }
}

// Cleanup function to unmap memory before exiting
static void cleanup() {
    unmap_peripheral_memory(&gpio_registers, GPIO_LEN);
    unmap_peripheral_memory(&pwm_registers, PWM_LEN);
    unmap_peripheral_memory(&clk_registers, CLK_LEN);
}

int main(int argc, char *argv[]) {
    unsigned nanos = 1000;  // Default pulse width
    unsigned pulses = 100;  // Default number of pulses
    unsigned gap = 5000;    // Default gap between pulses
    unsigned gpio_pin = 18; // Default GPIO pin for PWM
    int original_gpio_mode;

    // Parse command-line arguments
    if (argc > 1) nanos = atoi(argv[1]);
    if (argc > 2) pulses = atoi(argv[2]);
    if (argc > 3) gap = atoi(argv[3]);
    if (argc > 4) gpio_pin = atoi(argv[4]);

    // Validate input parameters
    if (nanos < 4) nanos = 4;
    else if (nanos > 224000) nanos = 224000;

    if (pulses < 1) pulses = 1;
    if (gap < 0) gap = 0;

    // Map peripheral memory
    if (map_peripheral_memory(GPIO_BASE, GPIO_LEN, &gpio_registers) != 0) {
        return EXIT_FAILURE;
    }
    CHECK_MAP(gpio_registers, "GPIO");

    if (map_peripheral_memory(PWM_BASE, PWM_LEN, &pwm_registers) != 0) {
        cleanup();
        return EXIT_FAILURE;
    }
    CHECK_MAP(pwm_registers, "PWM");

    if (map_peripheral_memory(CLK_BASE, CLK_LEN, &clk_registers) != 0) {
        cleanup();
        return EXIT_FAILURE;
    }
    CHECK_MAP(clk_registers, "Clock");

    // Calculate PWM configuration
    pwm_clock_config_t pwm_config = calculate_pwm_config(nanos);

    // Print configuration information
    printf("%d pulses of %d nanos with gap of %d nanos (div=%d bits=%d) on GPIO %u\n",
           pulses, pwm_config.divider * 2 * pwm_config.bits, gap, pwm_config.divider, pwm_config.bits, gpio_pin);

    // Save original GPIO mode
    original_gpio_mode = gpio_get_mode(gpio_pin);
    if (original_gpio_mode < 0) {
        cleanup();
        return EXIT_FAILURE;
    }

    // Set GPIO to ALT5 (PWM1)
    if (gpio_set_mode(gpio_pin, 2) != 0) {
        cleanup();
        return EXIT_FAILURE;
    }

    // Initialize PWM
    if (initialize_pwm(pwm_config.divider) != 0) {
        cleanup();
        return EXIT_FAILURE;
    }

    // Generate pulses
    for (unsigned i = 0; i < pulses; ++i) {
        if (send_pulse(pwm_config.bits) != 0) {
            cleanup();
            return EXIT_FAILURE;
        }
        precise_nanosleep(nanos + gap);
    }

    // Restore original GPIO mode
    if (gpio_set_mode(gpio_pin, original_gpio_mode) != 0) {
        cleanup();
        return EXIT_FAILURE;
    }

    // Cleanup and exit
    cleanup();
    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <time.h>
#include <gpiod.h>
#include <sched.h>
