// Constants
#define DS18B20_SKIP_ROM 0xCC
#define DS18B20_CONVERT_T 0x44
#define DS18B20_MATCH_ROM 0x55
#define DS18B20_SEARCH_ROM 0xF0
#define DS18B20_READ_SCRATCHPAD 0xBE
#define DS18B20_WRITE_SCRATCHPAD 0x4E
#define DS18B20_COPY_SCRATCHPAD 0x48

#define MAX_RETRY_COUNT 10

// Global variables
static struct gpiod_chip *gpio_chip = NULL;
static struct gpiod_line *gpio_line = NULL;
static unsigned int gpio_pin = 10; // Default GPIO pin
static unsigned int conversion_delay_ms = 750; // Default conversion delay
static int target_resolution = 0; // Target resolution (0 means no change)
static int scan_mode = 0; // 0 = read temperature, 1 = scan only
static char filename[256] = "";
static int file_mode = 0;

// Function prototypes
static int init_gpio(unsigned int pin);
static void deinit_gpio(void);
static int onewire_reset(void);
static void onewire_write_byte(unsigned char data);
static unsigned char onewire_read_byte(void);
static unsigned char calculate_crc(const unsigned char *data, unsigned char data_len);
static int read_scratchpad(unsigned char *scratchpad);
static int read_temperature(unsigned long long sensor_id, double *temperature, int *resolution);
static int global_start_conversion(void);
static void write_scratchpad(unsigned char th, unsigned char tl, unsigned char config);
static void copy_scratchpad(void);
static void change_sensor_resolution(int resolution);
static int search_sensors(unsigned long long *sensor_id, int *last_bit_change);
static void scan_for_sensors(void);
static void print_usage(const char *app_name);
static int parse_arguments(int argc, char *argv[]);
