// Helper macros for GPIO operations
#define GPIO_READ() gpiod_line_get_value(gpio_line)
#define GPIO_SET() gpiod_line_set_value(gpio_line, 1)
#define GPIO_CLR() gpiod_line_set_value(gpio_line, 0)


// Improved delay function using clock_gettime
static void delay_ns(int ns) {
    struct timespec start, end;
    clock_gettime(CLOCK_MONOTONIC, &start);
    long start_ns = start.tv_sec * 1000000000L + start.tv_nsec;
    long end_ns = start_ns + ns;

    do {
        clock_gettime(CLOCK_MONOTONIC, &end);
        long current_ns = end.tv_sec * 1000000000L + end.tv_nsec;
    } while (current_ns < end_ns);
}

// Initialize GPIO pin
static int init_gpio(unsigned int pin) {
    gpio_chip = gpiod_chip_open_by_name("gpiochip4");
    if (!gpio_chip) {
        gpio_chip = gpiod_chip_open_by_name("gpiochip0");
        if (!gpio_chip) {
            perror("Error opening GPIO chip");
            return -1;
        }
    }

    gpio_line = gpiod_chip_get_line(gpio_chip, pin);
    if (!gpio_line) {
        perror("Error getting GPIO line");
        gpiod_chip_close(gpio_chip);
        return -1;
    }

    if (gpiod_line_request_output_flags(gpio_line, "DS18B20", GPIOD_LINE_REQUEST_FLAG_OPEN_DRAIN | GPIOD_LINE_REQUEST_FLAG_BIAS_PULL_UP, 1) < 0) {
        perror("Error requesting GPIO line for output");
        gpiod_line_release(gpio_line);
        gpiod_chip_close(gpio_chip);
        return -1;
    }

    return 0;
}

// Deinitialize GPIO
static void deinit_gpio(void) {
    if (gpio_line) {
        gpiod_line_release(gpio_line);
        gpio_line = NULL;
    }
    if (gpio_chip) {
        gpiod_chip_close(gpio_chip);
        gpio_chip = NULL;
    }
}

// 1-Wire reset function
static int onewire_reset(void) {
    GPIO_SET();
    delay_ns(10000); // 10us
    GPIO_CLR();
    delay_ns(480000); // 480us
    GPIO_SET();
    delay_ns(60000); // 60us
    int presence = (GPIO_READ() == 0);
    delay_ns(420000); // 420us
    return presence;
}

// 1-Wire write byte function
static void onewire_write_byte(unsigned char data) {
    for (int i = 0; i < 8; i++) {
        GPIO_CLR();
        if ((data & 0x01) != 0) {
            delay_ns(1000); // 1us
            GPIO_SET();
            delay_ns(60000); // 60us
        } else {
            delay_ns(60000); // 60us
            GPIO_SET();
            delay_ns(1000); // 1us
        }
        delay_ns(60000); // 60us
        data >>= 1;
    }
    usleep(100); // Small delay after writing a byte
}

// 1-Wire read byte function
static unsigned char onewire_read_byte(void) {
    unsigned char data = 0;
    for (int i = 0; i < 8; i++) {
        GPIO_CLR();
        delay_ns(1000); // 1us
        GPIO_SET();
        delay_ns(2000); // 2us
        if (GPIO_READ() != 0) {
            data |= (1 << i);
        }
        delay_ns(60000); // 60us
    }
    return data;
}

// CRC calculation function
static unsigned char calculate_crc(const unsigned char *data, unsigned char data_len) {
    unsigned char crc = 0;
    for (unsigned char i = 0; i < data_len; i++) {
        unsigned char inbyte = data[i];
        for (unsigned char j = 0; j < 8; j++) {
            unsigned char mix = (crc ^ inbyte) & 0x01;
            crc >>= 1;
            if (mix)
                crc ^= 0x8C;
            inbyte >>= 1;
        }
    }
    return crc;
}

// Read scratchpad function
static int read_scratchpad(unsigned char *scratchpad) {
    onewire_write_byte(DS18B20_READ_SCRATCHPAD);
    for (int i = 0; i < 9; i++) {
        scratchpad[i] = onewire_read_byte();
    }
    return 0; // Success
}

// Select a specific sensor by ID
static void select_sensor(unsigned long long sensor_id) {
    onewire_write_byte(DS18B20_MATCH_ROM);
    for (int i = 0; i < 64; i++) {
        unsigned char bit = (sensor_id >> i) & 0x01;
        // Implement WriteBit using existing onewire_write_byte function
        GPIO_CLR();
        if (bit) {
            delay_ns(1000); // 1us
            GPIO_SET();
            delay_ns(60000); // 60us
        } else {
            delay_ns(60000); // 60us
            GPIO_SET();
            delay_ns(1000); // 1us
        }
        delay_ns(60000);
    }
}

// Read temperature from a sensor
static int read_temperature(unsigned long long sensor_id, double *temperature, int *resolution) {
    unsigned char scratchpad[9];
    int retry_count;

    for (retry_count = 0; retry_count < MAX_RETRY_COUNT; retry_count++) {
        if (!onewire_reset()) {
            usleep(10000);
            continue;
        }

        select_sensor(sensor_id);

        if (read_scratchpad(scratchpad) != 0) {
            continue;
        }

        unsigned char crc = calculate_crc(scratchpad, 8);
        if (crc != scratchpad[8]) {
            continue;
        }

        *resolution = 0;
        switch (scratchpad[4]) {
            case 0x1f: *resolution = 9; break;
            case 0x3f: *resolution = 10; break;
            case 0x5f: *resolution = 11; break;
            case 0x7f: *resolution = 12; break;
        }

        if (*resolution == 0) {
            continue;
        }

        short temp_reading = (scratchpad[1] << 8) | scratchpad[0];
        *temperature = 0.0625 * (double)temp_reading;

        return 0; // Success
    }

    return -1; // Failed after multiple retries
}

// Start temperature conversion globally
static int global_start_conversion(void) {
    for (int retry = 0; retry < MAX_RETRY_COUNT; retry++) {
        if (!onewire_reset()) {
            usleep(10000);
        } else {
            onewire_write_byte(DS18B20_SKIP_ROM);
            onewire_write_byte(DS18B20_CONVERT_T);
            usleep(conversion_delay_ms * 1000); // Wait for conversion
            return 0; // Success
        }
    }
    return -1; // Failed after multiple retries
}

// Write to scratchpad
static void write_scratchpad(unsigned char th, unsigned char tl, unsigned char config) {
    onewire_reset();
    usleep(10); // Small delay
    onewire_write_byte(DS18B20_SKIP_ROM);
    onewire_write_byte(DS18B20_WRITE_SCRATCHPAD);
    onewire_write_byte(th);
    onewire_write_byte(tl);
    onewire_write_byte(config);
}

// Copy scratchpad to EEPROM
static void copy_scratchpad(void) {
    onewire_reset();
    usleep(1000); // Small delay
    onewire_write_byte(DS18B20_SKIP_ROM);
    onewire_write_byte(DS18B20_COPY_SCRATCHPAD);
    usleep(100000); // Wait for copy
}

// Change sensor resolution
static void change_sensor_resolution(int resolution) {
    unsigned char config = 0;
    switch (resolution) {
        case 9:  config = 0x1f; break;
        case 10: config = 0x3f; break;
        case 11: config = 0x5f; break;
        default: config = 0x7f; break;
    }
    write_scratchpad(0xff, 0xff, config);
    usleep(1000); // Small delay
    copy_scratchpad();
}

// Search for sensors on the 1-Wire bus
static int search_sensors(unsigned long long *sensor_id, int *last_bit_change) {
    int bit_index;
    char bit, no_bit;

    if (*last_bit_change < 0) return 0;

    // Set bit at LastBitChange Position to 1
    // Every bit after LastbitChange will be 0
    if (*last_bit_change < 64) {
        *sensor_id |= (1ULL << *last_bit_change);
        for (bit_index = *last_bit_change + 1; bit_index < 64; bit_index++)
            *sensor_id &= ~(1ULL << bit_index);
    }

    *last_bit_change = -1;

    if (!onewire_reset()) return -1;

    onewire_write_byte(DS18B20_SEARCH_ROM);

    for (bit_index = 0; bit_index < 64; bit_index++) {
        no_bit = (char)(onewire_read_byte() & 0x01);
        bit = (char)(onewire_read_byte() & 0x01);

        if (bit && no_bit) return -2;

        if (!bit && !no_bit) {
            // ok 2 possibilities
            if ((*sensor_id >> bit_index) & 0x01) {
                // Bit High already set
                // Implement WriteBit using existing onewire_write_byte function
                GPIO_CLR();
                delay_ns(1000); // 1us
                GPIO_SET();
                delay_ns(60000); // 60us
                delay_ns(60000);
            } else {
                // ok let's try LOW value first
                *last_bit_change = bit_index;
                // Implement WriteBit using existing onewire_write_byte function
                GPIO_CLR();
                delay_ns(60000); // 60us
                GPIO_SET();
                delay_ns(1000); // 1us
                delay_ns(60000);
            }
        } else if (!bit) {
            // Implement WriteBit using existing onewire_write_byte function
            GPIO_CLR();
            delay_ns(1000); // 1us
            GPIO_SET();
            delay_ns(60000); // 60us
            delay_ns(60000);
            *sensor_id |= (1ULL << bit_index);
        } else {
            // Implement WriteBit using existing onewire_write_byte function
            GPIO_CLR();
            delay_ns(60000); // 60us
            GPIO_SET();
            delay_ns(1000); // 1us
            delay_ns(60000);
            *sensor_id &= ~(1ULL << bit_index);
        }
    }
    return 1;
}

// Scan for available sensors and read their temperatures
static void scan_for_sensors(void) {
    unsigned long long sensor_id = 0ULL;
    int next_bit = 64;
    int rcode;

    for (int retry = 0; retry < MAX_RETRY_COUNT;) {
        unsigned long long current_id = sensor_id;
        int current_next_bit = next_bit;
        rcode = search_sensors(&current_id, &current_next_bit);

        if (rcode == 1) {
            unsigned char id_crc = (unsigned char)(current_id >> 56);
            unsigned char calc_crc = calculate_crc((unsigned char *)&current_id, 7);
            if (id_crc == calc_crc) {
                if (scan_mode == 0) {
                    double temperature;
                    int resolution;
                    if (read_temperature(current_id, &temperature, &resolution) == 0) {
                        sensor_id = current_id;
                        next_bit = current_next_bit;
                        printf("Sensor ID: %016llX, Resolution: %d bits, Temperature: %.2f Celsius\n", sensor_id, resolution, temperature);
                        retry = 0; // Reset retry counter on success
                    } else {
                        retry++;
                    }
                } else {
                    sensor_id = current_id;
                    next_bit = current_next_bit;
                    printf("%016llX\n", sensor_id);
                    retry = 0; // Reset retry counter on success
                }
            } else {
                retry++;
            }
        } else if (rcode == 0) {
            break; // No more sensors found
        } else {
            retry++;
        }
    }
}

// Print usage information
static void print_usage(const char *app_name) {
    printf("Usage: %s -gpio <pin> [-bits <9|10|11|12>] [-scan] [-delay <ms>] [-file <filename>]\n", app_name);
    printf("  -gpio <pin>    : BCM GPIO pin number\n");
    printf("  -bits <9|10|11|12>: Set sensor resolution\n");
    printf("  -scan          : Scan for sensor IDs only\n");
    printf("  -delay <ms>    : Conversion delay in milliseconds\n");
    printf("  -file <filename>: Read sensor IDs from file\n");
}

// Parse command line arguments
static int parse_arguments(int argc, char *argv[]) {
    for (int i = 1; i < argc; i++) {
        if (strcmp(argv[i], "-gpio") == 0) {
            if (i + 1 < argc) {
                gpio_pin = atoi(argv[i + 1]);
                i++;
            } else {
                fprintf(stderr, "Error: -gpio requires a pin number\n");
                return -1;
            }
        } else if (strcmp(argv[i], "-bits") == 0) {
            if (i + 1 < argc) {
                target_resolution = atoi(argv[i + 1]);
                if (target_resolution < 9 || target_resolution > 12) {
                    fprintf(stderr, "Error: Invalid resolution. Must be 9, 10, 11, or 12\n");
                    return -1;
                }
                i++;
            } else {
                fprintf(stderr, "Error: -bits requires a resolution value\n");
                return -1;
            }
        } else if (strcmp(argv[i], "-scan") == 0) {
            scan_mode = 1;
        } else if (strcmp(argv[i], "-delay") == 0) {
            if (i + 1 < argc) {
                conversion_delay_ms = atoi(argv[i + 1]);
                i++;
            } else {
                fprintf(stderr, "Error: -delay requires a delay value\n");
                return -1;
            }
        } else if (strcmp(argv[i], "-file") == 0) {
            if (i + 1 < argc) {
                strncpy(filename, argv[i + 1], sizeof(filename) - 1);
                filename[sizeof(filename) - 1] = '\0'; // Ensure null termination
                file_mode = 1;
                i++;
            } else {
                fprintf(stderr, "Error: -file requires a filename\n");
                return -1;
            }
        } else {
            fprintf(stderr, "Error: Unknown argument '%s'\n", argv[i]);
            return -1;
        }
    }
    return 0;
}

// Read sensor IDs from a file
static void read_sensors_from_file(const char *filename) {
    FILE *fp = fopen(filename, "r");
    if (fp == NULL) {
        perror("Error opening file");
        return;
    }

    char line[256];
    while (fgets(line, sizeof(line), fp) != NULL) {
        unsigned long long sensor_id;
        if (sscanf(line, "%llx", &sensor_id) == 1) {
            double temperature;
            int resolution;
            if (read_temperature(sensor_id, &temperature, &resolution) == 0) {
                printf("Sensor ID: %016llX, Resolution: %d bits, Temperature: %.2f Celsius\n", sensor_id, resolution, temperature);
            } else {
                fprintf(stderr, "Error reading temperature from sensor ID %016llX\n", sensor_id);
            }
        }
    }
    fclose(fp);
}

// Set realtime priority
static void set_realtime_priority(void) {
    struct sched_param sched;
    memset(&sched, 0, sizeof(sched));
    sched.sched_priority = sched_get_priority_max(SCHED_FIFO);
    if (sched_setscheduler(0, SCHED_FIFO, &sched) != 0) {
        perror("Error setting realtime priority");
    }
}

// Set default priority
static void set_default_priority(void) {
    struct sched_param sched;
    memset(&sched, 0, sizeof(sched));
    sched.sched_priority = 0;
    if (sched_setscheduler(0, SCHED_OTHER, &sched) != 0) {
        perror("Error setting default priority");
    }
}

int main(int argc, char *argv[]) {
    // Parse command line arguments
    if (parse_arguments(argc, argv) != 0) {
        print_usage(argv[0]);
        return EXIT_FAILURE;
    }

    // Initialize GPIO
    if (init_gpio(gpio_pin) != 0) {
        fprintf(stderr, "Failed to initialize GPIO pin %u\n", gpio_pin);
        return EXIT_FAILURE;
    }

    // Check for pull-up resistor
    GPIO_SET();
    usleep(10000); // Wait 10ms
    if (GPIO_READ() == 0) {
        fprintf(stderr, "Error: No pull-up resistor detected on GPIO %u\n", gpio_pin);
        deinit_gpio();
        return EXIT_FAILURE;
    }

    // Change sensor resolution if requested
    if (target_resolution > 0) {
        change_sensor_resolution(target_resolution);
        change_sensor_resolution(target_resolution); // Do it twice, just in case
    }

    // Start global temperature conversion
    if (global_start_conversion() != 0) {
        fprintf(stderr, "Error: No DS18B20 sensor detected or conversion failed\n");
        deinit_gpio();
        return EXIT_FAILURE;
    }

    set_realtime_priority();

    // Read sensors from file or scan for sensors
    if (file_mode) {
        read_sensors_from_file(filename);
    } else {
        scan_for_sensors();
    }

    set_default_priority();

    // Deinitialize GPIO
    deinit_gpio();

    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <wiringPi.h>
#include <drcSerial.h>

// Constants
#define GERT_BASE 100
#define NUM_LEDS 6
#define BUTTON1_PIN (GERT_BASE + 16)
#define BUTTON2_PIN (GERT_BASE + 17)
#define SERIAL_DEVICE "/dev/ttyAMA0"
#define SERIAL_BAUD_RATE 115200

// LED pin mapping
static int led_pins[NUM_LEDS] = {
    GERT_BASE + 6, GERT_BASE + 5, GERT_BASE + 3, GERT_BASE + 10, GERT_BASE + 9, GERT_BASE + 13
};

// Sequence data (LED, State, Duration)
static int sequence_data[] = {
    0, 1, 1,
    1, 1, 1,
    0, 0, 0, 2, 1, 1,
    1, 0, 0, 3, 1, 1,
    2, 0, 0, 4, 1, 1,
    3, 0, 0, 5, 1, 1,
    4, 0, 1,
    5, 0, 1,

    0, 0, 1, // Extra delay

    5, 1, 1,
    4, 1, 1,
    5, 0, 0, 3, 1, 1,
    4, 0, 0, 2, 1, 1,
    3, 0, 0, 1, 1, 1,
    2, 0, 0, 0, 1, 1,
    1, 0, 1,
    0, 0, 1,

    0, 0, 1, // Extra delay

    0, 9, 0  // End marker
};

// Function prototypes
int setup_gpio(void);
int run_led_sequence(void);

int main(void) {
    printf("Raspberry Pi - 6-LED Sequence\n");
    printf("=============================\n");
    printf("\n");
    printf("Use the 2 buttons to temporarily speed up the sequence\n");

    // Initialize WiringPi and DRC
    if (wiringPiSetupSys() == -1) {
        fprintf(stderr, "WiringPi setup failed: %s\n", strerror(errno));
        return 1;
    }

    if (drcSetupSerial(GERT_BASE, 20, SERIAL_DEVICE, SERIAL_BAUD_RATE) == -1) {
        fprintf(stderr, "DRC Serial setup failed\n");
        return 1;
    }

    // Configure GPIO pins
    if (setup_gpio() != 0) {
        fprintf(stderr, "GPIO setup failed\n");
        return 1;
    }

    // Run the LED sequence
    if (run_led_sequence() != 0) {
        fprintf(stderr, "LED sequence failed\n");
        return 1;
    }

    return 0;
}

// Function to setup GPIO pins
int setup_gpio(void) {
    int i;

    // Set LED pins as output
    for (i = 0; i < NUM_LEDS; ++i) {
        pinMode(led_pins[i], OUTPUT);
    }

    // Set button pins as input with pull-up resistors
    pinMode(BUTTON1_PIN, INPUT);
    pinMode(BUTTON2_PIN, INPUT);
    pullUpDnControl(BUTTON1_PIN, PUD_UP);
    pullUpDnControl(BUTTON2_PIN, PUD_UP);

    return 0;
}

// Function to run the LED sequence
int run_led_sequence(void) {
    int data_ptr = 0;
    int led_index, led_state, duration;

    while (1) {
        // Read sequence data
        led_index = sequence_data[data_ptr++];
        led_state = sequence_data[data_ptr++];
        duration = sequence_data[data_ptr++];

        // Check for end marker
        if (led_state == 9) {
            data_ptr = 0; // Reset sequence
            continue;
        }

        // Error checking for led_index
        if (led_index < 0 || led_index >= NUM_LEDS) {
            fprintf(stderr, "Error: Invalid LED index %d\n", led_index);
            return 1; // Or handle the error as appropriate
        }

        // Set LED state
        digitalWrite(led_pins[led_index], led_state);

        // Calculate delay based on button presses
        int delay_time = duration * (digitalRead(BUTTON1_PIN) * 15 + digitalRead(BUTTON2_PIN) * 20);
        delay(delay_time);
    }

    return 0; // This will never be reached in the current implementation
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <time.h>
#include <gpiod.h>
#include <math.h>

// Constants
#define MAX_SENSORS 32
#define DS18B20_SKIP_ROM 0xCC
#define DS18B20_CONVERT_T 0x44
#define DS18B20_READ_SCRATCHPAD 0xBE
#define RETRY_MAX 3

// Data structure for sensor information
typedef struct {
    int pin;
    bool valid;
    unsigned char resolution;
    double temperature;
} sensor_data_t;

// Global variables
struct gpiod_chip *gpiochip = NULL;
sensor_data_t sensors[MAX_SENSORS];
int num_sensors = 0;

// Function prototypes
bool init_gpio(void);
bool add_sensor(int pin);
int reset_sensors(void);
void write_byte(unsigned char value);
void read_byte(unsigned int *datatable);
void extract_scratchpad(unsigned int bitmask, unsigned char *scratchpad, unsigned int *bitdatatable);
unsigned char calc_crc(unsigned char *data, unsigned char byteSize);
int read_temperatures(unsigned int *bitdatatable);
void delay_microseconds(int delay_us);

int main(int argc, char **argv) {
    int loop;
    unsigned long acq_delay;
    unsigned char highest_resolution = 9;

    if (argc == 1) {
        fprintf(stderr, "Usage: %s GPIO1 GPIO2 ... GPIO%d\n", argv[0], MAX_SENSORS);
        return EXIT_FAILURE;
    }

    // Initialize GPIO
    if (!init_gpio()) {
        fprintf(stderr, "Failed to initialize GPIO.\n");
        return EXIT_FAILURE;
    }

    // Add sensors from command line arguments
    for (loop = 1; loop < argc && num_sensors < MAX_SENSORS; loop++) {
        int pin = atoi(argv[loop]);
        if (add_sensor(pin)) {
            sensors[num_sensors].pin = pin;
            num_sensors++;
        } else {
            fprintf(stderr, "Failed to add sensor on GPIO %d.\n", pin);
        }
    }

    if (num_sensors == 0) {
        fprintf(stderr, "No valid sensors added. Exiting.\n");
        gpiod_chip_close(gpiochip);
        return EXIT_FAILURE;
    }

    // Determine highest resolution among sensors
    unsigned int bitdatatable[72];
    read_temperatures(bitdatatable);
    for (loop = 0; loop < num_sensors; loop++) {
        if (sensors[loop].valid && sensors[loop].resolution > highest_resolution) {
            highest_resolution = sensors[loop].resolution;
        }
    }

    // Set acquisition delay based on highest resolution
    switch (highest_resolution) {
        case 9:
            acq_delay = 94000;
            break;
        case 10:
            acq_delay = 188000;
            break;
        case 11:
            acq_delay = 375000;
            break;
        default:
            acq_delay = 750000;
    }

    printf("Highest resolution: %d bits. Acquisition delay: %ld ms.\n", highest_resolution, acq_delay / 1000);
    printf("Press Enter to start. Ctrl-C to exit.\n");
    getchar();

    // Main loop
    struct timespec start_time, acq_start_time, end_time;
    do {
        clock_gettime(CLOCK_MONOTONIC, &acq_start_time);

        // Reset and start temperature conversion
        if (reset_sensors() != 0) {
          fprintf(stderr, "Reset Failed, trying again.\n");
          continue;
        }

        write_byte(DS18B20_SKIP_ROM);
        write_byte(DS18B20_CONVERT_T);

        // Wait for conversion
        delay_microseconds(acq_delay);

        // Read temperatures
        read_temperatures(bitdatatable);

        clock_gettime(CLOCK_MONOTONIC, &end_time);

        printf("====\nAcquisition time: %.3f sec\n", (end_time.tv_sec - acq_start_time.tv_sec) + (end_time.tv_nsec - acq_start_time.tv_nsec) / 1e9);

        // Print results
        for (loop = 0; loop < num_sensors; loop++) {
            printf("GPIO %d: ", sensors[loop].pin);
            if (sensors[loop].valid) {
                printf("%02d bits  Temperature: %6.2f +/- %4.2f Celsius\n",
                       sensors[loop].resolution, sensors[loop].temperature,
                       0.0625 * (double)(1 << (12 - sensors[loop].resolution)));
            } else {
                printf("Invalid data\n");
            }
        }
        fflush(stdout);

    } while (1);

    // Clean up
    gpiod_chip_close(gpiochip);
    return 0;
}

bool init_gpio(void) {
    gpiochip = gpiod_chip_open_by_name("gpiochip4");
    if (!gpiochip) {
        gpiochip = gpiod_chip_open_by_name("gpiochip0");
        if (!gpiochip) {
            perror("gpiod_chip_open_by_name");
            return false;
        }
    }
    return true;
}

bool add_sensor(int pin) {
    struct gpiod_line *line = gpiod_chip_get_line(gpiochip, pin);
    if (!line) {
        perror("gpiod_chip_get_line");
        return false;
    }
    gpiod_line_release(line);
    return true;
}

int reset_sensors(void) {
    struct gpiod_line *line;
    int i, ret;

    // Set all sensor pins to output and high
    for (i = 0; i < num_sensors; i++) {
        line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
        if (!line) {
            perror("gpiod_chip_get_line");
            return -1;
        }
        ret = gpiod_line_request_output(line, "reset", 1);
        if (ret < 0) {
            perror("gpiod_line_request_output");
            gpiod_line_release(line);
            return -1;
        }
        gpiod_line_release(line);
    }

    delay_microseconds(10);

    // Drive all sensor pins low simultaneously
    for (i = 0; i < num_sensors; i++) {
        line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
        if (!line) {
            perror("gpiod_chip_get_line");
            return -1;
        }
        ret = gpiod_line_request_output(line, "reset", 0);
        if (ret < 0) {
            perror("gpiod_line_request_output");
            gpiod_line_release(line);
            return -1;
        }
        gpiod_line_release(line);
    }
    usleep(480);

    // Release the bus
    for (i = 0; i < num_sensors; i++) {
        line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
        if (!line) {
            perror("gpiod_chip_get_line");
            return -1;
        }
        ret = gpiod_line_request_input(line, "reset");
        if (ret < 0) {
            perror("gpiod_line_request_input");
            gpiod_line_release(line);
            return -1;
        }
        gpiod_line_release(line);
    }
    delay_microseconds(60);

    // Sample for presence pulse (not really used, but good practice)
    int presence[MAX_SENSORS];
    for (i = 0; i < num_sensors; i++) {
        line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
        if (!line) {
            perror("gpiod_chip_get_line");
            return -1;
        }
        ret = gpiod_line_get_value(line);
        if (ret < 0) {
            perror("gpiod_line_get_value");
            gpiod_line_release(line);
            return -1;
        }
        presence[i] = ret;
        gpiod_line_release(line);
    }

    delay_microseconds(420);

    // Check for any errors during reset
    for (i = 0; i < num_sensors; i++) {
        if (presence[i] == 1) {
            return -1; // Indicate error
        }
    }
    return 0; // Indicate success
}

void write_byte(unsigned char value) {
    struct gpiod_line *line;
    int i, bit;

    for (bit = 0; bit < 8; bit++) {
        for (i = 0; i < num_sensors; i++) {
            line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
            if (!line) {
                perror("gpiod_chip_get_line");
                return;
            }
            gpiod_line_request_output(line, "write", 0);
            gpiod_line_release(line);
        }

        if ((value & (1 << bit)) != 0) {
            delay_microseconds(1);
            for (i = 0; i < num_sensors; i++) {
                line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
                if (!line) {
                    perror("gpiod_chip_get_line");
                    return;
                }
                gpiod_line_request_output(line, "write", 1);
                gpiod_line_release(line);
            }
            usleep(60);
        } else {
            delay_microseconds(60);
            for (i = 0; i < num_sensors; i++) {
                line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
                if (!line) {
                    perror("gpiod_chip_get_line");
                    return;
                }
                gpiod_line_request_output(line, "write", 1);
                gpiod_line_release(line);
            }
            usleep(1);
        }
        delay_microseconds(60);
    }
    usleep(100);
}

void read_byte(unsigned int *datatable) {
    struct gpiod_line *line;
    int i, bit, ret;

    for (bit = 0; bit < 8; bit++) {
        for (i = 0; i < num_sensors; i++) {
            line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
            if (!line) {
                perror("gpiod_chip_get_line");
                return;
            }
            gpiod_line_request_output(line, "read", 0);
            gpiod_line_release(line);
        }

        delay_microseconds(1);

        for (i = 0; i < num_sensors; i++) {
            line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
            if (!line) {
                perror("gpiod_chip_get_line");
                return;
            }
            gpiod_line_request_input(line, "read");
            gpiod_line_release(line);
        }

        delay_microseconds(2);

        for (i = 0; i < num_sensors; i++) {
            line = gpiod_chip_get_line(gpiochip, sensors[i].pin);
            if (!line) {
                perror("gpiod_chip_get_line");
                return;
            }
            ret = gpiod_line_get_value(line);
            if (ret < 0) {
                perror("gpiod_line_get_value");
                return;
            }
            if (ret) {
                datatable[bit * num_sensors + i] = 1;
            } else {
                datatable[bit * num_sensors + i] = 0;
            }
        }

        delay_microseconds(60);
    }
}

void extract_scratchpad(unsigned int bitmask, unsigned char *scratchpad, unsigned int *bitdatatable) {
    int loop, loopr;
    unsigned char mask;

    for (loopr = 0; loopr < 9; loopr++) {
        mask = 1;
        scratchpad[loopr] = 0;
        for (loop = 0; loop < 8; loop++) {
            if ((bitdatatable[loopr * 8 * num_sensors + loop * num_sensors] & bitmask) != 0) {
                scratchpad[loopr] |= mask;
            }
            mask <<= 1;
        }
    }
}

unsigned char calc_crc(unsigned char *data, unsigned char byteSize) {
    unsigned char shift_register = 0;
    unsigned char loop, loop2;
    char dataByte;

    for (loop = 0; loop < byteSize; loop++) {
        dataByte = data[loop];
        for (loop2 = 0; loop2 < 8; loop2++) {
            if ((shift_register ^ dataByte) & 1) {
                shift_register >>= 1;
                shift_register ^= 0x8C;
            } else {
                shift_register >>= 1;
            }
            dataByte >>= 1;
        }
    }
    return shift_register;
}

int read_temperatures(unsigned int *bitdatatable) {
    int loop, retryloop;
    unsigned char scratchpad[9];
    unsigned char crc_byte;
    union {
        short SHORT;
        unsigned char CHAR[2];
    } int_temp;

    // Initialize sensors' valid flag to false
    for (loop = 0; loop < num_sensors; loop++) {
        sensors[loop].valid = false;
    }

    // Retry reading multiple times for reliability
    for (retryloop = 0; retryloop < RETRY_MAX; retryloop++) {
        // Reset data table
        memset(bitdatatable, 0, 72 * num_sensors * sizeof(unsigned int));

        // Reset the sensors
        if (reset_sensors() != 0) {
            fprintf(stderr, "Reset failed during temperature read, retrying.\n");
            continue;
        }

        // Send commands to read scratchpad
        write_byte(DS18B20_SKIP_ROM);
        write_byte(DS18B20_READ_SCRATCHPAD);

        // Read scratchpad data
        for (loop = 0; loop < 72; loop += 8) {
            read_byte(&bitdatatable[loop * num_sensors]);
        }

        // Extract data and validate CRC for each sensor
        for (loop = 0; loop < num_sensors; loop++) {
            extract_scratchpad(1 << loop, scratchpad, bitdatatable);
            crc_byte = calc_crc(scratchpad, 8);

            if (crc_byte == scratchpad[8]) {
                // Check resolution
                if ((scratchpad[4] & 0x9F) == 0x1F) {
                    sensors[loop].valid = true;
                    switch (scratchpad[4]) {
                        case 0x1F:
                            sensors[loop].resolution = 9;
                            break;
                        case 0x3F:
                            sensors[loop].resolution = 10;
                            break;
                        case 0x5F:
                            sensors[loop].resolution = 11;
                            break;
                        default:
                            sensors[loop].resolution = 12;
                            break;
                    }

                    // Read temperature
                    int_temp.CHAR[0] = scratchpad[0];
                    int_temp.CHAR[1] = scratchpad[1];
                    sensors[loop].temperature = 0.0625 * (double)int_temp.SHORT;
                }
            }
        }

        // Check if all sensors have valid data
        bool all_valid = true;
        for (loop = 0; loop < num_sensors; loop++) {
            if (!sensors[loop].valid) {
                all_valid = false;
                break;
            }
        }

        if (all_valid) {
            return 1; // Success
        }
    }

    return 0; // Failure
}

void delay_microseconds(int delay_us) {
    struct timespec ts;
    ts.tv_sec = 0;
    ts.tv_nsec = delay_us * 1000;
    nanosleep(&ts, NULL);
}

