// Define Raspberry Pi specific addresses.  Using the newer style.
// You might need to adjust BCM_PERI_BASE depending on your Raspberry Pi version.
#define BCM_PERI_BASE   0xFE000000UL  // For Raspberry Pi 4 and later
#define GPIO_BASE       (BCM_PERI_BASE + 0x200000) /* GPIO controller */

#define PAGE_SIZE       (4 * 1024)
#define BLOCK_SIZE      (4 * 1024)

// GPIO register access macros
#define GPIO_INP(g)     *(gpio + ((g) / 10)) &= ~(7 << (((g) % 10) * 3))
#define GPIO_OUT(g)    *(gpio + ((g) / 10)) |= (1 << (((g) % 10) * 3))
#define GPIO_SET_ALT(g, a) *(gpio + ((g) / 10)) |= (((a) <= 3 ? (a) + 4 : ((a) == 4) ? 3 : 2) << (((g) % 10) * 3))

#define GPIO_SET        *(gpio + 7)  // sets   bits which are 1, ignores bits which are 0
#define GPIO_CLR        *(gpio + 10) // clears bits which are 1, ignores bits which are 0
#define GPIO_READ(g)    ((*(gpio + 13) >> (g)) & 1) // Reads the bit at GPIO pin g

// DS18B20 commands
#define DS18B20_SKIP_ROM          0xCC
#define DS18B20_CONVERT_T         0x44
#define DS18B20_MATCH_ROM         0x55
#define DS18B20_SEARCH_ROM        0xF0
#define DS18B20_READ_SCRATCHPAD   0xBE
#define DS18B20_WRITE_SCRATCHPAD  0x4E
#define DS18B20_COPY_SCRATCHPAD   0x48

