// Decode command line arguments
int decode_arguments(int argc, char **argv)
{
    for (int i = 1; i < argc; ++i)
    {
        if (strcmp(argv[i], "-gpio") == 0)
        {
            if (i + 1 < argc)
            {
                ds_pin = atoi(argv[i + 1]);
                i++;
            }
            else
            {
                fprintf(stderr, "Error: -gpio requires a pin number\n");
                return -1;
            }
        }
        else if (strcmp(argv[i], "-9bits") == 0) arg_resolution = 9;
        else if (strcmp(argv[i], "-10bits") == 0) arg_resolution = 10;
        else if (strcmp(argv[i], "-11bits") == 0) arg_resolution = 11;
        else if (strcmp(argv[i], "-12bits") == 0) arg_resolution = 12;
        else if (strcmp(argv[i], "-s") == 0) arg_scan = 1;
        else if (strcmp(argv[i], "-t") == 0)
        {
            if (i + 1 < argc)
            {
                arg_wait_time = atoi(argv[i + 1]);
                i++;
            }
            else
            {
                fprintf(stderr, "Error: -t requires a delay value\n");
                return -1;
            }
        }
        else if (strcmp(argv[i], "-f") == 0)
        {
            if (i + 1 < argc)
            {
                arg_file = 1;
                strncpy(filename, argv[i + 1], sizeof(filename) - 1);
                filename[sizeof(filename) - 1] = 0; // Ensure null termination
                i++;
            }
            else
            {
                fprintf(stderr, "Error: -f requires a filename\n");
                return -1;
            }
        }
        else
        {
            fprintf(stderr, "Error: Unknown argument %s\n", argv[i]);
            return -1;
        }
    }
    return 0;
}

// Read sensor IDs from a file
void read_sensors_from_file(char *filename)
{
    FILE *src = fopen(filename, "rt");
    if (src == NULL)
    {
        perror("Error opening file");
        return;
    }

    char line_buffer[256];
    unsigned long long sensor_id;

    while (fgets(line_buffer, sizeof(line_buffer), src) != NULL)
    {
        if (sscanf(line_buffer, "%llx", &sensor_id) == 1)
        {
            ds18b20_read_sensor(sensor_id);
        }
    }
    fclose(src);
}

