// Configuration
#define PAGE_SIZE (4 * 1024)
#define BLOCK_SIZE (4 * 1024)
#define DS18B20_SKIP_ROM 0xCC
#define DS18B20_CONVERT_T 0x44
#define DS18B20_READ_SCRATCHPAD 0xBE
#define DS18B20_WRITE_SCRATCHPAD 0x4E
#define DS18B20_COPY_SCRATCHPAD 0x48

// Global Variables
static volatile unsigned int *gpio = NULL; // GPIO register map
static int mem_fd = 0;                     // File descriptor for /dev/gpiomem
static unsigned char scratchpad[9];        // Scratchpad memory for DS18B20
static double temperature = -9999.9;        // Temperature value
static int resolution = 0;                  // Resolution of the sensor
static unsigned int ds_pin = 4;             // GPIO pin connected to DS18B20
static unsigned long bcm_peri_base = 0xFE000000; //Base address for peripherals

// Function Prototypes
int setup_gpio();
void restore_default_priority(void);
void set_realtime_priority(void);
void delay_microseconds(int delay_us);
int ds18b20_reset(void);
void ds18b20_write_byte(unsigned char value);
unsigned char ds18b20_read_bit(void);
unsigned char ds18b20_read_byte(void);
int ds18b20_read_scratchpad(void);
unsigned char ds18b20_calculate_crc(unsigned char *data, unsigned char byteSize);
int ds18b20_read_sensor(void);
void ds18b20_write_scratchpad(unsigned char th, unsigned char tl, unsigned char config);
void ds18b20_copy_scratchpad(void);

// Function to set realtime priority
void set_realtime_priority(void) {
  struct sched_param sched;
  memset(&sched, 0, sizeof(sched));
  sched.sched_priority = sched_get_priority_max(SCHED_FIFO);
  if (sched_setscheduler(0, SCHED_FIFO, &sched) != 0) {
    perror("sched_setscheduler failed");
  }
}

// Function to restore default priority
void restore_default_priority(void) {
  struct sched_param sched;
  memset(&sched, 0, sizeof(sched));
  sched.sched_priority = 0;
  if (sched_setscheduler(0, SCHED_OTHER, &sched) != 0) {
    perror("sched_setscheduler failed");
  }
}

// Function to perform a delay in microseconds without sleep
void delay_microseconds(int delay_us) {
  struct timespec start, end;
  clock_gettime(CLOCK_MONOTONIC, &start);
  long start_ns = start.tv_sec * 1000000000L + start.tv_nsec;
  long end_ns = start_ns + delay_us * 1000L;

  do {
    clock_gettime(CLOCK_MONOTONIC, &end);
  } while (end.tv_sec * 1000000000L + end.tv_nsec < end_ns);
}

// Function to perform the DS18B20 reset sequence
int ds18b20_reset(void) {
  // Set pin as input initially
  *(gpio + ((ds_pin) / 10)) &= ~(7 << (((ds_pin) % 10) * 3));
  delay_microseconds(1000);

  // Drive the pin low for 480us
  *(gpio + ((ds_pin) / 10)) &= ~(7 << (((ds_pin) % 10) * 3)); // Set as output
  *(gpio + 7) = (1 << ds_pin);                                  // Clear the pin
  delay_microseconds(480);

  // Release the pin and set as input
  *(gpio + ((ds_pin) / 10)) &= ~(7 << (((ds_pin) % 10) * 3));
  delay_microseconds(60);

  // Check for presence pulse
  if ((*(gpio + 13) & (1 << ds_pin)) == 0) {
    delay_microseconds(380);
    return 1; // Presence detected
  }
  return 0; // No presence detected
}

// Function to write a byte to the DS18B20
void ds18b20_write_byte(unsigned char value) {
  unsigned char mask = 1;
  for (int i = 0; i < 8; i++) {
    // Drive the pin low
    *(gpio + ((ds_pin) / 10)) &= ~(7 << (((ds_pin) % 10) * 3)); // Set as output
    *(gpio + 7) = (1 << ds_pin);                                  // Clear the pin

    if ((value & mask) != 0) {
      delay_microseconds(1);
      *(gpio + ((ds_pin) / 10)) &= ~(7 << (((ds_pin) % 10) * 3)); // Set as input
      delay_microseconds(60);
    } else {
      delay_microseconds(60);
      *(gpio + ((ds_pin) / 10)) &= ~(7 << (((ds_pin) % 10) * 3)); // Set as input
      delay_microseconds(1);
    }
    mask *= 2;
    delay_microseconds(60);
  }
  delay_microseconds(100);
}

// Function to read a bit from the DS18B20
unsigned char ds18b20_read_bit(void) {
  // Drive the pin low
  *(gpio + ((ds_pin) / 10)) &= ~(7 << (((ds_pin) % 10) * 3)); // Set as output
  *(gpio + 7) = (1 << ds_pin);                                  // Clear the pin
  delay_microseconds(1);

  // Release the pin and set as input
  *(gpio + ((ds_pin) / 10)) &= ~(7 << (((ds_pin) % 10) * 3));
  delay_microseconds(2);

  // Read the pin state
  return (*(gpio + 13) & (1 << ds_pin)) ? 1 : 0;
}

// Function to read a byte from the DS18B20
unsigned char ds18b20_read_byte(void) {
  unsigned char mask = 1;
  unsigned char data = 0;

  for (int i = 0; i < 8; i++) {
    // Drive the pin low
    *(gpio + ((ds_pin) / 10)) &= ~(7 << (((ds_pin) % 10) * 3)); // Set as output
    *(gpio + 7) = (1 << ds_pin);                                  // Clear the pin
    delay_microseconds(1);

    // Release the pin and set as input
    *(gpio + ((ds_pin) / 10)) &= ~(7 << (((ds_pin) % 10) * 3));
    delay_microseconds(2);

    // Read the bit and store it
    if (*(gpio + 13) & (1 << ds_pin)) {
      data |= mask;
    }
    mask *= 2;
    delay_microseconds(60);
  }
  return data;
}

// Function to read the scratchpad from the DS18B20
int ds18b20_read_scratchpad(void) {
  if (ds18b20_reset()) {
    ds18b20_write_byte(DS18B20_SKIP_ROM);
    ds18b20_write_byte(DS18B20_READ_SCRATCHPAD);
    for (int i = 0; i < 9; i++) {
      scratchpad[i] = ds18b20_read_byte();
    }
    return 1;
  }
  return 0;
}

// Function to calculate the CRC of the data
unsigned char ds18b20_calculate_crc(unsigned char *data, unsigned char byteSize) {
  unsigned char shift_register = 0;
  for (int i = 0; i < byteSize; i++) {
    unsigned char dataByte = data[i];
    for (int j = 0; j < 8; j++) {
      if ((shift_register ^ dataByte) & 1) {
        shift_register = shift_register >> 1;
        shift_register ^= 0x8C;
      } else {
        shift_register = shift_register >> 1;
      }
      dataByte = dataByte >> 1;
    }
  }
  return shift_register;
}

// Function to read the temperature from the DS18B20
int ds18b20_read_sensor(void) {
  int retryCount;
  unsigned char crcByte;
  union {
    short SHORT;
    unsigned char CHAR[2];
  } intTemp;

  temperature = -9999.9; // Reset temperature value

  for (retryCount = 0; retryCount < 5; retryCount++) {
    if (!ds18b20_reset()) continue;

    // Start a conversion
    ds18b20_write_byte(DS18B20_SKIP_ROM);
    ds18b20_write_byte(DS18B20_CONVERT_T);

    int maxLoop = 0;
    // Wait until ready
    while (!ds18b20_read_bit()) {
      putchar('.');
      maxLoop++;
      if (maxLoop > 100000) break;
    }

    if (maxLoop > 100000) continue;

    if (!ds18b20_read_scratchpad()) continue;

#ifdef DEBUG
    printf("Scratchpad: ");
    for (int i = 0; i < 9; i++) {
      printf("%02X ", scratchpad[i]);
    }
    printf("\n");
    fflush(stdout);
#endif

    // Check CRC
    crcByte = ds18b20_calculate_crc(scratchpad, 8);
    if (crcByte != scratchpad[8]) continue;

    // Check Resolution
    resolution = 0;
    switch (scratchpad[4]) {
      case 0x1f:
        resolution = 9;
        break;
      case 0x3f:
        resolution = 10;
        break;
      case 0x5f:
        resolution = 11;
        break;
      case 0x7f:
        resolution = 12;
        break;
    }

    if (resolution == 0) continue;

    // Read Temperature
    intTemp.CHAR[0] = scratchpad[0];
    intTemp.CHAR[1] = scratchpad[1];

    temperature = 0.0625 * (double)intTemp.SHORT;

    printf("%02d bits  Temperature: %6.2f +/- %f Celsius\n", resolution, temperature, 0.0625 * (double)(1 << (12 - resolution)));

    return 1;
  }
  return 0;
}

// Function to write to the scratchpad
void ds18b20_write_scratchpad(unsigned char th, unsigned char tl, unsigned char config) {
  ds18b20_reset();
  delay_microseconds(1000);
  ds18b20_write_byte(DS18B20_SKIP_ROM);
  ds18b20_write_byte(DS18B20_WRITE_SCRATCHPAD);
  ds18b20_write_byte(th);
  ds18b20_write_byte(tl);
  ds18b20_write_byte(config);
}

// Function to copy the scratchpad to EEPROM
void ds18b20_copy_scratchpad(void) {
  ds18b20_reset();
  delay_microseconds(1000);
  ds18b20_write_byte(DS18B20_SKIP_ROM);
  ds18b20_write_byte(DS18B20_COPY_SCRATCHPAD);
  usleep(100000); // Wait for EEPROM copy
}

// Function to setup GPIO access
int setup_gpio() {
  int handle;

  #ifdef __arch64__
  struct {
    unsigned int V1, X1, V2, X2, V3, X3;
  } ranges;
  #else
  struct {
    unsigned int V1, V2, V3;
    unsigned int X1, X2, X3;
  } ranges;
  #endif

  /* open /dev/gpiomem */
  if ((mem_fd = open("/dev/gpiomem", O_RDWR | O_SYNC)) < 0) {
    printf("can't open /dev/gpiomem: %s\n", strerror(errno));
    return -1;
  }

  // read /proc/device-tree/soc/ranges
  // to check if we have the GPIO at 0x20000000 or 0x3F000000

#define Swap4Bytes(val)                                                                                                                                                                                 \
  ((((val) >> 24) & 0x000000FF) | (((val) >> 8) & 0x0000FF00) | (((val) << 8) & 0x00FF0000) | (((val) << 24) & 0xFF000000))

  handle = open("/proc/device-tree/soc/ranges", O_RDONLY);

  if (handle >= 0) {
    ssize_t count = read(handle, &ranges, 24);
    if (count == 24) bcm_peri_base = Swap4Bytes(ranges.V2);
    close(handle);
  }

  printf("BCM GPIO BASE= %lx\n", bcm_peri_base);

  /* mmap GPIO */
  gpio = (volatile unsigned int *)mmap(
      NULL,             // Any adddress in our space will do
      BLOCK_SIZE,       // Map length
      PROT_READ | PROT_WRITE, // Enable reading & writting to mapped memory
      MAP_SHARED,       // Shared with other processes
      mem_fd,           // File to map
      (bcm_peri_base + 0x200000)     // Offset to GPIO peripheral
  );

  if (gpio == MAP_FAILED) {
    printf("mmap error gpio_map=%p: %s\n", gpio, strerror(errno));
    close(mem_fd);
    return -1;
  }

  // Set the DS18B20 pin as input initially
  *(gpio + ((ds_pin) / 10)) &= ~(7 << (((ds_pin) % 10) * 3));
  return 0;
}

int main(int argc, char **argv) {
  int config;

  // Parse command line arguments
  if (argc == 2) {
    ds_pin = atoi(argv[1]);
  }

  printf("Using GPIO %d for DS18B20\n", ds_pin);

  if ((ds_pin < 1) || (ds_pin > 32)) {
    fprintf(stderr, "Invalid GPIO PIN.  Must be between 1 and 32.\n");
    return EXIT_FAILURE;
  }

  // Initialize GPIO
  if (setup_gpio() != 0) {
    fprintf(stderr, "GPIO setup failed.\n");
    return EXIT_FAILURE;
  }

  set_realtime_priority();

  if (ds18b20_read_sensor()) {
    printf("DS18B20 Resolution (9,10,11 or 12) ? ");
    fflush(stdout);

    config = 0;
    restore_default_priority();

    if (scanf("%d", &resolution) == 1) {
      switch (resolution) {
        case 9:
          config = 0x1f;
          break;
        case 10:
          config = 0x3f;
          break;
        case 11:
          config = 0x5f;
          break;
        case 12:
          config = 0x7f;
          break;
        default:
          printf("Invalid resolution value.\n");
          config = 0;
          break;
      }
    }

    if (config == 0) {
      printf("Invalid Value! Nothing done.\n");
    } else {
      printf("Try to set %d bits  config=%2X\n", resolution, config);
      usleep(1000);
      set_realtime_priority();

      ds18b20_write_scratchpad(scratchpad[2], scratchpad[3], config);
      usleep(1000);
      ds18b20_copy_scratchpad();
    }
  } else {
    fprintf(stderr, "Failed to read temperature from DS18B20.\n");
  }

  restore_default_priority();

  // Cleanup GPIO mapping
  if (gpio != MAP_FAILED) {
    if (munmap((void *)gpio, BLOCK_SIZE) != 0) {
      perror("munmap failed");
    }
  }
  if (mem_fd > 0) {
    close(mem_fd);
  }

  return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <time.h>
#include <sched.h>
#include <string.h>
#include <gpiod.h>
#include <errno.h>
#include <math.h>

// Constants for DS18B20 commands
#define DS18B20_SKIP_ROM 0xCC
#define DS18B20_CONVERT_T 0x44
#define DS18B20_READ_SCRATCHPAD 0xBE
#define DS18B20_WRITE_SCRATCHPAD 0x4E
#define DS18B20_COPY_SCRATCHPAD 0x48

// Default GPIO chip name
#define DEFAULT_GPIO_CHIP "gpiochip4"

// Global variables
static struct gpiod_chip *gpio_chip = NULL;
static struct gpiod_line *gpio_line = NULL;
static unsigned char scratchpad[9];
static double temperature = -9999.9;
static int resolution = 0;
static unsigned int ds_pin = 4; // Default GPIO pin

// Function prototypes
bool init_gpio(int pin);
int ds18b20_reset(void);
void write_byte(unsigned char value);
unsigned char read_byte(void);
int read_scratchpad(void);
unsigned char calculate_crc(unsigned char *data, unsigned char byte_size);
int read_sensor(void);
void write_scratchpad(unsigned char th, unsigned char tl, unsigned char config);
void copy_scratchpad(void);
void set_max_priority(void);
void set_default_priority(void);
void delay_microseconds(int delay_us);

// Helper macros for GPIO operations
#define GPIO_READ() gpiod_line_get_value(gpio_line)
#define GPIO_SET() gpiod_line_set_value(gpio_line, 1)
#define GPIO_CLEAR() gpiod_line_set_value(gpio_line, 0)
#define DELAY_1US() delay_microseconds(1)

// Function to initialize the GPIO line
bool init_gpio(int pin) {
  const char *chipname = DEFAULT_GPIO_CHIP;

  gpio_chip = gpiod_chip_open_by_name(chipname);
  if (!gpio_chip) {
    chipname = "gpiochip0";
    gpio_chip = gpiod_chip_open_by_name(chipname);
    if (!gpio_chip) {
      fprintf(stderr, "Error: Unable to open GPIO chip '%s' or '%s': %s\n", DEFAULT_GPIO_CHIP, chipname, strerror(errno));
      return false;
    }
  }

  gpio_line = gpiod_chip_get_line(gpio_chip, pin);
  if (!gpio_line) {
    fprintf(stderr, "Error: Unable to open GPIO line %d: %s\n", pin, strerror(errno));
    gpiod_chip_close(gpio_chip);
    return false;
  }

  if (gpiod_line_request_output_flags(gpio_line, "DS18B20", GPIOD_LINE_REQUEST_FLAG_OPEN_DRAIN | GPIOD_LINE_REQUEST_FLAG_BIAS_PULL_UP, 1) < 0) {
    fprintf(stderr, "Error: Unable to request GPIO line for output: %s\n", strerror(errno));
    gpiod_line_release(gpio_line);
    gpiod_chip_close(gpio_chip);
    return false;
  }

  return true;
}

// Function to perform the DS18B20 reset sequence
int ds18b20_reset(void) {
  GPIO_SET();
  delay_microseconds(10);
  GPIO_CLEAR();
  delay_microseconds(480);
  GPIO_SET();
  delay_microseconds(60);
  if (GPIO_READ() == 0) {
    delay_microseconds(420);
    return 1; // Presence detected
  }
  return 0; // No presence detected
}

// Function to write a byte to the DS18B20
void write_byte(unsigned char value) {
  unsigned char mask = 1;
  for (int i = 0; i < 8; i++) {
    GPIO_CLEAR();
    if ((value & mask) != 0) {
      DELAY_1US();
      GPIO_SET();
      delay_microseconds(60);
    } else {
      delay_microseconds(60);
      GPIO_SET();
      DELAY_1US();
    }
    mask *= 2;
    delay_microseconds(60);
  }
  usleep(100); // Small delay after writing a byte
}

// Function to read a byte from the DS18B20
unsigned char read_byte(void) {
  unsigned char mask = 1;
  unsigned char data = 0;

  for (int i = 0; i < 8; i++) {
    GPIO_CLEAR();
    DELAY_1US();
    GPIO_SET();
    delay_microseconds(2);
    if (GPIO_READ() != 0)
      data |= mask;
    mask *= 2;
    delay_microseconds(60);
  }
  return data;
}

// Function to read the DS18B20 scratchpad
int read_scratchpad(void) {
  if (ds18b20_reset()) {
    write_byte(DS18B20_SKIP_ROM);
    write_byte(DS18B20_READ_SCRATCHPAD);
    for (int i = 0; i < 9; i++) {
      scratchpad[i] = read_byte();
    }
    return 1;
  }
  return 0;
}

// Function to calculate the CRC of the data
unsigned char calculate_crc(unsigned char *data, unsigned char byte_size) {
  unsigned char shift_register = 0;
  for (int i = 0; i < byte_size; i++) {
    unsigned char data_byte = data[i];
    for (int j = 0; j < 8; j++) {
      if ((shift_register ^ data_byte) & 1) {
        shift_register = shift_register >> 1;
        shift_register ^= 0x8C;
      } else {
        shift_register = shift_register >> 1;
      }
      data_byte = data_byte >> 1;
    }
  }
  return shift_register;
}

// Function to read the temperature from the DS18B20 sensor
int read_sensor(void) {
  int retry_count;
  for (retry_count = 0; retry_count < 5; retry_count++) {
    if (!ds18b20_reset()) continue;

    // Start a temperature conversion
    write_byte(DS18B20_SKIP_ROM);
    write_byte(DS18B20_CONVERT_T);

    // Wait until the conversion is complete
    int max_loop = 0;
    while (!((bool)GPIO_READ())) {
      max_loop++;
      if (max_loop > 100000) break; // Timeout
    }

    if (max_loop > 100000) continue; // Retry if timeout

    if (!read_scratchpad()) continue; // Retry if scratchpad read fails

    // Verify CRC
    unsigned char crc_byte = calculate_crc(scratchpad, 8);
    if (crc_byte != scratchpad[8]) continue; // Retry if CRC fails

    // Determine resolution
    resolution = 0;
    switch (scratchpad[4]) {
      case 0x1f: resolution = 9; break;
      case 0x3f: resolution = 10; break;
      case 0x5f: resolution = 11; break;
      case 0x7f: resolution = 12; break;
    }

    if (resolution == 0) continue; // Retry if resolution is invalid

    // Read temperature
    union {
      short short_value;
      unsigned char char_value[2];
    } int_temp;

    int_temp.char_value[0] = scratchpad[0];
    int_temp.char_value[1] = scratchpad[1];

    temperature = 0.0625 * (double)int_temp.short_value;

    printf("Temperature: %.2f +/- %.2f Celsius (Resolution: %d bits)\n", temperature, 0.0625 * (double)(1 << (12 - resolution)), resolution);
    return 1; // Success
  }
  fprintf(stderr, "Error: Failed to read sensor after multiple retries.\n");
  return 0; // Failure after multiple retries
}

// Function to write to the DS18B20 scratchpad
void write_scratchpad(unsigned char th, unsigned char tl, unsigned char config) {
  ds18b20_reset();
  delay_microseconds(1000);
  write_byte(DS18B20_SKIP_ROM);
  write_byte(DS18B20_WRITE_SCRATCHPAD);
  write_byte(th);
  write_byte(tl);
  write_byte(config);
}

// Function to copy the scratchpad to EEPROM
void copy_scratchpad(void) {
  ds18b20_reset();
  delay_microseconds(1000);
  write_byte(DS18B20_SKIP_ROM);
  write_byte(DS18B20_COPY_SCRATCHPAD);
  usleep(100000);
}

// Function to set the maximum priority for real-time execution
void set_max_priority(void) {
  struct sched_param sched;
  memset(&sched, 0, sizeof(sched));
  sched.sched_priority = sched_get_priority_max(SCHED_FIFO);
  if (sched_setscheduler(0, SCHED_FIFO, &sched) != 0) {
    perror("Error setting maximum priority");
  }
}

// Function to set the default priority
void set_default_priority(void) {
  struct sched_param sched;
  memset(&sched, 0, sizeof(sched));
  sched.sched_priority = 0;
  if (sched_setscheduler(0, SCHED_OTHER, &sched) != 0) {
    perror("Error setting default priority");
  }
}

// Function for microsecond delays without sleep
void delay_microseconds(int delay_us) {
  struct timespec start, end;
  clock_gettime(CLOCK_MONOTONIC, &start);
  long start_ns = start.tv_sec * 1000000000L + start.tv_nsec;
  long end_ns = start_ns + delay_us * 1000L;

  do {
    clock_gettime(CLOCK_MONOTONIC, &end);
    long current_ns = end.tv_sec * 1000000000L + end.tv_nsec;
  } while (current_ns < end_ns);
}

int main(int argc, char **argv) {
  int config = 0;

  // Parse command-line arguments
  if (argc == 2) {
    ds_pin = atoi(argv[1]);
  }

  printf("Using GPIO pin: %d\n", ds_pin);

  if (ds_pin < 1 || ds_pin > 32) {
    fprintf(stderr, "Error: Invalid GPIO pin number. Must be between 1 and 32.\n");
    return EXIT_FAILURE;
  }

  // Initialize GPIO
  if (!init_gpio(ds_pin)) {
    return EXIT_FAILURE;
  }

  // Read sensor data
  set_max_priority(); // Set real-time priority before reading sensor
  if (read_sensor()) {
    printf("Enter desired resolution (9, 10, 11, or 12), or 0 to skip: ");
    fflush(stdout);
    set_default_priority(); // Restore default priority before user input

    if (scanf("%d", &resolution) == 1) {
      switch (resolution) {
        case 9:  config = 0x1f; break;
        case 10: config = 0x3f; break;
        case 11: config = 0x5f; break;
        case 12: config = 0x7f; break;
        case 0: printf("Skipping resolution change.\n"); break;
        default: printf("Invalid resolution value! Nothing done.\n"); config = 0; break;
      }
    } else {
      printf("Invalid input. Skipping resolution change.\n");
      config = 0;
    }

    if (config != 0) {
      printf("Setting resolution to %d bits (config = 0x%02X)\n", resolution, config);
      usleep(1000);
      set_max_priority(); // Set real-time priority before writing to sensor
      write_scratchpad(scratchpad[2], scratchpad[3], config);
      usleep(1000);
      copy_scratchpad();
    }
  } else {
    fprintf(stderr, "Error: Could not read sensor data.\n");
  }

  set_default_priority(); // Restore default priority before exiting

  // Clean up GPIO
  gpiod_line_release(gpio_line);
  gpiod_chip_close(gpio_chip);

  return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <linux/i2c-dev.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <unistd.h>
#include <stdint.h>
#include <errno.h>
#include <string.h>

// Constants
#define I2C_BUS "/dev/i2c-1" // I2C bus on Raspberry Pi
#define SENSOR_ADDRESS 0x27  // I2C address of the Honeywell sensor
#define MEASUREMENT_DELAY_US 100000 // Delay after initiating measurement (100ms)

// Function prototypes
int i2c_setup(int address);
int read_sensor_data(int file_descriptor, uint8_t *data);
double calculate_humidity(uint8_t msb, uint8_t lsb);
double calculate_temperature(uint8_t msb, uint8_t lsb);

int main()
{
    int i2c_file_descriptor;
    uint8_t sensor_data[4];
    double humidity, temperature;

    // Initialize I2C communication
    i2c_file_descriptor = i2c_setup(SENSOR_ADDRESS);
    if (i2c_file_descriptor == -1) {
        fprintf(stderr, "Error: I2C setup failed. Exiting.\n");
        return EXIT_FAILURE;
    }

    // Trigger sensor measurement
    if (i2c_smbus_write_quick(i2c_file_descriptor, 0) != 0) {
        fprintf(stderr, "Error: Failed to trigger measurement: %s\n", strerror(errno));
        close(i2c_file_descriptor);
        return EXIT_FAILURE;
    }

    // Wait for measurement to complete
    usleep(MEASUREMENT_DELAY_US);

    // Read sensor data
    if (read_sensor_data(i2c_file_descriptor, sensor_data) != 0) {
        fprintf(stderr, "Error: Failed to read sensor data. Exiting.\n");
        close(i2c_file_descriptor);
        return EXIT_FAILURE;
    }

    // Calculate humidity and temperature
    humidity = calculate_humidity(sensor_data[0], sensor_data[1]);
    temperature = calculate_temperature(sensor_data[2], sensor_data[3]);

    // Print results
    printf("Humidity: %.2f %%\n", humidity);
    printf("Temperature: %.2f °C\n", temperature);

    // Close I2C connection
    close(i2c_file_descriptor);

    return EXIT_SUCCESS;
}

// Initializes I2C communication.
// Returns the file descriptor of the I2C device, or -1 on error.
int i2c_setup(int address)
{
    int file_descriptor;

    // Open I2C bus
    file_descriptor = open(I2C_BUS, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error: Failed to open I2C bus %s: %s\n", I2C_BUS, strerror(errno));
        return -1;
    }

    // Set slave address
    if (ioctl(file_descriptor, I2C_SLAVE, address) < 0) {
        fprintf(stderr, "Error: Failed to set I2C slave address 0x%02x: %s\n", address, strerror(errno));
        close(file_descriptor);
        return -1;
    }

    return file_descriptor;
}

// Reads 4 bytes of data from the sensor.
// Returns 0 on success, -1 on error.
int read_sensor_data(int file_descriptor, uint8_t *data)
{
    if (read(file_descriptor, data, 4) != 4) {
        fprintf(stderr, "Error: Failed to read 4 bytes from I2C device: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

// Calculates humidity from the raw sensor data.
// Returns the humidity as a percentage.
double calculate_humidity(uint8_t msb, uint8_t lsb)
{
    unsigned int reading = (msb << 8) | lsb;
    return reading / 16382.0 * 100.0;
}

// Calculates temperature from the raw sensor data.
// Returns the temperature in degrees Celsius.
double calculate_temperature(uint8_t msb, uint8_t lsb)
{
    unsigned int reading = (msb << 6) | (lsb >> 2);
    return reading / 16382.0 * 165.0 - 40.0;
}

#include <bcm2835.h>
#include <stdio.h>
#include <stdlib.h>

// Define the GPIO pin to use (GPIO 17, which is RPi pin 11)
#define LED_PIN RPI_GPIO_P1_11

// Define the blink interval in milliseconds
#define BLINK_INTERVAL_MS 500

// Function to initialize the BCM2835 library and GPIO pin
int initialize_gpio() {
    if (!bcm2835_init()) {
        fprintf(stderr, "BCM2835 initialization failed!\n");
        return 1; // Indicate failure
    }

    // Set the LED pin as an output
    bcm2835_gpio_fsel(LED_PIN, BCM2835_GPIO_FSEL_OUTP);

    return 0; // Indicate success
}

// Function to blink the LED
void blink_led() {
    // Turn the LED on
    bcm2835_gpio_write(LED_PIN, HIGH);
    bcm2835_delay(BLINK_INTERVAL_MS);

    // Turn the LED off
    bcm2835_gpio_write(LED_PIN, LOW);
    bcm2835_delay(BLINK_INTERVAL_MS);
}

// Main function
int main(int argc, char **argv) {
    // Initialize the GPIO library
    if (initialize_gpio() != 0) {
        // If initialization fails, exit the program
        return 1;
    }

    // Blink the LED indefinitely
    while (1) {
        blink_led();
    }

    // This point will never be reached in the current implementation.
    // However, it's good practice to include a cleanup function.
    bcm2835_close();
    return 0;
}

#include <bcm2835.h>
#include <stdio.h>
#include <signal.h>
#include <stdlib.h>

// Define the GPIO pin to monitor (GPIO15 in this case, which is RPI pin P1-15)
#define GPIO_INPUT_PIN RPI_GPIO_P1_15

// Volatile flag to signal interrupt
volatile sig_atomic_t gpio_event_occurred = 0;

// Interrupt handler function
void gpio_event_handler(int signum) {
    gpio_event_occurred = 1;
}

int main(int argc, char **argv) {
    // Initialize bcm2835 library
    if (!bcm2835_init()) {
        fprintf(stderr, "bcm2835_init failed. Are you running as root?\n");
        return 1;
    }

    // Set the GPIO pin as an input
    bcm2835_gpio_fsel(GPIO_INPUT_PIN, BCM2835_GPIO_FSEL_INPT);

    // Enable pull-up resistor (optional, adjust as needed)
    bcm2835_gpio_set_pud(GPIO_INPUT_PIN, BCM2835_GPIO_PUD_UP);

    // Enable falling edge detection
    bcm2835_gpio_len(GPIO_INPUT_PIN);

    // Set up signal handler for SIGIO (GPIO event)
    signal(SIGIO, gpio_event_handler);

    // Allow non-root access to GPIO (if needed, for testing purposes)
    // bcm2835_set_debug(1);  // Remove this line for production

    // Set the owner of the GPIO pin (required for signal handling)
    if (bcm2835_gpio_set_pinen(GPIO_INPUT_PIN, 1) != 1) {
        fprintf(stderr, "Failed to set pin enable\n");
        bcm2835_close();
        return 1;
    }

    // Main loop
    while (1) {
        // Check if a GPIO event has occurred
        if (gpio_event_occurred) {
            // Clear the interrupt flag
            gpio_event_occurred = 0;

            // Clear the event detect status (EDS) flag
            bcm2835_gpio_set_eds(GPIO_INPUT_PIN);

            // Print a message indicating the event
            printf("Falling edge detected on GPIO %d\n", GPIO_INPUT_PIN);
        }

        // Wait for a short period to avoid busy-waiting
        bcm2835_delay(50); // Reduced delay for responsiveness
    }

    // Close the bcm2835 library before exiting
    bcm2835_close();
    return 0;
}

