#include <bcm2835.h>
#include <stdio.h>
#include <stdlib.h>

// Define the GPIO pin connected to the LED (RPi Plug P1 pin 12, GPIO18)
#define LED_GPIO_PIN RPI_GPIO_P1_12

// Define the PWM channel to use (only channel 0 is available on this pin)
#define PWM_CHANNEL 0

// Define the PWM range (resolution)
#define PWM_RANGE 1024

// Define the PWM clock divider (adjust for desired PWM frequency)
#define PWM_CLOCK_DIVIDER BCM2835_PWM_CLOCK_DIVIDER_16

// Function to initialize the BCM2835 library and PWM
bool initialize_pwm() {
    if (!bcm2835_init()) {
        fprintf(stderr, "Error: bcm2835_init() failed. Are you running as root?\n");
        return false;
    }

    // Configure the LED GPIO pin for PWM ALT function 5
    bcm2835_gpio_fsel(LED_GPIO_PIN, BCM2835_GPIO_FSEL_ALT5);

    // Set the PWM clock divider
    bcm2835_pwm_set_clock(PWM_CLOCK_DIVIDER);

    // Configure PWM channel 0 for markspace mode and enable it
    bcm2835_pwm_set_mode(PWM_CHANNEL, 1, 1); // Enable PWM, markspace mode

    // Set the PWM range
    bcm2835_pwm_set_range(PWM_CHANNEL, PWM_RANGE);

    return true;
}

// Function to safely cleanup and close the BCM2835 library
void cleanup_pwm() {
    bcm2835_close();
}

int main(int argc, char **argv) {
    if (!initialize_pwm()) {
        return 1; // Exit if initialization fails
    }

    int pwm_data = 1;          // Initial PWM data value
    int pwm_direction = 1;     // PWM direction (1 = increasing, -1 = decreasing)
    const int delay_ms = 1;    // Delay between PWM updates (milliseconds)

    // Main loop to vary the LED brightness
    while (1) {
        // Update PWM data value based on direction
        pwm_data += pwm_direction;

        // Reverse direction if PWM data reaches the limits
        if (pwm_data >= PWM_RANGE - 1) {
            pwm_direction = -1; // Switch to decreasing
        } else if (pwm_data <= 1) {
            pwm_direction = 1;  // Switch to increasing
        }

        // Set the PWM data for the channel
        bcm2835_pwm_set_data(PWM_CHANNEL, pwm_data);

        // Delay for a short period
        bcm2835_delay(delay_ms);
    }

    // This part of the code will never be reached in this example
    // because the while(1) loop runs indefinitely.
    // In a real application, you would need a way to break out of the loop
    // and call cleanup_pwm() before exiting.

    cleanup_pwm(); // Cleanup before exiting
    return 0;
}

