#define SPI_BIT_ORDER BCM2835_SPI_BIT_ORDER_MSBFIRST
#define SPI_CS BCM2835_SPI_CS0
#define SPI_CS_POLARITY LOW

// Function to initialize the SPI interface
bool init_spi()
{
    if (!bcm2835_init())
    {
        fprintf(stderr, "bcm2835_init failed. Are you running as root??\n");
        return false;
    }

    if (!bcm2835_spi_begin())
    {
        fprintf(stderr, "bcm2835_spi_begin failed. Are you running as root??\n");
        bcm2835_close();
        return false;
    }

    bcm2835_spi_setBitOrder(SPI_BIT_ORDER);
    bcm2835_spi_setDataMode(SPI_MODE);
    bcm2835_spi_setClockDivider(SPI_CLOCK_DIVIDER);
    bcm2835_spi_chipSelect(SPI_CS);
    bcm2835_spi_setChipSelectPolarity(SPI_CS, SPI_CS_POLARITY);

    return true;
}

int main(int argc, char **argv)
{
    // Initialize SPI
    if (!init_spi())
    {
        return 1;
    }

    // Data to send
    uint8_t send_data = 0x23;
    uint8_t read_data;

    // Transfer data
    read_data = bcm2835_spi_transfer(send_data);

    // Print results
    printf("Sent to SPI: 0x%02X. Received from SPI: 0x%02X.\n", send_data, read_data);

    // Check for loopback (optional, for testing)
    if (send_data != read_data)
    {
        printf("Warning: Loopback test failed. Check MOSI and MISO connection.\n");
    }

    // Close SPI
    bcm2835_spi_end();
    bcm2835_close();

