// Define SPI parameters
#define SPI_CHANNEL BCM2835_SPI_CS0
#define SPI_CLOCK_DIVIDER BCM2835_SPI_CLOCK_DIVIDER_64 //Adjust as needed for your device

// Function to initialize SPI
bool spi_init()
{
    if (!bcm2835_init()) {
        fprintf(stderr, "bcm2835_init failed. Are you running as root?\n");
        return false;
    }

    if (!bcm2835_spi_begin()) {
        fprintf(stderr, "bcm2835_spi_begin failed. Are you running as root?\n");
        bcm2835_close();
        return false;
    }

    bcm2835_spi_setBitOrder(BCM2835_SPI_BIT_ORDER_MSBFIRST);
    bcm2835_spi_setDataMode(BCM2835_SPI_MODE0);
    bcm2835_spi_setClockDivider(SPI_CLOCK_DIVIDER);
    bcm2835_spi_chipSelect(SPI_CHANNEL);
    bcm2835_spi_setChipSelectPolarity(SPI_CHANNEL, LOW);

    return true;
}

// Function to transfer data via SPI
bool spi_transfer(char *tx_buffer, char *rx_buffer, uint32_t data_length)
{
    if (tx_buffer == NULL || rx_buffer == NULL || data_length == 0) {
        fprintf(stderr, "Error: Invalid arguments to spi_transfer\n");
        return false;
    }

    bcm2835_spi_transfern(tx_buffer, data_length);
    memcpy(rx_buffer, tx_buffer, data_length); // Copy received data
    return true;
}

// Function to cleanup SPI
void spi_cleanup()
{
    bcm2835_spi_end();
    bcm2835_close();
}

int main(int argc, char **argv)
{
    if (!spi_init()) {
        return 1;
    }

    // Example Usage
    uint32_t data_size = 4;
    char tx_data[data_size];
    char rx_data[data_size];

    // Initialize transmit data
    tx_data[0] = 0x01;
    tx_data[1] = 0x02;
    tx_data[2] = 0x11;
    tx_data[3] = 0x33;

    if (spi_transfer(tx_data, rx_data, data_size)) {
        printf("Data sent and received successfully.\n");
        printf("Received data: 0x%02X 0x%02X 0x%02X 0x%02X\n", rx_data[0], rx_data[1], rx_data[2], rx_data[3]);
    } else {
        fprintf(stderr, "SPI transfer failed.\n");
    }

    spi_cleanup();
    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdbool.h>
#include <time.h>
#include <math.h>

// Constants
#define D6F_I2C_ADDR 0x6C  // D6F-PH I2C address (7-bit)
#define I2C_DEVICE "/dev/i2c-1" // I2C device file

// Function Prototypes
int i2c_write_bytes(int file_descriptor, uint8_t device_address, uint16_t register_address, const uint8_t *data, uint8_t length);
int i2c_read_bytes(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint8_t length);
float convert_raw_to_flow(uint16_t raw_flow);
int open_i2c_device(const char *device);
void close_i2c_device(int file_descriptor);

// Helper Functions
void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}

/**
 * Opens the I2C device.
 * @param device The path to the I2C device (e.g., "/dev/i2c-1").
 * @return The file descriptor of the opened device, or -1 on error.
 */
int open_i2c_device(const char *device) {
    int file_descriptor = open(device, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error opening I2C device %s: %s\n", device, strerror(errno));
    }
    return file_descriptor;
}

/**
 * Closes the I2C device.
 * @param file_descriptor The file descriptor of the I2C device.
 */
void close_i2c_device(int file_descriptor) {
    if (file_descriptor >= 0) {
        close(file_descriptor);
    }
}

/**
 * Writes bytes to an I2C device register.
 * @param file_descriptor The file descriptor of the I2C device.
 * @param device_address The I2C address of the device.
 * @param register_address The 16-bit register address to write to.
 * @param data The data to write.
 * @param length The number of bytes to write.
 * @return 0 on success, -1 on error.
 */
int i2c_write_bytes(int file_descriptor, uint8_t device_address, uint16_t register_address, const uint8_t *data, uint8_t length) {
    if (length > 125) { // Limiting the maximum data length
        fprintf(stderr, "Error: Write length exceeds maximum allowed (125 bytes).\n");
        return -1;
    }

    uint8_t buffer[128]; // Buffer to hold register address and data
    buffer[0] = (register_address >> 8) & 0xFF; // MSB of register address
    buffer[1] = register_address & 0xFF;        // LSB of register address

    if (data != NULL && length > 0) {
        memcpy(buffer + 2, data, length);
    }

    int total_length = length + 2;

    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C_SLAVE address: %s\n", strerror(errno));
        return -1;
    }

    ssize_t bytes_written = write(file_descriptor, buffer, total_length);
    if (bytes_written != total_length) {
        fprintf(stderr, "Error: I2C write failed: %s (Wrote %zd bytes, expected %d)\n", strerror(errno), bytes_written, total_length);
        return -1;
    }

    return 0;
}

/**
 * Reads bytes from an I2C device register.
 * @param file_descriptor The file descriptor of the I2C device.
 * @param device_address The I2C address of the device.
 * @param register_address The 8-bit register address to read from.
 * @param data The buffer to store the read data.
 * @param length The number of bytes to read.
 * @return 0 on success, -1 on error.
 */
int i2c_read_bytes(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint8_t length) {
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C_SLAVE address: %s\n", strerror(errno));
        return -1;
    }

    // Write the register address to read from
    ssize_t bytes_written = write(file_descriptor, &register_address, 1);
    if (bytes_written != 1) {
        fprintf(stderr, "Error: Failed to write register address: %s\n", strerror(errno));
        return -1;
    }

    // Read the data
    ssize_t bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Error: I2C read failed: %s (Read %zd bytes, expected %d)\n", strerror(errno), bytes_read, length);
        return -1;
    }

    return 0;
}

/**
 * Converts the raw flow sensor reading to a flow rate in L/min.
 * @param raw_flow The raw flow sensor reading (16-bit unsigned integer).
 * @return The flow rate in L/min.
 */
float convert_raw_to_flow(uint16_t raw_flow) {
    return ((float)raw_flow - 1024.0) * 10.0 / 60000.0;
}

int main() {
    int i2c_file_descriptor = open_i2c_device(I2C_DEVICE);
    if (i2c_file_descriptor < 0) {
        return EXIT_FAILURE;
    }

    // 1. Initialize sensor (0Bh, 00h)
    if (i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x0B00, NULL, 0) != 0) {
        fprintf(stderr, "Error: Failed to initialize sensor.\n");
        close_i2c_device(i2c_file_descriptor);
        return EXIT_FAILURE;
    }
    delay_ms(900);

    while (1) {
        // 2. Trigger getting data (00h, D0h, 40h, 18h, 06h)
        uint8_t trigger_data[] = {0x40, 0x18, 0x06};
        if (i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x00D0, trigger_data, sizeof(trigger_data)) != 0) {
            fprintf(stderr, "Error: Failed to trigger data acquisition.\n");
            close_i2c_device(i2c_file_descriptor);
            return EXIT_FAILURE;
        }

        delay_ms(50);

        // 3. Read data (00h, D0h, 51h, 2Ch) (07h)
        uint8_t read_command[] = {0x51, 0x2C};
        if (i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x00D0, read_command, sizeof(read_command)) != 0) {
            fprintf(stderr, "Error: Failed to send read command.\n");
            close_i2c_device(i2c_file_descriptor);
            return EXIT_FAILURE;
        }

        uint8_t flow_data[2];
        if (i2c_read_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x07, flow_data, sizeof(flow_data)) != 0) {
            fprintf(stderr, "Error: Failed to read flow data.\n");
            close_i2c_device(i2c_file_descriptor);
            return EXIT_FAILURE;
        }

        uint16_t raw_flow = (flow_data[0] << 8) | flow_data[1]; // Combine bytes to form 16-bit value
        float flow_rate = convert_raw_to_flow(raw_flow);

        printf("Flow Rate: %6.2f [L/min]\n", flow_rate);

        delay_ms(1000); // Read every 1 second
    }

    close_i2c_device(i2c_file_descriptor);
    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdbool.h>
#include <time.h>

// Constants
#define D6F_I2C_ADDR 0x6C  // D6F-PH I2C address (7-bit)
#define I2C_DEVICE "/dev/i2c-1" // I2C device file

// Function Prototypes
uint32_t i2c_write_bytes(int file_descriptor, uint8_t dev_addr, uint8_t* data, uint16_t length);
uint32_t i2c_read_bytes(int file_descriptor, uint8_t dev_addr, uint8_t reg_addr, uint8_t* data, uint16_t length);
uint16_t bytes_to_uint16(uint8_t* buffer);
void safe_delay_ms(int milliseconds);

int main() {
    int i2c_file_descriptor;
    uint8_t init_command[] = {0x0B, 0x00};
    uint8_t trigger_command[] = {0x00, 0xD0, 0x40, 0x18, 0x06};
    uint8_t read_command[] = {0x00, 0xD0, 0x51, 0x2C};
    uint8_t flow_data[2];
    uint16_t raw_flow_data;
    float flow_rate;
    uint32_t status;

    // Open I2C device
    i2c_file_descriptor = open(I2C_DEVICE, O_RDWR);
    if (i2c_file_descriptor < 0) {
        fprintf(stderr, "Error opening I2C device: %s\n", strerror(errno));
        return 1;
    }

    // Initialize sensor (0Bh, 00h)
    status = i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, init_command, 2);
    if(status != 0){
        fprintf(stderr, "Error initializing sensor\n");
        close(i2c_file_descriptor);
        return 1;
    }
    safe_delay_ms(900); // Initial delay after initialization

    while (1) {
        // Trigger data acquisition (00h, D0h, 40h, 18h, 06h)
        status = i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, trigger_command, 5);
        if(status != 0){
            fprintf(stderr, "Error triggering data acquisition\n");
            break;
        }

        safe_delay_ms(50); // Wait for conversion

        // Send read command (00h, D0h, 51h, 2Ch)
        status = i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, read_command, 4);
        if(status != 0){
            fprintf(stderr, "Error sending read command\n");
            break;
        }

        // Read flow data (07h)
        status = i2c_read_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x07, flow_data, 2);
        if(status != 0){
            fprintf(stderr, "Error reading flow data\n");
            break;
        }

        // Convert received bytes to unsigned 16-bit integer
        raw_flow_data = bytes_to_uint16(flow_data);

        // Calculate flow rate (0-20 L/min range)
        flow_rate = ((float)raw_flow_data - 1024.0) * 20.0 / 60000.0;

        printf("Flow Rate: %6.2f [L/min]\n", flow_rate);

        safe_delay_ms(1000); // Delay between readings
    }

    // Close I2C device
    close(i2c_file_descriptor);

    return 0;
}

// Function to write bytes to I2C device
uint32_t i2c_write_bytes(int file_descriptor, uint8_t dev_addr, uint8_t* data, uint16_t length) {
    if (file_descriptor < 0) return 1;

    if (ioctl(file_descriptor, I2C_SLAVE, dev_addr) < 0) {
        fprintf(stderr, "Error acquiring bus access or addressing slave: %s\n", strerror(errno));
        return 2;
    }

    ssize_t bytes_written = write(file_descriptor, data, length);
    if (bytes_written != length) {
        fprintf(stderr, "Error writing to I2C device: %s (Wrote %zd/%d bytes)\n", strerror(errno), bytes_written, length);
        return 3;
    }

    return 0; // Success
}

// Function to read bytes from I2C device
uint32_t i2c_read_bytes(int file_descriptor, uint8_t dev_addr, uint8_t reg_addr, uint8_t* data, uint16_t length) {
    if (file_descriptor < 0) return 1;

    if (ioctl(file_descriptor, I2C_SLAVE, dev_addr) < 0) {
        fprintf(stderr, "Error acquiring bus access or addressing slave: %s\n", strerror(errno));
        return 2;
    }

    // Write the register address to be read from
    ssize_t bytes_written = write(file_descriptor, &reg_addr, 1);
    if (bytes_written != 1) {
        fprintf(stderr, "Error writing register address: %s\n", strerror(errno));
        return 3;
    }

    // Read the data
    ssize_t bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Error reading from I2C device: %s (Read %zd/%d bytes)\n", strerror(errno), bytes_read, length);
        return 4;
    }

    return 0; // Success
}

// Function to convert two bytes to a 16-bit unsigned integer (Big Endian)
uint16_t bytes_to_uint16(uint8_t* buffer) {
    return (uint16_t)((((uint16_t)buffer[0]) << 8) | ((uint16_t)buffer[1]));
}

// Safe delay function using nanosleep
void safe_delay_ms(int milliseconds) {
    struct timespec req, rem;
    req.tv_sec = milliseconds / 1000;
    req.tv_nsec = (milliseconds % 1000) * 1000000L;
    while (nanosleep(&req, &rem) == -1) {
        if (errno == EINTR) {
            req = rem; // Resume interrupted sleep
        } else {
            perror("nanosleep");
            break; // Exit if nanosleep fails for other reasons
        }
    }
}

