// Define the I2C device file on Raspberry Pi
#define I2C_DEVICE "/dev/i2c-1"

// Function to convert a 16-bit integer to its high byte (uint8_t)
static inline uint8_t high_byte(int16_t value) {
    return (uint8_t)(value >> 8);
}

// Function to convert a 16-bit integer to its low byte (uint8_t)
static inline uint8_t low_byte(int16_t value) {
    return (uint8_t)(value & 0xFF);
}

// Function to convert two uint8_t values (big-endian) to a uint16_t
static inline uint16_t bytes_to_uint16(uint8_t high_byte, uint8_t low_byte) {
    return (uint16_t)(((uint32_t)high_byte << 8) | (uint32_t)low_byte);
}

// Function to perform a delay in milliseconds using nanosleep
void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}

// Function to write data to the I2C device using a 16-bit register address
int i2c_write(int file_descriptor, uint8_t device_address, uint16_t register_address, const uint8_t *data, uint8_t length) {
    uint8_t buffer[128]; // Buffer to hold the register address and data
    if (length > 125) {  // Maximum data length is 125 bytes (127 - 2 for reg address)
        fprintf(stderr, "Error: Data length exceeds maximum allowed (125 bytes).\n");
        return -1; // Indicate an error
    }

    buffer[0] = high_byte(register_address); // High byte of the register address
    buffer[1] = low_byte(register_address);  // Low byte of the register address

    if (data != NULL && length > 0) {
        memcpy(buffer + 2, data, length); // Copy the data to the buffer after the register address
    }

    // Set the I2C slave address for the device
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C device address. %s\n", strerror(errno));
        return -1; // Indicate an error
    }

    // Write the data to the I2C device
    ssize_t bytes_written = write(file_descriptor, buffer, length + 2); // Write reg addr + data
    if (bytes_written != (length + 2)) {
        fprintf(stderr, "Error: I2C write failed. Wrote %zd bytes, expected %d. %s\n", bytes_written, length + 2, strerror(errno));
        return -1; // Indicate an error
    }

    return 0; // Indicate success
}

// Function to read data from the I2C device using an 8-bit register address
int i2c_read(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint8_t length) {
    // Set the I2C slave address for the device
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C device address. %s\n", strerror(errno));
        return -1; // Indicate an error
    }

    // Write the register address to the I2C device
    if (write(file_descriptor, &register_address, 1) != 1) {
        fprintf(stderr, "Error: Could not write register address. %s\n", strerror(errno));
        return -1; // Indicate an error
    }

    // Read the data from the I2C device
    ssize_t bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Error: I2C read failed. Read %zd bytes, expected %d. %s\n", bytes_read, length, strerror(errno));
        return -1; // Indicate an error
    }

    return 0; // Indicate success
}

int main() {
    int file_descriptor; // File descriptor for the I2C device

    // Open the I2C device file
    file_descriptor = open(I2C_DEVICE, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error: Could not open I2C device. %s\n", strerror(errno));
        return 1; // Indicate an error
    }

    // 1. Initialize sensor (0Bh, 00h)
    if (i2c_write(file_descriptor, D6F_ADDR, 0x0B00, NULL, 0) != 0) {
        fprintf(stderr, "Error: Sensor initialization failed.\n");
        close(file_descriptor);
        return 1;
    }
    delay_ms(900);

    while (1) {
        // 2. Trigger getting data (00h, D0h, 40h, 18h, 06h)
        uint8_t trigger_data[] = {0x40, 0x18, 0x06};
        if (i2c_write(file_descriptor, D6F_ADDR, 0x00D0, trigger_data, sizeof(trigger_data)) != 0) {
            fprintf(stderr, "Error: Trigger write failed.\n");
            close(file_descriptor);
            return 1;
        }

        delay_ms(50); // wait 50ms

        // 3. Read data (00h, D0h, 51h, 2Ch) (07h)
        uint8_t read_command[] = {0x51, 0x2C};
        if (i2c_write(file_descriptor, D6F_ADDR, 0x00D0, read_command, sizeof(read_command)) != 0) {
            fprintf(stderr, "Error: Read command write failed.\n");
            close(file_descriptor);
            return 1;
        }

        uint8_t flow_data[2];
        if (i2c_read(file_descriptor, D6F_ADDR, 0x07, flow_data, sizeof(flow_data)) != 0) {
            fprintf(stderr, "Error: Flow data read failed.\n");
            close(file_descriptor);
            return 1;
        }

        uint16_t raw_flow = bytes_to_uint16(flow_data[0], flow_data[1]);
        float flow_rate;

        // 0-50[L/min] range
        flow_rate = ((float)raw_flow - 1024.0) * 50.0 / 60000.0;

        printf("Flow Rate: %6.2f [L/min]\n", flow_rate);

        delay_ms(100); // Add a small delay between readings
    }

    close(file_descriptor);
    return 0;
}

