// Constants
#define D6F_I2C_ADDR 0x6C  // D6F-PH I2C address (7-bit)
#define I2C_DEVICE "/dev/i2c-1" // I2C device file

// Function Prototypes
uint32_t i2c_write_bytes(int file_descriptor, uint8_t dev_addr, uint16_t reg_addr, const uint8_t *data, uint8_t length);
uint32_t i2c_read_bytes(int file_descriptor, uint8_t dev_addr, uint8_t reg_addr, uint8_t *data, uint8_t length);
uint16_t bytes_to_uint16(const uint8_t *buf);
void delay_ms(int milliseconds);

int main() {
    int i2c_file_descriptor;
    uint8_t read_buffer[2];
    uint16_t raw_flow_data;
    float flow_rate_lpm;
    uint32_t i2c_result;

    // Open I2C device
    i2c_file_descriptor = open(I2C_DEVICE, O_RDWR);
    if (i2c_file_descriptor < 0) {
        fprintf(stderr, "Error: Could not open I2C device %s: %s\n", I2C_DEVICE, strerror(errno));
        return EXIT_FAILURE;
    }

    // 1. Initialize sensor (0Bh, 00h)
    i2c_result = i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x0B00, NULL, 0);
    if (i2c_result != 0) {
        fprintf(stderr, "Error: Sensor initialization failed with code %u\n", i2c_result);
        close(i2c_file_descriptor);
        return EXIT_FAILURE;
    }
    delay_ms(900);

    while (1) {
        // 2. Trigger data acquisition (00h, D0h, 40h, 18h, 06h)
        uint8_t trigger_data[] = {0x40, 0x18, 0x06};
        i2c_result = i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x00D0, trigger_data, sizeof(trigger_data));
        if (i2c_result != 0) {
            fprintf(stderr, "Error: Trigger write failed with code %u\n", i2c_result);
            close(i2c_file_descriptor);
            return EXIT_FAILURE;
        }

        delay_ms(50);  // Wait for conversion

        // 3. Request data read (00h, D0h, 51h, 2Ch)
        uint8_t request_data[] = {0x51, 0x2C};
        i2c_result = i2c_write_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x00D0, request_data, sizeof(request_data));
        if (i2c_result != 0) {
            fprintf(stderr, "Error: Data request write failed with code %u\n", i2c_result);
            close(i2c_file_descriptor);
            return EXIT_FAILURE;
        }

        // Read flow data (07h)
        i2c_result = i2c_read_bytes(i2c_file_descriptor, D6F_I2C_ADDR, 0x07, read_buffer, sizeof(read_buffer));
        if (i2c_result != 0) {
            fprintf(stderr, "Error: Data read failed with code %u\n", i2c_result);
            close(i2c_file_descriptor);
            return EXIT_FAILURE;
        }

        // Convert raw bytes to flow rate
        raw_flow_data = bytes_to_uint16(read_buffer);
        flow_rate_lpm = ((float)raw_flow_data - 1024.0) * 70.0 / 60000.0; // 0-70 L/min range

        printf("Flow Rate: %6.2f [L/min]\n", flow_rate_lpm);

        delay_ms(100); // Sample every 100ms
    }

    close(i2c_file_descriptor);
    return EXIT_SUCCESS;
}

// Helper Functions

/**
 * @brief Writes bytes to an I2C device register.
 *
 * @param file_descriptor The I2C device file descriptor.
 * @param dev_addr The I2C device address.
 * @param reg_addr The register address to write to.
 * @param data Pointer to the data to write.
 * @param length The number of bytes to write.
 * @return 0 on success, or an error code on failure.
 */
uint32_t i2c_write_bytes(int file_descriptor, uint8_t dev_addr, uint16_t reg_addr, const uint8_t *data, uint8_t length) {
    uint8_t buffer[128]; // Buffer to hold register address and data
    if (length > 125) {
        fprintf(stderr, "Error: Write length exceeds maximum of 125 bytes\n");
        return 11;
    }

    // Set I2C slave address
    if (ioctl(file_descriptor, I2C_SLAVE, dev_addr) < 0) {
        fprintf(stderr, "Error: Could not set I2C slave address: %s\n", strerror(errno));
        return 12;
    }

    // Prepare the buffer: reg_addr (MSB first) followed by data
    buffer[0] = (reg_addr >> 8) & 0xFF; // MSB of register address
    buffer[1] = reg_addr & 0xFF;        // LSB of register address
    memcpy(buffer + 2, data, length);     // Copy data to the buffer

    // Write the data
    ssize_t bytes_written = write(file_descriptor, buffer, length + 2);
    if (bytes_written != length + 2) {
        fprintf(stderr, "Error: I2C write failed: %s (wrote %zd bytes, expected %d)\n", strerror(errno), bytes_written, length + 2);
        return 13;
    }

    return 0; // Success
}

/**
 * @brief Reads bytes from an I2C device register.
 *
 * @param file_descriptor The I2C device file descriptor.
 * @param dev_addr The I2C device address.
 * @param reg_addr The register address to read from.
 * @param data Pointer to the buffer to store the read data.
 * @param length The number of bytes to read.
 * @return 0 on success, or an error code on failure.
 */
uint32_t i2c_read_bytes(int file_descriptor, uint8_t dev_addr, uint8_t reg_addr, uint8_t *data, uint8_t length) {
    // Set I2C slave address
    if (ioctl(file_descriptor, I2C_SLAVE, dev_addr) < 0) {
        fprintf(stderr, "Error: Could not set I2C slave address: %s\n", strerror(errno));
        return 21;
    }

    // Write the register address to read from
    if (write(file_descriptor, &reg_addr, 1) != 1) {
        fprintf(stderr, "Error: Could not write register address: %s\n", strerror(errno));
        return 22;
    }

    // Read the data
    ssize_t bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Error: I2C read failed: %s (read %zd bytes, expected %d)\n", strerror(errno), bytes_read, length);
        return 23;
    }

    return 0; // Success
}

/**
 * @brief Converts two bytes (big-endian) to a 16-bit unsigned integer.
 *
 * @param buf Pointer to the byte array.
 * @return The 16-bit unsigned integer.
 */
uint16_t bytes_to_uint16(const uint8_t *buf) {
    return (uint16_t)((((uint32_t)buf[0]) << 8) | ((uint32_t)buf[1]));
}

