// Configuration
#define D6F_I2C_ADDR 0x6C  // D6F-PH I2C address (7-bit)
#define I2C_DEVICE "/dev/i2c-1" // I2C device file

// Function Prototypes
static uint32_t i2c_write_reg16(uint8_t dev_addr, uint16_t reg_addr, const uint8_t *data, uint8_t length);
static uint32_t i2c_read_reg8(uint8_t dev_addr, uint8_t reg_addr, uint8_t *data, uint8_t length);
static uint16_t bytes_to_uint16(const uint8_t *buf);
static void delay_ms(int milliseconds);

/**
 * @brief Writes data to a 16-bit register on an I2C device.
 *
 * @param dev_addr The I2C device address.
 * @param reg_addr The 16-bit register address to write to.
 * @param data A pointer to the data to write.
 * @param length The number of bytes to write.
 * @return 0 on success, or an error code on failure.
 */
static uint32_t i2c_write_reg16(uint8_t dev_addr, uint16_t reg_addr, const uint8_t *data, uint8_t length) {
    if (length > 125) {
        fprintf(stderr, "Error: Write length exceeds maximum allowed (125 bytes).\n");
        return 1; // Error code for invalid length
    }

    int file_descriptor = open(I2C_DEVICE, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error: Failed to open I2C device %s: %s\n", I2C_DEVICE, strerror(errno));
        return 2; // Error code for failed to open device
    }

    uint8_t buffer[128]; // Buffer to hold register address and data
    buffer[0] = (reg_addr >> 8) & 0xFF; // MSB of register address
    buffer[1] = reg_addr & 0xFF;      // LSB of register address

    if (data != NULL && length > 0) {
        memcpy(buffer + 2, data, length);
    }

    ssize_t bytes_to_write = length + 2;

    if (ioctl(file_descriptor, I2C_SLAVE, dev_addr) < 0) {
        fprintf(stderr, "Error: Failed to acquire bus access and/or talk to slave: %s\n", strerror(errno));
        close(file_descriptor);
        return 3; // Error code for failed I2C_SLAVE ioctl
    }

    ssize_t bytes_written = write(file_descriptor, buffer, bytes_to_write);
    if (bytes_written != bytes_to_write) {
        fprintf(stderr, "Error: Failed to write to I2C device. Expected %zd bytes, wrote %zd bytes: %s\n",
                bytes_to_write, bytes_written, strerror(errno));
        close(file_descriptor);
        return 4; // Error code for short write
    }

    close(file_descriptor);
    return 0; // Success
}

/**
 * @brief Reads data from an 8-bit register on an I2C device.
 *
 * @param dev_addr The I2C device address.
 * @param reg_addr The 8-bit register address to read from.
 * @param data A pointer to the buffer to store the read data.
 * @param length The number of bytes to read.
 * @return 0 on success, or an error code on failure.
 */
static uint32_t i2c_read_reg8(uint8_t dev_addr, uint8_t reg_addr, uint8_t *data, uint8_t length) {
    int file_descriptor = open(I2C_DEVICE, O_RDWR);
    if (file_descriptor < 0) {
        fprintf(stderr, "Error: Failed to open I2C device %s: %s\n", I2C_DEVICE, strerror(errno));
        return 5; // Error code for failed to open device
    }

    if (ioctl(file_descriptor, I2C_SLAVE, dev_addr) < 0) {
        fprintf(stderr, "Error: Failed to acquire bus access and/or talk to slave: %s\n", strerror(errno));
        close(file_descriptor);
        return 6; // Error code for failed I2C_SLAVE ioctl
    }

    // Write the register address to be read from
    ssize_t bytes_written = write(file_descriptor, &reg_addr, 1);
    if (bytes_written != 1) {
        fprintf(stderr, "Error: Failed to write register address: %s\n", strerror(errno));
        close(file_descriptor);
        return 7; // Error code for failed register address write
    }

    // Read the data
    ssize_t bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Error: Failed to read from I2C device. Expected %zd bytes, read %zd bytes: %s\n",
                length, bytes_read, strerror(errno));
        close(file_descriptor);
        return 8; // Error code for short read
    }

    close(file_descriptor);
    return 0; // Success
}

/**
 * @brief Converts two bytes (big-endian) to a 16-bit unsigned integer.
 *
 * @param buf A pointer to the byte array.
 * @return The converted 16-bit unsigned integer.
 */
static uint16_t bytes_to_uint16(const uint8_t *buf) {
    return (uint16_t)(((uint32_t)buf[0] << 8) | (uint32_t)buf[1]);
}

/**
 * @brief Delays execution for a specified number of milliseconds.
