#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdbool.h>
#include <time.h>
#include <math.h>

// Constants
#define D6F_PH_I2C_ADDR 0x6C  // D6F-PH I2C address (7-bit)
#define I2C_DEV_PATH "/dev/i2c-1" // I2C device path

// Function Prototypes
int i2c_write(int file_descriptor, uint8_t device_address, uint8_t *data, uint16_t length);
int i2c_read(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint16_t length);
float read_differential_pressure(int file_descriptor);

// Helper Functions
uint16_t bytes_to_uint16(uint8_t *buffer);
void delay_ms(int milliseconds);

int main() {
    int i2c_file_descriptor;

    // Open I2C device
    if ((i2c_file_descriptor = open(I2C_DEV_PATH, O_RDWR)) < 0) {
        fprintf(stderr, "Error: Could not open I2C device %s: %s\n", I2C_DEV_PATH, strerror(errno));
        return EXIT_FAILURE;
    }

    // Initialize sensor (0Bh, 00h)
    uint8_t init_data[] = {0x0B, 0x00};
    if (i2c_write(i2c_file_descriptor, D6F_PH_I2C_ADDR, init_data, 2) != 0) {
        fprintf(stderr, "Error: Failed to initialize sensor.\n");
        close(i2c_file_descriptor);
        return EXIT_FAILURE;
    }
    delay_ms(900);

    // Main loop
    while (1) {
        float pressure = read_differential_pressure(i2c_file_descriptor);
        if (isnan(pressure)){
            fprintf(stderr, "Error reading pressure. Retrying...\n");
            delay_ms(100);
            continue;
        }
        printf("Differential Pressure: %6.2f [Pa]\n", pressure);
        delay_ms(100); // Sample every 100ms
    }

    close(i2c_file_descriptor);
    return EXIT_SUCCESS;
}

// I2C Write Function
int i2c_write(int file_descriptor, uint8_t device_address, uint8_t *data, uint16_t length) {
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C slave address: %s\n", strerror(errno));
        return -1;
    }

    ssize_t bytes_written = write(file_descriptor, data, length);
    if (bytes_written != length) {
        fprintf(stderr, "Error: I2C write failed: %s (Wrote %zd/%d bytes)\n", strerror(errno), bytes_written, length);
        return -1;
    }

    return 0; // Success
}

// I2C Read Function
int i2c_read(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint16_t length) {
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C slave address: %s\n", strerror(errno));
        return -1;
    }

    // Write register address
    ssize_t bytes_written = write(file_descriptor, &register_address, 1);
    if (bytes_written != 1) {
        fprintf(stderr, "Error: Failed to write register address: %s\n", strerror(errno));
        return -1;
    }

    // Read data
    ssize_t bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Error: I2C read failed: %s (Read %zd/%d bytes)\n", strerror(errno), bytes_read, length);
        return -1;
    }

    return 0; // Success
}

// Function to Read Differential Pressure
float read_differential_pressure(int file_descriptor) {
    // Trigger data acquisition (0x00D0, 0x40, 0x18, 0x06)
    uint8_t trigger_data[] = {0x00, 0xD0, 0x40, 0x18, 0x06};
    if (i2c_write(file_descriptor, D6F_PH_I2C_ADDR, trigger_data + 2, 3) != 0) {
        fprintf(stderr, "Error: Failed to trigger data acquisition.\n");
        return NAN;
    }
    delay_ms(50);

    // Read data (0x00D0, 0x51, 0x2C) and register 0x07
    uint8_t read_command[] = {0x00, 0xD0, 0x51, 0x2C};
    uint8_t read_data[2];
    if (i2c_write(file_descriptor, D6F_PH_I2C_ADDR, read_command + 2, 2) != 0) {
        fprintf(stderr, "Error: Failed to send read command.\n");
        return NAN;
    }

    if (i2c_read(file_descriptor, D6F_PH_I2C_ADDR, 0x07, read_data, 2) != 0) {
        fprintf(stderr, "Error: Failed to read pressure data.\n");
        return NAN;
    }

    uint16_t raw_pressure = bytes_to_uint16(read_data);
    float flow_rate = ((float)raw_pressure - 1024.0) * 100.0 / 60000.0 - 50.0;
    return flow_rate;
}

// Helper Function: Convert 2 bytes to unsigned 16-bit integer (Big Endian)
uint16_t bytes_to_uint16(uint8_t *buffer) {
    return (uint16_t)((((uint16_t)buffer[0]) << 8) | ((uint16_t)buffer[1]));
}

// Helper Function: Delay for specified milliseconds
void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdbool.h>
#include <time.h>
#include <math.h>

// Constants
#define D6F_ADDR 0x6C  // D6F-PH I2C client address (7-bit)
#define I2C_DEVICE "/dev/i2c-1" // I2C device file

// Function Prototypes
static int i2c_write_bytes(int file_descriptor, uint8_t device_address, uint16_t register_address, const uint8_t *data, uint8_t length);
static int i2c_read_bytes(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint8_t length);
static uint16_t bytes_to_uint16(const uint8_t *buffer);
static void delay_ms(int milliseconds);

// Main Function
int main() {
    int i2c_file_descriptor;
    uint8_t read_buffer[2];
    uint16_t raw_flow_data;
    float flow_rate;
    int status;

    // Open I2C device
    i2c_file_descriptor = open(I2C_DEVICE, O_RDWR);
    if (i2c_file_descriptor < 0) {
        fprintf(stderr, "Error opening I2C device: %s\n", strerror(errno));
        return EXIT_FAILURE;
    }

    // Initialize sensor (0Bh, 00h)
    status = i2c_write_bytes(i2c_file_descriptor, D6F_ADDR, 0x0B00, NULL, 0);
    if (status != 0) {
        fprintf(stderr, "Error initializing sensor\n");
        close(i2c_file_descriptor);
        return EXIT_FAILURE;
    }
    delay_ms(900);

    while (1) {
        // Trigger data acquisition (00h, D0h, 40h, 18h, 06h)
        uint8_t trigger_data[] = {0x40, 0x18, 0x06};
        status = i2c_write_bytes(i2c_file_descriptor, D6F_ADDR, 0x00D0, trigger_data, sizeof(trigger_data));
        if (status != 0) {
            fprintf(stderr, "Error triggering data acquisition\n");
            break; // Exit loop on error
        }

        delay_ms(50); // Wait for conversion

        // Request data (00h, D0h, 51h, 2Ch) and read (07h)
        uint8_t request_data[] = {0x51, 0x2C};
        status = i2c_write_bytes(i2c_file_descriptor, D6F_ADDR, 0x00D0, request_data, sizeof(request_data));
        if (status != 0) {
            fprintf(stderr, "Error requesting data\n");
            break; // Exit loop on error
        }

        status = i2c_read_bytes(i2c_file_descriptor, D6F_ADDR, 0x07, read_buffer, sizeof(read_buffer));
        if (status != 0) {
            fprintf(stderr, "Error reading sensor data\n");
            break; // Exit loop on error
        }

        // Convert raw data to flow rate
        raw_flow_data = bytes_to_uint16(read_buffer);
        flow_rate = ((float)raw_flow_data - 1024.0) * 1000.0 / 60000.0 - 500.0;

        // Print flow rate
        printf("Flow Rate: %6.2f [Pa]\n", flow_rate);

        delay_ms(1000); // Sample every 1 second
    }

    // Close I2C device
    close(i2c_file_descriptor);

    return (status == 0) ? EXIT_SUCCESS : EXIT_FAILURE;
}

// Helper Functions

/**
 * @brief Writes bytes to an I2C device.
 *
 * @param file_descriptor The I2C file descriptor.
 * @param device_address The I2C device address.
 * @param register_address The register address to write to.
 * @param data The data to write.
 * @param length The number of bytes to write.
 * @return 0 on success, -1 on failure.
 */
static int i2c_write_bytes(int file_descriptor, uint8_t device_address, uint16_t register_address, const uint8_t *data, uint8_t length) {
    uint8_t buffer[128]; // Increased buffer size for safety
    if (length > 122) { // Maximum data length is now 122 to accommodate register address
        fprintf(stderr, "Error: Data length exceeds maximum allowed (122 bytes).\n");
        return -1; // Indicate failure
    }

    buffer[0] = (register_address >> 8) & 0xFF; // MSB of register address
    buffer[1] = register_address & 0xFF;        // LSB of register address

    if (data != NULL && length > 0) {
        memcpy(buffer + 2, data, length);
    }

    int total_length = length + 2;

    // Set the I2C slave address for the file descriptor
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C device address: %s\n", strerror(errno));
        return -1; // Indicate failure
    }

    ssize_t bytes_written = write(file_descriptor, buffer, total_length);
    if (bytes_written != total_length) {
        fprintf(stderr, "Error: I2C write failed: %s (Wrote %zd bytes, expected %d)\n", strerror(errno), bytes_written, total_length);
        return -1; // Indicate failure
    }

    return 0; // Indicate success
}

/**
 * @brief Reads bytes from an I2C device.
 *
 * @param file_descriptor The I2C file descriptor.
 * @param device_address The I2C device address.
 * @param register_address The register address to read from.
 * @param data The buffer to store the read data.
 * @param length The number of bytes to read.
 * @return 0 on success, -1 on failure.
 */
static int i2c_read_bytes(int file_descriptor, uint8_t device_address, uint8_t register_address, uint8_t *data, uint8_t length) {
    // Set the I2C slave address for the file descriptor
    if (ioctl(file_descriptor, I2C_SLAVE, device_address) < 0) {
        fprintf(stderr, "Error: Could not set I2C device address: %s\n", strerror(errno));
        return -1; // Indicate failure
    }

    // Write the register address to be read from
    ssize_t bytes_written = write(file_descriptor, &register_address, 1);
    if (bytes_written != 1) {
        fprintf(stderr, "Error: Could not write register address: %s\n", strerror(errno));
        return -1; // Indicate failure
    }

    // Read the data from the I2C device
    ssize_t bytes_read = read(file_descriptor, data, length);
    if (bytes_read != length) {
        fprintf(stderr, "Error: I2C read failed: %s (Read %zd bytes, expected %d)\n", strerror(errno), bytes_read, length);
        return -1; // Indicate failure
    }

    return 0; // Indicate success
}

/**
 * @brief Converts two bytes (big-endian) to a 16-bit unsigned integer.
 *
 * @param buffer Pointer to the byte array.
 * @return The 16-bit unsigned integer.
 */
static uint16_t bytes_to_uint16(const uint8_t *buffer) {
    return ((uint16_t)buffer[0] << 8) | (uint16_t)buffer[1];
}

/**
 * @brief Delays execution for a specified number of milliseconds.
 *
 * @param milliseconds The number of milliseconds to delay.
 */
static void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}

#include <stdio.h>
#include <stdint.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <stdbool.h>
#include <time.h>
#include <math.h>

// Configuration
#define D6T_ADDR 0x0A  // I2C 7-bit address of the D6T sensor
#define D6T_CMD 0x4C   // Command to request temperature data
#define NUM_PIXELS 1   // Number of pixels in the sensor (D6T-1A-01/02 has 1)
#define I2C_BUS "/dev/i2c-1" // I2C bus interface on Raspberry Pi

// Data buffer size (2 bytes per pixel + 2 bytes for PTAT + 1 byte for PEC)
#define DATA_BUFFER_SIZE ((NUM_PIXELS + 1) * 2 + 1)

// Function Prototypes
int i2c_read_data(int file_descriptor, uint8_t *data_buffer, int length);
bool check_pec(uint8_t *data_buffer, int length);
int16_t convert_bytes_to_int16(uint8_t *data_buffer, int index);
void delay_ms(int milliseconds);

int main() {
    int i2c_file_descriptor;
    uint8_t data_buffer[DATA_BUFFER_SIZE];
    double ambient_temperature, pixel_temperature;

    // Open I2C bus
    i2c_file_descriptor = open(I2C_BUS, O_RDWR);
    if (i2c_file_descriptor < 0) {
        fprintf(stderr, "Error opening I2C bus %s: %s\n", I2C_BUS, strerror(errno));
        return 1;
    }

    // Set I2C slave address
    if (ioctl(i2c_file_descriptor, I2C_SLAVE, D6T_ADDR) < 0) {
        fprintf(stderr, "Error setting I2C slave address: %s\n", strerror(errno));
        close(i2c_file_descriptor);
        return 1;
    }

    // Initial delay to allow sensor to stabilize
    delay_ms(220);

    while (1) {
        // Read temperature data from the sensor
        if (i2c_read_data(i2c_file_descriptor, data_buffer, DATA_BUFFER_SIZE) != 0) {
            fprintf(stderr, "Error reading temperature data\n");
            continue; // Retry on error
        }

        // Verify PEC (Packet Error Check)
        if (!check_pec(data_buffer, DATA_BUFFER_SIZE - 1)) {
            // Extract ambient temperature (PTAT - Proportional to Absolute Temperature)
            ambient_temperature = (double)convert_bytes_to_int16(data_buffer, 0) / 10.0;

            // Extract pixel temperature
            pixel_temperature = (double)convert_bytes_to_int16(data_buffer, 2) / 10.0;

            // Print the temperature data
            printf("Ambient Temperature: %.1f °C, Pixel Temperature: %.1f °C\n", ambient_temperature, pixel_temperature);
        } else {
            fprintf(stderr, "PEC check failed. Data may be corrupted.\n");
        }

        // Delay before the next reading
        delay_ms(100);
    }

    // Close I2C bus (this will never be reached in the current loop)
    close(i2c_file_descriptor);
    return 0;
}

// Function to read data from the I2C device
int i2c_read_data(int file_descriptor, uint8_t *data_buffer, int length) {
    int bytes_written, bytes_read;

    // Write the command to initiate the read
    bytes_written = write(file_descriptor, &D6T_CMD, 1);
    if (bytes_written != 1) {
        fprintf(stderr, "Failed to write command to I2C device: %s\n", strerror(errno));
        return -1;
    }

    // Read the data from the device
    bytes_read = read(file_descriptor, data_buffer, length);
    if (bytes_read != length) {
        fprintf(stderr, "Failed to read data from I2C device: %s (Expected %d bytes, got %d)\n", strerror(errno), length, bytes_read);
        return -1;
    }

    return 0;
}

// Function to calculate the CRC8 checksum (PEC) and verify data integrity
bool check_pec(uint8_t *data_buffer, int length) {
    uint8_t crc = 0x00;
    uint8_t polynomial = 0x07; // CRC-8 polynomial

    // Calculate CRC for the data
    for (int i = 0; i < length; i++) {
        crc ^= data_buffer[i];
        for (int j = 0; j < 8; j++) {
            if (crc & 0x80) {
                crc = (crc << 1) ^ polynomial;
            } else {
                crc <<= 1;
            }
        }
    }

    // Compare calculated CRC with the received CRC
    return (crc != data_buffer[length]);
}

// Function to convert two bytes from the buffer to a signed 16-bit integer (little-endian)
int16_t convert_bytes_to_int16(uint8_t *data_buffer, int index) {
    int16_t value = (int16_t)((data_buffer[index + 1] << 8) | data_buffer[index]);
    return value;
}

// Function to introduce a delay in milliseconds
void delay_ms(int milliseconds) {
    struct timespec ts;
    ts.tv_sec = milliseconds / 1000;
    ts.tv_nsec = (milliseconds % 1000) * 1000000;
    nanosleep(&ts, NULL);
}
